INSERT INTO `ecom_productos` VALUES (1, NULL, 'producto', '7500211001184', 0x414C492D323542, 'Q125', 10.00, 'Alimento betta bit frasco', '<p>Alimento bettabit frasco</p><p>Cantidad: 50 gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Alimento en pellets para pez Betta.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Pellets de 1.5 mm de diámetro.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Especial para desarrollar a los peces Betta.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Hundimiento lento con movimientos que mimetizan las presas de los Bettas.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Alimento rico en proteínas de fácil asimilación y completamente balanceado para el adecuado cuidado de los Bettas.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Carecterísticas: Es compatible para otras especies cuyas necesidades alimenticias sean las mismas.</span></p>', 0, 30, NULL, 1, NULL, NULL, NULL, '2024-04-11 19:54:34', '2023-12-02 22:04:41', NULL, 'Alimento-betta-bit-frasco', 0, 0);
INSERT INTO `ecom_productos` VALUES (2, NULL, 'producto', '7501556406467', 0x414C492D3842, 'WAT646', 16.00, 'Alimento betta premium 8 gramos ', '<p>Alimento betta premium</p><p>cantidad: 8 gramos</p><p><br></p><p>Descripción:</p><p>Nutricional mente balanceado</p><p>Realza los colores</p><p>Mini pellet flotante</p>', 1, 20, 124, 1, NULL, NULL, NULL, '2025-07-11 13:26:45', NULL, NULL, 'Alimento-betta-premium-8-gramos-', 0, 0);
