INSERT INTO `ecom_productos` VALUES (6, NULL, 'producto', '7501556466164', 0x414C492D3131304342, 'WAT616', 5.00, 'Alimento japones golfish pellets premium', '<p>Alimento japones golfish</p><p>Cantidad: 90 gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Ofrece una nutrición superior y brillantes coloraciones a los peces japoneses, son pellets flotantes en bocados medianos. </span></p><p><span style=\"color: rgb(102, 102, 102);\">﻿Es de tamaño adecuado y contiene todos los nutrientes que sus peces necesitan para crecer y desarrollarse de manera correcta.</span></p>', 1, 35, 124, 1, NULL, NULL, NULL, '2025-12-26 22:55:05', NULL, NULL, 'Alimento-japones-golfish-pellets-premium', 0, 0);
INSERT INTO `ecom_productos` VALUES (7, NULL, 'producto', '046798771609', 0x414C4954452D3238, 'AQ-77160', 5.00, 'Alimento hojuela tetra color 28g para peces', '<p>Alimento tetra color chico</p><p>Cantidad: 28 gramos</p><p><br></p><p>Descripción:</p><p>Fórmula patentada ProCare que favorece el buen funcionamiento del sistema inmunológico del pez para una salud óptima y larga vida. Mezcla científicamente desarrollada de ingredientes altamente nutritivos, con vitaminas y minerales. Las hojuelas TetraMin de Tetra han sido desarrolladas especialmente para una fácil ingesta, gracias a su forma, textura y sabor. Dieta diseñada especialmente para resaltar los colores rosa, rojo y naranja de los peces de agua dulce.</p><p><br></p><p>Características</p><p>Fórmula avanzada, enriquecida con vitaminas y minerales.</p><p>Excelente textura y palatabilidad.</p><p>Perfeccionado para la óptima nutrición de peces.</p><p>Favorece la coloración intensa de los peces.</p><p>Alta digestibilidad.</p><p>No enturbia el agua.</p><p><br></p><p><br></p><p><br></p>', 1, 160, 124, 1, NULL, NULL, NULL, '2025-08-24 15:16:30', NULL, NULL, 'Alimento-hojuela-tetra-color-28g-para-peces', 0, 0);
INSERT INTO `ecom_productos` VALUES (8, NULL, 'variante', 'CAMAFLMROSA07', 0x43414D4D2D3037, 'PI0101-0036', 2.00, 'Cama antiestrés mediana para perros y gatos', '<p>Cama antiestrés mediana para mascotas</p><p>Medidas: 60 x 15 cm (circuferencia x alto)</p><p>Color: rosa</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros , gatos, uron, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p>', 1, 560, NULL, 1, NULL, NULL, NULL, '2024-02-05 21:11:04', '2024-02-05 15:11:04', NULL, 'Cama_antiestres_mediana_para_perros_y_gatos', NULL, NULL);
