INSERT INTO `ecom_productos` VALUES (14, NULL, 'producto', '7502234330364', 0x414C49544F2D3031, 'SFF-01', 4.00, 'Alimento para tortuga bites (bolitas)', '<p>Alimento para tortuga bites (bolitas)</p><p>Cantidad: 90 gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Es un alimento flotante destinado para alimentacion diaria de las tortugas acuaticas y semiacuaticas tanto onmnivoro como carnivoro. Los nutrientes bien equilibrados y un conjunto de vitaminas y minerales garantizan un crecimientio uniforme, asi como buana condicion y salud de las tortugas jovenes. el suplemento de zeolita influye de manera positiva en sistema digestivo y elimina las toxinas del organismo.</span></p>', 1, 35, 124, 1, NULL, NULL, NULL, '2025-08-24 13:54:01', '2023-12-02 22:04:41', NULL, 'Alimento-para-tortuga-bites-(bolitas)', 0, 0);
INSERT INTO `ecom_productos` VALUES (15, NULL, 'producto', '7502234330371', 0x414C49544F2D3032, 'SFF-02', 5.00, 'Alimento para tortuga stick (palitos)', '<p>Alimento para tortuga sticks (palitos)</p><p>Cantidad: 70 gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Es un alimento flotante destinado para alimentacion diaria de las tortugas acuaticas y semiacuaticas tanto onmnivoro como carnivoro. Los nutrientes bien equilibrados y un conjunto de vitaminas y minerales garantizan un crecimientio uniforme, asi como buana condicion y salud de las tortugas jovenes. el suplemento de zeolita influye de manera positiva en sistema digestivo y elimina las toxinas del organismo.</span></p>', 1, 35, 124, 1, NULL, NULL, NULL, '2025-08-24 13:54:51', NULL, NULL, 'Alimento-para-tortuga-stick-(palitos)', 0, 0);
INSERT INTO `ecom_productos` VALUES (16, NULL, 'producto', '7501556450033', 0x414C492D313048, 'TP-3501', 18.00, 'Alimento hojuela básicas mini para peces', '<p>Alimento hojuela básicas mini</p><p>Cantidad: 10 gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Dedicado a la excelencia en nutrición para los peces tropicales.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Realza los colores de los peces.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Digestibilidad mejorada.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fórmula avanzada “C” </span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">﻿Instrucciones de alimentación:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Se debe dar de comer a los peces varías veces al día.</span></p><p><span style=\"color: rgb(102, 102, 102);\">No les de más de lo que consuman en 5 min.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Las hojuelas Básicas no enturbian el agua si se dispensan adecuadamente.</span></p><p><br></p><p><br></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2024-03-24 15:38:38', '2023-12-02 22:04:41', NULL, 'Alimento-hojuela-basicas-mini-para-peces', 0, 0);
