INSERT INTO `ecom_productos` VALUES (26, NULL, 'producto', '7500211004369', 0x414C4953552D3230, 'Q815', 7.00, 'Alimento hojuelas super flakes 20gr para peces', '<p>Alimento hojuelas super flakes</p><p>Cantidad: 20 grs</p><p><br></p><p>Descripción:</p><p>Para todas las estapas de la vida</p><p><span style=\"color: rgb(64, 43, 64);\">Es una mezcla de hojuelas de colores rojo, verde y amarillo, con olor a camarón y de textura quebradiza, diseñado para ajustarse a las necesidades nutricionales de la mayoría de los peces tropicales y de agua dulce.&nbsp;</span></p><p><span style=\"color: rgb(64, 43, 64);\">Las hojuelas están diseñadas para fortalecer a tus peces en dos vías. Primero la adición de Beta-glucanos estimula la inmunidad celular en la línea de glóbulos blancos encargados de la producción de anticuerpos. Segundo, la incorporación de glucomananos favorece la implantación de una flora microbiana robusta de especies bacterianas benéficas que impiden el establecimiento de patógenos a lo largo del tracto digestivo y por si fuera poco, mejoran significativamente la absorción de los nutrientes.</span></p><p><br></p><p>Ingredientes especiales: Con prebióticos y probióticos</p>', 1, 45, 124, 1, NULL, NULL, NULL, '2025-08-25 16:11:16', '2023-12-02 22:04:41', NULL, 'Alimento-hojuelas-super-flakes-20gr-para-peces', 0, 0);
INSERT INTO `ecom_productos` VALUES (27, NULL, 'producto', '7500211001047', 0x414C4942412D3031, 'Q111', 3.00, 'Alimento peces hojuelas basicas 110gr', '<p>Alimento hojuelas basicas</p><p>Cantidad:110 grs</p><p><br></p><p>Descripción:</p><p>Alimento para peces tropicales</p><p>No enturbia el agua</p><p><span style=\"color: rgb(70, 71, 74);\">Es un alimento en hojuelas ideal para peces tropicales. A tu pez le encantará, ya que está elaborado con ingredientes naturales y con el correcto balance dietético.</span></p>', 1, 150, 124, 1, NULL, NULL, NULL, '2025-08-26 12:24:24', '2023-12-02 22:04:41', NULL, 'Alimento-peces-hojuelas-basicas-110gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (28, NULL, 'producto', '7502217856775', 0x414C49582D3031, 'A100', 5.00, 'Alimento para ajolote axolotinas mini ', '<p>Alimento para axolote ajolote</p><p>Cantidad: 60 grs</p><p>esferas: 2.5mm de diametro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para crias de ajolotes.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fórmula omnívora, predominantemente cárnica.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Cuenta con un excelente balance calcio:fósforo. Sin duda, la mejor opción del mercado para la completa nutrición de estos Ejemplares.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fórmula diseñada, probada y comprobada por especialistas en cría de ajolotes. </span></p><p><br></p>', 1, 60, 124, 1, NULL, NULL, NULL, '2025-08-26 16:21:38', '2023-12-02 22:04:41', NULL, 'Alimento-para-ajolote-axolotinas-mini-', 0, 0);
