INSERT INTO `ecom_productos` VALUES (37, NULL, 'producto', '7501556440324', 0x4C494D2D3032, 'FL8912', 5.00, 'limpiador magnético mediano para pecera', '<p>Limipador maganético mediano</p><p>Medidas: 8 x 4 cm (largo x ancho)</p><p><br></p><p>Descripción:</p><p>El limpiador magnético de Lomas quita con facilidad las algas del cristal del acuario sin rayarlo.</p><p>Puede utilizarse en acuarios marinos o dulces, sin afectar la calidad del agua.</p><p>Es un método práctico y efectivo de limpieza del tanque.</p><p>Los potentes imanes aseguran un agarre firme en el vidrio, por lo que no es necesario introducir las manos en el acuario.</p><p>Recomendacion de superficie vidrio</p><p><br></p><p><br></p>', 1, 178, NULL, 1, NULL, NULL, NULL, '2024-03-28 22:39:47', NULL, NULL, 'limpiador-magnetico-mediano-para-pecera', 0, 0);
