INSERT INTO `ecom_productos` VALUES (40, NULL, 'producto', '7502234330388', 0x414C492D393047, 'SFF-03', 3.00, 'Alimento premium para pez goldfish 90 grs', '<p>Alimento premium para pez goldfish</p><p>Cantidad: 90 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Alimento especial y completo de uso diario que realza los colores y que esirve para todo tipo de goldfish, hecho a base de una formula alimenticia balanceada con una variedad de ingredientes altamente digestibles adaptados a las necesidades energeticas del goldfish con </span>formula estabilizada de Vitamina C el cual ayuda a reforzar el sistema inmine.</p><p><br></p><p><br></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2023-10-14 15:20:05', NULL, NULL, 'Alimento_premium_para_pez_goldfish_90_grs', NULL, NULL);
