INSERT INTO `ecom_productos` VALUES (42, NULL, 'producto', '7500211004383', 0x414C4953552D313530, 'Q817', 5.00, 'Alimento hojuela super flakes 150gr para peces ', '<p>Alimento hojuelas para peces super flakes grande</p><p>Cantidad: 150 grs</p><p><br></p><p>Descripción:</p><p>Para todas las estapas de la vida</p><p><span style=\"color: rgb(64, 43, 64);\">Es una mezcla de hojuelas de colores rojo, verde y amarillo, con olor a camarón y de textura quebradiza, diseñado para ajustarse a las necesidades nutricionales de la mayoría de los peces tropicales y de agua dulce.&nbsp;</span></p><p><br></p><p><span style=\"color: rgb(64, 43, 64);\">﻿Las hojuelas están diseñadas para fortalecer a tus peces en dos vías. Primero la adición de Beta-glucanos estimula la inmunidad celular en la línea de glóbulos blancos encargados de la producción de anticuerpos. Segundo, la incorporación de glucomananos favorece la implantación de una flora microbiana robusta de especies bacterianas benéficas que impiden el establecimiento de patógenos a lo largo del tracto digestivo y por si fuera poco, mejoran significativamente la absorción de los nutrientes.</span></p><p><br></p><p>Ingredientes especiales: Con prebióticos y probióticos</p>', 1, 150, 124, 1, NULL, NULL, NULL, '2025-08-25 16:16:24', '2023-12-02 22:04:41', NULL, 'Alimento-hojuela-super-flakes-150gr-para-peces-', 0, 0);
