INSERT INTO `ecom_productos` VALUES (44, NULL, 'producto', '015561221863', 0x464C4F522D3039, 'HPT2186', 5.00, 'Foco para reptil UVB 100 13w', '<p>Foco para reptil UVB 100</p><p>Luz: blanco neutro</p><p>Voltaje: 120v</p><p>Watts: 13w</p><p>Indice de UVB: 5</p><p><br></p><p>Caracteristicas:</p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para reptiles tropicales y subtropicales.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alta producción de radiación UVB.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Efectivo por encima de los 30 cm (12 \").</span></p><p><span style=\"color: rgb(102, 102, 102);\">Proporciona los necesarios rayos UVB para un óptimo metabolismo del calcio, Estimula el apetito, actividad y comportamiento reproductivo por medio de la radiación UVA. Es recomendable en combinación con Repti Glo 2.0 para una producción de luz visible.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ventajas:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Exo Terra Repti Glo emite la radiación UVB similar a los ambientes sombreados tales como</span></p><p><span style=\"color: rgb(102, 102, 102);\">bosques lluviosos y otras localidades tropicales. </span></p>', 0, 740, 124, 1, NULL, NULL, NULL, '2025-10-02 16:30:47', '2023-12-05 14:50:06', NULL, 'Foco-para-reptil-UVB-100-13w', 0, 0);
INSERT INTO `ecom_productos` VALUES (45, NULL, 'producto', 'GALLQUESO05', 0x47414C4C2D3035, 'FL3846', 5.00, 'Galletas premio sabor queso para perro', '<p>Galletas premio para perro</p><p>Cantidad:100 grs</p><p>Edad de perro: Adulto</p><p>Sabor: queso</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(55, 61, 63);\">Galletas en forma de hueso&nbsp;</span><strong style=\"color: rgb(55, 61, 63);\">sabor queso</strong><span style=\"color: rgb(55, 61, 63);\">. Además, están</span><strong style=\"color: rgb(55, 61, 63);\">&nbsp;fortificadas con vitaminas</strong><span style=\"color: rgb(55, 61, 63);\">, no contienen grasa, son muy saludables y ricas, a tu perro seguro le encantan.</span></p>', 1, 45, 124, 1, NULL, NULL, NULL, '2025-10-21 22:55:11', NULL, NULL, 'Galletas-premio-sabor-queso-para-perro', 0, 0);
