INSERT INTO `ecom_productos` VALUES (47, NULL, 'producto', '7501556479645', 0x43414E432D3031, 'FL7964', 3.00, 'Canutillos anillos de ceramica ', '<p>Canutillos (anillos de ceramica)</p><p>Cantidad: 450 grs</p><p><br></p><p>Incluye: una bolsa de malla</p><p><br></p><p>Descripcion: favorece el desarrollo de bacaterias beneficas que auxilian en el control de amoniaco y nitritos, ideal para acuarios de agua dulce y salada, contribuye a crear un hábitat saludable para los peces</p><p><br></p><p>Recomendaciones:</p><p>Enjuague los anillos con agua corriente antes de introduccirlos por primera vez en el acuario</p><p><br></p>', 1, 170, NULL, 1, NULL, NULL, NULL, '2023-06-22 13:11:08', NULL, NULL, 'Canutillos_anillos_de_ceramica_', NULL, NULL);
INSERT INTO `ecom_productos` VALUES (48, NULL, 'producto', '750155445022', 0x43415A412D3032, 'FL4502', 5.00, 'Snack yummy sticks', '<p>Yummy sticks</p><p>Contenido: 3 piezas de (60grs)</p><p><br></p><p>Descripción:</p><p>Snack vitaminado y minerales para perros, promueve la salud dental ayudando a eliminar residuos de comida alojados entre dientes al mismo tiempo ayuda a reducir el estrés y liberar energía al ejercitar su mandíbula y entretiene a tu mascota</p><p><br></p>', 0, 35, NULL, 1, NULL, NULL, NULL, '2024-05-09 22:40:15', NULL, NULL, 'Snack-yummy-sticks', 0, 0);
