INSERT INTO `ecom_productos` VALUES (51, NULL, 'producto', '7501556440034', 0x414C49492D3033, 'FL4003', 7.00, 'Alimento para iguana juvenil 350 gramos ', '<p>Alimento para iguana juvenil</p><p>Cantidad: 350 grs</p><p>Sabor: platano</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(15, 17, 17);\">Fórmula elaborada con ingredientes naturales mezclados y balanceados de manera adecuada el calcio que participa en el óptimo desarrollo de los huesos,alimento con </span> exquisito sabor plátano lo hace altamente palatable para las iguanas, ayudando a su sano y equilibrado crecimiento para todas las etapas de la vida.</p><p><br></p><p><br></p><p><br></p><p><br></p>', 1, 110, 124, 1, NULL, NULL, NULL, '2025-08-24 12:55:35', '2023-12-05 14:50:06', NULL, 'Alimento-para-iguana-juvenil-350-gramos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (52, NULL, 'producto', '7501556440027', 0x414C49492D3034, 'FL4002', 10.00, 'Alimento para iguana juvenil 700 gramos', '<p>Alimento para iguana juvenil</p><p>Cantidad: 700grs</p><p>Sabor: platano</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(15, 17, 17);\">Fórmula elaborada con ingredientes naturales mezclados y balanceados de manera adecuada el calcio que participa en el óptimo desarrollo de los huesos,alimento con </span> exquisito sabor plátano lo hace altamente palatable para las iguanas, ayudando a su sano y equilibrado crecimiento recomendado para etapa joven adulto.</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ingredientes: trigo, pasta de soya, gluten de maíz, carbonato de calcio, oleína de palma, fosfato di cálcico, vitamina a, vitamina d3, vitamina b12, riboflavina, niacina, ácido fólico, menadiona, ácido pantoténico, etc.</span></p><p><br></p>', 1, 190, 124, 1, NULL, NULL, NULL, '2025-12-26 22:49:12', '2023-12-05 14:50:06', NULL, 'Alimento-para-iguana-juvenil-700-gramos', 0, 0);
