INSERT INTO `ecom_productos` VALUES (54, NULL, 'producto', '7501556421521', 0x43414C492D3031, 'FL2152', 15.00, 'Calcio + minerales para reptil 135 grs', '<p>Calcio + minerales para reptil</p><p>Cantidad:135 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(57, 61, 66);\">Reptilia Suplemento con Calcio y Minerales para Reptiles y Anfibios, contiene calcio que es un mineral fundamental para la salud de los reptiles y anfibios. Influye en el correcto desarrollo y mantenimiento de los huesos, impulsos nerviosos, contracciones musculares, acciones enzimáticas y coagulación de la sangre. En los reptiles y anfibios hembras ayuda en la formación de los huevos. Cuando se tiene deficiencia de calcio se pueden padecer enfermedades que afectan la calidad de vida del reptil o anfibio.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ingredientes:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Carbonato de calcio, sulfato de cobre, sulfato ferroso, óxido de manganeso, óxido de zinc, óxido de magnesio, sal, sodio, potasio, aceite mineral, cascarilla de arroz.</span></p>', 1, 75, 124, 1, NULL, NULL, NULL, '2025-08-24 13:26:55', '2023-12-05 14:50:06', NULL, 'Calcio-+-minerales-para-reptil-135-grs', 0, 0);
INSERT INTO `ecom_productos` VALUES (55, NULL, 'producto', '7713042266138', 0x414C49452D312E3254, 'EX005', 10.00, 'Alimento para erizo tenebrio grande', '<p>Alimento para erizo</p><p>Cantidad: 1.2 grs</p><p>Sabor: tenebrio</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Contiene:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Vitamina e y Omega 3.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Pellet de tamaño ideal.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Sabor Tenebrio.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Modo de uso:</span></p><p><span style=\"color: rgb(102, 102, 102);\">El erizo siempre debe tener libre acceso al alimento y agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Los recipientes del agua y la comida devén limpiarse con regularidad para evitar enfermedades.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendaciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">También puedes proporcionarle de 1 a 3 veces por semana alimento vivo,</span></p>', 1, 399, NULL, 1, NULL, NULL, NULL, '2024-02-04 02:57:32', '2023-11-16 12:36:35', NULL, 'Alimento-para-erizo-tenebrio-grande', 0, 0);
