INSERT INTO `ecom_productos` VALUES (58, NULL, 'producto', '7501556440126', 0x414C4950412D3031, 'FL4012', 8.00, 'Mezcla de semillas para finches y canarios para pajaros', '<p>Mezcla de semillas</p><p>Para: Finches, canarios y gorriones.</p><p>Cantidad: 500 grs</p><p><br></p><p>Descripción: Este alimento elaborado con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá</p><p>Fortificado con vitaminas y minerales.</p><p>Fórmula 100% natural balanceada</p><p>Coloque diariamente el alimento en un recipiente limpio y seco.</p>', 1, 90, 124, 1, NULL, NULL, NULL, '2026-04-08 07:39:50', NULL, NULL, 'Mezcla-de-semillas-para-finches-y-canarios-para-pajaros', 0, 0);
