INSERT INTO `ecom_productos` VALUES (60, NULL, 'producto', '7501556404043', 0x4449532D3031, 'DYNV05', 4.00, 'Disco giratorio chico para hámster', '<p>Disco giratorio para hámster (ruso, enano)</p><p>Medidas: 12.7 cm diametro</p><p>color: transparente</p><p><br></p><p>Descripción: disco giratorio para ejercitar tu hamster.</p><p><br></p><p><br></p><p><br></p>', 1, 160, NULL, 1, NULL, NULL, NULL, '2024-02-17 18:33:02', '2023-11-28 17:38:30', NULL, 'Disco-giratorio-chico-para-hamster', 0, 0);
INSERT INTO `ecom_productos` VALUES (61, NULL, 'producto', '590046904123', 0x414C4948412D3034, '50412', 3.00, 'Alimento para hámster premimun', '<p>Alimento para hámster premium</p><p>Cantidad: 750gr</p><p><br></p><p>Descipción:</p><p>Comida con la adiccion de verduras, frutas y hierbas.</p><p>Belleza y cuidado</p><p>Digestión óptima</p><p>Inmunidad pro</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Alimento completo para hámsters a base de granulados con hierbas, alfalfa, manzana, grosella, semillas de linaza y pavo, así como con adición de verduras, frutas secas ricas en vitaminas y hierbas aromáticas la estructura y la forma de los granulados, así como las frutas, verduras y los fragmentos verdes de las plantas favorecen la abrasión de los dientes las semillas de linaza ricas en ácidos grasos insaturados dan el aspecto saludable a la piel y el brillo al pelo el alto contenido de fibra y la adición de remolacha y hierbas regulan la digestión las propiedades prebióticas de muchos ingredientes del alimento estimulan el desarrollo de la flora intestinal y apoyan al sistema inmunitario de los hámsters la zeolita reduce el olor desagradable de los heces el alimento no contiene componentes genéticamente modificados (OGM), conservantes, potenciadores del sabor, adición de azúcar ni aromas.</span></p>', 1, 280, 124, 1, NULL, NULL, NULL, '2026-04-08 07:20:20', '2023-11-28 17:38:30', NULL, 'Alimento-para-hamster-premimun', 0, 0);
INSERT INTO `ecom_productos` VALUES (62, NULL, 'producto', '7502234337455', 0x414C49434F2D3031, 'TP-3745', 23.00, 'Alimento para conejo mezcla de mix', '<p>Alimento para conejo</p><p>Cantidad:500grs</p><p><br></p><p>Descripción:</p><p>Control de olor de heces</p><p>Sano crecimiento</p><p>Mejora de digestión</p><p><span style=\"color: rgb(102, 102, 102);\">Nutrición Avanzada, contiene frutas, vegetales, semillas y granos.</span></p><p>Es m<span style=\"color: rgb(102, 102, 102);\">ezcla completa de cereales con adición de granulados, destinada para la alimentación diaria de hámster. Además de granos de cereales enriquecidos con manzanas, girasol y maíz, que son obtenidos por extrusión, que aumenta la digestibilidad y favorece la asimilación de los nutrientes contenidos en los cereales.</span></p><p><br></p><p><br></p><p><br></p><p><br></p>', 1, 95, 124, 1, NULL, NULL, NULL, '2026-04-08 07:01:33', '2023-11-28 17:38:30', NULL, 'Alimento-para-conejo-mezcla-de-mix', 0, 0);
