INSERT INTO `ecom_productos` VALUES (65, NULL, 'variante', 'CAMAFLUGRI04', 0x43414D462D3034, 'PI0101-0004', 2.00, 'Cama antiestrés mini para mascotas', '<p>Cama antiestrés mini para mascotas</p><p>Medidas: 35 x 10 cm (circuferencia x alto)</p><p>color: gris</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 1, 210, NULL, 1, NULL, NULL, NULL, '2024-08-30 01:42:35', '2024-08-30 01:42:35', NULL, 'Cama-antiestres-mini-para-mascotas', 0, 0);
