INSERT INTO `ecom_productos` VALUES (67, NULL, 'producto', '7501556491821', 0x4A55502D3032, 'FL9182', 7.00, 'Juguete para aves calcio triple ', '<p>Jueguete para aves calcio triple</p><p>Medidas: 18 cm </p><p>Peso: 68 grs </p><p><br></p><p>Descripción:</p><p>Juguete colgante triple con calcio para aves.</p><p>Cuentas de plástico.</p><p>Flores de acrílico.</p><p>Campana y gancho de metal.</p><p>Enriquecido con calcio.</p><p>Ideal para aves pequeñas y medianas.</p><p>Ofrece entretenimiento para el ave.</p><p>Ayuda a ejercitar al ave física y mentalmente.</p><p>Incita la curiosidad del ave.</p>', 1, 199, NULL, 1, NULL, NULL, NULL, '2023-10-02 21:14:04', NULL, NULL, 'Juguete_para_aves_calcio_triple_', NULL, NULL);
INSERT INTO `ecom_productos` VALUES (68, NULL, 'producto', '6931254210065', 0x4449532D3038, 'SH-230147', 2.00, 'Dispensadores cometa', '<p>Dispensador colores</p><p>Bebedero: 1.5 litros</p><p>Medidas: 30 x 32 x 19 cm (largo x ancho x alto)</p><p>Incluye:colador, tazon para alimento</p><p><br></p><p>Descripción: bebedero por gravedad conforme la mascota se alimenta comienza a desender el agua , bridandole agua para varias ocaciones del dia, de facil insatalamiento y limpieza, dispensadores para perros pequeños, gatos, urones, mini pig, etc.</p><p>Para: razas pequeñas.</p><p><br></p><p>Colores: Rosa, Gris, gris Azulado (Sujetos a dispobilidad)</p>', 1, 550, NULL, 1, NULL, NULL, NULL, '2024-02-26 21:11:30', '2023-11-21 14:59:48', NULL, 'Dispensadores-cometa', 0, 0);
INSERT INTO `ecom_productos` VALUES (69, NULL, 'producto', 'hamali87261', 0x4244524F2D3036, 'SP-3671', 0.00, 'Bebedero para hámster 800 ml ', '<p>Bebedero para hámster</p><p><br></p><p>Capacidad: 800 ml</p><p>Color: rojo, verde, amarillo, morado,azul (sujetos a disponibilidad).</p><p><br></p><p>Incluye:</p><p>Resorte de metal con gancho para colgar</p><p><br></p><p>Descripció: boquilla de acero inoxidable con doble balin antigoteo</p>', 1, 165, NULL, 1, NULL, NULL, NULL, '2024-08-08 23:50:21', NULL, NULL, 'Bebedero-para-hamster-800-ml-', 0, 0);
INSERT INTO `ecom_productos` VALUES (70, NULL, 'producto', '7501556466768', 0x414C49434F2D3033, 'WAT676', 10.00, 'Alimento para conejo pellets balanceados', '<p>Alimento para conejo pellets balanceados</p><p>Cantidad: 1.2 kgrs</p><p><br></p><p>Descripción:</p><p>Natural 100 %</p><p>Sano crecimiento</p><p>Mejora de digestión</p><p><span style=\"color: rgb(0, 0, 0);\">Alimento completamente balanceado, cumple con las necesidades de salud de los conejos.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Fuente de energía y nutrición. Ingredientes de origen natural. </span></p><p><span style=\"color: rgb(0, 0, 0);\">Contiene trozos de zanahoria. Delicioso sabor. Conserve el alimento en un lugar fresco y seco. </span></p><p><span style=\"color: rgb(0, 0, 0);\">Con vitaminas y minerales que maximizan la salud y pelaje brillante</span></p><p><span style=\"color: rgb(0, 0, 0);\">Alfalfa deshidratada como fuente de energía</span></p>', 1, 105, 124, 1, NULL, NULL, NULL, '2026-04-08 07:04:15', NULL, NULL, 'Alimento-para-conejo-pellets-balanceados', 0, 0);
INSERT INTO `ecom_productos` VALUES (71, NULL, 'producto', '7501556404500', 0x414C4948412D3032, 'WAT-450', 11.00, 'Alimento para hámster croquetas', '<p>Alimento para hámster croquetas</p><p>Cantidad:450 grs</p><p><br></p><p>Descripción:</p><p>Alimento balanceado para hamster y gerbo Fortificado con vitaminas y minerales</p><p>Nutricon 100 % balanceada aportación necesaria para el óptimo desarrollo del roedor.</p><p>Adicionado con vitaminas y minerales para reforzar el sistema inmune y beneficiar la salud general de tu mascota.</p><p>Fuente de carbohidratos para un alto nivel de energía.</p><p>Alimento en forma de rosetas balanceados.</p><p><br></p>', 1, 98, 124, 1, NULL, NULL, NULL, '2026-04-06 08:02:20', '2023-11-28 17:38:30', NULL, 'Alimento-para-hamster-croquetas', 0, 0);
INSERT INTO `ecom_productos` VALUES (72, NULL, 'producto', 'ALIHENOPACA18', 0x414C49482D3138, 'ALIH-18', 0.00, 'Heno de avena alimento por paca', '<p>Heno de avena alimento para paca</p><p>Cantidad: 20 kgrs aproximadamente</p><p>Para: conejos, cuyos, conejillo de indias, chinchilla, hámster, gerbos, ratas, tortugas sulcatas, degus, cerdos, ovejas, cabras, caballos, vacas y mas.</p><p><br></p><p>Descipción:</p><p>El heno de avena constituye el 80% de la alimentación de su mascota, es uno de los henos mas adecuados para ayudar al desgaste de los dientes y a mejorar la digestón, ya que actua como antioxidante y es un potenciador del sistema inmunitario. Destaca por su aporte en glucosa y hierro que ofrecen a nuestras mascotas un pelaje mas brillante y terso.</p><p><br></p><p>El heno <span style=\"color: rgb(102, 102, 102);\">lleva un proceso de deshidratación y secado lento en sombra para que conserve sus nutrientes, aroma y sobre todo su hoja.</span></p><p><br></p><p><br></p>', 0, 1250, 124, 1, NULL, NULL, NULL, '2026-04-05 21:14:21', NULL, NULL, 'Heno-de-avena-alimento-por-paca', 0, 0);
INSERT INTO `ecom_productos` VALUES (73, NULL, 'variante', 'CAMAFLNEGRA06', 0x43414D462D303620, 'PI0101-0008', 2.00, 'Cama antiestrés mini para mascotas', '<p>Cama antiestrés mini para mascotas</p><p>Medidas: 35 x 10 cm (circuferencia x alto)</p><p>color: negro</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 1, 210, NULL, 1, NULL, NULL, NULL, '2024-08-30 01:42:35', '2024-08-30 01:42:35', NULL, 'Cama-antiestres-mini-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (74, NULL, 'producto', '7501556421514', 0x43414C2D3032, 'FL2151', 14.00, 'Suplemento calcio + vitaminas D3', '<p>Suplemento calcio + vitaminas</p><p>Cantidad:135 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(57, 61, 66);\">Suplemento en polvo para Reptiles y Anfibios, </span><span style=\"color: rgb(102, 102, 102);\">Excelente para reptiles carnívoros por no contener fosforo. Ayuda a la absorción del calcio</span></p><p><span style=\"color: rgb(102, 102, 102);\">no altera el sabor del alimento.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Modo de empleo:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Coloque cantidad suficiente en un recipiente con tapa para cubrir a los insectos vivos. Tape y ruede suavemente el recipiente hasta que los insectos queden totalmente cubiertos</span></p><p><span style=\"color: rgb(102, 102, 102);\">Vegetales y fruta: Mezcle ½ cucharada (equivalente a 10g de suplemento) por cada 500g de mezcla de vegetales y fruta.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ingredientes:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Carbonato de calcio, vitamina D3, aceite mineral, cascarilla de arroz..</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendaciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Limpie el recipiente del alimento entes de colocar una nueva ración. No olvide proporcionar a la mascota agua fresca y limpia, así como proveer de luz y temperaturas adecuadas para la especie.</span></p>', 1, 75, 124, 1, NULL, NULL, NULL, '2025-07-17 08:15:46', '2023-12-05 14:50:06', NULL, 'Suplemento-calcio-+-vitaminas-D3', 0, 0);
INSERT INTO `ecom_productos` VALUES (75, NULL, 'producto', '7502271355399', 0x54415A2D3032, 'ART.50623', 3.00, 'Tazon duo hueso ', '<p>Tazon duo hueso</p><p>Medidas: 30.8 x 18.5 x 7cm (largo x ancho x alto)</p><p>Color: azul, rosa, verde (colores sujetos a disponibilidad)</p><p><br></p><p>Descripción: tazon para agua y comida en un solo lugar de un tamaño ideal para tu mascota.</p><p><br></p>', 1, 120, NULL, 1, NULL, NULL, NULL, '2023-10-14 15:52:07', NULL, NULL, 'Tazon_duo_hueso_', NULL, NULL);
INSERT INTO `ecom_productos` VALUES (76, NULL, 'producto', '7500211000330', 0x4152452D3031, 'G501', 29.00, 'Arena para gato 3 kilos', '<p>Arena para gato</p><p>Cantidad: 3 kgr</p><p><br></p><p>Descripción:</p><p>Evita malos olores</p><p>Absorbe y Aglutina</p><p>Por su acción aglutinante, forma terrones fácilmente removibles</p><p>No se necesita cambiar toda la arena</p><p>Solo retire los terrones y reemplace la porción utilizada</p><p>Material echo a base silice</p><p><br></p>', 1, 75, NULL, 1, NULL, NULL, NULL, '2026-06-03 08:15:27', '2026-06-03 08:15:27', NULL, 'Arena-para-gato-3-kilos', 0, 0);
INSERT INTO `ecom_productos` VALUES (77, NULL, 'producto', '7502271354811', 0x41524F2D3134, 'ART.7646', 10.00, 'Arenero seren con sernidor', '<p>Arenero seren con sernidor</p><p>Medidas: 51 X 35 X 25cm (largo x ancho x alto)</p><p><br></p><p>Incluye:</p><p>Serindor</p><p>Pala</p><p>Controno montable y desmontable para evitar derrames de arena baño para gatos.</p><p><br></p><p>Color: azul cielo o rosa con blanco (colores sujetos a disponibilidad)</p><p><br></p>', 1, 550, 124, 1, NULL, NULL, NULL, '2026-03-27 22:20:38', NULL, NULL, 'Arenero-seren-con-sernidor', 0, 0);
