INSERT INTO `ecom_productos` VALUES (98, NULL, 'producto', '7501556439229', 0x4341542D3031, 'FL3922', 0.00, 'Catnip para gatos ', '<p>Catnip para gatos</p><p><br></p><p>Cantidad: 28 gramos</p><p>Incrementa la actividad y el ejercicio del gato</p><p>Perfecto para usar en rascadores, juguetes y cama de la mascota</p><p><br></p><p>Ingredientes 100% naturales <span style=\"color: rgb(72, 72, 72);\">onformado por la hierba Nepeta cataria deshidratada</span></p><p><br></p><p><span style=\"color: rgb(72, 72, 72);\">Este producto no causa hábito, no es adictivo, ni toxico. No apto perros. Consulte al Médico Veterinario.</span></p>', 0, 70, NULL, 1, NULL, NULL, NULL, '2024-08-30 08:47:52', NULL, NULL, 'Catnip-para-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (99, NULL, 'producto', '7502271353456', 0x41524F2D3038, 'ART.10170', 10.00, 'Arenero abatible horizontal ', '<p>Arenero abatible horizontal</p><p>Medidas: 50 X 41 X 39 (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero tapado para prevención de desborde de arena abatible <span style=\"color: rgb(94, 98, 120);\">de plástico resistente fácil de cargar y limpiar baño para gatos.</span></p><p>Color: azul, cafe, verde aqua, rosa (colres sujetos a disponibilidad)</p><p><br></p><p>Incluye: pala</p>', 0, 680, 124, 1, NULL, NULL, NULL, '2026-03-27 22:16:21', NULL, NULL, 'Arenero-abatible-horizontal-', 0, 0);
INSERT INTO `ecom_productos` VALUES (100, NULL, 'producto', '7501556440133', 0x414C4950412D3032, 'FL4013', 5.00, 'Mezcla de semillas loros y cacatúas alimento para pajaros', '<p>Mezcla de semillas</p><p>Para: Loros cacatúas y conuros</p><p>Cantidad: 500 grs</p><p><br></p><p>Descripción: Este alimento elaborado para aves adultas con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá</p><p>Fortificado con vitaminas y minerales.</p><p>Fórmula 100% natural balanceada</p><p>Coloque diariamente el alimento en un recipiente limpio y seco.</p>', 1, 100, 124, 1, NULL, NULL, NULL, '2026-04-08 07:40:03', NULL, NULL, 'Mezcla-de-semillas-loros-y-cacatuas-alimento-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (101, NULL, 'producto', '7502234337998', 0x4341542D3032, 'SP-3799', 10.00, 'Catnip menta para gatos', '<p>Cat nip menta para gatos</p><p>Cantidad:30grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(119, 119, 119);\">Es un producto 100 %&nbsp;natural conformado por la hierba&nbsp;</span><em style=\"color: rgb(119, 119, 119);\">Nepeta cataria</em><span style=\"color: rgb(119, 119, 119);\">&nbsp;deshidratada, la cual estimula el juego y la curiosidad, incrementando la actividad y el ejercicio del gato.</span></p><p><br></p><p><span style=\"color: rgb(119, 119, 119);\">Etiquetas: </span></p><p><span style=\"color: rgb(51, 72, 98);\">Catnip, hirba gatera, nepeta, menta para gatos.</span></p>', 1, 70, NULL, 1, NULL, NULL, NULL, '2024-08-30 08:48:44', NULL, NULL, 'Catnip-menta-para-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (102, NULL, 'variante', 'CAMFLMULTI07', 0x43414D462D3037, 'PI0101-0012', 5.00, 'Cama antiestrés mini para mascotas', '<p>Cama antiestrés mini para mascotas</p><p>Medidas: 35 x 10 cm (circuferencia x alto)</p><p>color: multicolor</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 1, 240, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:18:55', '2024-09-30 17:18:55', NULL, 'Cama-antiestres-mini-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (103, NULL, 'producto', '8022967065313', 0x41524F2D3134, 'MP080403', 3.00, 'Arenero marco plus chico', '<p>Arenero marco plus chico</p><p>Medidas: <span style=\"color: rgb(51, 51, 51);\">40 cm X 25 cm X 10 cm</span>(largo x ancho x alto)</p><p><br></p><p><br></p><p>Descripción:</p><p>Arenero con contorno para evitar derrames de arena en la entrada con tipo sernidor para cuando pise caiga residuos de arena de sus patas baño para gatos.</p><p><br></p><p>Colores: azul, rojo, verde (sujetos a disponibilidad)</p><p><br></p>', 1, 250, 124, 1, NULL, NULL, NULL, '2025-06-03 23:09:29', '2025-06-03 23:09:29', NULL, 'Arenero-marco-plus-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (104, NULL, 'producto', '037461415364', 0x535553502D3031, '415364', 0.00, 'Sustrato de papel uber confeti 36 L para roedor ', '<p>Sustrato de papel para roedores</p><p>Medidas: 22 x 10 x 40cm</p><p>Rinde: 36 L</p><p>Color: colores</p><p><br></p><p>Descripción:</p><p>Control de olor 14 dias su cama de papel de larga duración mantiene la jaula de su mascota fresca hasta por dos semanas, el sustrato de papel hace una cama acogedora y suave es un papael triturado virgen apto para uso alimentario; cómodo y encajable para animales pequeños 99.9% libre de polvo y sin aditivos químicos para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p>', 0, 495, 124, 1, NULL, NULL, NULL, '2026-01-31 08:53:02', NULL, NULL, 'Sustrato-de-papel-uber-confeti-36-L-para-roedor-', 0, 0);
INSERT INTO `ecom_productos` VALUES (105, NULL, 'producto', '03746141356', 0x535553502D3034, '413568', 2.00, 'Sustrato de papel natural grande para roedor ', '<p>Sustrato de papel para roedores</p><p>Medidas: 33 x 14 x 35 cm</p><p>Rinde: 56 L</p><p><br></p><p>Descripción:</p><p>Control de olor 14 dias su cama de papel de larga duración mantiene la jaula de su mascota fresca hasta por dos semanas, el sustrato de papel hace una cama acogedora y suave es un papael triturado virgen apto para uso alimentario; cómodo y encajable para animales pequeños 99.9% libre de polvo y sin aditivos químicos para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, mini pig etc.</p>', 0, 675, 124, 1, NULL, NULL, NULL, '2026-04-13 07:19:15', NULL, NULL, 'Sustrato-de-papel-natural-grande-para-roedor-', 0, 0);
INSERT INTO `ecom_productos` VALUES (106, NULL, 'producto', '7502261581678', 0x4D41532D3032, 'OP-2', 5.00, 'Mascotera transportadora chica', '<p>Mascotera transportadora mini</p><p>Medidas: 17.5 x 10.5 x 12 cm (largo x ancho x alto)</p><p>Para: insectos, arañas, escorpiones, chapulines, grillos, tarantulas, alacranes u roedores pequeños como hámster, peces como betta, guppy, cebras, y reptiles como iguanas, tortugas, etc.</p><p><br></p><p>Descripción: Mascotera sirve para trasladar a un animal pequeño de un punto a otro o hacerle un mini habitat, en este contenedor de plastico acrilico transparente.</p><p><br></p><p>Incluye:</p><p>Puerta abatible</p><p>Asa de sujetación</p><p>Tapa plastica de rejilla</p>', 1, 90, 124, 1, NULL, NULL, NULL, '2025-09-21 12:11:21', NULL, NULL, 'Mascotera-transportadora-chica', 0, 0);
