INSERT INTO `ecom_productos` VALUES (109, NULL, 'producto', '6920232203311', 0x41524F2D3138, 'SH-230331', 0.00, 'Arenero craft', '<p>Arenero craft</p><p>Medidas: 47.5 x 47.5 x 44.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>No esparce olores en el entorno, bloqueo 360° para la arena</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño moderno y adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>Puerta abatible</p><p>Pala</p><p>Charola extraible</p><p>Rascador integrado en la parte superior</p><p>Soporte discreto para pala</p><p><br></p><p>Colres: rosa, gris, blanco ( sujetos a disponibilidad)</p>', 1, 0, NULL, 0, NULL, NULL, NULL, '2024-02-01 21:50:38', NULL, NULL, '', 0, 0);
