INSERT INTO `ecom_productos` VALUES (122, NULL, 'producto', '7501556439700', 0x5348412D3034, 'FL3970', 2.00, 'Shampoo todo tipo de pelo grande', '<p>Shampoo todo tipo de pelo para perro</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials para Todo Tipo de Pelo está formulado para remover la suciedad hasta del pelaje más complejo, dejándolo suave para un fácil cepillado.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No irrita la piel ni los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Limpia e hidrata.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Suaviza y fortalece el pelaje.</span></p>', 1, 95, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:34:13', NULL, NULL, 'Shampoo-todo-tipo-de-pelo-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (123, NULL, 'producto', '7501556439762', 0x5348412D3035, 'FL3976', 2.00, 'Shampoo desinfectante grande ', '<p>Shampoo para perro desinfectante grande</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials Desinfectante de contiene extracto de semilla de toronja que funciona como agente antibacterial y fungicida manteniendo el pelo limpio y saludable. No irrita la piel ni los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Elaborado con extracto de semilla de toronja. Antibacterial y fungicida</span></p>', 1, 120, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:41:16', NULL, NULL, 'Shampoo-desinfectante-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (124, NULL, 'producto', '7502278910409', 0x42532D313230, '6004', 7.00, 'Bomba sumergible 1.2 m ', '<p>Bomba sumergible 1.2 m</p><p><br></p><p>Medidas: 5.5 x 4 x 5cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Regulador de presion</p><p>Para agua dulce/salada</p><p>Volts 110/120v</p><p>Potencia 8.5w</p><p>Frecuencia 50/60hz</p><p>Capacidad:600l/h</p><p><br></p><p>Incluye:</p><p>Adaptadores: 1/2\" , 1/3\" , 5/8\" con venturi</p><p>Manguera</p><p>Regulador de aire</p><p><br></p><p><br></p>', 1, 360, NULL, 1, NULL, NULL, NULL, '2024-04-09 23:31:55', '2023-12-04 12:03:13', NULL, 'Bomba-sumergible-1.2-m-', 0, 0);
INSERT INTO `ecom_productos` VALUES (125, NULL, 'producto', '7500211005175', 0x414C49544F2D3039, 'T130', 0.00, 'Alimento para tortugas en crecimiento', '<p>Alimento para tortugas en crecimiento</p><p>Cantidad:100 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Es un alimento que contiene todos los nutrientes esenciales para las tortugas acuáticas en pleno desarrollo Incluyendo las proporciones de minerales y vitaminas A y D3, así como calcio, para evitar anomalías esqueléticas, como el reblandecimiento del caparazón entre otras.</span></p><p><br></p>', 0, 35, 124, 1, NULL, NULL, NULL, '2025-08-24 13:59:04', NULL, NULL, 'Alimento-para-tortugas-en-crecimiento', 0, 0);
INSERT INTO `ecom_productos` VALUES (126, NULL, 'producto', '7502278910416', 0x42532D313630, '6005', 7.00, 'Bomba sumergible 1.6 m ', '<p>Bomba sumergible 1.6 m</p><p>Medidas: 7 x 5 x 6.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Regulador de presión</p><p>Para agua dulce/salada</p><p>Volts 110/120v</p><p>Potencia 13w</p><p>Frecuencia 50/60hz</p><p>Capacidad: 800 l/h</p><p><br></p><p>Incluye:</p><p>Adaptadores: 1/2\" , 5/8\" con venturi</p><p>Manguera</p><p>Regulador de aire</p>', 1, 460, 124, 1, NULL, NULL, NULL, '2025-12-26 08:57:13', '2023-12-04 12:03:13', NULL, 'Bomba-sumergible-1.6-m-', 0, 0);
INSERT INTO `ecom_productos` VALUES (127, NULL, 'producto', '7502278910423', 0x42532D323030, '6006', 7.00, 'Bomba sumergible 2 m ', '<p>Bomba sumergible 2 m</p><p>Medidas: 9 x 5.5 x 7cm (largo x ancho x alto)</p><p>Volts 110/120v</p><p>Potencia 18w</p><p>Frecuencia 50/60hz</p><p>Capacidad:1200l/h</p><p>Regulador de presión</p><p>Para agua dulce/salada</p><p><br></p><p>Descripción:</p><p>Bomba sumergible de uso continuo usada para maquinaria de contrucción, muros llorones, fuentes, para un flitro un sump, pasar agua de un punto a otro.</p><p><br></p><p>Recomendaciónes:</p><p>La bomba sumergible debe de quedar completamente sumergida en el agua, sis se basea el contenedor de agua rellenar porque si se queda sin agua y la bomba no queda sumergida se quema por falta de agua. si es para un muro lloron se suma lo alto de su muro mas lo ancho y la sumatoria que le de es la bomba necesitara.</p><p><br></p><p>Incluye:</p><p>Adaptadores: 1/2\" , 5/8\" , 3/4\" , 5/8\" con venturi</p><p>Manguera</p><p>Regulador de aire</p><p><br></p><p><br></p><p><br></p><p><br></p>', 0, 595, 124, 1, NULL, NULL, NULL, '2025-12-26 08:57:55', NULL, NULL, 'Bomba-sumergible-2-m-', 0, 0);
