INSERT INTO `ecom_productos` VALUES (137, NULL, 'producto', '7713042267753', 0x414C49452D3035, 'EX031', 6.00, 'Alimento para erizo bombyx chico', '<p>Alimento para erizo</p><p>Cantidad: 250grs</p><p>Sabor: Bombyx mori (gusano de cera)</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Contiene:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Vitamina e y Omega 3.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Pellet de tamaño ideal.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Modo de uso:</span></p><p><span style=\"color: rgb(102, 102, 102);\">El erizo siempre debe tener libre acceso al alimento y agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Los recipientes del agua y la comida devén limpiarse con regularidad para evitar enfermedades.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendaciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">También puedes proporcionarle de 1 a 3 veces por semana alimento vivo</span></p>', 1, 199, 124, 1, NULL, NULL, NULL, '2025-08-06 11:36:11', '2023-11-16 12:36:35', NULL, 'Alimento-para-erizo-bombyx-chico', 0, 0);
