INSERT INTO `ecom_productos` VALUES (139, NULL, 'producto', '7502211996248', NULL, 'NULL', 1.00, 'Calentador 200 w biopro', 'Calentador 200 w biopro', 1, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `ecom_productos` VALUES (140, NULL, 'producto', '75030083788702', 0x43414C2D533035, 'SGH-280', 4.00, 'Calentador (termostato) 200 watts', '<p><strong>Capacidad</strong>: 200 w</p><p><br></p><p>La relación es 1 w x litros</p><p><br></p><p><strong>USO COMPLETAMENTE SUMERGIBLE: </strong><span style=\"color: rgb(102, 102, 102);\">El equipo debe sumergirse completamente en el Acuario ya que usarlo fuera del agua puede causar daños en los empaques o cristal del equipo.&nbsp;</span></p><p><br></p><p><strong>PERILLA REGULADORA: </strong><span style=\"color: rgb(102, 102, 102);\">Su equipo cuenta con una perilla en la parte superior&nbsp;la cual le permite regular la temperatura del agua dentro de su acuario, al llegar a la temperatura deseada el calentador se apagara de forma automática, y se encenderá nuevamente cuando detecte una baja en la temperatura configurada.</span></p><p><br></p><p><strong>TOMA DE CORRIENTE:</strong> <span style=\"color: rgb(102, 102, 102);\">Nuestros calentadores están especialmente diseñados para uso completamente sumergido y que usted solo deba conectarlo al toma corriente para comenzar a hacer uso del equipo.&nbsp;</span></p>', 1, 250, 0, 1, NULL, NULL, NULL, '2025-03-03 12:53:40', '2023-12-02 22:04:41', NULL, 'Calentador-(termostato)-200-watts', 0, 0);
INSERT INTO `ecom_productos` VALUES (141, NULL, 'producto', '7502211996200', NULL, 'NULL', 0.00, 'Calentador 25 w biopro', 'Calentador 25 w biopro', 1, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `ecom_productos` VALUES (142, NULL, 'producto', '7501556486018', 0x43414C2D3031, 'FL8601', 5.00, 'Calentador (termostato) eco 25w', '<p>Calentador termostato</p><p>Potencia: 25 w</p><p>Voltaje: 120v</p><p>hertzios: 60 Hz</p><p><br></p><p>Descripción:</p><p>Cristal de alto impacto</p><p>Escalas de temperatura de facil lectura</p><p>Núcleo de cerámica que distribuye mejor el calor</p><p>Calentador sumergible con termostato</p><p><br></p><p>Recomendaciónes: Elija la potencia correcta para el tamaño de su pecera por lo general, un watt por cada litro de agua del acuario deberá ser suficiente.</p>', 1, 200, NULL, 1, NULL, NULL, NULL, '2023-11-10 20:43:26', NULL, NULL, 'Calentador-(termostato)-eco-25w', NULL, NULL);
