INSERT INTO `ecom_productos` VALUES (150, NULL, 'producto', '7502271355863', 0x5445522D3031, 'ART.1802', 20.00, 'Termometro digital aderible (calacamonia) ', '<p>Termometro digital aqua-krill aderible grande</p><p>Medidas: 2.3 x 12 cm (ancho x alto)</p><p><br></p><p>Descripción:</p><p>Termometro de calca adherente al cristal por la parte de afuera de la pecera el cual te indicara la temperatura en la se enecunetra el agua macrandote los grados en celsius o fahrentheit.</p><p><br></p><p>Instrucciones: </p><p>Adherirse al exterior del acuario por debajo del nivel del agua. </p><p>Verificar temperatura regularmente</p><p><br></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2023-08-04 12:42:45', NULL, NULL, 'Termometro_digital_aderible_(calacamonia)_', NULL, NULL);
INSERT INTO `ecom_productos` VALUES (151, NULL, 'producto', '7501556440102', 0x414C4943552D3032, 'FL4010', 5.00, 'Alimento para cuyo pellets balanceados', '<p>Alimento para cuyo pellets balanceados</p><p>Cantidad: 850 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Alimento 100% natural para mantener a su cuyo saludable.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fortalece al sistema inmune.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Evita la deficiencia de vitamina C.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fortificado con vitaminas y minerales.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Bolsa resellable que mantiene fresco el alimento y con todas sus propiedades.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendaciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Para gazapos (crías) y cuyos juveniles deben ser alimentados a libre acceso. Cuyos adultos deben ser alimentados con una ración de 25 a 45g diarios (45g equivalen</span></p><p><span style=\"color: rgb(102, 102, 102);\">a 1/4 de taza).</span></p><p><br></p>', 1, 145, 124, 1, NULL, NULL, NULL, '2026-04-08 06:55:31', NULL, NULL, 'Alimento-para-cuyo-pellets-balanceados', 0, 0);
INSERT INTO `ecom_productos` VALUES (152, NULL, 'producto', '015561221368', 0x464C4F522D3034, 'HPT2136', 3.00, 'Foco intense basking spot para reptil 75w', '<p>Foco intense basking spot para reptil</p><p>Volts: 110 v</p><p>Potencia: 75 w</p><p><br></p><p>Descripción:</p><p>Es una bombilla especialmente diseñada como una lámpara de luz concentrada.</p><p>El rayo de luz puede enfocarse precisamente en un área para crear un sitio para el calentamiento.</p><p>Aumento del 35 % de luz y calor</p><p>Crea un área de calentamiento para la termo-regulación</p><p>Aumenta la temperatura del aire</p><p>Emision de luz natural</p><p>Bombilla diurna de propositos multiples</p><p>Incrementa la coloracion del animal</p><p>Se puede combinar con el Night Heat Lamp o Infrared Basking Spot por un ciclo de 24 horas</p><p>La luz y el calor aumentan en un 35% permitiendo así una mayor separación entre la fuente luminosa y el sitio elegido para el calentamiento.</p><p>La luz ultravioleta estimula el comportamiento reproductivo de los reptiles.</p><p><br></p><p>Ofrecer a los reptiles un hábitat adecuado requiere mantener ciertas condiciones muy específicas, sobre todo en cuanto a temperatura.</p><p>Lo ideal es que el ambiente se asemeje lo más posible a su hábitat natural.</p><p>Proporciona la temperatura adecuada para el terrario y las condiciones necesarias para los reptiles.</p><p><br></p><p><br></p><p><br></p><p><br></p>', 1, 175, 124, 1, NULL, NULL, NULL, '2025-12-26 22:27:28', NULL, NULL, 'Foco-intense-basking-spot-para-reptil-75w', 0, 0);
INSERT INTO `ecom_productos` VALUES (153, NULL, 'producto', '015561221146', 0x464C4F522D3035, 'PT2114', 2.00, 'Foco de día para reptil 150w ', '<p>Foco de día para reptil</p><p>Potencia: 150 w</p><p>Voltaje: 120- 110 v</p><p><br></p><p>Descripción:</p><p>Es una bombilla especialmente diseñada como una lámpara de luz concentrada.</p><p>El rayo de luz puede enfocarse precisamente en un área para crear un sitio para el calentamiento.</p><p>Aumento del 35 % de luz y calor</p><p>Crea un área de calentamiento para la termo-regulación</p><p>Aumenta la temperatura del aire</p><p>Emision de luz natural</p><p>Bombilla diurna de propositos multiples</p><p>Incrementa la coloracion del animal</p><p>Se puede combinar con el Night Heat Lamp o Infrared Basking Spot por un ciclo de 24 horas</p><p>La luz y el calor aumentan en un 35% permitiendo así una mayor separación entre la fuente luminosa y el sitio elegido para el calentamiento.</p><p>La luz ultravioleta estimula el comportamiento reproductivo de los reptiles.</p><p><br></p><p>Ofrecer a los reptiles un hábitat adecuado requiere mantener ciertas condiciones muy específicas, sobre todo en cuanto a temperatura.</p><p>Lo ideal es que el ambiente se asemeje lo más posible a su hábitat natural.</p><p>Proporciona la temperatura adecuada para el terrario y las condiciones necesarias para los reptiles.</p><p><br></p>', 1, 320, 124, 1, NULL, NULL, NULL, '2025-03-22 07:18:39', '2023-12-05 14:50:06', NULL, 'Foco-de-dia-para-reptil-150w-', 0, 0);
INSERT INTO `ecom_productos` VALUES (154, NULL, 'producto', '015561221269', 0x464C4F522D3032, 'PT2126', 4.00, 'Foco de noche para reptil 50w', '<p>Foco de noche para reptil</p><p>Potencia: 50 w</p><p>Luz: Nocturna</p><p>Para: Anfibios, reptiles, iguanas, ranas, etc.</p><p>Voltaje:110 v</p><p><br></p><p>Descripción:</p><p>Para temperaturas de noche tropical</p><p>Proporciona vision nocturna</p><p>Estimula la actividad nocturna</p><p><span style=\"color: rgb(102, 102, 102);\">Esta lámpara simula la luz natural de la luna que permite una visión nocturna sin interferir con el ciclo diurno y nocturno del animal.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La luz emitida es azulada debido a uso de vidrio color azul.</span></p><p><span style=\"color: rgb(102, 102, 102);\">El calor que genera es mínimo pero es suficiente para crear temperaturas de una noche tropical.</span></p><p><span style=\"color: rgb(102, 102, 102);\">El bajo voltaje de estas lámparas no interfiere con las bajas de temperatura de una noche natural.</span></p>', 1, 185, 124, 1, NULL, NULL, NULL, '2025-12-26 08:32:20', '2023-11-29 12:45:54', NULL, 'Foco-de-noche-para-reptil-50w', 0, 0);
INSERT INTO `ecom_productos` VALUES (155, NULL, 'producto', 'FOCOINF50W', 0x464F522D3033, 'PT2141', 3.00, 'Foco infrarrojo para reptil 50w', '<p>Foco infrarrojo</p><p>Potencia: 50 w</p><p>Volts: 110 a 120 v</p><p><br></p><p>Descripción:</p><p>Luz solar esecial</p><p>90% de la energia como calor infrarrojo</p><p>Penetracion optima de calor</p><p>Estimula la actividad natural</p><p>Bombilla de calor diurno para acelerar el crecimiento y una digestion optima.</p><p><span style=\"color: rgb(102, 102, 102);\">Emite ondas térmicas infrarrojas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Se puede usar en conjunto con Daytime Heat Lamp o Night Heat Lamp en un ciclo de 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Una excelente fuente de calor por 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aumenta la temperatura en todo el terrario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aporta el calor necesario para la actividad y la digestión.</span></p><p><span style=\"color: rgb(102, 102, 102);\">No interfiere con el ciclo natural de actividad.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para la visión nocturna.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Los radiadores infrarojos&nbsp;son&nbsp;lamparas de incandescencia que irradian energia en el rango infrarrojo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Esta radiacion infrarroja calienta el aire en una pequeña proporción, penetrando en cambia en los cuerpos expuestos a ella , donde se transforma totalmente en calor. Los campos de aplicacion son variados, utilizandode en avicultura, horticultura, industria, hosteleria, hogar...</span></p><p><span style=\"color: rgb(102, 102, 102);\">En la cria de animales, los&nbsp;</span>rayos infrarrojos<span style=\"color: rgb(102, 102, 102);\">&nbsp;se pueden utilizar para los animales recien nacidos, ya que al penetrar el calor profundamente en su piel activa la circulacion sanguinea y su metabolismo. Se utilizan con exito con los pollitos, cochinillos, pichones, perros, etc..Los pollitos y otras aves jovenes sometidos a radiaciones infrarrojas,&nbsp;se caracterizan de manera especial por su apetencia extraordinaria.</span></p>', 1, 320, 124, 1, NULL, NULL, NULL, '2025-03-22 07:17:35', '2023-11-28 17:38:30', NULL, 'Foco-infrarrojo-para-reptil-50w', 0, 0);
INSERT INTO `ecom_productos` VALUES (156, NULL, 'producto', 'CARDINAMO02', 0x4341522D3032, 'SH-230145', 0.00, 'Carriola dinamo para mascotas azul', '<p>Carriola dinamo para mascotas</p><p>Medidas expandido: 69 x 46 x 91(largo x ancho x alto)</p><p>Peso Máximo resiste: 15 kgr</p><p><br></p><p>Descripción:</p><p>Almohadilla impermeable extraíble, mango ajustable, entrada con cremallera, tragaluz de malla (azul) transpirable, Las ruedas delanteras giran 360° para facilitar el empuje.</p><p><br></p><p>Para: perros, gatos, mini pig y más mascotas pequeñas.</p><p><br></p><p>Colores: rosa, negro y azul (sujetos a disponibilidad</p>', 0, 2100, NULL, 1, NULL, NULL, NULL, '2024-03-15 17:14:01', '2023-11-21 14:36:05', NULL, 'Carriola-dinamo-para-mascotas-azul', 0, 0);
