INSERT INTO `ecom_productos` VALUES (165, NULL, 'producto', '7501556419122', 0x5041C391412D3034, 'FL1912', 7.00, 'pañales para perro chicos ', '<p>Pañales para cachorros jovenes</p><p>Cintura: 33cm - 48cm</p><p>Peso: 4- 7 kg</p><p>Contenido: 12 pañales</p><p><br></p><p>Descripcion:</p><p>Antiescurrimientos</p><p>Superabsorbentes</p><p>Material externo respirable</p><p>Nesutraliza olores</p><p><br></p><p>Sugerencia para:</p><p>Hembras en celo</p><p>Perros con incontinencia o convalecientes</p><p>Perros que haran viajes largos</p><p>Perros nerviosos</p><p><br></p>', 1, 199, NULL, 1, NULL, NULL, NULL, '2025-01-09 13:58:56', '2023-11-28 17:38:30', NULL, 'panales-para-perro-chicos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (166, NULL, 'producto', '7501556471748', 0x5441502D3032, 'FL7174', 5.00, 'Tapete entrenador desechable soft 30 pza para mascotas', '<p>Tapete entrenador desechable y absorbente para mascotas</p><p>Contenido: 30 tapetes</p><p>Medidas: 56 X 56 cm</p><p><br></p><p>Descripcion:</p><p>Ahora con parches adhesivos y 5 capas</p><p>Contiene atrayente para facilitar el entrenamiento</p><p>Con cubierta antiderrames</p><p>Sin malos olores gracias a su rapida asorbcion y accion desodorante</p><p>Se adiere a pisos y superficies</p><p><br></p><p>Sugerencia para:</p><p><span style=\"color: rgb(33, 37, 41);\">Facilita el entrenamiento de tu perro a la hora de ir al baño ideal para todas las razas </span></p><p><span style=\"color: rgb(33, 37, 41);\">Utiliza el tapete para los cachorros y perros que están solos en casa </span></p><p><span style=\"color: rgb(33, 37, 41);\">Para perros que está en edad avanzada o en recuperación de alguna cirugía práctico y seguro fácil de limpiar y Para educar a tu amigo de forma gradual. </span></p>', 1, 350, 124, 1, NULL, NULL, NULL, '2026-04-01 07:32:14', NULL, NULL, 'Tapete-entrenador-desechable-soft-30-pza-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (167, NULL, 'producto', 'TAZONREPTMED01', 0x54412D3031, 'TA-01', 10.00, 'Comedero para reptil mediano', '<p>Comedero de plástico para reptil mediano</p><p>Medidas: <span style=\"color: rgb(94, 98, 120);\">12 x 8.5 x 4cm (largo x ancho x alto)</span></p><p><br></p><p>Descripcion: Tazon para agua o comida para retiles como iguana, vivora, Tarantula, camaleon, tortugas, geckos pagona, etc.</p><p>Colores: negro, azul, verde (colores sujetos a disponibilidad)</p><p>Material: plastico.</p><p><br></p>', 1, 50, NULL, 1, NULL, NULL, NULL, '2023-12-19 21:14:55', NULL, NULL, 'Comedero-para-reptil-mediano', NULL, NULL);
