INSERT INTO `ecom_productos` VALUES (176, NULL, 'producto', 'RASCLEON02', 0x5241532D30324C45, 'PI0709-0348', 3.00, 'Rascadero colgante león', '<p>Rascadero colgante león</p><p>Medidas: 42 x 12 x 1.5 cm (largo x ancho x alto)</p><p>Medidas con colgadera: 54 x 12 x 1.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios pequeños donde puedas colgar el rascadero en la silla, sillon, buro, puerta, pared en aquel espacio para colgar asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p><br></p><p>Material: Elaborado con MDF de 12 pulgadas tapizante y tela soft y yute, hechos con henequén.</p>', 1, 220, 124, 1, NULL, NULL, NULL, '2025-03-30 07:28:20', '2023-11-29 16:17:59', NULL, 'Rascadero-colgante-leon', 0, 0);
INSERT INTO `ecom_productos` VALUES (177, NULL, 'producto', '7501556477900', 0x4D55464F, 'FL7790', 5.00, 'Muelle flotante para tortugas ', '<p>Muelle flotante para tortugas</p><p><br></p><p>Descripción:</p><p>Muelle flotante para tortugas, permite a las tortugas exponerse al calor de los focos infrarrojos uvb. Ideal para tortugas acuáticos, ranas y cangrejos, de fácil de instalar.</p><p><br></p><p>Incluye: 4 ventosas</p>', 1, 160, NULL, 1, NULL, NULL, NULL, '2024-11-08 08:20:11', NULL, NULL, 'Muelle-flotante-para-tortugas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (178, NULL, 'variante', 'CASAPANALCAFE01', 0x50414E2D3031, 'PI0320-0359', 1.00, 'Casa cama panal cafe para mascotas', '<p>Casa cama panal cafe para mascotas</p><p>Medidas casa: 42 x 33 cm (circuferencia x alto)</p><p>Medidas camita: 42 x 18 cm <span style=\"color: rgb(94, 98, 120);\">(circuferencia x alto)</span></p><p>Incluye: Cojin</p><p><br></p><p>Descripción: Casa con un diseño natural, elegantes y comodas casas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas con tela de oso, poliéster, dubetina.</p><p><br></p><p>Uso: como casita plegable o cama con doble diseño</p>', 1, 499, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:15:09', '2024-09-30 17:15:09', NULL, 'Casa-cama-panal-cafe-para-mascotas', 0, 0);
