INSERT INTO `ecom_productos` VALUES (183, NULL, 'producto', '7501556439243', 0x535052412D3031, 'FL3924', 5.00, 'Spray antipulgas para perros ', '<p>Polvo antipulgas para perros y gatos</p><p><br></p><p>Descripción:</p><p>Es un producto elaborado a base de extractos naturales, que repelen y previenen la infestación de pulgas. Una vez aplicado el producto, éste permanecerá adherido al pelo y a la piel del perro, lo que aleja a las pulgas evitando que se alojen y se reproduzcan.</p>', 1, 98, NULL, 1, NULL, NULL, NULL, '2024-11-09 17:50:18', NULL, NULL, 'Spray-antipulgas-para-perros-', 0, 0);
