INSERT INTO `ecom_productos` VALUES (190, NULL, 'producto', '046798771845', 0x434F414C2D3032, 'TE77184', 3.00, 'Control de alga grande ', '<p>AlgaeControl grande </p><p>Cantidad: 100 ml</p><p><br></p><p>Descripción:</p><p>Combate el crecimiento de algas, el cual es causante de la coloración verde en el agua del acuario. Elimina las algas que crecen sobre los cristales y la decoración del acuario, combate algas verdes y marrón. controlando el agua verde de los acuarios.</p><p><br></p>', 1, 230, NULL, 1, NULL, NULL, NULL, '2024-03-28 23:11:09', NULL, NULL, 'Control-de-alga-grande-', 0, 0);
