INSERT INTO `ecom_productos` VALUES (192, NULL, 'producto', '7501556494686', 0x4A55472D3434, 'FL9468', 5.00, 'Juguete estrella de mar para perro ', '<p>Juguete estrella de mar para perro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Juguetes para perros que tienen una necesidad natural de morder y masticar para mantener sus dientes y encías saludables, así como para liberar estrés. Son juguetes con texturas y materiales resistentes pueden ayudar a satisfacer esta necesidad de morder de manera segura, con un squeaker integrado puede proporcionar entretenimiento adicional, ya que el sonido puede atraer su atención.</span></p><p><br></p>', 1, 150, NULL, 1, NULL, NULL, NULL, '2024-10-11 23:46:03', NULL, NULL, 'Juguete-estrella-de-mar-para-perro-', 0, 0);
INSERT INTO `ecom_productos` VALUES (193, NULL, 'producto', '7501556491814', 0x4A55502D3033, 'FL9181-MED', 7.00, 'Juguete para aves calcio mediano', '<p>Jueguete para aves calcio mediano</p><p>Medidas: 15.5 cm</p><p>Peso: 74 grs</p><p><br></p><p>Descripción:</p><p>Juguete colgante con calcio para aves.</p><p>Cuentas de plástico.</p><p>Campana y gancho de metal.</p><p>Enriquecido con calcio.</p><p>Ideal para aves pequeñas y medianas.</p><p>Ofrece entretenimiento para el ave.</p><p>Ayuda a ejercitar al ave física y mentalmente.</p><p>Incita la curiosidad del ave.</p>', 1, 185, NULL, 1, NULL, NULL, NULL, '2024-02-04 03:31:04', NULL, NULL, 'Juguete-para-aves-calcio-mediano', 0, 0);
INSERT INTO `ecom_productos` VALUES (194, NULL, 'producto', '7501556440317', 0x414C49532D3034, 'FL4031', 10.00, 'Barra de semillas para loritos y ninfas para pajaros', '<p>Barritas de semillas</p><p>Para: Loritos, agapornis, ninfas, periquitos australianos y pericos de collar</p><p>Cantidad: 2 barras de 36grs cada una</p><p><br></p><p>Descripcion: Son un snack elaborado con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá al mismo tiempo que estimulan su curiosidad y acatividad.</p><p>Fortificado con vitaminas y minerales</p><p>Fórmula 100% natural balanceada</p><p>Con practico gancho que permite colocarla dentro de la jaula,&nbsp;</p>', 1, 55, 124, 1, NULL, NULL, NULL, '2026-01-28 23:05:01', '2023-11-28 17:38:30', NULL, 'Barra-de-semillas-para-loritos-y-ninfas-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (195, NULL, 'producto', '7501556440331', 0x414C49532D3032, 'FL4033', 7.00, 'Barra de semillas para loros y cacatúas para pajaros', '<p>Barra de semillas</p><p>Para: loros, cacatúas y conuros</p><p>Cantidad: 100 grs</p><p><br></p><p>Descripcion: Son un snack elaborado con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá al mismo tiempo que estimulan su curiosidad y acatividad.</p><p>Fortificado con vitaminas y minerales</p><p>Fórmula 100% natural balanceada</p><p>Con practico gancho que permite colocarla dentro de la jaula,&nbsp;</p>', 1, 55, 124, 1, NULL, NULL, NULL, '2026-01-28 23:05:54', '2023-11-28 17:38:30', NULL, 'Barra-de-semillas-para-loros-y-cacatuas-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (196, NULL, 'producto', 'POS30SELVA07', 0x504F532D3037, 'POS-07', 1.00, 'Póster selva 30 cm en rollo ', '<p>Póster selva 30cm de altura</p><p><br></p><p>Descripción:</p><p>Póster respaldos para pecera con altura de 30 cm de plástico con doble vista por un lado forma un paisaje y del otro otro distinto puede ir en el agua o como tal por fuera del cristal lo cual enbellecera ese espacio unico y exclusivo para ti y tu peces dando una vista encantadora.</p><p><br></p><p>Metros por rollo:15 m</p>', 1, 300, 0, 1, NULL, NULL, NULL, '2025-02-27 00:31:51', NULL, NULL, 'Poster-selva-30-cm-en-rollo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (197, NULL, 'producto', '7501556439861', 0x535052412D3032, 'FL3966', 5.00, 'Desifectante para patas y cojines ', '<p>Desifectante para patas y cojines</p><p><br></p><p>Descripción:</p><p>El Desinfectante Essentials para patas y cojinetes sanitiza las patitas de los perros y gatos después del paseo.</p><p>Actúa directamente sobre bacterias, hongos y virus.</p><p>Su fórmula incolora humecta los cojinetes de la mascota. No contiene fragancia ni alcohol, evitando la resequedad y ardor. El producto promueve la buena higiene y salubridad ya que en las patas se acumulan gran parte de bacterias que pueden causar enfermedades.</p><p>Promueve la higiene y buenas condiciones de salubridad en tu hogar.</p><p><br></p>', 1, 60, NULL, 1, NULL, NULL, NULL, '2024-04-10 19:48:12', NULL, NULL, 'Desifectante-para-patas-y-cojines-', 0, 0);
