INSERT INTO `ecom_productos` VALUES (206, NULL, 'variante', '98649', 0x41524F2D3335415A, '98649', 2.00, 'Arenero catyclean azul ', '<p>Arenero catyclean</p><p>Medidas: 56 x 40 x 40 cm(largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Arenero cerrado para evitar derrames de arena fuera del arenero con puerta abatible baño para gatos.Cuenta con asa que facilita la tarea de moverlo.&nbsp;</p><p>Incluye pala higiénica con filtro de carbon activo para evitar que olores salgan del arenero.&nbsp;</p><p><br></p><p><br></p><p>Colores: gris, azul (sujetos a disponibilidad)</p>', 1, 650, NULL, 1, NULL, NULL, NULL, '2024-09-07 06:37:40', '2024-09-07 06:37:40', NULL, 'Arenero-catyclean-azul-', 0, 0);
INSERT INTO `ecom_productos` VALUES (207, NULL, 'producto', '7501556440324', 0x414C49532D3031, 'FL4032', 10.00, 'Barra de semillas canarios y finches para pajaros', '<p>Barritas de semillas</p><p>Para: canarios, finches y gorriones</p><p>Cantidad: 2 barras de 36grs cada una</p><p><br></p><p>Descripcion: Son un snack elaborado con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá al mismo tiempo que estimulan su curiosidad y acatividad.</p><p>Fortificado con vitaminas y minerales</p><p>Fórmula 100% natural balanceada</p><p><span style=\"color: rgb(94, 98, 120);\">Con practico gancho que permite colocarla dentro de la jaula,&nbsp;</span></p>', 1, 55, 124, 1, NULL, NULL, NULL, '2026-01-28 23:04:17', '2023-11-28 17:38:30', NULL, 'Barra-de-semillas-canarios-y-finches-para-pajaros', 0, 0);
