INSERT INTO `ecom_productos` VALUES (223, NULL, 'producto', '7501556440089', 0x414C49434F2D3032, 'FL4008', 4.00, 'Alimento para conejo conejina envasada', '<p>Alimento para conejo</p><p>Sabor: zanahoria</p><p>Cantidad: 1 kgrs</p><p><br></p><p>Descripcion:Contiene harina de alfalfa y maíz como fuentes de carbohidratos que ayudan a mantener un nivel alto de energía.</p><p>Proporcione al conejo el alimento a libre acceso.</p><p>Dependiendo del tamaño de su mascota, variará la cantidad de consumo.</p><p>Complemente la dieta del conejo con porciones pequeñas de vegetales frescos (pepino, zanahoria, lechuga, entre otros).Proporcione agua en abundancia al conejo en todo momento.</p><p><br></p><p>Fortificado con vitaminas y minerales</p><p>100% nutrición completa</p><p><br></p>', 1, 135, 124, 1, NULL, NULL, NULL, '2026-04-08 07:03:40', '2023-11-28 17:38:30', NULL, 'Alimento-para-conejo-conejina-envasada', 0, 0);
