INSERT INTO `ecom_productos` VALUES (269, NULL, 'producto', '5414365070397', 0x48454E452D3031, 'ART.NR.411', 10.00, 'Henera esfera para heno ', '<p>Henera circular para heno</p><p><br></p><p>Descripción:</p><p>Bola dispensadora de alimentación para mascotas manteniendo un suministro generoso de comida y heno en un comedero limpio y organizado. Alimentador para jaula colgante, dispensador de alimento de juguete con bolas colgadas para animales. Se puede fijar a o colgar desde la parte superior de para satisfacer sus necesidades.</p><p><br></p>', 1, 120, NULL, 1, NULL, NULL, NULL, '2024-04-19 17:50:17', NULL, NULL, 'Henera-esfera-para-heno-', 0, 0);
INSERT INTO `ecom_productos` VALUES (270, NULL, 'producto', '7502271253364', 0x46494C542D3031, '1070', 10.00, 'Filtro para acuaterrario tortugueros', '<p>Filtro para acuaterrario</p><p>Voltaje: 1110-120 v</p><p>Flujo maximo 180 lts / h</p><p>Potencia: 3 w</p><p><br></p><p>Descripción:</p><p>Opera con un nivel mínimo de 3.5 cm de agua con cartucho filtrante reemplazable, aclara y deodoriza el agua.</p><p>Capacidad maxima del filtro 20 lts para peceras y tortugueros con poca agua filtra y oxigena al mismo tiempo.</p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">Cartucho con filtrante y biocerámicas </span></p><p><br></p>', 1, 330, 124, 1, NULL, NULL, NULL, '2025-10-16 15:04:16', NULL, NULL, 'Filtro-para-acuaterrario-tortugueros', 0, 0);
