INSERT INTO `ecom_productos` VALUES (273, NULL, 'producto', 'RASCCHANG03', 0x5241532D30324348, 'PI0709-0345', 2.00, 'Rascadero colgante chango', '<p>Rascadero colgante chango</p><p>Medidas: 42 x 12 x 1.5 cm (largo x ancho x alto)</p><p>Medidas con colgadera: 54 x 12 x 1.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios pequeños donde puedas colgar el rascadero en la silla, sillon, buro, puerta, pared en aquel espacio para colgar asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p><br></p><p>Material: Elaborado con MDF de 12 pulgadas tapizante y tela soft y yute, hechos con henequén.</p>', 1, 220, 124, 1, NULL, NULL, NULL, '2025-03-30 07:07:11', '2023-11-29 16:17:59', NULL, 'Rascadero-colgante-chango', 0, 0);
