INSERT INTO `ecom_productos` VALUES (277, NULL, 'producto', '7501556439625', 0x5348412D3039, 'FL3962', 6.00, 'Shampoo pelo dorado chico para perro', '<p>Shampoo pelo dorado chico para perro</p><p>Cantidad: 250 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials para Pelo Negro está formulado con ingredientes cuidadosamente seleccionados para resaltar el color, limpiar y suavizar el pelo.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No irrita la piel ni los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Elaborado con extracto de manzanilla.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Proporciona brillo y resalta el color dorado del pelaje.</span></p>', 1, 65, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:27:35', '2023-12-02 22:04:41', NULL, 'Shampoo-pelo-dorado-chico-para-perro', 0, 0);
