INSERT INTO `ecom_productos` VALUES (314, NULL, 'variante', 'CAMAFLCROSA07', 0x43414D432D3037, 'PI0101-0023', 2.00, 'Cama antiestrés chica para mascotas', '<p>Cama antiestrés chica para mascotas</p><p>Medidas: 45 x 12 cm (circuferencia x alto)</p><p>Color: rosa</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, uron, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p>', 1, 420, NULL, 1, NULL, NULL, NULL, '2024-02-05 21:10:41', '2024-02-05 15:10:41', NULL, 'Cama_antiestres_chica_para_mascotas', NULL, NULL);
