INSERT INTO `ecom_productos` VALUES (317, NULL, 'producto', '7501556439687', 0x5348412D3031, 'FL3968', 0.00, 'Shampoo para cachorro perros y gatos chico', '<p>Shampoo essentials para cachorro perro y gato chico</p><p>Cantidad: 250 ml</p><p><br></p><p>Descripción:</p><p>El Shampoo Essentials para Cachorro limpia y suaviza al mismo tiempo el pelo, con ingredientes que cuidan su piel y proporcionan sedosidad facilitando el cepillado.</p><p>Elaborado con esencia de mora azul.</p><p>Proporciona limpieza y sedosidad.</p><p>Suave con la piel delicada.</p><p>No irrita la piel ni los ojos del cachorro.</p><p><br></p>', 1, 65, 124, 1, NULL, NULL, NULL, '2026-03-04 20:43:13', '2023-12-02 22:04:41', NULL, 'Shampoo-para-cachorro-perros-y-gatos-chico', 0, 0);
