INSERT INTO `ecom_productos` VALUES (322, NULL, 'producto', 'BEBECILTO04', 0x4245544F2D3034, '8413856516373', 3.00, 'Bebedero tubular 5 ', '<p>Bebedero tubular 5</p><p>Capacidad: 225ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Ideal para mantener a tus mascotas hidratadas. Cada bebedero es fácil de usar y limpiar, lo que lo convierte en una opción práctica y eficiente. Su diseño compacto y ligero permite colocarlo en cualquier lugar de tu hogar. Además, su material de alta calidad garantiza su durabilidad y resistencia.</span></p>', 1, 70, NULL, 1, NULL, NULL, NULL, '2024-04-09 23:37:11', '2023-11-16 12:36:35', NULL, 'Bebedero-tubular-5-', 0, 0);
