INSERT INTO `ecom_productos` VALUES (331, NULL, 'producto', 'CARALAMO01', 0x4341522D3031, 'SH-230146', 0.00, 'Carriola álamo para mascotas', '<p>Carriola álamo para mascotas</p><p>Medidas expandido: 67 x 47 x 100(largo x ancho x alto)</p><p>Medidas plegable: 35 x 20 x 80 (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Eje de acero inoxidable, fuerte resistencia al desgaste.</p><p>La rueda delantera tiene una función de amortiguación, que puede soportar fácilmente varias superficies de caminos con baches.</p><p>Contiene:</p><p>Toldo de malla con cremallera bien ventilación</p><p>Cinturón de seguridad mantén a tu mascota bien sujeta</p><p>Parte inferior de la cesta fácil de guardar</p><p>Proporciona un paseo suave muelles amortiguadores</p><p><br></p><p>Para: perros, gatos, mini pig y más mascotas pequeñas.</p><p><br></p><p>Colores: rosa, negro y cafe (sujetos a disponibilidad</p>', 1, 0, NULL, 0, NULL, NULL, NULL, '2024-09-07 15:24:08', NULL, NULL, '', 0, 0);
INSERT INTO `ecom_productos` VALUES (332, NULL, 'producto', 'PerDis92947', 0x4449532D433031, '50493', 6.00, 'Dispensador Comedero colores', '<p>Dispensador comedero colores</p><p>Comedero: 2.3 kg</p><p><br></p><p>Descripción: comedero por gravedad conforme la mascota se alimenta comienza a desender bajar la comida, bridandoles alimento para varias ocaciones del dia, de facil insatalamiento y limpieza, dispensadores para perros, gatos, urones, mini pig, etc.</p><p>Para: razas pequeñas, medianas.</p><p><br></p><p>Colores: Rosa, Gris, Verde, Azul (Sujetos a dispobilidad)</p>', 1, 280, NULL, 1, NULL, NULL, NULL, '2024-01-31 18:51:27', '2023-11-21 14:36:05', NULL, 'Dispensador-Comedero-colores', 0, 0);
INSERT INTO `ecom_productos` VALUES (333, NULL, 'producto', 'BECOBOREAL09', 0x4449532D3039, 'SH-230907', 2.00, 'Bebedero y Comedero boreal', '<p>Bebedero y comedero boreal</p><p>Medidas:&nbsp;32 x 16 x 17.5 cm (largo x ancho x alto)</p><p>Capacidad del bebedero: 1.8 ml</p><p><br></p><p>Descripción:</p><p>Cubo doble para alimento y agua. Purificador de agua potable, fuente de bebida automática.</p><p>Recarga automática de agua, agrega una vez y tu mascota consumirá hasta por 3 días. Fácil de armar y limpiar.</p><p>Separa alimento seco y húmedo. No combina olores.</p><p><br></p><p>Colores: blanco con rosa, azul, gris o verde ( sujetos a disponibilidad)</p><p><br></p>', 1, 550, NULL, 1, NULL, NULL, NULL, '2024-02-26 21:13:24', '2023-11-16 12:36:35', NULL, 'Bebedero-y-Comedero-boreal', 0, 0);
INSERT INTO `ecom_productos` VALUES (334, NULL, 'producto', 'BECOJAKE07', 0x54415A2D3037, 'SH-230909', 2.00, 'Tazón doble jake de cerámica ', '<p>Tazón doble jake</p><p>Medidas:41 x 15 x 20.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Cuenco elevado con inclinación de 2,15 ° Comedero ajustable con tazones de resina / ceramica de excelente calidad. Barrera contra salpicaduras para evitar fugas de alimentos.</p><p>Las patas del comedero se pueden guardar para hacerlo mas bajo para mascotas pequeñas y ajustar la altura. Desmontable</p><p>Facil de limpiar.</p><p><br></p><p>Color: naranja, morado, verde ( sujetos a disponibilidad)</p><p><br></p>', 1, 550, NULL, 1, NULL, NULL, NULL, '2024-01-31 18:54:21', '2023-11-16 12:36:35', NULL, 'Tazon-doble-jake-de-ceramica-', 0, 0);
INSERT INTO `ecom_productos` VALUES (335, NULL, 'producto', '7502234336519', 0x4449532D433032, 'SP-3651', 4.00, 'Comedero para perros o gatos 2.3 kilos', '<p>Capacidad: 2.3 kg</p><p><br></p><p>Colores: Beige, Negro, Gris (Sujetos a disponibilidad)</p>', 1, 325, NULL, 1, NULL, NULL, NULL, '2024-01-31 18:56:06', NULL, NULL, 'Comedero-para-perros-o-gatos-2.3-kilos', 0, 0);
INSERT INTO `ecom_productos` VALUES (336, NULL, 'producto', '6920228240054', 0x4449532D3038, 'SH-230124', 0.00, 'Bebedero automático organic', '<p>Dispensador de agua organic (fuente)</p><p>Capacidad:alrededor 2 litros</p><p>Medidas: 22.5 x 24 x 6 cm (largo x ancho x alto)</p><p><br></p><p>Descripción: Dispensador de agua automático, ahorrador de energía en lo cual durante un mes consume hasta 5kWh con diseño amigable para tu mascota (la silicona no lastima su lengua), con flujo ajustable a tres velocidades distintas con diseño de tazón en dos capas, nose derrapa (almohadillas en el inferior) cargador USB, antibacteriana. Motivando a la mascota ala ingestion de agua por el movimiento continuo bridandole agua para varias ocaciones del dia, de facil insatalamiento y limpieza, dispensadores para perros pequeños, gatos, urones, mini pig, etc.</p><p>Para: razas pequeñas.</p><p><br></p><p>Colores: verde con blanco.</p>', 0, 480, 124, 1, NULL, NULL, NULL, '2025-12-26 23:04:22', '2023-11-21 14:59:48', NULL, 'Bebedero-automatico-organic', 0, 0);
INSERT INTO `ecom_productos` VALUES (337, NULL, 'producto', '6920232301529', 0x4449532D3037, 'SH-230152', 0.00, 'Bebedero automático aguacate', '<p>Dispensador de agua aguacate</p><p>Capsacidad:alrededor 2 litros</p><p><br></p><p>Descripción: bebedero con función de apagado automático con diseño de control inteligente con filtrado de 4 capas para limpiar la calidad del agua, corriente continua de agua, y luz led, motivando a la mascota ala ingestion de agua por el movimiento continuo bridandole agua para varias ocaciones del dia, de facil insatalamiento y limpieza, dispensadores para perros pequeños, gatos, urones, mini pig, etc.</p><p>Para: razas pequeñas.</p><p><br></p><p>Colores: verde, Gris, blanco (Sujetos a dispobilidad)</p>', 0, 560, 124, 1, NULL, NULL, NULL, '2025-12-26 23:04:42', '2023-11-21 14:59:48', NULL, 'Bebedero-automatico-aguacate', 0, 0);
INSERT INTO `ecom_productos` VALUES (338, NULL, 'producto', '5900469504628', 0x414C494348492D3033, '50462', 5.00, 'Alimento para chinchilla premium ', '<p>Alimento para chinchilla premium</p><p>Cantidad: 750gr</p><p><br></p><p>Descipción:</p><p>Comida con la adiccion de verduras y hierbas.</p><p>Belleza y cuidado</p><p>Digestión óptima</p><p>Inmunidad pro</p><p><br></p><p>Alimento saludable para chinchillas a base de gránulos con alfalfa, hierbas y manzanas y con la adición de verduras secas, ricas en vitaminas y hierbas aromáticas</p><p>La adición de linaza y girasol ricos en ácidos grasos insaturados asegura una piel sana y un pelaje brillante</p><p>Alto contenido de fibra y la adición de remolacha y hierbas regulan la digestión</p><p>Las propiedades prebióticas de muchos componentes de los alimentos estimulan el desarrollo de la flora bacteriana intestinal normal y apoyan el sistema inmunológico de las chinchillas</p><p>La adición de zeolita reduce el olor desagradable de las heces</p><p>El alimento no contiene ingredientes genéticamente modificados (OGM), conservantes, potenciadores del sabor, azúcar añadida y sabores</p>', 1, 350, 124, 1, NULL, NULL, NULL, '2026-04-08 07:24:43', NULL, NULL, 'Alimento-para-chinchilla-premium-', 0, 0);
INSERT INTO `ecom_productos` VALUES (339, NULL, 'producto', '6920232203144', 0x434F4E542D3031, 'SH-220314', 1.00, 'Contenedor de alimento belmor', '<p>Contenedor Dispensador de alimento belmor</p><p>Capacidad:5 kgrs</p><p><br></p><p>Descripción: contenedor de alimento para tu mascota con lengüeta para servir comida con tapa qaue genera vacío al cerrar.</p><p>Diseño ergonómico, con soporte de pala discreto dentro de la tapa con diseño a prueba de humedad, calor, moho y plagas. Evita la salida de olores.</p><p><br></p><p>Incluye: pala y tazon</p><p><br></p><p>Colores: gris, rosa, azul (sujetos a disponibilidad)</p>', 1, 630, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:05:57', '2023-11-21 14:59:48', NULL, 'Contenedor-de-alimento-belmor', 0, 0);
INSERT INTO `ecom_productos` VALUES (340, NULL, 'producto', '7713042267258', 0x414C49452D312E3242, 'EX035', 9.00, 'Alimento para erizo bombyx grande', '<p>Erizo</p><p>Alimento para erizo</p><p>Cantidad: 1.2 kgrs</p><p>Sabor: Bombyx mori (gusano de cera)</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Contiene:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Vitamina e y Omega 3.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Pellet de tamaño ideal.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Modo de uso:</span></p><p><span style=\"color: rgb(102, 102, 102);\">El erizo siempre debe tener libre acceso al alimento y agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Los recipientes del agua y la comida devén limpiarse con regularidad para evitar enfermedades.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendaciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">También puedes proporcionarle de 1 a 3 veces por semana alimento vivo</span></p>', 1, 399, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:06:19', '2023-11-16 12:36:35', NULL, 'Alimento-para-erizo-bombyx-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (341, NULL, 'producto', 'AcuFil57584', NULL, 'NULL', 100.00, 'Aereador 100 piezas', 'Aereador 100 piezas', 1, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `ecom_productos` VALUES (342, NULL, 'producto', '750226158210', 0x4149522D3033, 'OC-5', 15.00, 'Bomba de aire 1 salida oce', '<p>Bomba de aire 1 salida oce</p><p>Para acuarios de 10 a 50 lts máximo</p><p>Voltaje: 120 v </p><p>Potencia: 2 w</p><p>Frecuencia: 60Hz</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Silenciosa con alta tecnología, Incrementando la oxigenación del acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alto rendimiento con diseño ultra compacto de fácil colocación con salida unica.</span></p><p><br></p><p>Modo de empleo:</p><p><span style=\"color: rgb(102, 102, 102);\">No sumerja la bomba de aire, dentro del agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Debe ser colocada por encima del nivel del agua.</span></p>', 1, 110, NULL, 1, NULL, NULL, NULL, '2026-05-17 22:15:50', '2026-05-17 22:15:50', NULL, 'Bomba-de-aire-1-salida-oce', 0, 0);
INSERT INTO `ecom_productos` VALUES (343, NULL, 'producto', '7502234336106', 0x4149522D3031, 'SAP-300', 7.00, 'Bomba de aire 1 salida ', '<p>Bomba de aire 1 salida</p><p>Voltaje: 120 v</p><p>Freciencia: 60 Hz</p><p>Potencia: 2 w</p><p>Sailda de aire: 1.5 L/min</p><p><br></p><p><span style=\"color: rgb(94, 98, 120);\">Instrucciones:</span></p><p><span style=\"color: rgb(94, 98, 120);\">La bomba de aire debe ser colocada por encima del nivel del agua</span></p><p><br></p><p>Advertencia:</p><p>No sumerja la bomba de aire dentro del agua</p><p><br></p><p><br></p><p><br></p>', 1, 110, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:14:01', '2023-12-02 22:04:41', NULL, 'Bomba-de-aire-1-salida-', 0, 0);
INSERT INTO `ecom_productos` VALUES (344, NULL, 'producto', '7502234336113', 0x4149522D3032, 'SAP-301', 14.00, 'Bomba de aire 2 salidas ', '<p>Bomba de aire 2 salidas</p><p><br></p><p>Voltaje: 120 v</p><p>Freciencia: 60 Hz</p><p>Potencia: 2 w</p><p>Sailda de aire: 2 x 2 L/min</p><p><br></p><p><span style=\"color: rgb(94, 98, 120);\">Instrucciones:</span></p><p><span style=\"color: rgb(94, 98, 120);\">La bomba de aire debe ser colocada por encima del nivel del agua</span></p><p><br></p><p>Advertencia:</p><p>No sumerja la bomba de aire dentro del agua</p><p><br></p>', 1, 220, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:24:39', '2023-12-04 12:03:13', NULL, 'Bomba-de-aire-2-salidas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (345, NULL, 'producto', '7501556440058', 0x414C49552D3031, 'FL4005', 2.00, 'Alimento para hurón premium', '<p>Alimento para uron</p><p>Cantidad:850 grs</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">DESCRIPCION:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Hecho con carne de pollo.</span></p><p><span style=\"color: rgb(102, 102, 102);\">No contiene harinas de subproductos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La mas calidad de nutrientes.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Además de su sabor, el alimento para Huron contiene todos los nutrientes esenciales para un sano crecimiento y completo desarrollo del hurón, manteniéndolo en condiciones optimas de salud. El alimento Premium fue desarrollado con tres factores fundamentales para la salud de la mascota:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Promueve la salud de la piel y el pelo.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ayuda a mantener la condición física, el crecimiento de músculos y huesos, y la vitalidad del hurón.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Incrementa la longevidad gracias a la adición de antioxidantes, como la vitamina E.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Guía de alimentación:</span></p><p><span style=\"color: rgb(102, 102, 102);\">El hurón comerá entre 40 y 60 gramos de alimento Premium para hurón por día dependiendo de su edad, nivel de actividad y temperamento. Para obtener un nivel nutricional óptimo es posible que tenga que ajustar las cantidades de alimento que ofrece al hurón. Comience por ofrecer 60 gramos de alimento al día.Si el hurón no consume la cantidad total en 24 horas, redúzcala hasta llegar a su consumo normal.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Para evitar problemas de sobrepeso o desperdicio, no ofrezca al hurón más de 60 gramos al día.</span></p><p><br></p><p><br></p>', 1, 230, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:25:48', NULL, NULL, 'Alimento-para-huron-premium', 0, 0);
INSERT INTO `ecom_productos` VALUES (346, NULL, 'producto', '015561107990', 0x4149522D3037, 'HA799', 5.00, 'Bomba de aire elite 799', '<p>Bomba de aire elite 799</p><p>Salidas: 1</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Las bombas de aire elite son una fuente confiable de aire para artículos operados por aire como las rocas vivas ELITE, las burbujas de aire elite, los adornos accionados por aire, o los separadores de urea que funcionan con aire para añadir movimiento u oxigeno a cualquier acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Cubierta para amortiguar el ruido con la placa de la base impide la vibración y el movimiento de la bomba.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Bobinas que no se calientan de larga vida útil.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Bisagra de brazo oscilante integrada al ensamble del diafragma Tensible Flex.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ensamble de la salida de aire integrado al cuerpo de la válvula.</span></p>', 1, 179, 124, 1, NULL, NULL, NULL, '2025-12-26 09:05:47', NULL, NULL, 'Bomba-de-aire-elite-799', 0, 0);
