INSERT INTO `ecom_productos` VALUES (359, NULL, 'producto', '7502261581005', 0x46494C43432D3031, 'OC-280', 2.00, 'Filtro Cascada 280 ', '<p>Filtro Cascada 280</p><p>Medidas: 11cm x 9cm x12cm (largo x anxho x alto)</p><p>Voltaje: 120 v</p><p>Flujo maximo 280 L/H</p><p>Potencia: 3.5 w</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Regulador de flujo de agua</span></p><p>Capacidad maxima del filtro 30 lts</p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">&nbsp;1 placa filtración biológica, placa de carbón y fibra</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Instrucciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Antes de encender el equipo (antes de conectarlo a la luz), es INDISPENSABLE llenar el compartimiento del cuerpo del filtro con la misma agua de la pecera, una vez instalado y llenado previamente conectar a la luz.</span></p><p><br></p>', 1, 280, NULL, 1, NULL, NULL, NULL, '2026-05-17 22:05:28', '2026-05-17 22:05:28', NULL, 'Filtro-Cascada-280-', 0, 0);
