INSERT INTO `ecom_productos` VALUES (362, NULL, 'producto', '7503008378001', 0x46494C43432D3038, 'SHF-1000', 3.00, 'Filtro Cascada (doble) 1000', '<p>Filtro Cascada (doble) 1000</p><p><br></p><p>Medidas: <span style=\"color: rgba(0, 0, 0, 0.9);\"> 35</span><span style=\"color: rgb(102, 102, 102);\"> cm x 15 cm x 20 cm </span><span style=\"color: rgba(0, 0, 0, 0.9);\">(largo x ancho x alto)</span></p><p>Voltaje: 110-120 v</p><p>Flujo maximo 950 L/H</p><p>Potencia: 7 w</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Valvula ajustable de flujo de agua</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para acuarios de agua dulce y agua salada</span></p><p>Capacidad maxima del filtro 240 lts</p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">Cartucho con esponja y carbón activado para limpiar el agua y quitar los malos olores para filtracion mecanica y biologica.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Instrucciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Antes de encender el equipo (antes de conectarlo a la luz), es INDISPENSABLE llenar el compartimiento del cuerpo del filtro con la misma agua de la pecera, una vez instalado y llenado previamente conectar a la luz.</span></p>', 1, 890, NULL, 1, NULL, NULL, NULL, '2024-09-20 00:44:09', '2023-12-04 12:03:13', NULL, 'Filtro-Cascada-(doble)-1000', 0, 0);
INSERT INTO `ecom_productos` VALUES (363, NULL, 'producto', '7503008378179', 0x46494C43432D3035, 'SHF-300', 5.00, 'Filtro Cascada 300', '<p>Filtro Cascada 300</p><p><br></p><p>Medidas: <span style=\"color: rgba(0, 0, 0, 0.9);\"> </span><span style=\"color: rgb(102, 102, 102);\">11.5 cm x 9 cm x 14 cm </span><span style=\"color: rgba(0, 0, 0, 0.9);\">(largo x ancho x alto)</span></p><p>Voltaje: 120 v</p><p>Flujo maximo 300 L/H</p><p>Potencia: 4 w</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Regulador de flujo de agua</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para acuarios de agua dulce y agua salada</span></p><p>Capacidad maxima del filtro 50 lts</p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">Cartucho con esponja y carbón activado para limpiar el agua y quitar los malos olores</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Insrucciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Antes de encender el equipo (antes de conectarlo a la luz), es INDISPENSABLE llenar el compartimiento del cuerpo del filtro con la misma agua de la pecera, una vez instalado y llenado previamente conectar a la luz.</span></p>', 1, 350, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:46:19', '2023-12-04 12:03:13', NULL, 'Filtro-Cascada-300', 0, 0);
