INSERT INTO `ecom_productos` VALUES (383, NULL, 'producto', '7502261583368', 0x46494F502D3031, 'OCI-500', 10.00, 'filtro interno ocean 500', '<p>filtro interno (cabeza de poder)</p><p>Filtracion: 500l/h</p><p>Voltaje: 120v</p><p>Potencia: 5w</p><p>Capacidad maxima: 40 lts</p><p><br></p><p>Incluye:</p><p>sujetador con tres ventosas</p><p>cabezal</p><p>maguera con valvulita</p><p><br></p><p>Descripción:</p><p>Funciona para para peces de agua dulce y agua salada</p><p>perforaciones en sus paredes para permitir una mayor calidad en su filtrado</p><p>Venturi, para acelerar el ciclo del agua</p><p><br></p><p>Indicaciones: nunca deje de trabajar el filtro en seco, esto le causara un daño muy severo, debe de de quedar completamente sumergido en el agua.</p><p><br></p><p><br></p>', 1, 250, 124, 1, NULL, NULL, NULL, '2025-12-26 22:46:28', '2023-12-02 22:04:41', NULL, 'filtro-interno-ocean-500', 0, 0);
