INSERT INTO `ecom_productos` VALUES (387, NULL, 'producto', '7502261581685', 0x4D41532D3033, '0P-03', 5.00, 'Mascotera transportadora mediana', '<p>Mascotera transportadora mediana</p><p>Medidas: 21 x 13 x 14 cm (largo x ancho x alto)</p><p>Para: insectos, arañas, escorpiones, chapulines, grillos, tarantulas, alacranes u roedores pequeños como hámster, peces como betta, guppy, cebras, y reptiles como iguanas, tortugas, etc.</p><p><br></p><p>Descripción: Mascotera sirve para trasladar a un animal pequeño de un punto a otro o hacerle un mini habitat, en este contenedor de plastico acrilico transparente.</p><p><br></p><p>Incluye:</p><p>Puerta abatible</p><p>Asa de sujetación</p><p>Tapa plastica de rejilla</p>', 1, 140, 124, 1, NULL, NULL, NULL, '2025-09-21 12:08:49', NULL, NULL, 'Mascotera-transportadora-mediana', 0, 0);
