INSERT INTO `ecom_productos` VALUES (396, NULL, 'producto', 'NANOAC0725L', 0x4E414E4F2D3037, 'ACUANANO07', 0.00, 'Acuario lenor de 22 L con mueble ', '<p>Pecera acuario</p><p>Capacidad: 22 litros</p><p>Medidas puro acuario: 38 x 25 x 43 cm (largo x ancho x alto)</p><p>Medidas con mueble: 38 x 25 x 108 cm (largo x ancho x alto)</p><p>Lampara potencia: w</p><p>Voltaje: v</p><p>Cabeza de poder flujo maximo: l/h</p><p><br></p><p>Descrpción:</p><p>Acuario panoramico curvo puede montarse como acuarios de agua dulce cuenta con filtro superior en forma de cascada para todo el acuario con lámpara led de bajo consumo y tapa de plástico. Es ideal para peces tropicales, peces japoneces, betas, elegante, sofisticado de tamaño precenciable de instalación rápida y fácil mantenimiento.</p><p><br></p><p>Incluye:</p><p>Tapa con luz</p><p>Mubele de madera mdf</p><p>filtro interno</p>', 0, 3000, 124, 1, NULL, NULL, NULL, '2026-02-22 17:19:01', NULL, NULL, 'Acuario-lenor-de-22-L-con-mueble-', 0, 0);
INSERT INTO `ecom_productos` VALUES (397, NULL, 'producto', '4602533783595', 0x414C494348492D3034, '4602533783595', 0.00, 'Alimento one para chinchilla', '<p>Alimento para chichilla one</p><p>Cantidad: 900 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Alimento para chichilla contiene el complejo total de proteinas, grasas, carbohidratos, vitaminas y minerales necesarios para birndar una nutrición de alta calidad y buena salud para tu mascota.&nbsp;</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-08 07:25:05', NULL, NULL, 'Alimento-one-para-chinchilla', 0, 0);
INSERT INTO `ecom_productos` VALUES (398, NULL, 'producto', '7501556439151', 0x4341542D3033, 'FL3915', 10.00, 'Extracto de catnip en spray para gatos ', '<p>Extracto de catnip en spray para gatos</p><p><br></p><p>Descripción:</p><p>Está recomendado para la aplicación directa sobre los objetos de tu mascota, como auxiliar en procesos conductuales y como método de refuerzo positivo, despertando el interés mediante el juego y favoreciendo la socialización. Su presentación en spray hace más fácil su distribución, además de no dejar residuos.</p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>', 1, 85, NULL, 1, NULL, NULL, NULL, '2024-08-30 08:49:06', '2023-11-21 14:36:05', NULL, 'Extracto-de-catnip-en-spray-para-gatos-', 0, 0);
