INSERT INTO `ecom_productos` VALUES (463, NULL, 'producto', '7501556411478', 0x415A554C2D3032, 'FL1102M', 22.00, 'Azul de metileno 60 ml ', '<p>Azul de metileno</p><p>Cantidad: 60 ml</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(102, 102, 102);\">Como preventivo, agregue 1 gota de azul de metileno por cada 2 litros de agua. En peces enfermos, agregue 2 gotas por cada litro de agua, eleve la temperatura gradualmente a 28°C, aplique cada 48 horas durante 4 o 6 días, al terminar el tratamiento haga un cambio del 25% del agua y reanude el uso de carbón activado. No apto para el consumo humano.</span></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2024-02-01 19:55:25', '2023-12-02 22:04:41', NULL, 'Azul-de-metileno-60-ml-', 0, 0);
