INSERT INTO `ecom_productos` VALUES (487, NULL, 'producto', '7501556440355', 0x414C4948412D3033, 'FL4035', 5.00, 'Alimento Mezcla de semillas para hámster frasco', '<p>Alimento Mezcla de semillas para hámster frasco</p><p>Cantidad: 1 kgrs</p><p><br></p><p>Descripción:</p><p>Formula balanceada</p><p>Fortificado con vitapellet</p><p>Natural 100 %</p><p>Es m<span style=\"color: rgb(102, 102, 102);\">ezcla completa de cereales con adición de granulados, destinada para la alimentación diaria de hámster. Además de granos de cereales enriquecidos con girasol y maíz, que son obtenidos por extrusión, que </span>aportan los nutrientes necesarios para mantener a su mascota sana y equilibrada.</p><p><br></p>', 1, 145, 124, 1, NULL, NULL, NULL, '2026-04-06 08:02:45', '2023-11-28 17:38:30', NULL, 'Alimento-Mezcla-de-semillas-para-hamster-frasco', 0, 0);
