INSERT INTO `ecom_productos` VALUES (490, NULL, 'producto', '7501556440065', 0x504F4C2D3031, 'FL4006', 6.00, 'Polvo para baño para pequeños animales ', '<p>Polvo para baño para pequeños animales</p><p>Cantidad: 1.8 kgrs</p><p><br></p><p>Descripción:</p><p>Es el perfecto auxiliar para la higiene de tu mascota mantiene a tu mascota limpia, fresca y sana.</p><p>Limpia su pelaje, elimina el exceso de grasa y absorbe humedad.</p><p>Al ser un polvo fino, penetra de manera más eficaz en el pelaje denso, otorgando sedosidad y brillo, al mismo tiempo que cuida la piel y la salud de tu mascota.</p><p>Ideal para la higiene de pequeños animales como: chinchilla, conejo, hámster, gerbo, degú, hurón.</p><p>La mascota debe revolcarse libremente en el polvo aproximadamente de 10 a 15 minutos.</p><p>Natural 100 % polvo de piedra pomez.</p><p><br></p><p><br></p><p><br></p>', 1, 135, 124, 1, NULL, NULL, NULL, '2025-10-08 17:20:09', '2023-11-28 17:38:30', NULL, 'Polvo-para-bano-para-pequenos-animales-', 0, 0);
