INSERT INTO `ecom_productos` VALUES (513, NULL, 'producto', '5900469504321', 0x414C49434F2D3034, 'TP-50432', 3.00, 'Alimento para conejo premium', '<p>Alimento para conejo premium</p><p>Cantidad: 750gr</p><p><br></p><p>Descipción:</p><p>Comida con la adiccion de cereales, frutas, semillas</p><p>Belleza y cuidado</p><p>Digestión óptima</p><p>Inmunidad pro</p><p><br></p><p>Es un alimento completo para conejos jóvenes (desde la 8° semana de vida hasta el primer año) a base de granulados ricos en fibra. También cuenta con hierbas, alfalfa, manzana y semillas de girasol, así como con adición de verduras secas ricas en vitaminas y hierbas aromáticas.</p><p>Gracias a su composición rica del alimento proporciona todos los nutrientes necesarios a los conejos jóvenes. Además cuenta con un alto contenido de fibra y la adición de remolacha y hierbas regulan la digestión y previenen la formación de bolas de pelo.</p><p>Las propiedades prebióticas de muchos ingredientes de alimento estimulan el desarrollo de la flora intestinal y apoyan al sistema inmunitario de los conejos. El alimento no contiene granos enteros de cereales, componentes genéticamente&nbsp;(OGM), conservadores, potenciadores de sabor, adición de azúcar ni aromas.</p><p><br></p><p>Guia de alimentación:</p><p><span style=\"color: rgb(109, 109, 109);\">Alimentar con alimento premium 2 veces al día, 50/80g por día. Garantizar el acceso permanente al heno y agua. Si la dieta del conejo se completa con verduras y frutas frescas, se puede reducir la cantidad de alimento administrado.</span></p>', 1, 280, 124, 1, NULL, NULL, NULL, '2026-06-01 21:57:21', '2023-11-28 17:38:30', NULL, 'Alimento-para-conejo-premium', 0, 0);
INSERT INTO `ecom_productos` VALUES (514, NULL, 'producto', '6920228230611', 0x4A434F2D3136, 'SH-230602', 0.00, 'Jaula casa corner para mascotas ', '<p>Jaula casa corner para mascotas</p><p>Medidas: 109 x 39 x 75 cm <span style=\"color: rgb(94, 98, 120);\">(largo x ancho x alto)</span></p><p><br></p><p>Incluye:</p><p>2 Plataformas</p><p>2 Rampas</p><p>2 Puertas</p><p><br></p><p>Descripción: gran espacio de descanso y juego de construcción duradera, facil instalación, material de alambre, adecuada para mascotas pequeñas como conejillos de indias, hurones, ratas, conejos, chichillas, gatos.</p><p><br></p>', 0, 1350, NULL, 1, NULL, NULL, NULL, '2024-08-09 01:19:34', '2023-11-21 14:59:48', NULL, 'Jaula-casa-corner-para-mascotas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (515, NULL, 'producto', '6957892301118', 0x4345502D3031, 'SH-230111', 4.00, 'Cepillo de limpieza ', '<p>Cepillo de limpieza</p><p>Medidas: 18 x 10.5 x 10 cm (largo x ancho x alto)</p><p><br></p><p>Descripción: Cepillo de limpieza de pelusa y removedor de pelo equipado con gran espacio de almacenamiento, ligero y portátil, apto para el hogar y tambie para viajes reutilizable y con mayor tiempo de servicio, diseñado con ruedas dobles</p><p><br></p><p>Color: Blanco</p>', 1, 260, NULL, 1, NULL, NULL, NULL, '2024-02-02 03:20:07', '2023-12-05 14:50:06', NULL, 'Cepillo-de-limpieza-', 0, 0);
INSERT INTO `ecom_productos` VALUES (516, NULL, 'producto', '7501556471540', 0x4A55472D3037, 'FL7154', 5.00, 'Juguete pelota de tenis chica ', '<p>Juguete pelota de tenis chica</p><p>Medidas: 5cm diametro</p><p><br></p><p>Descripción:</p><p>Con esta pelota de tenis bicolor con sonido tu perrito se divertirá en grande.El juguete clásico para lanzar, atrapar e interactuar por horas, el que no falla, avalado por cientos de perritos felices es agradable para los perros por su textura.</p><p>Selecciona el juguete apropiado de acuerdo con los hábitos de juego de tu perro al jugar interactúas con tu amigo y estimulas su instinto de caza.</p><p><br></p><p>Material: caucho</p><p>Colores a disponibilidad (amarillo flourecente)</p>', 1, 98, NULL, 1, NULL, NULL, NULL, '2024-02-02 03:20:47', NULL, NULL, 'Juguete-pelota-de-tenis-chica-', 0, 0);
INSERT INTO `ecom_productos` VALUES (517, NULL, 'producto', '7501556471564', 0x4A55472D3036, 'FL7156', 5.00, 'Juguete pelota de tenis grande ', '<p>Juguete pelota de tenis grande</p><p><br></p><p>Descripción:</p><p>Al presionarla emite un sonido que sorprenderá a tu perro; Juguete clásico para lanzar, atrapar e interactuar por horas con textura agradable para tu mascota.</p><p>Estimulas sus instintos naturales de cacería, ejercita mandíbula.</p><p><br></p><p>Material: caucho</p><p>Colores a disponibilidad (amarillo flourecente)</p>', 1, 90, NULL, 1, NULL, NULL, NULL, '2024-02-02 03:23:41', NULL, NULL, 'Juguete-pelota-de-tenis-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (518, NULL, 'producto', '7502278910096', 0x46494C43432D3039, 'ART.9516', 6.00, 'Filtro de cascada transparente ', '<p>Filtro de cascada transparente</p><p>Capacidad maxima: 30 lts</p><p>Voltaje: 110-120 v</p><p>Flujo maximo 250 L/H</p><p>Potencia: 3 w</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(51, 51, 51);\">Mantendras una filtración mecanica y bilogica adecuadas en el acuario gracias a sus dos componentes filtrantes colo lo es fobra que retiene las particulas en suspensión y bilogica con sus biobolas que hayudaran a crear un desarrollo de bacterias beneficas muy importantes en tu acuario. Tenfras una oxigenacion y filtracion correctas en tu acuario con un bajo consumo de energia proporcionando un ambiente adecuado limpio y saludable para tus peces.</span></p>', 1, 250, NULL, 1, NULL, NULL, NULL, '2024-02-02 03:26:18', '2023-12-04 12:03:13', NULL, 'Filtro-de-cascada-transparente-', 0, 0);
INSERT INTO `ecom_productos` VALUES (519, NULL, 'producto', '7501556439052', 0x44454E2D3031, 'FL3905', 9.00, 'Dental kit para perros', '<p>Dental kit para perros</p><p>Cantidad pasta dental: 90 grs</p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Características:</span></p><p>Optima salud dental</p><p>Mejora el aliento</p><p>Reduce la fomación de del sarro y placa bacteriana</p><p>Mango ergonómico para mejor control con dos tamaños de cabeza para adaptarse a todas las razas con cerdas suaves</p><p>Sabor hierbabuena</p><p><br></p><p><br></p>', 1, 110, NULL, 1, NULL, NULL, NULL, '2024-02-02 03:26:45', '2023-12-02 22:04:41', NULL, 'Dental-kit-para-perros', 0, 0);
INSERT INTO `ecom_productos` VALUES (520, NULL, 'producto', '6938954621047', 0x54554E452D3031, 'SH-230106', 0.00, 'Tunel de tela 6 salidas ', '<p>Tunel de tela 6 salidas</p><p>Materail: Poliester</p><p>color: Negro con azul</p><p><br></p><p>Descripción:</p><p>Juguete plegable para un almacenamiento compacto y viajar, el tunel se puede plegar y almacenar fácilmente cuando no está en uso</p><p><br></p>', 0, 650, 124, 1, NULL, NULL, NULL, '2026-02-22 17:21:38', '2023-11-21 14:59:48', NULL, 'Tunel-de-tela-6-salidas-', 0, 0);
