INSERT INTO `ecom_productos` VALUES (522, NULL, 'variante', 'CAMAFLMNEGRO05', 0x43414D4D2D3035, 'PI0101-0034', 2.00, 'Cama antiestrés mediana para perros y gatos', '<p>Cama antiestrés mediana para mascotas</p><p>Medidas: 60 x 15 cm (circuferencia x alto)</p><p>Color: negra</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros , gatos, uron, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p>', 1, 560, NULL, 1, NULL, NULL, NULL, '2024-02-05 21:11:04', '2024-02-05 15:11:04', NULL, 'Cama-antiestres-mediana-para-perros-y-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (523, NULL, 'producto', '7501556440744', 0x414C49462D3031, 'FL4074', 0.00, 'Cubos de alfalfa alimento para roedores', '<p>Mezcla de semillas</p><p>Para: Cuyos, gerbos, conejos, chinchillas.</p><p>Cantidad: 1kgr</p><p><br></p><p>Descripcion: Los cubos de alfalfa son un bocadillo nutritivo para animales herbívoros. Elaborados con alfalfa deshidratada natural, la cual contiene un alto porcentaje de proteínas, es rica en minerales como calcio, magnesio, potasio, hierro y fósforo, así como en vitaminas C, D, E, K y betacarotenos.</p><p>Fibra para una buena digestión y salud intestinal.</p><p>Fortificado con vitaminas y minerales.</p><p>Fórmula 100% natural balanceada</p><p><br></p>', 0, 145, 124, 1, NULL, NULL, NULL, '2026-03-03 23:32:28', NULL, NULL, 'Cubos-de-alfalfa-alimento-para-roedores', 0, 0);
