INSERT INTO `ecom_productos` VALUES (528, NULL, 'producto', '7502271358055', 0x434F5252412D3031, 'ART.1340', 17.00, 'Corral krill 60 x 60cm de 6 paneles ', '<p>Corral 1.20 largo x 60 altura </p><p>Medida de cada panel:61 x 61 cm (largo x alto)</p><p>Material: metalico </p><p>Color: negro</p><p><br></p><p>Descripciòn:</p><p>Corral plegable con 6 paneles para conejo, cuyo, cachorros, puerquitos, etc. <span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos.</span></p><p><br></p><p>Incluye:</p><p>Puerta abatible con doble pasador</p><p>Pintura resistente a la corrosiòn</p><p>3 bandolas de seguridad</p><p>6 ganchos de seguridad</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Configuarción de armado: hexagono 120cm x 60cm, Cuadrado 60 x 60 cm, rectangular 120 x 60 cm, o de valla 360 cm</span></p><p><br></p>', 1, 690, 124, 1, NULL, NULL, NULL, '2026-03-02 05:59:16', '2023-12-04 12:03:13', NULL, 'Corral-krill-60-x-60cm-de-6-paneles-', 0, 0);
