INSERT INTO `ecom_productos` VALUES (530, NULL, 'producto', '7501556423266', 0x4A55472D3031, 'FL9326', 2.00, 'Juguete rama bambu grande carne', '<p>Juguete rama de bambu grande</p><p>Sabor: carne</p><p>Medidas: 24 cm</p><p>Peso: 198 grs</p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Características:</span></p><p><span style=\"color: rgb(33, 37, 41);\">· Juguete masticable en forma de hueso, ideal para satisfacer el instinto de morder de los perros.</span></p><p><span style=\"color: rgb(33, 37, 41);\">· Gracias a su material de fabricación con fibra de bambú, proporciona textura y consistencia como si mordiera una rama de árbol.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Satisface el instinto natural de masticación al mismo tiempo que su textura limpia los dientes.</span></p><p><br></p><p>Material: Fibra natural de bambu</p>', 1, 220, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:12:49', NULL, NULL, 'Juguete-rama-bambu-grande-carne', 0, 0);
