INSERT INTO `ecom_productos` VALUES (535, NULL, 'producto', '8820180133655', 0x4A5547472D3036, 'WO-128', 1.00, 'Juguete con sonido circulo feliz para gato', '<p>Juguete con sonido circulo feliz para gato</p><p>Medidas: 22 x 6 cm (diametro x alto)</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Trae un resorte de 30 cms con un raton con una pluma en la punta hacen que se mueva para todos lados y asi mantiene la atencion de tu gato si parar.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La base contiene una pelota que gira al rededor del circulo con sonido</span></p>', 1, 345, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:27:53', NULL, NULL, 'Juguete-con-sonido-circulo-feliz-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (536, NULL, 'producto', '7501556495157', 0x4A55472D3038, 'FL8515', 1.00, 'Juguete para perros boomerang ', '<p>Juguete para perro boomerang</p><p>Medidas: 6.5 cm</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(33, 37, 41);\">Juguete con bordes limpiadores para promover la salud dental del perro, sirve para morder, entretener e interactuar y al mismo tiempo limpiar los dientes, además de ofrecer un suave masaje a las encías, gracias a su diseño. Ideal para cachorros y perros de raza pequeña. </span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p>Ayuda a mantener limpios los dientes.</p><p>El perro se distrae, hace ejercicio y ejercita la mandíbula.</p><p>Material lavable.</p><p><br></p><p>Material: caucho</p><p>Colores a disponibilidad (rosa, verde, naranja, azul)</p><p><br></p>', 1, 38, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:20:22', NULL, NULL, 'Juguete-para-perros-boomerang-', 0, 0);
