INSERT INTO `ecom_productos` VALUES (549, NULL, 'producto', '7502271353555', 0x5241532D3031, '50450', 2.00, 'Rascadero poste para gato', '<p>Rascadero poste para gato</p><p>Medidas: 31 x 31 x 31 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios vacios donde puedas colocar el rascadero entre salas, cuartos, etc. en aquel espacio en tu casa asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p>Material tapizante: felpa y yute</p>', 1, 320, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:26:07', '2023-12-04 12:03:13', NULL, 'Rascadero-poste-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (550, NULL, 'variante', 'CAMAFLMFUCSIA02', 0x43414D4D2D3032, 'PI0101-0029', 2.00, 'Cama antiestrés mediana para perros y gatos', '<p>Cama antiestrés mediana para mascotas</p><p>Medidas: 60 x 15 cm (circuferencia x alto)</p><p>Color: fucsia</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros , gatos, uron, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p>', 1, 560, NULL, 1, NULL, NULL, NULL, '2024-02-05 21:11:04', '2024-02-05 15:11:04', NULL, 'Cama-antiestres-mediana-para-perros-y-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (551, NULL, 'producto', '7500211002235', 0x5045522D3031, 'Q407', 10.00, 'Permaseptic desifectante ', '<p>Permaseptic desifectante para acuarios y plantas acuáticas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Es una solución de permanganato de potasio al 2.5% y es el producto ideal para la desinfección de las plantas naturales que van a ser introducidas en el acuario, así como diversos objetos decorativos naturales como rocas, ramas y troncos, evitando así la introducción en la pecera de enfermedades infecciosas y parasitarias.</span></p><p><br></p>', 1, 30, 124, 1, NULL, NULL, NULL, '2025-08-26 18:29:44', NULL, NULL, 'Permaseptic-desifectante-', 0, 0);
