INSERT INTO `ecom_productos` VALUES (556, NULL, 'producto', '7502271350653', 0x5349462D3031, '1097', 10.00, 'Sifon con perilla para pecera', '<p>Sifon con perilla para pecera</p><p>Medidas:</p><p><br></p><p>Descripción: Realiza de manera higiénica para cambio totales o parciales de agua. cuenta con colador removible para limpieza de grava.</p><p><br></p><p>Recomendaciónes: para que funcione es necesario que el extremo que va la cubeta se encuente en un nivel inferior al extremo sumergido en el acuario, con un desnivel mínimo de 20cm. y que el nivel de agua del acuario esté a 4 cm o menos del borde superior.</p><p>Se recomienda realizar el sifonado del acuario una vez a la semana.</p><p><br></p>', 1, 120, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:30:21', NULL, NULL, 'Sifon-con-perilla-para-pecera', 0, 0);
INSERT INTO `ecom_productos` VALUES (557, NULL, 'producto', 'CASIAZUL04', 0x4341532D3034, '10245', 3.00, 'Casa inova extra chica azul ', '<p>Casa inova extrachica</p><p>Color:azul</p><p>Medidas: 36 x 32 x 33cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Casa para perro pequeño, gatos, mini pig, conejo, y mas de plástico rigido ecológico en dos piezas de facil armado</p><p><br></p>', 1, 550, 124, 1, NULL, NULL, NULL, '2025-09-03 07:21:23', NULL, NULL, 'Casa-inova-extra-chica-azul-', 0, 0);
