INSERT INTO `ecom_productos` VALUES (559, NULL, 'producto', '7501556492156', 0x4E45432D3032, 'FL9215', 5.00, 'Néctar para colibrí polvo ', '<p>Néctar para colibrí polvo</p><p>Cantidad: 400 gramos</p><p><br></p><p>Presentación de néctar en polvo en color rojo. Con un agradable sabor para el ave.</p><p>Para una salud óptima, Ppor su presentación líquida, es más fácil, práctico y rápido de servir.</p><p>Fortalece huesos y cascarones.</p><p><br></p>', 1, 75, NULL, 1, NULL, NULL, NULL, '2024-02-02 14:11:43', '2023-11-28 17:38:30', NULL, 'Nectar-para-colibri-polvo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (560, NULL, 'producto', '7501556411164', 0x435259532D3330, 'FL1116', 12.00, 'Cristalize aclarador de agua para acuarios', '<p>Crystalize</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripcion:</p><p>Aclarador de agua para acuarios, elimina la turbidez causada por particulas suspendidas. (polvo, materia organica o algas).</p><p><br></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:31:36', '2023-12-02 22:04:41', NULL, 'Cristalize-aclarador-de-agua-para-acuarios', 0, 0);
