INSERT INTO `ecom_productos` VALUES (562, NULL, 'producto', '7501556482768', 0x4A55472D3139, 'FL8276', 2.00, 'Juguete scruch papas para perro', '<p>Juguete para perro con sonido</p><p>Medidas: 22 x 6 cm (diametro x alto)</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(33, 37, 41);\">- Diseño divertido</span></p><p><span style=\"color: rgb(33, 37, 41);\">- Con squeaker</span></p><p><span style=\"color: rgb(33, 37, 41);\">- Material resistente</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios:</span></p><p><span style=\"color: rgb(33, 37, 41);\">- Ideal para cachorros de razas medianas y grandes para desarrollar instintos a partir del juego.</span></p><p><span style=\"color: rgb(33, 37, 41);\">- El juego ayuda al desarrollo cognitivo de los perros y reforzar los vínculos emocionales entre mascotas y cuidadores.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Material: 100% poliester tela</span></p>', 1, 80, NULL, 1, NULL, NULL, NULL, '2024-02-02 18:34:09', NULL, NULL, 'Juguete-scruch-papas-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (563, NULL, 'variante', 'CAMAFUCSIA-03', 0x43414D462D3033, 'PI0101-0003', 3.00, 'Cama antiestres mini para mascotas', '<p>Cama antiestres mini para mascotas</p><p>Medidas: 35 x 10 cm (circuferencia x alto)</p><p>color: fucsia</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 1, 210, NULL, 1, NULL, NULL, NULL, '2024-08-30 01:42:35', '2024-08-30 01:42:35', NULL, 'Cama-antiestres-mini-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (564, NULL, 'producto', '7501556439717', 0x5348412E3036, 'FL3971', 3.00, 'Shampoo pelo negro grande ', '<p>Shampoo pelo negro grande</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials para Pelo Negro está formulado con ingredientes cuidadosamente seleccionados para resaltar el color, limpiar y suavizar el pelo.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No irrita la piel ni los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Elaborado con extracto de nogal.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Mantiene el pelaje con un color intenso.</span></p>', 1, 100, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:38:30', NULL, NULL, 'Shampoo-pelo-negro-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (565, NULL, 'producto', '7501556479577', 0x4E414E4F2D3031, 'FL7957', 2.00, 'Acuario nano reef ', '<p>Nano reef acuario</p><p>Medidas: 27 x 25 x 27.5cm (largo x ancho x alto)</p><p>Capacidad: 18 lts</p><p>Voltaje: 110 v</p><p><br></p><p>Descripción:<span style=\"color: rgb(102, 102, 102);\">Nano acuario marino con sistemas de filtración e iluminación para peces y corales blandos incluye su espumador bomba de recirculacion es un acuario con esquinas curvas de cristal ultraclaro</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Incluye: </span></p><p><span style=\"color: rgb(102, 102, 102);\">﻿lampara led </span></p><p><span style=\"color: rgb(102, 102, 102);\">Tapa de acrílico </span></p><p><br></p>', 1, 2600, 124, 1, NULL, NULL, NULL, '2026-05-12 07:39:47', NULL, NULL, 'Acuario-nano-reef-', 0, 0);
INSERT INTO `ecom_productos` VALUES (566, NULL, 'producto', '7501556479614', 0x4E414E4F2D3032, 'FL7961', 1.00, 'Acuario nano minus 15 lts', '<p>Pecera acuario nano minus</p><p>Capacidad: 15 litros</p><p>Medidas: 40 x 16 x 37 cm (largo x ancho x alto)</p><p>Lampara potencia 5.10 w</p><p><br></p><p><br></p><p>Descrpción:</p><p>Acuario nano con filtro de cascada integrado en la parte superior, lámpara led de bajo consumo y taoa de plástico con abertura para alimentar a los peces. Es ideal para peces tropicales, peces japoneces, betas o como un micro tanque de arrecife con flitro de cascada integrado. Bomba de agua, elegante de instalación rápida y fácil mantenimiento.</p><p><br></p>', 1, 1890, NULL, 1, NULL, NULL, NULL, '2024-08-20 07:32:06', NULL, NULL, 'Acuario-nano-minus-15-lts', 0, 0);
INSERT INTO `ecom_productos` VALUES (567, NULL, 'producto', '7501556439724', 0x5348412D3037, 'FL3972', 2.00, 'Shampoo pelo dorado grande', '<p>Shampoo pelo dorado para perro</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials para Pelo Negro está formulado con ingredientes cuidadosamente seleccionados para resaltar el color, limpiar y suavizar el pelo.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No irrita la piel ni los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Elaborado con extracto de manzanilla.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Proporciona brillo y resalta el color dorado del pelaje.</span></p>', 1, 100, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:39:14', NULL, NULL, 'Shampoo-pelo-dorado-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (568, NULL, 'producto', 'NANO861903', 0x4E414E4F2D3033, 'FL8619', 2.00, 'Acuario nano parvo 25 lts en kit', '<p>Pecera acuario nano parvo en kit</p><p>Capacidad: 25 litros</p><p>Medidas: 35.5 x 26 x 41 cm (largo x ancho x alto)</p><p>Lampara potencia 5 w</p><p>Voltaje:110- 120 v</p><p>Cabeza de poder flujo maximo: 500 l/h</p><p><br></p><p>Descrpción:</p><p>Acuario rectangular puede montarse como acuarios de agua dulce o salada, cuenta con filtro superior adaptable a cabeza de poder para brimdar calidad de gua para todo el acuario con lámpara led de bajo consumo y tapa de plástico con abertura para alimentar a los peces. Es ideal para peces tropicales, peces japoneces, betas Bomba de agua, elegante de instalación rápida y fácil mantenimiento.</p><p><br></p><p>Incluye:</p>', 1, 2900, 124, 1, NULL, NULL, NULL, '2026-05-12 07:41:18', NULL, NULL, 'Acuario-nano-parvo-25-lts-en-kit', 0, 0);
INSERT INTO `ecom_productos` VALUES (569, NULL, 'producto', 'PERE9LTRI06', 0x504552452D3036, 'PERE-06', 10.00, 'Pecera rectangular triple 9 litros equipo básico', '<p>Pecera rectangular triple equipo básico</p><p>Capacidad 9 litros</p><p>Medidas: 41 x 12 x 20 cm (Largo x ancho x alto)</p><p>Grosor: 3mm</p><p><br></p><p>Incluye:</p><p>Grava (se puede cambiar el tono) sujetos a disponibilidad</p><p>Alimento</p><p>3 Planta artificial (se puede cambiar planta) sujetos a disponibilidad</p><p>Alimento</p><p>Poster<span style=\"color: rgb(94, 98, 120);\"> (se puede cambiar diseño) sujetos a disponibilidad</span></p><p>2 divisiones</p><p><br></p><p>Descripción:</p><p>Pecera con divisiones de cristal extraibles para formar tres betteras en una sola pecera con marcos de plástico, para bettas o peces pequeños </p><p><br></p>', 1, 360, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:04:30', NULL, NULL, 'Pecera-rectangular-triple-9-litros-equipo-basico', 0, 0);
INSERT INTO `ecom_productos` VALUES (570, NULL, 'producto', 'TORTHEXAT14', 0x544F522D3134, 'TOR-14', 4.00, 'Tortuguero hexagonal elevado en kit ', '<p>Tortuguero hexagonal elevado en kit</p><p>Medidas:</p><p><br></p><p>Descripción: con distintos diseños la forma de la isla de cistal para tortugas pequeñas con rampa para que la totuga suba su zona seca.</p><p><br></p><p>Incluye:</p><p>Isla se puede cambiar el color de la grava y diseño de la forma. (sujetos a disponibilidad)</p><p>Grava se cambiar el color de la grava</p><p>Calcio</p><p>Alimento</p><p>Vitamina a</p><p><br></p><p>Colores: azul cielo, azul marino, rosa , verde, naranja, roja, cafe, arena, blanca, negra, y mas (colores sujetos a disponibilidad).</p><p><br></p>', 1, 799, NULL, 1, NULL, NULL, NULL, '2024-10-03 16:13:37', NULL, NULL, 'Tortuguero-hexagonal-elevado-en-kit-', 0, 0);
INSERT INTO `ecom_productos` VALUES (571, NULL, 'producto', '5900469504222', 0x414C4943552D3033, '50422', 5.00, 'Alimento para cuyo premium', '<p>Alimento para cuyo (cavia, cobaya,)premium</p><p>Cantidad: 750gr</p><p><br></p><p>Descipción:</p><p>Comida con la adiccion de cerales, frutas y verduras.</p><p>Belleza y cuidado</p><p>Digestión óptima</p><p>Inmunidad pro</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Alimento completo para cobayas a base de granulados con alfalfa, manzana y adición de verduras, frutas secas ricas en vitaminas y hierbas aromáticas</span></p><p><span style=\"color: rgb(102, 102, 102);\">Las semillas de linaza ricas en ácidos grasos insaturados dan el aspecto saludable a la piel y el brillo al pelo </span></p><p><span style=\"color: rgb(102, 102, 102);\">alimento enriquecido con vitamina C dimento</span></p><p><span style=\"color: rgb(102, 102, 102);\">El alto contenido de fibra y la adición de remolacha y hierbas regulan la digestión las propiedades prebióticas de muchos ingredientes del alimento estimulan el desarrollo de la flora intestinal y apoyan al sistema inmunitario de las cobayas</span></p><p><span style=\"color: rgb(102, 102, 102);\">El alimento no contiene componentes genéticamente modificados (OGM), conservantes, potenciadores del sabor, adición de azúcar ni aromas</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Alimentación: alimentar dos veces al dia, 30-50 g/día. Garantizar el acceso permanente al heno y agua.</span></p><p><br></p>', 1, 280, 124, 1, NULL, NULL, NULL, '2026-04-08 07:18:32', NULL, NULL, 'Alimento-para-cuyo-premium', 0, 0);
INSERT INTO `ecom_productos` VALUES (572, NULL, 'producto', '7501556466485', 0x414C49422D3238, 'WAT648', 20.00, 'Alimento betta premium sobre ', '<p>Alimento betta premium sobre</p><p>cantidad: 20 gramos</p><p><br></p><p>Descripción:</p><p>nutricional mente balanceado</p><p>realza los colores</p><p>mini pellet flotante</p>', 1, 25, 124, 1, NULL, NULL, NULL, '2025-08-25 14:56:26', NULL, NULL, 'Alimento-betta-premium-sobre-', 0, 0);
INSERT INTO `ecom_productos` VALUES (573, NULL, 'producto', '7501556439434', 0x4A41424F2D3032, 'FL3943', 5.00, 'Jabón insecticida ', '<p>Jabón insecticida para perros</p><p><br></p><p>Descripción:</p><p>jabón para el control y tratamiento de infestaciónes por ácaros, garrapatas, moscas, piojos y pulgas en perros. Proteje hasta por 15 días agradable aroma.</p><p><br></p>', 1, 85, NULL, 1, NULL, NULL, NULL, '2024-11-09 17:36:52', NULL, NULL, 'Jabon-insecticida-', 0, 0);
