INSERT INTO `ecom_productos` VALUES (575, NULL, 'producto', '7501556439786', 0x5348412D3038, 'FL3978', 0.00, 'Shampoo para cachorro perro y gato grande', '<p>Shampoo essentials para cachorro perro y gato grande</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p>El Shampoo Essentials para Cachorro limpia y suaviza al mismo tiempo el pelo, con ingredientes que cuidan su piel y proporcionan sedosidad facilitando el cepillado.</p><p>Elaborado con esencia de mora azul.</p><p>Proporciona limpieza y sedosidad.</p><p>Suave con la piel delicada.</p><p>No irrita la piel ni los ojos del cachorro.</p><p><br></p>', 1, 100, 124, 1, NULL, NULL, NULL, '2026-03-04 20:43:40', NULL, NULL, 'Shampoo-para-cachorro-perro-y-gato-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (576, NULL, 'producto', 'PERE9L03', 0x504552452D3033, 'PERE-03', 3.00, 'Pecera rectagular 9 lts equipo básico', '<p>Pecera rectangular equipo básico</p><p>Capacidad:9 lts</p><p>Medidas: 30 x 15 x 20 cm (largo x ancho x alto)</p><p>Grosor: 3mm</p><p><br></p><p>Incluye:</p><p>Grava (se puede cambiar el tono) sujetos a disponibilidad</p><p>Alimento 10grs</p><p>Filtro cascada</p><p>Planta artificial (se puede cambiar planta) sujetos a disponibilidad</p><p>Red</p><p>Bacteria</p><p>Poster <span style=\"color: rgb(94, 98, 120);\">(se puede cambiar diseño) sujetos a disponibilidad</span></p><p><br></p><p>Descripción: pecera equipo básico para su instalación pronta con marcos de plastico. Para peces pequeños y bettas</p><p><br></p>', 1, 550, 124, 1, NULL, NULL, NULL, '2025-09-02 05:46:01', NULL, NULL, 'Pecera-rectagular-9-lts-equipo-basico', 0, 0);
INSERT INTO `ecom_productos` VALUES (577, NULL, 'producto', 'PERE20L04', 0x504552452D3034, 'PERE-04', 5.00, 'Pecera rectangular 20lts equipo básico', '<p>Pecera rectangular equipo básico</p><p>Capacidad: 20 lts</p><p>Medidas: 41 x 21 x 28 cm (largo x ancho x alto)</p><p>Grosor: 3mm</p><p><br></p><p>Incluye:</p><p>Grava (se puede cambiar el tono) sujetos a disponibilidad</p><p>Alimento 10 gr</p><p>Filtro cabeza de poder</p><p>Planta artificial (se puede cambiar planta) sujetos a disponibilidad</p><p>Red</p><p>Bacteria</p><p>Poster<span style=\"color: rgb(94, 98, 120);\"> (se puede cambiar diseño) sujetos a disponibilidad</span></p><p><br></p><p>Descripción: pecera equipado básico para su instalación pronta con marcos de plastico. para peces chicos medianos y bettas</p><p><br></p>', 1, 699, 124, 1, NULL, NULL, NULL, '2025-09-02 05:42:38', NULL, NULL, 'Pecera-rectangular-20lts-equipo-basico', 0, 0);
INSERT INTO `ecom_productos` VALUES (578, NULL, 'producto', '7501556439793', 0x5348412D3033, 'FL3979', 3.00, 'Shampoo piel sensible grande ', '<p>Shampoo essentials piel sensible para perro</p><p>Cantidad: 500 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">El Shampoo Essentials para Piel Sensible está formulado con extractos de aloe vera y avena sativa que cuidan y protegen la piel y el pelaje; además contiene pantenol, glicerina y aceite graso para aumentar el brillo y suavidad. No irrita los ojos del perro.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Con extractos de aloe vera y avena sativa.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Humectante y emoliente que disminuye la irritación en la piel y calma la comezón.</span></p>', 1, 100, NULL, 1, NULL, NULL, NULL, '2024-07-09 07:37:28', NULL, NULL, 'Shampoo-piel-sensible-grande-', 0, 0);
