INSERT INTO `ecom_productos` VALUES (606, NULL, 'producto', '7502217856799', 0x414C49582D3032, 'A300', 4.00, 'Alimento para ajolote axolotinas adulto', '<p>Alimento para axolote</p><p>Cantidad: 60 grs</p><p>Esferas: 4.5 mm de diametro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para ajolotes talla adulto</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fórmula omnívora, predominantemente cárnica.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Cuenta con un excelente balance calcio:fósforo. Sin duda, la mejor opción del mercado para la completa nutrición de estos </span></p><p><span style=\"color: rgb(102, 102, 102);\">Ejemplares.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Fórmula diseñada, probada y comprobada por especialistas en cría de ajolotes. </span></p><p><br></p>', 1, 60, 124, 1, NULL, NULL, NULL, '2025-08-26 16:24:19', '2023-12-02 22:04:41', NULL, 'Alimento-para-ajolote-axolotinas-adulto', 0, 0);
INSERT INTO `ecom_productos` VALUES (607, NULL, 'producto', 'TOR1MTROIS18', 0x544F522D3138, 'TOR-18', 5.00, 'Tortuguero rectangular 100 x 30cm altura ', '<p>Tortuguero rectangular 1 metro </p><p>Capacidad: 78lts varia dependiendo de la cantidad que se le ponga</p><p>Medidas: 100 x 26 x 30 cm (largo x ancho x alto)</p><p>Grosor: 6 mm</p><p><br></p><p>Descripción:</p><p>Pecera con isla de cristal para que tengan su zona seca y puedan descansar un lugar sin agua.</p>', 1, 1690, 124, 1, NULL, NULL, NULL, '2025-12-05 22:04:24', NULL, NULL, 'Tortuguero-rectangular-100-x-30cm-altura-', 0, 0);
