INSERT INTO `ecom_productos` VALUES (609, NULL, 'producto', 'CARACOLMZA01', 0x434152412D3031, 'CARA-01', 2.00, 'Caracol mazano ', '<p>Caracol mazano</p><p><br></p><p>Descripción:</p><p>Es una especie herbívora muy voraz que se alimenta de numerosas especies de plantas acuáticas de fácil digestión. Realiza las puestas fuera del agua, en masas compactas sobre superficies duras o vegetación acuática. lista para comer la alga que se genera en peceras. </p>', 1, 15, NULL, 1, NULL, NULL, NULL, '2024-05-11 21:39:04', NULL, NULL, 'Caracol-mazano-', 0, 0);
