INSERT INTO `ecom_productos` VALUES (613, NULL, 'producto', '6932102450138', 0x41524F2D3137, 'SH-230133', 3.00, 'Arenero aqua', '<p>Arenero aqua</p><p>Medidas: 45 x 34 x 39 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>Desmontable con doble puerta intergrada una con puerta y la otra sin para que facil salga con lipiador de patas.</p><p>Absorbe malos olores y evita q se propagen al exterior</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño vanguardista y exclusivo adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>Puerta abatible</p><p>Pala</p><p>Charola extraible</p><p><br></p><p>Colres: rosa gris, azul ( sujetos a disponibilidad)</p>', 1, 820, 124, 1, NULL, NULL, NULL, '2025-06-03 23:19:23', '2025-06-03 23:19:23', NULL, 'Arenero-aqua', 0, 0);
INSERT INTO `ecom_productos` VALUES (614, NULL, 'producto', '7502261581708', 0x4D41532D3035, '0P-5', 5.00, 'Mascotera transportadora extragrande ', '<p>Mascotera transportadora extragrande</p><p>Medidas: 32.5 x 21.5 x 19 cm (largo x ancho x alto)</p><p>Para: insectos, arañas, escorpiones, chapulines, grillos, tarantulas, alacranes u roedores pequeños como hámster, peces como betta, guppy, cebras, y reptiles como iguanas, tortugas, etc.</p><p><br></p><p>Descripción: Mascotera sirve para trasladar a un animal pequeño de un punto a otro o hacerle un mini habitat, en este contenedor de plastico acrilico transparente.</p><p><br></p><p>Incluye:</p><p>2 Puerta abatible</p><p>2 Asa de sujetación</p><p>Tapa plastica de rejilla</p>', 1, 260, NULL, 1, NULL, NULL, NULL, '2024-02-01 20:28:39', NULL, NULL, 'Mascotera-transportadora-extragrande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (615, NULL, 'producto', '6938954621238', 0x41524F2D3136, 'SH-230121', 0.00, 'Arenero venus', '<p>Arenero venus</p><p>Medidas: 50 x 35 x 38 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>Desmontable con doble puerta intergrada.</p><p>Absorbe malos olores y evita q se propagen al exterior</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño vanguardista y exclusivo adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>2 Puerta abatible</p><p>Pala</p><p>Charola extraible</p><p><br></p><p>Colres: rosa gris, verde, naranja, morado ( sujetos a disponibilidad)</p>', 0, 0, NULL, 0, NULL, NULL, NULL, '2024-02-03 20:58:54', NULL, NULL, '', 0, 0);
INSERT INTO `ecom_productos` VALUES (616, NULL, 'producto', 'LUCAARO19', 0x41524F2D3139, 'SH-230407', 5.00, 'Arenero lucah', '<p>Arenero lucah</p><p>Medidas: 53 x 43 x 25 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>Libre acceso, mejor ventilación bloqueo 360 para evitar derrames de arena</p><p>Reduce crecimiento bacteriano.</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño moderno y reforzado adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>Pala</p><p><br></p><p>Colres: verde, rojo, azul ( sujetos a disponibilidad)</p>', 1, 490, NULL, 1, NULL, NULL, NULL, '2024-02-03 20:59:38', '2023-11-21 14:59:48', NULL, 'Arenero-lucah', 0, 0);
