INSERT INTO `ecom_productos` VALUES (620, NULL, 'producto', '7501556477856', 0x46494C54462D3031, 'FL7785', 3.00, 'filtro interno de flauta ', '<p>Filtro interno faluta</p><p>Medidas: 12.5 <span style=\"color: rgba(0, 0, 0, 0.9);\">cm x 7 cm x 15.5cm (largo x ancho x alto)</span></p><p>Voltaje: 110 v</p><p>Flujo maximo: 230 Lts / h</p><p><br></p><p>Descripción:</p><p>Mini filtro interno sumergible poderoso, potente, silencioso</p><p>Diseño ultra compacto de fácil colocación</p><p>Barra disfusora para oxigenación y circulación</p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para acuarios de agua dulce </span></p><p>Capacidad maxima del filtro 25 lts</p><p><br></p><p><br></p>', 1, 230, NULL, 1, NULL, NULL, NULL, '2024-02-03 21:09:08', NULL, NULL, 'filtro-interno-de-flauta-', 0, 0);
INSERT INTO `ecom_productos` VALUES (621, NULL, 'producto', 'PEZPAREGU01', 0x50455A50472D3031, 'PEZPG-01', 30.00, 'Pez pareja de guppy', '<p>Pareja de guppy</p><p>Cantidad: 2 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(31, 32, 36);\">También conocidos como&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">peces millón</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;o&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">lebistes</strong><span style=\"color: rgb(31, 32, 36);\">, son pequeños peces de agua dulce&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">tropicales</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;muy populares en acuariofilia. Son apreciados por sus&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">colores vibrantes</strong><span style=\"color: rgb(31, 32, 36);\">, su&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">facilidad de cuidado</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;y su&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">reproducción rápida</strong><span style=\"color: rgb(31, 32, 36);\">.</span></p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-11 21:25:03', NULL, NULL, 'Pez-pareja-de-guppy', 0, 0);
INSERT INTO `ecom_productos` VALUES (622, NULL, 'producto', 'PECED201', 0x504552452D3031, 'PERE-01', 5.00, 'Pecera rectangular 2lts equipo básico', '<p>Pecera rectangular mini equipada</p><p>Capacidad: 2 litros</p><p>Medidas: 16 x 11 x 15 cm (largo x ancho x alto)</p><p>Grosor:3mm</p><p><br></p><p>Incluye:</p><p>Grava (se puede cambiar el tono) sujetos a disponibilidad</p><p>Alimento</p><p>Planta artificial (se puede cambiar planta) sujetos a disponibilidad</p><p>Poster <span style=\"color: rgb(94, 98, 120);\">(se puede cambiar diseño) sujetos a disponibilidad</span></p><p><br></p><p>Descripción: pecera equipada para betta con marcos de plástico.</p><p><br></p><p><br></p><p><br></p>', 1, 175, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:07:14', NULL, NULL, 'Pecera-rectangular-2lts-equipo-basico', 0, 0);
