INSERT INTO `ecom_productos` VALUES (627, NULL, 'producto', 'PEZCRPAKCH01', 0x50455A4B2D3031, 'PEZK-01', 44.00, 'Pez carpas koi chicas', '<p>Pez carpas koi chicas </p><p><br></p><p>Descripción:</p><p>Pez carpas chicas s<span style=\"color: rgb(51, 51, 51);\">on animales que resisten bien las bajas temperaturas (incluso con la superficie del agua helada) mediante la reducción drástica de la movilidad y la respiración, pero de verdad están a gusto y despliegan toda su coreografía en un hábitat templado, de 17º a 24º. Por encima de esta temperatura, la escasez de oxígeno las vuelve más agresivas. También puede asomar ese comportamiento si se disputan el espacio con demasiados congéneres.</span></p><p><br></p>', 1, 35, NULL, 1, NULL, NULL, NULL, '2024-05-09 19:52:37', NULL, NULL, 'Pez-carpas-koi-chicas', 0, 0);
