INSERT INTO `ecom_productos` VALUES (631, NULL, 'producto', 'BACG12003', 0x4241432D3033, 'BAC-03', 3.00, 'Bacteria co grande 120 ml', '<p>Bacteria co grande</p><p>Cantidad: 120 ml</p><p><br></p><p>Descripción:</p><p>Es un producto diseñado para ayudarlo con un ciclo biológico y de esta forma prevenir mortandad y mejorar el entorno de sus peces.</p><p><br></p><p>Ciclo es una forma de ayudarlo a mantener su ciclo bacteriano de forma estable ya que es un compendio de aminoácidos, enzimas, bacterias y toda una gama de compuestos enfocados a un pronto proliferación bacteriana.</p><p><br></p><p>Agítese antes de usar, use una tapita 5 ml cada 40 Lts 2 o tres veces por semana al hacer cambios de agua o al iniciar con una nueva pecera.</p><p><br></p>', 1, 145, NULL, 1, NULL, NULL, NULL, '2024-04-11 20:46:35', NULL, NULL, 'Bacteria-co-grande-120-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (632, NULL, 'producto', 'PEZCEB03DUR', 0x50455A432D3033, 'PEZC-03', 149.00, 'Pez cebra durazno neón ', '<p>Pez cebra durazno neon</p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p>Pez cebra flourecente con luz azul modificadas geneticamete, el pez <span style=\"color: rgb(51, 51, 51);\">no posee dientes ni estómago, se alimenta haciendo uso de sus branquias espinosas succionando el alimento.</span></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 5, NULL, 1, NULL, NULL, NULL, '2024-05-09 19:22:47', NULL, NULL, 'Pez-cebra-durazno-neon-', 0, 0);
