INSERT INTO `ecom_productos` VALUES (639, NULL, 'producto', 'LAM60CMREC03', 0x4C414D2D54523033, 'FL7352', 5.00, 'Lampara para pecera de tapa de 60cm ', '<p>Lampara de tapa rectangular 60cm</p><p>Potencia: 8 w</p><p>Volts: 85- 265 v</p><p>Frecuencia: 50-60 Hz</p><p><br></p><p>Descripción:</p><p>La lampara de tapa para pecera de 60cm x 30cm con tecnologia led de alta densidad y larga duración se ajusta a la mayoría de los acuarios d 80 lts bajo consumo de energía.</p><p>Diseño elegante y delgado.</p>', 1, 750, NULL, 1, NULL, NULL, NULL, '2024-02-03 21:11:17', NULL, NULL, 'Lampara-para-pecera-de-tapa-de-60cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (640, NULL, 'producto', 'PEZGU03AZU', 0x50455A472D3033, 'PEZG-03', 20.00, 'Pez guramy azul', '<p>Pez guramy azul</p><p><br></p><p>Descripción:<span style=\"color: rgb(58, 58, 58);\">&nbsp;está considerado un&nbsp;pez de agua fria. Su resistencia a las bajadas de temperatura es espectacular,&nbsp;</span><strong style=\"color: rgb(58, 58, 58);\">puede soportar temperaturas cercanas a 0ºC. su temperatura recomendada es entre los 10 °C a los 22 °C, puede llegar alcanzar una longuitud de hasta 10cm.</strong></p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p><p><strong style=\"color: rgb(58, 58, 58);\">﻿</strong></p>', 1, 45, NULL, 1, NULL, NULL, NULL, '2024-05-28 00:27:42', NULL, NULL, 'Pez-guramy-azul', 0, 0);
