INSERT INTO `ecom_productos` VALUES (643, NULL, 'producto', 'PEZMONJNR01', 0x50455A4D4E2D3031, 'PEZMN-01', 90.00, 'Pez monja neón roja', '<p>Pez monja transgenica</p><p>Color: roja</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neónen la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:51:35', NULL, NULL, 'Pez-monja-neon-roja', 0, 0);
INSERT INTO `ecom_productos` VALUES (644, NULL, 'producto', 'PEZMYBLNE04', 0x50455A4D592D3034, 'PEZMY-04', 20.00, 'Pez molly balón negro ', '<p>Pez molly</p><p>Color: negro</p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(31, 32, 36);\">También conocida como Molly lira,&nbsp;&nbsp;puede alcanzar una talla de 15 cm temperatura ideal entre los 23 a 26 °C</span></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-15 00:04:25', NULL, NULL, 'Pez-molly-balon-negro-', 0, 0);
