INSERT INTO `ecom_productos` VALUES (646, NULL, 'producto', 'PEZRAFPUN01', 0x50455A52502D3031, 'PEZRP-01', 2.00, 'Pez rafaello de puntos', '<p>Pez rafaello de puntos</p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p>Les gusta esconderse entre rocas o troncos que formen pequeñas cuevas. Acostumbrada a enterrarse en la grava o arena llegan alcanzar  un tamaño de hasta 24 cm de longuitud, la temperatura ideal es entre los 20 y 26 °C. </p><p><br></p>', 1, 180, NULL, 1, NULL, NULL, NULL, '2024-05-15 01:05:17', NULL, NULL, 'Pez-rafaello-de-puntos', 0, 0);
