INSERT INTO `ecom_productos` VALUES (651, NULL, 'producto', 'CORRALTELA01', 0x434F52542D3031, 'SH-230107', 0.00, 'Corral de tela panal chico', '<p>Corral de tela panal chico</p><p>Corral diametro: 90cm</p><p>Medida de cada panel:32 x 45 cm (largo x alto)</p><p><br></p><p>Descripción:</p><p>Corral plegable con 8 paneles para cachorros, puerquitos, etc. <span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos o como cama, cuenta con un seguro multifuncional, de alto rendimiento, transpirable, doble uso para interiores y exteriores, fácil de transportar.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Material: poliester.</span></p><p><br></p><p>Colores: amarillo, azul, rosa, blanco rojo (colores sujetos a disponibilidad)</p>', 0, 480, NULL, 1, NULL, NULL, NULL, '2024-04-19 16:59:22', NULL, NULL, 'Corral-de-tela-panal-chico', 0, 0);
