INSERT INTO `ecom_productos` VALUES (659, NULL, 'producto', 'PEZANG01MINI', 0x50455A412D3031, 'PEZA-01', 10.00, 'Pez angel mixto mini ', '<p>Pez angel mixto mini </p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(24, 24, 24);\">Los peces ángel son omnívoros, por lo que su alimentación debe ser variada. Se les puede suministrar alimentos comerciales en forma de escamas, gránulos o pellets, pero también es importante incluir alimentos frescos como larvas de mosquito, camarones o algas.</span></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 30, NULL, 1, NULL, NULL, NULL, '2024-05-09 19:39:11', NULL, NULL, 'Pez-angel-mixto-mini-', 0, 0);
