INSERT INTO `ecom_productos` VALUES (663, NULL, 'producto', 'PEZCEB02VER', 0x50455A432D3032, 'PEZC-02', 64.00, 'Pez cebra verde neón', '<p>Pez cebra verde neón</p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p>Pez cebra flourecente con luz azul modificadas geneticamete, el pez <span style=\"color: rgb(51, 51, 51);\">no posee dientes ni estómago, se alimenta haciendo uso de sus branquias espinosas succionando el alimento.</span></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 5, NULL, 1, NULL, NULL, NULL, '2024-05-09 19:16:53', NULL, NULL, 'Pez-cebra-verde-neon', 0, 0);
