INSERT INTO `ecom_productos` VALUES (669, NULL, 'producto', 'PECEHEXA6001', 0x504552412D4833383530, 'PERA-H3850', 7.00, 'Pecera hexagonal 38 x 38 x 50 cm altura 65 litros 6 mm ', '<p>Pecera hexagonal</p><p>Capacidad: 64 litros</p><p>Medidas: 21 x 50cm (largo x alto) de cada cristal</p><p>Grosor: 6 mm</p><p>Cristales: 6 pza</p><p><br></p><p>Descripción: pecera medida estandar para peces medianos, con marcos de plástico.</p>', 1, 890, 124, 1, NULL, NULL, NULL, '2026-05-25 10:21:17', '2026-05-25 10:21:17', NULL, 'Pecera-hexagonal-38-x-38-x-50-cm-altura-65-litros-6-mm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (670, NULL, 'producto', 'PEZGUPDUM01', 0x50455A47442D3031, 'PEZGD-01', 0.00, 'Pez guppy dumbo ', '<p>Pez guppy dumbo</p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(31, 32, 36);\">También conocidos como&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">peces millón</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;o&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">lebistes</strong><span style=\"color: rgb(31, 32, 36);\">, son pequeños peces de agua dulce&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">tropicales</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;muy populares en acuariofilia. Son apreciados por sus&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">colores vibrantes</strong><span style=\"color: rgb(31, 32, 36);\">, su&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">facilidad de cuidado</strong><span style=\"color: rgb(31, 32, 36);\">&nbsp;y su&nbsp;</span><strong style=\"color: rgb(31, 32, 36);\">reproducción rápida</strong><span style=\"color: rgb(31, 32, 36);\">.</span></p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-05 21:12:46', NULL, NULL, 'Pez-guppy-dumbo-', 0, 0);
