INSERT INTO `ecom_productos` VALUES (680, NULL, 'producto', '', 0x50455A4D4E2D3036, 'PEZMN-06', 40.00, 'Pez monja negra ', '<p>Pez monja transgenica</p><p>Color: negra</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neón, negra en la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:51:21', NULL, NULL, 'Pez-monja-negra-', 0, 0);
INSERT INTO `ecom_productos` VALUES (681, NULL, 'producto', 'PEZTMOCA02', 0x50455A544D2D3032, 'PEZTM-02', 20.00, 'Pez moro calico chico ', '<p>Pez moro telescopio calico chico</p><p>Cantidad: 1 pza </p><p><br></p><p>Descripción:</p><p>Los ojos grandes del pez que parecen dos telescopios unidos a su cabeza.Tiene una cola larga que se abre en abanico y fluye en el agua pez que requiere oxigeno.Es<span style=\"color: rgb(31, 32, 36);\">ta variedad de pez telescopio puede alcanzar un tamaño de hasta 15 cm de largo. temperatura recomendada entre los 23 a 20 °C.</span></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-16 19:30:30', NULL, NULL, 'Pez-moro-calico-chico-', 0, 0);
INSERT INTO `ecom_productos` VALUES (682, NULL, 'producto', '7501556438420', 0x47414C4C2D3033, 'FL3842', 5.00, 'Galletas premio sabor pollo para perro', '<p>Galletas premio para perro</p><p>Cantidad:100 grs</p><p>Edad de perro: Adulto</p><p>Sabor: pollo</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(55, 61, 63);\">Galletas en forma de hueso&nbsp;</span><strong style=\"color: rgb(55, 61, 63);\">sabor pollo</strong><span style=\"color: rgb(55, 61, 63);\">. Además, están</span><strong style=\"color: rgb(55, 61, 63);\">&nbsp;fortificadas con vitaminas</strong><span style=\"color: rgb(55, 61, 63);\">, no contienen grasa, son muy saludables y ricas, a tu perro seguro le encantan.</span></p>', 1, 45, 124, 1, NULL, NULL, NULL, '2025-10-21 22:54:50', NULL, NULL, 'Galletas-premio-sabor-pollo-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (683, NULL, 'producto', 'PEZTELMNE01', 0x50455A544D3031, 'PEZTM-01', 30.00, 'Pez moro negro chico', '<p>Pez moro telescopio negro chico</p><p>Cantidad: 1 pza </p><p><br></p><p>Descripción:</p><p>Los ojos grandes del pez que parecen dos telescopios unidos a su cabeza.Tiene una cola larga que se abre en abanico y fluye en el agua pez que requiere oxigeno.Es<span style=\"color: rgb(31, 32, 36);\">ta variedad de pez telescopio puede alcanzar un tamaño de hasta 15 cm de largo. temperatura recomendada entre los 23 a 20 °C.</span></p><p><br></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-16 18:39:26', NULL, NULL, 'Pez-moro-negro-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (684, NULL, 'producto', '7501556438444', 0x47414C4C2D3032, 'FL3844', 5.00, 'Galletas premio sabor carne para perro', '<p>Galletas premio para perro</p><p>Cantidad:100 grs</p><p>Edad de perro: Adulto</p><p>Sabor: carne</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(55, 61, 63);\">Galletas en forma de hueso&nbsp;</span><strong style=\"color: rgb(55, 61, 63);\">sabor carne</strong><span style=\"color: rgb(55, 61, 63);\">. Además, están</span><strong style=\"color: rgb(55, 61, 63);\">&nbsp;fortificadas con vitaminas</strong><span style=\"color: rgb(55, 61, 63);\">, no contienen grasa, son muy saludables y ricas, a tu perro seguro le encantan.</span></p><p><br></p>', 1, 45, 124, 1, NULL, NULL, NULL, '2025-10-21 22:54:30', NULL, NULL, 'Galletas-premio-sabor-carne-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (685, NULL, 'producto', '7501556440362', 0x414C49532D3033, 'FL4036', 16.00, 'Barra de semillas mijo para pajaros', '<p>Barritas de semillas</p><p>Para: todo tipo de vaes canarios, finches y gorriones agapornis, periquito australiano, isabelas, cardenales, etc.</p><p>Cantidad: 95 grs</p><p><br></p><p>Descripcion: Son un snack elaborado con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá al mismo tiempo que estimulan su curiosidad y acatividad.</p><p>Fortificado con vitaminas y minerales</p><p>Fórmula 100% natural balanceada</p><p>Con practico gancho que permite colocarla dentro de la jaula,&nbsp;</p>', 1, 55, 124, 1, NULL, NULL, NULL, '2026-01-28 23:05:29', '2023-11-28 17:38:30', NULL, 'Barra-de-semillas-mijo-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (686, NULL, 'producto', 'PEZOSNEG01', 0x50455A4F532D3031, 'PEZOS-01', 0.00, 'Pez oscar grande ', '<p>Pez oscar grande </p><p><br></p><p>Descripción:</p><p>El pez óscar forma parte de la familia de los cíclidos. Se alimenta de gusanos, crustáceos, insectos, pedazos de pescado o pollo, larvas rojas e incluso come peces pequeños, puede llegar a medir hasta 40cm.</p><p><br></p><p><br></p>', 1, 200, NULL, 1, NULL, NULL, NULL, '2024-05-11 22:07:43', NULL, NULL, 'Pez-oscar-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (687, NULL, 'producto', 'AniPec64557', NULL, 'NULL', 0.00, 'Pez platty micky naranja', 'Pez platty micky naranja', 1, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `ecom_productos` VALUES (688, NULL, 'producto', '7501556491135', 0x4C494D2D3033, 'FL8913', 5.00, 'Limpiador magnético grande ', '<p>Limipador maganetico grande</p><p>Medidas: 10 x 4 cm (largo x ancho)</p><p><br></p><p>Descripción:</p><p>El limpiador magnético de Lomas quita con facilidad las algas del cristal del acuario sin rayarlo.</p><p>Puede utilizarse en acuarios marinos o dulces, sin afectar la calidad del agua.</p><p>Es un método práctico y efectivo de limpieza del tanque.</p><p>Los potentes imanes aseguran un agarre firme en el vidrio, por lo que no es necesario introducir las manos en el acuario.</p><p>Recomendacion de superficie vidrio</p><p><br></p>', 1, 198, NULL, 1, NULL, NULL, NULL, '2024-03-28 22:39:05', NULL, NULL, 'Limpiador-magnetico-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (689, NULL, 'producto', 'PEZSUMVER01', 0x50455A532D3031, 'PEZS-01', 0.00, 'Pez sumatrano tigre verde ', '<p>Pez sumatrano tigre verde </p><p>Cantidad: 1 pza</p><p><br></p><p>Descripción:</p><p>Temperatura sin nigún probelma el alimento en escamas, y se los puede mantener exclusivamente a base de este. Lo ideal seria alimentarlos dos veces al día, una de ellas con comida en copos y la otra con comida \"naural\" como puede ser pasta de hígado o manto de mejillón. Artemias adultas, dafnias, tubifex, larvas de mosquito, aliemnto congelado pueden estar en una temperatura de 22 a 28 °C y pueden alcanzar un tamaño de 7.5 cm </p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-05-11 20:55:55', NULL, NULL, 'Pez-sumatrano-tigre-verde-', 0, 0);
INSERT INTO `ecom_productos` VALUES (690, NULL, 'producto', 'ALIPAJSEALIS05', 0x414C49532D3035, 'FL4037', 5.00, 'Barrita de semillas para pajaros canoras', '<p>Barritas de semillas</p><p>Para: canoras y de ornato</p><p>Cantidad: 2 barras de 36grs cada una</p><p><br></p><p>Descripcion: Son un snack elaborado con una mezcla de semillas exclusivas y balanceadas con larva deshidratada de mosca soldado para este tipo de aves que los nutrirá al mismo tiempo que estimulan su curiosidad y acatividad.</p><p>Fortificado con vitaminas y minerales</p><p>Fórmula 100% natural balanceada</p><p>Con practico gancho que permite colocarla dentro de la jaula,&nbsp;</p>', 1, 48, NULL, 1, NULL, NULL, NULL, '2024-02-03 22:13:15', NULL, NULL, 'Barrita-de-semillas-para-pajaros-canoras', 0, 0);
