INSERT INTO `ecom_productos` VALUES (698, NULL, 'producto', '7501556407761', 0x524550452D3032, 'FL3776', 1.00, 'Repelente entrenador stay  para perros ', '<p>Repelente entrenador para perros</p><p><br></p><p>Descripción:</p><p>Mantiene alejado al perro de los muebles y objetos prohibidos</p><p>No es toxico, no deja manchas</p><p><br></p>', 1, 50, NULL, 1, NULL, NULL, NULL, '2024-02-03 22:15:40', NULL, NULL, 'Repelente-entrenador-stay--para-perros-', 0, 0);
INSERT INTO `ecom_productos` VALUES (699, NULL, 'variante', 'CAMAFLUMINI01', 0x43414D462D3031, 'PI0101-0002', 1.00, 'Cama antiestres mini para mascotas', '<p>Cama antiestres para mascotas</p><p><span style=\"background-color: var(--kt-input-bg); color: var(--kt-input-color);\">Medidas: 35 x 10 cm (circuferencia x alto)</span></p><p>color: azul</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 1, 210, NULL, 1, NULL, NULL, NULL, '2024-08-30 01:42:35', '2024-08-30 01:42:35', NULL, 'Cama-antiestres-mini-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (700, NULL, 'producto', '7501556437706', 0x524550452D3031, 'FL3770', 1.00, 'Repelente entrenador para perro', '<p>Repelente entrenador para perro</p><p><br></p><p>Descripción:</p><p>Uso de interiores eficaz para delimitar las áreas que el perro debe respetar, evita que el perro orine o defeque en una área prohibida</p>', 1, 115, NULL, 1, NULL, NULL, NULL, '2024-01-31 19:45:16', NULL, NULL, 'Repelente-entrenador-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (701, NULL, 'producto', '7501556441109', 0x415452412D3031, 'NA110', 1.00, 'Atrayente para cachorros ', '<p>Atrayente para cachorros</p><p><br></p><p>Descripción:</p><p>Aatrayente entrenador para perros, Útil para enseñar al perro el lugar correcto donde ir al baño, ayuda a reducir el tiempo de aprendizaje.</p>', 1, 110, NULL, 1, NULL, NULL, NULL, '2024-02-03 22:17:18', NULL, NULL, 'Atrayente-para-cachorros-', 0, 0);
INSERT INTO `ecom_productos` VALUES (702, NULL, 'producto', '7500211002013', NULL, 'NULL', 1.00, 'Acondicionador para bettas Betta-Safe 35 ml', 'Acondicionador para bettas Betta-Safe 35 ml', 1, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `ecom_productos` VALUES (703, NULL, 'producto', '046798771838', 0x434F414C2D3031, 'TE77183', 3.00, 'Control de alga chico', '<p>AlgaeControl</p><p>Cantidad: 50 ml</p><p><br></p><p>Descripción:</p><p>Combate el crecimiento de algas, el cual es causante de la coloración verde en el agua del acuario. Elimina las algas que crecen sobre los cristales y la decoración del acuario, combate algas verdes y marrón. controlando el agua verde de los acuarios.</p><p><br></p>', 1, 144, NULL, 1, NULL, NULL, NULL, '2024-04-17 15:23:11', NULL, NULL, 'Control-de-alga-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (704, NULL, 'producto', '7501556411010', 0x415449436C2D3330, 'FL11001', 27.00, 'Anticloro 30 ml ', '<p>Anticloro</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(102, 102, 102);\">Agregue 1 gota de anticloro por cada 4 litros de agua y mezcle bien.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Si el agua huele a cloro (Más de 2 ppm), agregue 2 gotas por cada 4 litros de agua.</span></p>', 1, 20, NULL, 1, NULL, NULL, NULL, '2024-02-03 22:17:37', '2023-12-02 22:04:41', NULL, 'Anticloro-30-ml-', 0, 0);
INSERT INTO `ecom_productos` VALUES (705, NULL, 'producto', '7501556411218', 0x415155412D3031, 'FL1124', 10.00, 'Aquari-sol chico', '<p>Aquari-sol</p><p><br></p><p>Descripción:</p><p>Combate Ich, protozoarios, enfermedad del terciopelo, evita que los peces se froten contra las rocas.</p><p>Para acuarios de agua dulce exclusivamente.</p><p>Ideal para aquellas especies con piel sensible, ayuda a mantener una buena salud y que no sufran molestias.</p><p>Protege la piel de peces sensibles.</p><p>Evita que se froten contra las rocas.</p><p><br></p>', 1, 25, 124, 1, NULL, NULL, NULL, '2025-08-26 18:26:43', NULL, NULL, 'Aquari-sol-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (706, NULL, 'producto', '7501556411027', 0x415A554C2D3031, 'FL11002', 15.00, 'Azul de metileno 30 ml ', '<p>Azul de metileno</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(102, 102, 102);\">Como preventivo, agregue 1 gota de azul de metileno por cada 2 litros de agua. En peces enfermos, agregue 2 gotas por cada litro de agua, eleve la temperatura gradualmente a 28°C, aplique cada 48 horas durante 4 o 6 días, al terminar el tratamiento haga un cambio del 25% del agua y reanude el uso de carbón activado. No apto para el consumo humano.</span></p>', 1, 25, 124, 1, NULL, NULL, NULL, '2025-08-26 18:28:07', '2023-12-02 22:04:41', NULL, 'Azul-de-metileno-30-ml-', 0, 0);
INSERT INTO `ecom_productos` VALUES (707, NULL, 'producto', '7500211002327', 0x415A554C2D3034, 'Q306', 10.00, 'Azul de metileno chico ', '<p>Azul de metileno</p><p>Cantidad: 45 ml</p><p><br></p><p>Descripcion:</p><p>Aplique una gota de azul de metileno por cada 2 litros de agua. se recomienda cada vez que ingrese organismos nuevos al acuario.</p><p><br></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-04-11 19:38:04', NULL, NULL, 'Azul-de-metileno-chico-', 0, 0);
INSERT INTO `ecom_productos` VALUES (708, NULL, 'producto', 'BACTMED6001', 0x4241432D3031, 'BAC-01', 5.00, 'Bacteria co mediana 60ml', '<p>Bacteria co mediana</p><p>Cantidad: 60 ml</p><p><br></p><p>Descripción:</p><p>Es un producto diseñado para ayudarlo con un ciclo biologico y de esta forma prevenir mortandad y mejorar el entorno de sus peces.</p><p><br></p><p>Ciclo es una forma de ayudarlo a mantener su ciclo bacteriano de forma estable ya que es un compendio de aminoácidos, enzimas, bacterias y toda una gama de compuestos enfocados a un pronto proliferación bacteriana.</p><p><br></p><p>Agítese antes de usar, use una tapita 5 ml cada 40 Lts 2 o tres veces por semana al hacer cambios de agua o al iniciar con una nueva pecera.</p><p><br></p>', 1, 100, NULL, 1, NULL, NULL, NULL, '2024-04-11 20:44:46', NULL, NULL, 'Bacteria-co-mediana-60ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (709, NULL, 'producto', 'BACTCH02', 0x4241432D3032, 'BAC-02', 5.00, 'Bacteria co 30ml', '<p>Bacteria co chica</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripción:</p><p>Es un producto diseñado para ayudarlo con un ciclo biologico y de esta forma prevenir mortandad y mejorar el entorno de sus peces.</p><p><br></p><p>Ciclo es una forma de ayudarlo a mantener su ciclo bacteriano de forma estable ya que es un compendio de aminoácidos, enzimas, bacterias y toda una gama de compuestos enfocados a un pronto proliferación bacteriana.</p><p><br></p><p>Agítese antes de usar, use una tapita 5 ml cada 40 Lts 2 o tres veces por semana al hacer cambios de agua o al iniciar con una nueva pecera.</p><p><br></p>', 1, 55, NULL, 1, NULL, NULL, NULL, '2024-04-11 20:45:55', NULL, NULL, 'Bacteria-co-30ml', 0, 0);
