INSERT INTO `ecom_productos` VALUES (713, NULL, 'producto', '7500211001719', 0x434C4F2D3032, 'Q201', 10.00, 'Anticloro clorkrill 45 ml', '<p>Anticloro</p><p>Cantidad: 45 ml</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(102, 102, 102);\">Agregue 1 gota de Clorkill por cada 2 litros de agua y revuelva perfectamente, no es necesario esperar ya que Clorkill es de acción inmediata.</span></p><p><br></p><p><br></p><p><br></p>', 1, 25, 124, 1, NULL, NULL, NULL, '2025-08-26 17:20:22', NULL, NULL, 'Anticloro-clorkrill-45-ml', 0, 0);
