INSERT INTO `ecom_productos` VALUES (718, NULL, 'producto', 'SALALI01233', 0x53414C492D3031, '3Q233', 30.00, 'Sal-halita para acuario ', '<p>Sal-halita para acuario 250 gramos </p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(87, 82, 80);\">Es una sal de elevada pureza que se contiene por la evaporación del agua de mar y cuyo contenido en cloruro de sodio es del 99.96% en promedio, lo cual significa que es la sal más pura de que se pueda disponer de manera económica para incrementar la salinidad del agua en los acuarios, por lo tanto no enturbia el agua.</span></p><p><br></p><p><span style=\"color: rgb(87, 82, 80);\">Instrucciones de uso: Sal para Acuarios Auxiliar en la Prevención de Enfermedades Como preventivo contra enfermedades causadas por parásitos, hongos y bacterias: Adicione 1 ó 2 cucharadas soperas de San-Halita por cada 40 litros de agua, o si lo prefiere, un gramo por cada litro. Como terapéutico para el tratamiento del ICH: Adicione de 2 a 3 cucharadas soperas de San-Halita por cada 40 litros de agua, combinando con Cubrix o Green- Bac y eleve la temperatura del agua a 28 ó 30ºC Para el tratamiento de enfermedades causadas por hongos (algodoncillo): Adicione de 2 a 4 cucharadas soperas de San-Halita por cada 40 litros de agua combinado con Acrivelt. Para peces de aguas salobres como Mollys, Escatófagos, Pangasios, etc.: Adicione de 2 a 3 cucharadas soperas de San-Halita por cada 40 litros de agua.</span></p><p><span style=\"color: rgb(87, 82, 80);\">﻿</span></p>', 1, 15, NULL, 1, NULL, NULL, NULL, '2024-08-20 07:42:10', NULL, NULL, 'Sal-halita-para-acuario-', 0, 0);
INSERT INTO `ecom_productos` VALUES (719, NULL, 'producto', '7501556411034', 0x564552502D3330, 'FL11003', 18.00, 'Verde plus 30 ml', '<p>Verde plus</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripcion:</p><p>Es un tratamiento indicado para combatir ICH (enfermedad de punto blanco) y fungus enfermedad de la boca del algodon, el limo corporal y la nube de ojos y las infecciones de pudricion de la aleta y cola.</p><p><br></p><p>Intrucciones:</p><p>Como preventivo agrege una gota de verde plus por cada litro de agua.</p><p><br></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-02-04 19:40:30', '2023-12-02 22:04:41', NULL, 'Verde-plus-30-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (720, NULL, 'producto', '7501556411072', 0x564954412D3330, 'FL1107', 17.00, 'Vitamina A para tortuga ', '<p>Vitamina A para tortuga</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripcion:</p><p>Tratamiento preventivo contra edema en parpados uso Acuicola.</p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-02-04 19:40:59', '2023-12-02 22:04:41', NULL, 'Vitamina-A-para-tortuga-', 0, 0);
