INSERT INTO `ecom_productos` VALUES (743, NULL, 'producto', '7502261583511', 0x4149522D3034, 'OC-10', 10.00, 'Bomba de aire 2 salidas oc', '<p>Bomba de aire 2 salidas oc</p><p>Potencia: 4 w</p><p>Voltaje: 120 v</p><p>Frecuencia: 60 Hz</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Silenciosa con alta tecnología, Incrementando la oxigenación del acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alto rendimiento con diseño ultra compacto de fácil colocación con dos salida unicas.</span></p><p><br></p><p>Modo de empleo:</p><p><span style=\"color: rgb(102, 102, 102);\">No sumerja la bomba de aire, dentro del agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Debe ser colocada por encima del nivel del agua.</span></p><p><br></p><p><br></p>', 1, 225, NULL, 1, NULL, NULL, NULL, '2026-05-17 22:13:37', '2026-05-17 22:13:37', NULL, 'Bomba-de-aire-2-salidas-oc', 0, 0);
INSERT INTO `ecom_productos` VALUES (744, NULL, 'producto', 'arenerogemin18', 0x41524F2D3138, 'SH-230132', 5.00, 'Arenero gemin ', '<p>Arenero gemin</p><p>Medidas: 47 x 40 x 39 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p><br></p><p>Baño con puerta abatible con filtro absorve olores con asa para mejor movilidad; Compatible con cualquier tipo de arena, facil armado y limpieza con diseño en terminado mate y exclusivo adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>Pala</p><p><br></p><p>Colores: rosa, azul, verde ( sujetos a disponibilidad)</p>', 1, 590, 124, 1, NULL, NULL, NULL, '2025-09-02 06:06:37', '2023-11-21 14:59:48', NULL, 'Arenero-gemin-', 0, 0);
INSERT INTO `ecom_productos` VALUES (745, NULL, 'producto', '7501556451610', 0x414C49544F2D3131, 'WAT061', 5.00, 'Alimento para tortuga reptil sticks baby 300 grs', '<p>Alimento para tortuga reptil sticks baby</p><p>Cantidad: 300grs</p><p><br></p><p>Descripción:</p><p>Aporta vitaminas, minerales y aminoácidos esenciales para una óptima nutrición y en c<span style=\"color: rgb(15, 17, 17);\">antidades óptimas para el correcto desarrollo del caparazón de las tortugas.</span></p>', 1, 95, 124, 1, NULL, NULL, NULL, '2025-08-24 14:00:21', '2023-11-28 17:38:30', NULL, 'Alimento-para-tortuga-reptil-sticks-baby-300-grs', 0, 0);
INSERT INTO `ecom_productos` VALUES (746, NULL, 'producto', '7501556491111', 0x4C494D2D3031, 'FL8911', 5.00, 'Limpiador magnético chico para pecera', '<p>Limipador maganético mediano</p><p>Medidas: 5 x 3.5 cm (largo x ancho )</p><p><br></p><p>Descripción:</p><p>El limpiador magnético de Lomas quita con facilidad las algas del cristal del acuario sin rayarlo.</p><p>Puede utilizarse en acuarios marinos o dulces, sin afectar la calidad del agua.</p><p>Es un método práctico y efectivo de limpieza del tanque.</p><p>Los potentes imanes aseguran un agarre firme en el vidrio, por lo que no es necesario introducir las manos en el acuario.</p><p>Recomendacion de superficie vidrio</p>', 1, 118, NULL, 1, NULL, NULL, NULL, '2024-03-28 22:40:21', NULL, NULL, 'Limpiador-magnetico-chico-para-pecera', 0, 0);
INSERT INTO `ecom_productos` VALUES (747, NULL, 'producto', '7501556471731', 0x5441502D3034, 'FL7173', 5.00, 'Tapete entrenador desechable soft 30 pza  con carbón activado para mascotas', '<p>Tapete entrenador desechable y absorbente con carbón activado para mascotas</p><p>Contenido: 14 tapetes</p><p>Medidas: 56 X 56 cm</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Tapete mejorado con tecnología avanzada y carbón activado para neutralizar y absorber malos olores</span></p><p>Ahora con parches adhesivos y 5 capas</p><p>Contiene atrayente para facilitar el entrenamiento</p><p>Con cubierta antiderrames</p><p>Sin malos olores gracias a su rapida asorbcion y accion desodorante</p><p>Se adiere a pisos y superficies</p><p><br></p><p>Sugerencia para:</p><p><span style=\"color: rgb(33, 37, 41);\">Facilita el entrenamiento de tu perro a la hora de ir al baño ideal para todas las razas </span></p><p><span style=\"color: rgb(33, 37, 41);\">Utiliza el tapete para los cachorros y perros que están solos en casa </span></p><p><span style=\"color: rgb(33, 37, 41);\">Para perros que está en edad avanzada o en recuperación de alguna cirugía práctico y seguro fácil de limpiar y Para educar a tu amigo de forma gradual. </span></p>', 1, 180, 124, 1, NULL, NULL, NULL, '2026-04-01 07:27:28', NULL, NULL, 'Tapete-entrenador-desechable-soft-30-pza--con-carbon-activado-para-mascotas', 0, 0);
