INSERT INTO `ecom_productos` VALUES (749, NULL, 'producto', '6957892301132', 0x4A5547472D3035, 'SH-230113', 4.00, 'Juguete interactivo wave para gato ', '<p>Jueguete interactivo wave para gato</p><p><br></p><p>Descripción: Juguete reforzado interna y externamente, resistente al desgaste y a caídas, compartimento para comida y premios con sonido de campana y pluma para atención del gato, alivio de aburrimiento, estrés y soledad, varita interactiva. lo que estimula el olfato a seguir jugando y al  mismo timpo comer.</p><p><br></p><p>Colores: verde, Gris, blanco (Sujetos a dispobilidad)</p>', 1, 220, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:30:49', '2023-12-05 14:50:06', NULL, 'Juguete-interactivo-wave-para-gato-', 0, 0);
INSERT INTO `ecom_productos` VALUES (750, NULL, 'producto', '7500463292323', 0x5355532D3130, 'K-10', 20.00, 'Sustrato Organico para roedores agranel', '<p>Sustrato para roedores</p><p>Cantidad:10 kgrs</p><p><br></p><p>Descripción:</p><p>No genera olores a pipi y asorbe</p><p>Un sustrato moderno para mascotas 100% natural, biodegradable, no toxico. diseñado para máxima asorbción de olores y liquidos</p><p><br></p><p>Instrucciones:</p><p>Una vez que se hace polvo es necesario cambiarlo y aquellos que queden enteros seguir usando hasta que se haga polvo.</p><p><br></p><p>Hecho a base de aserrin de pino y paja de cereales.</p><p>Para: gatos, perros, cuyos, hamster, conejos, erizo, avez, chinchilla, uron, ardillas, ratas, etc.</p><p><br></p><p><br></p>', 1, 400, 124, 1, NULL, NULL, NULL, '2026-04-13 07:15:19', NULL, NULL, 'Sustrato-Organico-para-roedores-agranel', 0, 0);
INSERT INTO `ecom_productos` VALUES (751, NULL, 'producto', '7501556440638', 0x5355542D3035, 'FL4063', 2.00, 'Sustrato organico para reptil polvillo de coco', '<p>Sustrato orgánico fibra polvillo de coco</p><p>Tamaño: extra fina</p><p>Cantidad: 1 kgr</p><p><br></p><p>Descripcion: sustrato en el piso de su terrario, recomendado para reptiles, anfibios, insectos y arácnidos de ambientes tropicales y subtropicales, así como para animales con hábitos excavadores.</p><p>100% natural y compostable.</p><p>Para: Iguana, taratulas, camaleones, serpientes, etc.</p><p><br></p><p>Son excelentes para mentenimiento de humedad. Tienen excelentes propiedades antisépticas al inhibir el crecimiento del hongos y bacterias.</p><p>Especial para reptiles y anfibios semitropicales y tropicales, esterilizado para uso en terrarios.</p><p><br></p>', 1, 115, NULL, 1, NULL, NULL, NULL, '2024-04-16 13:42:30', '2023-11-28 17:38:30', NULL, 'Sustrato-organico-para-reptil-polvillo-de-coco', 0, 0);
