INSERT INTO `ecom_productos` VALUES (758, NULL, 'producto', '7501556440386', 0x5355534D412D3031, 'FL4038', 10.00, 'Sustrato de maíz para mascotas', '<p>Sustrato de maíz para mascotas roedores</p><p>Cantidad:2 kgrs</p><p><br></p><p>Descripción:</p><p>Altamente asorbente</p><p>Mantiene seco por mas tiempo</p><p>100% natural biodegradable</p><p>No toxico si llegara a consumirse, no tiene ningún riesgo.</p><p><br></p><p>Instrucciones:</p><p>Una vez a la semana cambia el sustrato, desinfecta bien la jaula antes de agregar el nuevo sustrato.</p><p>Hecho a base de aserrin de pino y paja de cereales.</p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, etc.</p><p><br></p><p><br></p>', 1, 120, 124, 1, NULL, NULL, NULL, '2026-04-13 06:28:54', NULL, NULL, 'Sustrato-de-maiz-para-mascotas', 0, 0);
