INSERT INTO `ecom_productos` VALUES (761, NULL, 'producto', '7500211002372', 0x4355582D3031, 'Q311', 1.00, 'Cubrix ', '<p>Cubrix</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Cubrix es un efectivo medicamento contra enfermedades causadas por hongos parásitos, como tremátodos, ICH, Oodinium, entre otros. Cubrix puede dañar a los invertebrados, por lo que se aconseja retirar a estos del acuario antes de aplicarlo. Cubrix es una solución estabilizada y parcialmente quelatada de sales solubles de cobre al 1.4%, adicionada con pequeñas cantidades de formaldehído. </span></p>', 1, 30, NULL, 1, NULL, NULL, NULL, '2024-04-11 18:56:33', NULL, NULL, 'Cubrix-', 0, 0);
INSERT INTO `ecom_productos` VALUES (762, NULL, 'producto', '7500211002174', 0x414352492D3031, 'Q335', 10.00, 'Acrivelt Acriflavina ', '<p>Acrivelt Acriflavina</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Es excelente remedio contra enfermedades bacterianas y micóticas, como la putrefacción de las aletas en los peces, la enfermedad bacteriana de las branquias y las llagas, heridas y úlceras en la piel infectada, así como el algodoncillo sobre la piel y aletas.</span></p><p><br></p><p><span style=\"color: rgb(0, 0, 0);\"> Éste potente antiséptico está recomendado para tratar y prevenir infecciones causadas por hongos y bacterias, siendo muy eficaz sobre todo en las etapas precoces de la enfermedad.</span></p><p><br></p><p><br></p>', 1, 45, NULL, 1, NULL, NULL, NULL, '2024-04-11 19:04:26', NULL, NULL, 'Acrivelt-Acriflavina-', 0, 0);
