INSERT INTO `ecom_productos` VALUES (766, NULL, 'producto', '7501556411157', 0x43414C432D3031, 'FL1115', 50.00, 'Calcio para tortuga doble ', '<p>Calcio para tortuga doble</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Adicionada con vitamina A, lo cual ayudara a prevenir los síntomas de concha suave y edema en párpados.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Para mantener sana a tu tortuga.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Cada paquete contiene 2 tabletas de calcio.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Instrucciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Introduzca la tableta de calcio en su tortuguero. La tableta empezara a disolverse lentamente liberando en el agua calcio y vitamina A gradualmente.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Para una mejor absorción raspe un poco de calcio de la tableta y espolvoréelo sobre el alimento de la tortuga.</span></p><p><br></p>', 1, 55, 124, 1, NULL, NULL, NULL, '2025-12-05 13:50:07', '2023-11-28 17:38:30', NULL, 'Calcio-para-tortuga-doble-', 0, 0);
INSERT INTO `ecom_productos` VALUES (767, NULL, 'producto', '7501556450422', 0x414C49544F2D3130, 'WAT042', 69.00, 'Alimento para tortuga reptil sticks baby 70grs', '<p>Alimento para tortuga reptil sticks baby</p><p>Cantidad: 70grs</p><p><br></p><p>Descripción:</p><p>Aporta vitaminas, minerales y aminoácidos esenciales para una óptima nutrición y en c<span style=\"color: rgb(15, 17, 17);\">antidades óptimas para el correcto desarrollo del caparazón de las tortugas.</span></p>', 1, 35, 124, 1, NULL, NULL, NULL, '2025-08-24 13:59:41', '2023-11-28 17:38:30', NULL, 'Alimento-para-tortuga-reptil-sticks-baby-70grs', 0, 0);
INSERT INTO `ecom_productos` VALUES (768, NULL, 'producto', 'TORTUPANMINI05', 0x544F522D3137, 'TOR-17', 5.00, 'Tortuguero panoramico mini ', '<p>Tortuguero panoramico mini</p><p>Medidas: 23 x 17 x 12 cm (Largo x ancho x alto)</p><p>Grosor:3 mm</p><p><br></p><p>Descripción: con distintos diseños la forma de la isla de cistal para tortugas pequeñas con rampa para que la totuga suba su zona seca.</p><p><br></p><p>Incluye:</p><p>Isla se puede cambiar el color de la grava y diseño de la forma. (sujetos a disponibilidad)</p><p>Grava se cambiar el color de la grava</p><p>Calcio</p><p>Alimento</p><p>Vitamina a</p><p><br></p><p>Colores: azul cielo, azul marino, rosa , verde, naranja, roja, cafe, arena, blanca, negra, y mas (colores sujetos a disponibilidad).</p><p>Material: cristal.</p>', 1, 290, 124, 1, NULL, NULL, NULL, '2026-01-16 07:28:05', NULL, NULL, 'Tortuguero-panoramico-mini-', 0, 0);
