INSERT INTO `ecom_productos` VALUES (787, NULL, 'producto', 'mochiladisco03', 0x4D4F432D3033, 'SH-220340', 2.00, 'Mochila disco para mascotas ', '<p>Mochila disco para mascotas</p><p>Medidas: 37 x 34 x 25cm (largo x ancho x alto)</p><p><br></p><p>Descripción: Malla transpirable y refrescante integrada, resistente a desgaste y arañazos, duradera y elástica, cintas ajustables con parte trasera alchonada para mayor comodidad al cargar, impermeable con compartimentos adaptables a tus accesorioso de tu mascota, cómoda para un paseo agradable para perros pequeños, gatos, mini pig, cuyos, conejos, chinchillas, pajaros pequeños, urones, ratas, etc,</p><p><br></p><p>color: rosa, azul verde, morado (colores sujetos a disponibilidad)</p>', 1, 550, 124, 1, NULL, NULL, NULL, '2025-09-02 06:09:02', '2023-11-21 14:59:48', NULL, 'Mochila-disco-para-mascotas-', 0, 0);
