INSERT INTO `ecom_productos` VALUES (805, NULL, 'producto', '7501556411133', 0x4E45552D3031, 'FL1113', 10.00, 'Neutra stress chico 30 ml', '<p>Neutra stress Chico</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Elimina cloro, protege las mucosas de los peces y detoxificametales pesados.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Contiene Vitamina B1.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Para restablecer las mucosas dañadas de los peces, agregue 1 ml. por cada 10 litros de agua (2 gotas por litro).</span></p><p><br></p>', 1, 25, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:01:50', '2023-12-02 22:04:41', NULL, 'Neutra-stress-chico-30-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (806, NULL, 'producto', 'TORELEVADA11', 0x544F522D3131, 'TOR-11', 3.00, 'Tortuguero un metro isla elevada ', '<p><span style=\"color: rgb(94, 98, 120);\">Tortuguero un metro isla elevada </span></p><p>Medidas: 100 x 26 x 30 cm (largo x ancho x alto)</p><p>Grosor: 6 mm</p><p><br></p><p>Descripción:</p><p>Tortuguero con isla en el contorno de la pecera para que la tortuga tenga más área donde pueda caminar en zona seca.</p><p><br></p><p>Color: se puede cambiar el color azul, verde, rosa blanco, café, negro, rojo y más (sujetos a disponibilidad).</p><p><span style=\"color: rgb(94, 98, 120);\">﻿</span></p>', 1, 2290, 124, 1, NULL, NULL, NULL, '2025-12-09 09:05:58', NULL, NULL, 'Tortuguero-un-metro-isla-elevada-', 0, 0);
INSERT INTO `ecom_productos` VALUES (807, NULL, 'producto', '7501556479065', 0x4249422D3031, 'FL7906', 6.00, 'Biberon para cachorro 56 ml ', '<p>Biberon para cachorro</p><p>Capacidad: 56 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Biberón con chupón extra de repuesto para alimentación de cachorros y gatitos recién nacidos o huérfanos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Con marcas en la botella como guía para dosificar la cantidad correcta de formula láctea.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Mamila o chupón imita el pezón materno, es del tamaño perfecto para adaptarse a cada cachorro.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Es un producto indispensable para alimentar a perritos recién nacidos o cuya lactancia materna se vea interrumpida.</span></p><p><br></p><p>Material:</p><p><span style=\"color: rgb(102, 102, 102);\">Plástico no tóxico</span></p><p><span style=\"color: rgb(102, 102, 102);\">•Chupón de silicón.</span></p><p><br></p><p><br></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:03:07', '2023-12-05 14:50:06', NULL, 'Biberon-para-cachorro-56-ml-', 0, 0);
INSERT INTO `ecom_productos` VALUES (808, NULL, 'producto', '7501556438437', 0x47414C4C2D3031, 'FL3843', 5.00, 'Galletas premio sabor tocino para perro', '<p>Galletas premio para perro</p><p>Cantidad:100 grs</p><p>Edad de perro: Adulto</p><p>Sabor: tocino</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(55, 61, 63);\">Galletas en forma de hueso&nbsp;</span><strong style=\"color: rgb(55, 61, 63);\">sabor a tocino</strong><span style=\"color: rgb(55, 61, 63);\">. Además, están</span><strong style=\"color: rgb(55, 61, 63);\">&nbsp;fortificadas con vitaminas</strong><span style=\"color: rgb(55, 61, 63);\">, no contienen grasa, son muy saludables y ricas, a tu perro seguro le encantan.</span></p><p><br></p>', 0, 45, 124, 1, NULL, NULL, NULL, '2025-10-21 22:54:15', NULL, NULL, 'Galletas-premio-sabor-tocino-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (809, NULL, 'producto', '7501556407464', 0x43415A412D3031, 'FL3745', 5.00, 'Carnaza premios 100 pza para perro', '<p>Carnaza premios para perros</p><p>Cantidad: 100 pza</p><p>20 Natural</p><p>20 Carne</p><p>20 Pollo</p><p>20 Cafe</p><p>20 Cacahuate</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">Mantienen limpios los dientes previniendo la formación de sarro, evitando al mismo tiempo el mal aliento, ejercitan la mandíbula y entretienen al perro.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Permiten que interactué con la mascota y pueden proporcionarse como premio en los entrenamientos o como juguete.</span></p>', 0, 320, NULL, 1, NULL, NULL, NULL, '2024-04-01 19:00:17', NULL, NULL, 'Carnaza-premios-100-pza-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (810, NULL, 'producto', 'RASCADOUBLE06', 0x5241532D3035, 'SH-230128', 1.00, 'Rascadero double', '<p>Rascadero double</p><p>Medidas: 38.5 x 43 x 1.5cm</p><p><br></p><p>Descripción:</p><p>Facil de armar, con diseño innovador resistente al desgaste y arañazos donde tu gato podra afilar sus uñas naturalmente y entretener y mantener activo a tu felino de corrugado resistente y duradero con espacio amplio para rascarse.</p><p><br></p><p>Incluye: Catnip</p>', 0, 250, 124, 1, NULL, NULL, NULL, '2026-01-27 08:43:12', NULL, NULL, 'Rascadero-double', 0, 0);
INSERT INTO `ecom_productos` VALUES (811, NULL, 'producto', 'CONEJINA-40KG', 0x434F4E454A494E412D34304B47, 'CONEJINA-40KG', 40.00, 'Conejina alimento agranel ', '<p>Conejina alimento para roedores</p><p>Cantidad: 40 kgrs</p><p><br></p><p>Descipción:</p><p>Para: c<span style=\"color: rgb(102, 102, 102);\">uyos, conejos, hamsters, ardillas, chinchillas y pequeñas especies en todas las edades.</span></p>', 0, 800, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:05:47', NULL, NULL, 'Conejina-alimento-agranel-', 0, 0);
INSERT INTO `ecom_productos` VALUES (812, NULL, 'producto', '7501556440348', 0x4841502D3031, 'FL4034', 13.00, 'Premio de semillas para hámster corazón', '<p>Premio de semillas para hamster corazón</p><p>Cantidad:2 barras de 72 grs</p><p><br></p><p>Descripción:</p><p>Los premios para hámster de Redkite son snacks elaborados con una deliciosa mezcla balanceada de semillas.</p><p>Tienen un exquisito sabor que les encantará mientras ayudan a fortalecer sus dientes y estimulan su curiosidad, también fomentan la actividad ya que pueden entretenerse mientras mordisquean el premio.</p><p>Consiente a tu hámster.</p><p><br></p>', 0, 75, 124, 1, NULL, NULL, NULL, '2025-12-10 08:02:23', '2023-11-28 17:38:30', NULL, 'Premio-de-semillas-para-hamster-corazon', 0, 0);
INSERT INTO `ecom_productos` VALUES (813, NULL, 'producto', 'arenerotunelore19', 0x41524F2D3139, 'SH-230101', 0.00, 'Arenero tunel ore', '<p>Arenero tunel ore</p><p>Medidas: 57.5 x 56.4 x 40 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>Desmontable con doble puerta intergrada.</p><p>Absorbe malos olores y evita q se propagen al exterior</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño vanguardista y exclusivo adaptable a cualquier espacio de material resistente.</p><p><br></p><p>Incluye:</p><p>Pala</p><p><br></p><p>Colores: rosa, azul ( sujetos a disponibilidad)</p>', 0, 0, NULL, 0, NULL, NULL, NULL, '2024-02-05 02:06:52', NULL, NULL, '', 0, 0);
INSERT INTO `ecom_productos` VALUES (814, NULL, 'producto', '802296705320', 0x41524F2D3135, 'S08040400', 2.00, 'Arenero marco plus grande ', '<p>Arenero marco plus grande</p><p>Medidas: 49 x 39 x 17 (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Arenero con contorno para evitar derrames de arena en la entrada con tipo sernidor para cuando pise caiga residuos de arena de sus patas baño para gatos.</p><p><br></p><p>Colores: azul, rojo, verde (sujetos a disponibilidad)</p>', 0, 399, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:07:25', NULL, NULL, 'Arenero-marco-plus-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (815, NULL, 'producto', '7502271355368', 0x54415A2D3035, 'ART.50488', 5.00, 'Tazon gato', '<p>Tazon gato</p><p>Medidas: 11.5 x 5.2 cm (Circunferecia x alto)</p><p>Color: azul, rosa, verde (colores sujetos a disponibilidad)</p><p><br></p><p>Descripcion: tazon para agua y comida en un solo lugar de un tamaño ideal para tu mascota para gatos, perros, etc.</p><p><br></p>', 0, 45, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:07:56', NULL, NULL, 'Tazon-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (816, NULL, 'producto', '7502278912946', 0x41524F2D3132, '1515', 12.00, 'Arenero plus azul ', '<p>Arenero plus azul</p><p>Medidas: <span style=\"color: rgb(94, 98, 120);\">49 x 40 x 42 cm </span> (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero tapado para prevención de desborde de arena <span style=\"color: rgb(94, 98, 120);\">de plástico fácil de cargar armar y limpiar baño para gatos.</span></p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">Cubierta con filtro (Absorbente de olores)</span></p><p><span style=\"color: rgb(102, 102, 102);\">Puerta </span></p><p><br></p>', 0, 580, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:08:32', NULL, NULL, 'Arenero-plus-azul-', 0, 0);
INSERT INTO `ecom_productos` VALUES (817, NULL, 'producto', '7502278912953', 0x41524F2D3133, '1519', 8.00, 'Arenero space azul', '<p>Arenero space azul</p><p>Medidas: <span style=\"color: rgb(94, 98, 120);\">53 x 41 x 42 cm </span>(largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero cerrado para prevención de desborde de arena<span style=\"color: rgb(94, 98, 120);\"> práctico de plástico fácil de armar, cargar y limpiar baño para gatos.</span></p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(102, 102, 102);\">Cubierta con filtro </span></p><p><span style=\"color: rgb(102, 102, 102);\">Puerta </span></p><p><span style=\"color: rgb(102, 102, 102);\">Asa de carga</span></p><p><br></p>', 0, 680, NULL, 1, NULL, NULL, NULL, '2024-02-05 02:09:02', NULL, NULL, 'Arenero-space-azul', 0, 0);
INSERT INTO `ecom_productos` VALUES (818, NULL, 'producto', 'BASRE402005', 0x424153522D3035, 'BASR-05', 5.00, 'Base rectangular de herreria para pecera de 40 x 20 cm', '<p>Base rectangular de herreria para pecera</p><p>Medidas: 42.6 x 22.8 x 75.8 cm (largo x ancho x alto)</p><p>Patas: 4 patas</p><p><br></p><p>Descripción:</p><p>Base rectangular para pecera de 20 lts, mueble de herreria,<span style=\"color: rgb(146, 146, 159);\"> con diseños de lineas curvas y lineas rectas.</span></p><p><br></p><p>2 Diseños sujetos a disponibilidad.</p>', 0, 490, 124, 1, NULL, NULL, NULL, '2026-05-12 09:16:05', NULL, NULL, 'Base-rectangular-de-herreria-para-pecera-de-40-x-20-cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (819, NULL, 'producto', '015561221382', NULL, 'NULL', 3.00, 'Foco de dia 100w exoterra', 'Foco de dia 100w exoterra', 0, 0, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL);
INSERT INTO `ecom_productos` VALUES (820, NULL, 'producto', 'FOCODIA60W01', 0x464F522D3031, 'PT2110', 10.00, 'Foco de dia para reptil 60w', '<p>Foco de dia para reptil</p><p>Volts: 110 v</p><p>Potencia: 60 w</p><p><br></p><p>Descripción:</p><p>Es una bombilla especialmente diseñada como una lámpara de luz concentrada.</p><p>El rayo de luz puede enfocarse precisamente en un área para crear un sitio para el calentamiento.</p><p>Aumento del 35 % de luz y calor</p><p>Crea un área de calentamiento para la termo-regulación</p><p>Aumenta la temperatura del aire</p><p>Emision de luz natural</p><p>Bombilla diurna de propositos multiples</p><p>Incrementa la coloracion del animal</p><p>Se puede combinar con el Night Heat Lamp o Infrared Basking Spot por un ciclo de 24 horas</p><p>La luz y el calor aumentan en un 35% permitiendo así una mayor separación entre la fuente luminosa y el sitio elegido para el calentamiento.</p><p>La luz ultravioleta estimula el comportamiento reproductivo de los reptiles.</p><p><br></p><p>Ofrecer a los reptiles un hábitat adecuado requiere mantener ciertas condiciones muy específicas, sobre todo en cuanto a temperatura.</p><p>Lo ideal es que el ambiente se asemeje lo más posible a su hábitat natural.</p><p>Proporciona la temperatura adecuada para el terrario y las condiciones necesarias para los reptiles.</p>', 0, 175, 124, 1, NULL, NULL, NULL, '2025-03-22 07:17:25', '2023-12-05 14:50:06', NULL, 'Foco-de-dia-para-reptil-60w', 0, 0);
INSERT INTO `ecom_productos` VALUES (821, NULL, 'producto', '015561221306', 0x464C4F522D3036, 'HPT2130', 5.00, 'Foco de noche para reptil 75w ', '<p>Foco de noche para reptil</p><p>Potencia: 75 w</p><p>Luz: Nocturna</p><p>Para: Anfibios, reptiles, iguanas, ranas, etc.</p><p>Voltaje:110 v</p><p><br></p><p>Descripción:</p><p>Para temperaturas de noche tropical</p><p>Proporciona vision nocturna</p><p>Estimula la actividad nocturna</p><p><span style=\"color: rgb(102, 102, 102);\">Esta lámpara simula la luz natural de la luna que permite una visión nocturna sin interferir con el ciclo diurno y nocturno del animal.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La luz emitida es azulada debido a uso de vidrio color azul.</span></p><p><span style=\"color: rgb(102, 102, 102);\">El calor que genera es mínimo pero es suficiente para crear temperaturas de una noche tropical.</span></p><p><span style=\"color: rgb(102, 102, 102);\">El bajo voltaje de estas lámparas no interfiere con las bajas de temperatura de una noche natural.</span></p>', 0, 175, 124, 1, NULL, NULL, NULL, '2025-03-22 07:17:57', NULL, NULL, 'Foco-de-noche-para-reptil-75w-', 0, 0);
INSERT INTO `ecom_productos` VALUES (822, NULL, 'producto', '015561221443', 0x464C4F522D3037, 'PT2144', 5.00, 'Foco infrarrojo para reptiles 100w', '<p>Foco infrarrojo</p><p>Potencia: 100 w</p><p>Volts: 110 a 120 v</p><p><br></p><p>Descripcion:</p><p>Luz solar esecial</p><p>90% de la energia como calor infrarrojo</p><p>Penetracion optima de calor</p><p>Estimula la actividad natural</p><p>Bombilla de calor diurno para acelerar el crecimiento y una digestion optima.</p><p><span style=\"color: rgb(102, 102, 102);\">Emite ondas térmicas infrarrojas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Se puede usar en conjunto con Daytime Heat Lamp o Night Heat Lamp en un ciclo de 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Una excelente fuente de calor por 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aumenta la temperatura en todo el terrario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aporta el calor necesario para la actividad y la digestión.</span></p><p><span style=\"color: rgb(102, 102, 102);\">No interfiere con el ciclo natural de actividad.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para la visión nocturna.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Los radiadores infrarojos&nbsp;son&nbsp;lamparas de incandescencia que irradian energia en el rango infrarrojo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Esta radiacion infrarroja calienta el aire en una pequeña proporción, penetrando en cambia en los cuerpos expuestos a ella , donde se transforma totalmente en calor. Los campos de aplicacion son variados, utilizandode en avicultura, horticultura, industria, hosteleria, hogar...</span></p><p><span style=\"color: rgb(102, 102, 102);\">En la cria de animales, los&nbsp;</span>rayos infrarrojos<span style=\"color: rgb(102, 102, 102);\">&nbsp;se pueden utilizar para los animales recien nacidos, ya que al penetrar el calor profundamente en su piel activa la circulacion sanguinea y su metabolismo. Se utilizan con exito con los pollitos, cochinillos, pichones, perros, etc..Los pollitos y otras aves jovenes sometidos a radiaciones infrarrojas,&nbsp;se caracterizan de manera especial por su apetencia extraordinaria.</span></p>', 0, 399, 124, 1, NULL, NULL, NULL, '2026-01-05 21:27:10', NULL, NULL, 'Foco-infrarrojo-para-reptiles-100w', 0, 0);
INSERT INTO `ecom_productos` VALUES (823, NULL, 'producto', '015561221429', 0x464C4F522D3038, 'HPT2142', 3.00, 'Foco infrarrojo para reptil 75 w', '<p>Foco infrarrojo</p><p>Potencia: 75w</p><p>Volts: 110 v</p><p><br></p><p>Descripción:</p><p>Luz solar esecial</p><p>90% de la energia como calor infrarrojo</p><p>Penetracion optima de calor</p><p>Estimula la actividad natural</p><p>Bombilla de calor diurno para acelerar el crecimiento y una digestion optima.</p><p><span style=\"color: rgb(102, 102, 102);\">Emite ondas térmicas infrarrojas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Se puede usar en conjunto con Daytime Heat Lamp o Night Heat Lamp en un ciclo de 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Una excelente fuente de calor por 24 horas.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aumenta la temperatura en todo el terrario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Aporta el calor necesario para la actividad y la digestión.</span></p><p><span style=\"color: rgb(102, 102, 102);\">No interfiere con el ciclo natural de actividad.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para la visión nocturna.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Los radiadores infrarojos&nbsp;son&nbsp;lamparas de incandescencia que irradian energia en el rango infrarrojo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Esta radiacion infrarroja calienta el aire en una pequeña proporción, penetrando en cambia en los cuerpos expuestos a ella , donde se transforma totalmente en calor. Los campos de aplicacion son variados, utilizandode en avicultura, horticultura, industria, hosteleria, hogar...</span></p><p><span style=\"color: rgb(102, 102, 102);\">En la cria de animales, los&nbsp;</span>rayos infrarrojos<span style=\"color: rgb(102, 102, 102);\">&nbsp;se pueden utilizar para los animales recien nacidos, ya que al penetrar el calor profundamente en su piel activa la circulacion sanguinea y su metabolismo. Se utilizan con exito con los pollitos, cochinillos, pichones, perros, etc..Los pollitos y otras aves jovenes sometidos a radiaciones infrarrojas,&nbsp;se caracterizan de manera especial por su apetencia extraordinaria.</span></p>', 0, 330, 124, 1, NULL, NULL, NULL, '2025-03-22 07:17:46', NULL, NULL, 'Foco-infrarrojo-para-reptil-75-w', 0, 0);
INSERT INTO `ecom_productos` VALUES (824, NULL, 'producto', '5900469504420', 0x414C49434F2D3036, 'TP-50442', 5.00, 'Alimento para conejo adulto preminum', '<p>Alimento para conejo adulto</p><p>Cantidad:750gr</p><p><br></p><p>Descripción:</p><p>Alimento completo a base de granulados ricos en fibra. También cuenta con hierbas, alfalfa, manzana y semillas de girasol, así como con adición de verduras secas ricas en vitaminas y hierbas aromáticas.</p><p>Además cuenta común alto contenido de fibra y la adición de remolacha y hierbas regulan la digestión y previenen la formación de bolas de pelo.</p>', 0, 280, 124, 1, NULL, NULL, NULL, '2026-06-01 21:56:24', NULL, NULL, 'Alimento-para-conejo-adulto-preminum', 0, 0);
