INSERT INTO `ecom_productos` VALUES (826, NULL, 'producto', '7501556484427', 0x464C49562D3235, 'FL8442', 5.00, 'Filtro interno de caja verde ', '<p>Filtro interno de caja verde</p><p>para acuarios de hasta: 25 L</p><p>Medidas: 8cm x 8cm x 8cm (largo x ancho x alto)</p><p>Voltaje 110v</p><p><br></p><p>Descripcion:</p><p>Favorece la filtración y oxigenación del agua.</p><p>es ideal para peces pequeños y de crianza.</p><p>Para su funcionamiento requiere de una bomba de aire lo que permite mejorar el nivel de oxigenación y filtración (No incluida).</p><p><br></p><p>incluye:</p><p>Material filtrante (fibra, carbón activado y zeolita) que permite absorber impurezas y olores, elimina materia orgánica y proporciona un filtrado con poca turbulencia.</p><p><span style=\"color: rgb(56, 56, 56);\">Ventosas para adherirse a la base del acuario</span></p>', 0, 99, 124, 1, NULL, NULL, NULL, '2025-12-26 22:58:34', NULL, NULL, 'Filtro-interno-de-caja-verde-', 0, 0);
