INSERT INTO `ecom_productos` VALUES (833, NULL, 'producto', 'TENEBAGRA01', 0x54454E2D3031, 'TEN-01', 10.00, 'Tenebrio por millar agranel ', '<p>Tenebrio por millar agranel</p><p>Cantidad: 1000 pza</p><p><br></p><p>Descripción:</p><p>Alimento vivo <span style=\"color: rgb(42, 55, 62);\">para especies de animales como reptiles, aves, peces, anfibios, mamíferos pequeños.</span></p><p>Los tenebrios <span style=\"color: rgb(83, 73, 45);\">contienen un alto contenido proteico y también grasas, fibras, aminoácidos y minerales. Además, su crianza es relativamente sencilla: pueden ser alimentadas con una variedad de frutas y hortalizas.</span></p>', 0, 260, NULL, 1, NULL, NULL, NULL, '2024-02-05 04:25:59', NULL, NULL, 'Tenebrio-por-millar-agranel-', 0, 0);
