INSERT INTO `ecom_productos` VALUES (835, NULL, 'producto', 'CASACAMAPERRO', 0x4341432D3031, 'PI0304-0151', 3.00, 'Casa cama perrito para mascotas', '<p>Casa cama perrito para mascotas</p><p>Medidas: 35 x 35 x 40 (largo x ancho x alto)</p><p>Incluye: Cojin</p><p><br></p><p>Descripción: Casa con un diseño animalesco, divertidas y comodas casas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior con poliéster impermeable, interior angora extra suave, rellenas con esponja de poliuretano y delcrón.</p><p><br></p>', 0, 480, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:15:26', '2023-11-21 14:36:05', NULL, 'Casa-cama-perrito-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (836, NULL, 'producto', 'RASCACANGRE03', 0x5241532D3034, 'SH-230405', 0.00, 'Rascadero cangrejo para gato', '<p>Rascador cangrejo</p><p>Medidas: 38 x 38 x 8.2 cm</p><p><br></p><p>Descripción:</p><p>Facil de armar, cascabel interactiva de luz integradas al interior de las pinzas, tu gato podra afilar sus uñas y entretenerse de corrugado resistente y duradero con espacio amplio para rascarse, nose derrapa (almohadillas en la parte inferior). A prueba de humedad e insectos</p><p><br></p><p>Incluye: Catnip</p>', 0, 370, NULL, 1, NULL, NULL, NULL, '2024-11-15 06:54:55', NULL, NULL, 'Rascadero-cangrejo-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (837, NULL, 'producto', 'TORTUREC4001', 0x544F522D3135, 'TOR-15', 5.00, 'Tortuguero 50 x 26 x 30cm', '<p>Tortuguero 50 cm</p><p>Medidas: 50 x 26 x 30 cm (largo x ancho x alto)</p><p>Espesor: 3 mm</p><p><br></p><p>Descripción: con distintos diseños la forma de la isla de cistal para tortugas pequeñas y medinas con rampa para que la totuga suba su zona seca.</p><p><br></p><p>Incluye:</p><p>Isla</p><p>Planta artificial mini</p><p><br></p><p>Colores: azul cielo, azul marino, rosa , verde, naranja, roja, cafe, arena, blanca, negra, y mas (colores sujetos a disponibilidad).</p><p><br></p><p><br></p>', 0, 750, 124, 1, NULL, NULL, NULL, '2026-03-27 07:39:26', NULL, NULL, 'Tortuguero-50-x-26-x-30cm', 0, 0);
