INSERT INTO `ecom_productos` VALUES (840, NULL, 'producto', 'CARDAROJA01', 0x4341522D3031, 'FL9402', 1.00, 'Carda roja chica para mascotas ', '<p>Carda roja chica para mascotas</p><p>Para: perros, gatos etc.</p><p><br></p><p><br></p><p>Descripción:Las cardas están diseñadas con cerdas metálicas flexibles de gran resistencia que atrapan el pelo muerto y lo desenredan con facilidad.</p><p>Ideal para razas de pelo medio, largo, liso o rizado.Proporciona un cepillado profundo, estimula la producción de aceites naturales protectores en la piel del perro.</p><p>Desenreda y elimina cuerpos extraños del pelaje.</p><p><br></p>', 0, 140, NULL, 1, NULL, NULL, NULL, '2024-02-06 20:32:00', '2023-11-28 17:38:30', NULL, 'Carda-roja-chica-para-mascotas-', 0, 0);
