INSERT INTO `ecom_productos` VALUES (843, NULL, 'producto', 'PEZMN04AMA', 0x50455A4D4E2D3034, 'PEZMN-04', 100.00, 'Pez monja neón amarilla', '<p>Pez monja transgenica</p><p>Color: amarilla</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neónen la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p>', 0, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:52:27', NULL, NULL, 'Pez-monja-neon-amarilla', 0, 0);
INSERT INTO `ecom_productos` VALUES (844, NULL, 'producto', 'PEZNEVE02', 0x50455A4D4E2D3032, 'PEZMN-02', 60.00, 'Pez monja neón verde ', '<p>Pez monja transgenica</p><p>Color: verde</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neónen la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p>', 0, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:53:23', NULL, NULL, 'Pez-monja-neon-verde-', 0, 0);
