INSERT INTO `ecom_productos` VALUES (850, NULL, 'producto', '7501556483529', 0x4341522D3032, 'FL8352', 1.00, 'Carda de goma para mascotas ', '<p>Carda de goma para mascotas</p><p>Para: perro y gato</p><p><br></p><p>Descripciòn:Las cardas están diseñadas con cerdas de goma flexibles recomienda su uso para pelajes enmarañados o enrredados.</p><p>Su mango ergonómico permite que el cepillado sea más cómodo y sencillo.</p><p>Ideal para razas de pelo medio, corto.</p><p>ideal para remover el pelo suelto y muerto de mascotas sus puntas de goma masajean, estimulan la producciòn de aceites naturales de la piel y la circulaciòn sanguìnea`la flexibilidad de la carda permite adecuarse al cuerpo de la mascota.</p>', 0, 145, NULL, 1, NULL, NULL, NULL, '2024-02-06 20:31:11', '2023-11-28 17:38:30', NULL, 'Carda-de-goma-para-mascotas-', 0, 0);
