INSERT INTO `ecom_productos` VALUES (853, NULL, 'producto', '7501556440409', 0x5355534D412D3032, 'FL4040', 5.00, 'Sustrato de maiz para roedores 5kgr', '<p>Sustrato de maíz para roedores</p><p>Cantidad: 5 kgrs</p><p><br></p><p>Descripción:</p><p>Altamente asorbente</p><p>Mantiene seco por mas tiempo</p><p>100% natural biodegradable</p><p>No toxico si llegara a consumirse, no tiene ningún riesgo.</p><p><br></p><p>Instrucciones:</p><p>Una vez a la semana cambia el sustrato, desinfecta bien la jaula antes de agregar el nuevo sustrato.</p><p>Hecho a base de aserrin de pino y paja de cereales.</p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, etc.</p>', 0, 250, 124, 1, NULL, NULL, NULL, '2026-04-13 06:29:23', NULL, NULL, 'Sustrato-de-maiz-para-roedores-5kgr', 0, 0);
INSERT INTO `ecom_productos` VALUES (854, NULL, 'producto', '7502217852665', 0x5355542D, 'S1003', 5.00, 'Sustrato corteza de arbol ', '<p>Sustrato orgánico corteza de árbol</p><p>Tamaño: grande</p><p>Cantidad: 1 kgr</p><p><br></p><p>Descripción: sustrato en el piso de su terrario, recomendado para reptiles, anfibios, insectos y arácnidos de ambientes tropicales y subtropicales, así como para animales con hábitos excavadores.</p><p>100% natural y compostable.</p><p>Para: Iguana, taratulas, camaleones, serpientes, etc.</p><p><br></p><p>Son excelentes para mentenimiento de humedad. Tienen excelentes propiedades antisépticas al inhibir el crecimiento del hongos y bacterias.</p><p>Especial para reptiles y anfibios semitropicales y tropicales, esterilizado para uso en terrarios.</p><p><br></p>', 0, 125, NULL, 1, NULL, NULL, NULL, '2024-11-16 08:13:31', NULL, NULL, 'Sustrato-corteza-de-arbol-', 0, 0);
