INSERT INTO `ecom_productos` VALUES (864, NULL, 'producto', '7501556438413', 0x47414C4C2D3034, 'FL3841', 5.00, 'Galletas premio sabor chocolate para perro', '<p>Galletas premio para perro</p><p>Cantidad:100 grs</p><p>Edad de perro: Adulto</p><p>Sabor: Chocolate</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(55, 61, 63);\">Galletas en forma de hueso&nbsp;</span><strong style=\"color: rgb(55, 61, 63);\">sabor chocolate</strong><span style=\"color: rgb(55, 61, 63);\">. Además, están</span><strong style=\"color: rgb(55, 61, 63);\">&nbsp;fortificadas con vitaminas</strong><span style=\"color: rgb(55, 61, 63);\">, no contienen grasa, son muy saludables y ricas, a tu perro seguro le encantan.</span></p>', 0, 45, 124, 1, NULL, NULL, NULL, '2025-10-21 22:55:02', NULL, NULL, 'Galletas-premio-sabor-chocolate-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (865, NULL, 'producto', 'PEZCUPAY01', 0x50455A43552D3031, 'PEZCU-01', 5.00, 'Pez kulhi payaso', '<p>Pez kulhi payaso</p><p>Color: cafesoso </p><p><br></p><p>Descripción:</p><p>Son capaces de soportar bajos tenores de oxigeno ya que la mucosa intestinal realiza funciones respiratorias. Durante el amanecer suben a la superficie en busca de oxigeno llegan a tener una longuitud de 12 cm . su temperatura óptima es entre los 24 a 27 °C.</p><p><br></p>', 0, 35, NULL, 1, NULL, NULL, NULL, '2024-05-12 00:10:25', NULL, NULL, 'Pez-kulhi-payaso', 0, 0);
INSERT INTO `ecom_productos` VALUES (866, NULL, 'producto', '7501556411102', 0x4E45552D3032, 'FL1110', 12.00, 'Neutra stress mediano 60 ml', '<p>Neutra stress Chico</p><p>Cantidad: 60 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Elimina cloro, protege las mucosas de los peces y detoxificametales pesados.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Contiene Vitamina B1.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Para restablecer las mucosas dañadas de los peces, agregue 1 ml. por cada 10 litros de agua (2 gotas por litro).</span></p><p><br></p><p><br></p>', 0, 60, NULL, 1, NULL, NULL, NULL, '2024-02-05 17:59:27', '2023-12-02 22:04:41', NULL, 'Neutra-stress-mediano-60-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (867, NULL, 'producto', '7503000709100', 0x42415248412D3031, '7503000709100', 0.00, 'Palanqueta para hamster y ratón ', '<p>Palanqueta para hámster y ratón</p><p>Contenido: 2 barras de 90 grs cada una</p><p><br></p><p>Descripción:</p><p>Es una palanqueta desarrollada a partir de la combinación de semillas frescas, esta enriquecida con vitaminas, orto fosfatos y miel que le proporcionan a la mascota una fuente de energía, nutrición y diversión.</p><p>incluye dos barras de palanqueta para hamster y ratón enriquecida con vitaminas.</p><p><br></p><p><br></p>', 0, 100, 124, 1, NULL, NULL, NULL, '2026-02-22 17:23:15', NULL, NULL, 'Palanqueta-para-hamster-y-raton-', 0, 0);
INSERT INTO `ecom_productos` VALUES (868, NULL, 'producto', '7501556466386', 0x414C49462D3031, 'WAT638', 4.00, 'Alimento para peces de fondo 70 grs', '<p>Alimento para peces de fondo</p><p>Cantidad: 70 grs</p><p><br></p><p>Descripción:</p><p>Alimento vegetal para peces herbívoros</p><p>Fórmula perfeccionada para peces de fondo en forma de discos para la fácil ingesta de este tipo de peces.</p><p>Alta concentración de alga espirulina para acentuar los colores.</p><p>Adicionado con vitamina C estabilizada y un suplemento multivitamínico para nutrir a los peces y favorecer a su buena salud.</p><p>Alimento en forma de discos para peces de fondo.</p><p><br></p>', 0, 35, NULL, 1, NULL, NULL, NULL, '2024-02-05 17:59:41', '2023-11-28 17:38:30', NULL, 'Alimento-para-peces-de-fondo-70-grs', 0, 0);
INSERT INTO `ecom_productos` VALUES (869, NULL, 'producto', 'PEZMEN04AZUL', 0x50455A4D4E2D3034, 'PEZMN-04', 4.00, 'Pez monja azul ', '<p>Pez monja transgenica</p><p>Color: azul</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neónen la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p><p><br></p>', 0, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:53:38', NULL, NULL, 'Pez-monja-azul-', 0, 0);
INSERT INTO `ecom_productos` VALUES (870, NULL, 'producto', 'PEZMONAMA03', 0x50455A4D4E2D3033, 'PEZMN-03', 100.00, 'Pez monja neón rosa ', '<p>Pez monja transgenica</p><p>Color: rosa</p><p><br></p><p>Descripción:</p><p>Pez monja transgenica o neónen la naturaleza pueden crecer hasta los 7.5cm pero en los acuarios pueden alcanzar un tamaño de entre 4 y 6 cm asimismo la tempratura del agua debe estar en el rango de 27 a 29 °C.</p><p><br></p><p><span style=\"color: rgb(51, 51, 51);\">Pez que requiere oxigeno en las peceras para vivir.</span></p>', 0, 25, NULL, 1, NULL, NULL, NULL, '2024-05-27 23:53:52', NULL, NULL, 'Pez-monja-neon-rosa-', 0, 0);
