INSERT INTO `ecom_productos` VALUES (876, NULL, 'producto', 'ALICOTO229', 0x414C49582D3032, '8420717305229', 0.00, 'Alimento loros y Cotorras max ', '<p>Alimento loros y cotorras max</p><p>Cantidad: 2 kgr</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Deliciosa mezcla de frutas deshidratadas (piña, papaya, plátano y pasas), cereales, cacahuetes, cañamones, y semillas de calabaza.</span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">﻿Para: loros y Cotorras</span></p>', 0, 355, 124, 1, NULL, NULL, NULL, '2025-07-17 08:21:43', '2023-11-21 14:36:05', NULL, 'Alimento-loros-y-Cotorras-max-', 0, 0);
