INSERT INTO `ecom_productos` VALUES (878, NULL, 'producto', '8420717020719', 0x414C49582D3033, '8420717020719', 0.00, 'Alimento periquitos max', '<p>Alimento periquitos max</p><p>Cantidad: 1 kgr</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Alimento completo elaborado a base de granos limpios, seleccionados y correctamente mezclados para facilitarla alimentación que necesita tu periquito. Además ha sido enriquecido con gránulos vitaminados que proporcionan el aporte extra alimenticio que los pájaros necesitan en periodos de cría, crecimiento o muda.&nbsp;</span></p><p><br></p><p><br></p>', 0, 95, 124, 1, NULL, NULL, NULL, '2026-01-31 07:21:08', '2023-11-21 14:36:05', NULL, 'Alimento-periquitos-max', 0, 0);
INSERT INTO `ecom_productos` VALUES (879, NULL, 'producto', '8420717305137', 0x414C494348492D3032, '8420717305137', 0.00, 'Alimento chinchilla max ', '<p>Alimento chinchilla max</p><p>Cantidad: 800 grs</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Chinchillas es un alimento de alta calidad, especialmente diseñado para satisfacer las necesidades nutricionales de tu chinchilla.&nbsp;</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Basada en una selección de hierbas naturales, ricas en fibra, que favorecen la digestión y el bienestar general</span></p>', 0, 145, 124, 1, NULL, NULL, NULL, '2026-04-08 07:24:17', '2023-11-21 14:36:05', NULL, 'Alimento-chinchilla-max-', 0, 0);
INSERT INTO `ecom_productos` VALUES (880, NULL, 'producto', '8420717305083', 0x414C49434F2D3035, '8420717305236', 0.00, 'Alimento conejo max ', '<p>Alimento conejo max</p><p>Cantidad: 800 grs</p><p><br></p><p>Descripción:</p><p>Alimento <span style=\"color: rgba(0, 0, 0, 0.9);\">Para Conejos es la elección perfecta para mantener a tu conejo sano y feliz. Con su fórmula especializada, este alimento proporciona todos los nutrientes necesarios para una dieta equilibrada.&nbsp;</span></p><p><br></p><p><br></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-04-08 07:10:05', '2023-11-28 18:18:28', NULL, 'Alimento-conejo-max-', 0, 0);
INSERT INTO `ecom_productos` VALUES (881, NULL, 'producto', '8420717002159', 0x414C4943552D3034, '8420717002159', 0.00, 'Alimento para cuyo max', '<p>Alimento para cuyo</p><p>Cantidad: 1 kgrs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Elección perfecta para mantener a tu mascota saludable y feliz. Este producto es especialmente formulado para cobayas, cuyos y guinea pigs, garantizando una dieta balanceada y nutritiva.</span></p><p><br></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-04-08 06:55:57', '2023-11-21 14:36:05', NULL, 'Alimento-para-cuyo-max', 0, 0);
