INSERT INTO `ecom_productos` VALUES (887, NULL, 'producto', 'ARE24ROYAL', 0x41524F2D3234, 'SH-230902', 1.00, 'Arenero royal', '<p>Arenero royal</p><p>Medidas: 52 x 40 x 39cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Desmontable con doble compuerta integrada. Absorbe malos olores y evita que se propaguen al exterior. Compatible con cualquier tipo de arena de fácil armado y limpieza.</p><p>Diseño vanguardista y exclusivo Adaptable a cualquier espacio.</p><p>Incluye pala.</p><p><br></p><p>Colores: rosa, azul, gris (sujetos a disponibilidad)</p>', 0, 880, 124, 1, NULL, NULL, NULL, '2025-06-03 23:23:52', '2025-06-03 23:23:52', NULL, 'Arenero-royal', 0, 0);
INSERT INTO `ecom_productos` VALUES (888, NULL, 'producto', 'ARETUBAMBU25', 0x41524F2D3235, 'SH-230903', 5.00, 'Arenero bambú tunel', '<p>Arenero royal</p><p>Medidas: 52 x 57 x 37cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Desmontable con una compuerta integrada tipo tunel/ casita.</p><p>Absorbe malos olores y evita que se propaguen al exterior, Compatible con cualquier tipo de arena. Fácil armado y limpieza.</p><p>Diseño vanguardista y exclusivo Adaptable a cualquier espacio.</p><p>Incluye pala.</p><p><br></p><p>Colores: verde, azul, amarillo (sujetos a disponibilidad)</p>', 0, 1500, NULL, 1, NULL, NULL, NULL, '2024-02-05 18:19:05', NULL, NULL, 'Arenero-bambu-tunel', 0, 0);
INSERT INTO `ecom_productos` VALUES (889, NULL, 'variante', '6938954621030', 0x41524F2D32364E41, 'SH-230904', 1.00, 'Arenero ovejamamba naranja', '<p>Arenero ovejamamba</p><p>Medidas: 53 x 41 x 38cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Desmontable con una compuerta integrada. Absorbe malos olores y evita que se propaguen al exterior con asa para facil transporte.</p><p>Compatible con cualquier tipo de arena.</p><p>Fácil armado y limpieza.</p><p>Diseño vanguardista y exclusivo</p><p>Adaptable a cualquier espacio.</p><p>Material resistente.</p><p>Incluye pala.</p><p><br></p><p>Colores: rosa, azul, naranja (sujetos a disponibilidad)</p>', 0, 700, NULL, 1, NULL, NULL, NULL, '2025-06-03 23:25:57', '2025-06-03 23:25:57', NULL, 'Arenero-ovejamamba-naranja', 0, 0);
INSERT INTO `ecom_productos` VALUES (890, NULL, 'producto', 'AREDUBLINA27', 0x53482D32323137, 'SH-2217', 1.00, 'Arenero Dublín', '<p>Arenero Dublín</p><p>Medidas: 49.5 x 37.5 x 36.5cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Desmontable con doble compuerta integrada. Absorbe malos olores y evita que se propaguen al exterior compatible con cualquier tipo de arena.</p><p>Fácil armado y limpieza.</p><p>Diseño vanguardista y exclusivo Adaptable a cualquier espacio. Material resistente.</p><p>Incluye pala.</p><p><br></p><p>Colores: verde, gris, morado (sujetos a disponibilidad)</p>', 0, 960, NULL, 1, NULL, NULL, NULL, '2024-02-05 18:20:47', '2023-11-16 12:36:35', NULL, 'Arenero-Dublin', 0, 0);
INSERT INTO `ecom_productos` VALUES (891, NULL, 'producto', 'AREORIONARO28', 0x41524F2D3238, 'SH-230419', 0.00, 'Arenero orion', '<p>Arenero orion</p><p>Medidas: 53.4 x 51 x 48.3 cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Amplio espacio, brinda privacidad para tu gato.</p><p>Diseño minimalista, elegante y exclusivo. Ideal para gatos pequeños y grandes.</p><p>Diseño cerrado, evita esparcimiento de olores. Incluye pala y facilita movimiento con mango pequeño en la parte superior.</p><p>Fácil de limpiar.</p><p>Colores adaptables a tu entorno.</p><p><br></p><p>Colores: verde, rosa, verde aqua (sujetos a disponibilidad)</p>', 0, 1360, 124, 1, NULL, NULL, NULL, '2026-03-04 20:35:46', '2023-11-16 12:36:35', NULL, 'Arenero-orion', 0, 0);
INSERT INTO `ecom_productos` VALUES (892, NULL, 'producto', 'ARESITYARO29', 0x41524F2D3239, 'SH-230122', 1.00, 'Arenero sity', '<p>Arenero sity</p><p>Medidas: 51 x 41 x 38cm (largo x ancho x alto)</p><p><br></p><p>Descipción:</p><p>Sin propagación de malos olores. Mantiene la privacidad de tu gatos. Asa y hebillas resistentes y seguras para facilitar su transporte. La salida en la parte superior mantendrá entretenida a tu</p><p>mascota de Limpieza fácil.</p><p>Soporte para pala.</p><p>Incluye pala y cajón frontal.</p><p>Puerta delantera desmontable para gatos grandes Y barra de refuerzo inferior.</p><p><br></p><p>Colores: azul, rosa, gris (sujetos a disponibilidad)</p>', 0, 1050, NULL, 1, NULL, NULL, NULL, '2024-02-05 18:22:32', '2023-11-16 12:36:35', NULL, 'Arenero-sity', 0, 0);
