INSERT INTO `ecom_productos` VALUES (900, NULL, 'producto', 'ALIOBARRAFRU05', 0x34363032353333303031303032, '4602533001002', 0.00, 'Alimento barras de frutas one ', '<p>Alimento barras de frutas one</p><p>Cantidad: 180 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Gran sabor y variedad de composición incluye semillas de jardín y varias frutas (manzana, platano, pasas, naranja, cranberrys) Juntos con una crujiente textura, hace a esta barrita especial, deliciosa y atractiva.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Para Chinchillas, Hamsters, Conejos, Cuyos, Cobayos y todos los pequeños mamíferos.</span></p><p><br></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2025-07-17 08:26:33', NULL, NULL, 'Alimento-barras-de-frutas-one-', 0, 0);
INSERT INTO `ecom_productos` VALUES (901, NULL, 'producto', 'ALIOBARRA06', 0x414C494F2D3036, '4602533001026', 0.00, 'Alimento barras de hierbas y flores one', '<p>Alimento barras de hierbas y flores one</p><p>Cantidad: 160 grs</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">Garantiza una alimentación equilibrada y saludable para tus mascotas. Su fórmula única combina una selección de hierbas y flores cuidadosamente seleccionadas para proporcionarles los nutrientes esenciales que necesitan.&nbsp;</span></p><p><span style=\"color: rgba(0, 0, 0, 0.9); background-color: var(--kt-input-bg);\">Para Chinchillas, Hamsters, Conejos, Cuyos, Cobayos y todos los pequeños mamíferos.</span></p><p><br></p><p><br></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2025-07-17 08:26:45', NULL, NULL, 'Alimento-barras-de-hierbas-y-flores-one', 0, 0);
