INSERT INTO `ecom_productos` VALUES (912, NULL, 'producto', 'BEBCOMDOGGI12', 0x4449532D3132, 'SH-220313', 5.00, 'Bebedero y comedero doggy', '<p>Bebedero y comedero doggy</p><p>Medidas:&nbsp;39.5 x 10.5 x 20.7cm (largo x ancho x alto)</p><p>Capacidad del bebedero: 500 ml</p><p><br></p><p>Descripción:</p><p>Anti-atragantamiento, evita asfixia, indigestión y vómito. Protege la salud de tu mascota, evita la obesidad.</p><p>Resistente a altas/bajas temperaturas. Resistente a mordeduras y golpes. Diseño de columna para comida lenta. No se derrapa</p><p>Tazon de acero inoxidable desmontable.</p><p><br></p><p>Colores: rosa, amarillo( sujetos a disponibilidad)</p><p><br></p>', 0, 250, NULL, 1, NULL, NULL, NULL, '2024-02-26 21:16:53', '2023-11-16 12:36:35', NULL, 'Bebedero-y-comedero-doggy', 0, 0);
INSERT INTO `ecom_productos` VALUES (913, NULL, 'producto', 'DISPEGASO13', 0x4449532D3133, 'SH-220308', 3.00, 'Bebedero y comedero pegaso', '<p>Bebedero y comedero pegaso</p><p>Medidas:&nbsp;30 x 23 x 30 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Anti-atragantamiento.</p><p>Evita asfixia, indigestión y vómito. Protege la salud de tu mascota, evita la obesidad.</p><p>Función de alimentación y bebida 2 en 1 Tazón de alimentación y dispensador de agua potable con diseño de partición</p><p>Incluye una manija rotativa con función interactiva.</p><p><br></p><p>Colores: rosa, azul, gris( sujetos a disponibilidad)</p><p><br></p>', 0, 340, 124, 1, NULL, NULL, NULL, '2026-03-27 06:20:51', '2023-11-16 12:36:35', NULL, 'Bebedero-y-comedero-pegaso', 0, 0);
INSERT INTO `ecom_productos` VALUES (914, NULL, 'producto', 'CACOMINI01', 0x4341434F2D303120, 'CAMCOMINI', 0.00, 'Cama corona mini', '<p>Cama corona mini</p><p>Medidas:</p><p><br></p><p>Descripción: cama mini para mascotas pequeñas como conejos mini, cuyos, hámster sirio, pequeños mamíferos.</p>', 0, 180, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:11:02', NULL, NULL, 'Cama-corona-mini', 0, 0);
