INSERT INTO `ecom_productos` VALUES (916, NULL, 'variante', 'CAMTOMCH02', 0x544F4D2D3032, 'PI0203-0135', 1.00, 'Cama colchoneta Tom chica tinta ', '<p>Cama tom chica para mascotas</p><p>Medidas: 40 x 5 x 55 cm (largo x ancho x alto)</p><p>Color: tinta</p><p><br></p><p>Descripción: confortable colchoneta elegantes y comodas camas para perros , gatos, uron, puerco mini pig, etc. .Colchoneta de alta desidad ortopédico, amterisl externo curri fresco con cierre laterar. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro inferior de tiburón 100% políester impermeable lavable, ideal para casas rigidas, transportadoras y/o salas de recuperación.</p>', 0, 300, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:13:20', '2024-09-30 17:13:20', NULL, 'Cama-colchoneta-Tom-chica-tinta-', 0, 0);
INSERT INTO `ecom_productos` VALUES (917, NULL, 'producto', 'CACOCIRC03', 0x4341434F2D3033, 'ACCESORIO', 0.00, 'Cama dona mini ', '<p>Cama dona mini</p><p>Medidas:</p><p><br></p><p>Descripción: cama mini para mascotas pequeñas como conejos mini, cuyos, chinchilla, ardilla, y más pequeños mamíferos.</p><p><br></p><p>De color (sujeto a disponibiidad)</p>', 0, 160, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:11:23', NULL, NULL, 'Cama-dona-mini-', 0, 0);
INSERT INTO `ecom_productos` VALUES (918, NULL, 'producto', 'FLAU-01', 0x482D313032, 'H-102', 12.00, 'Filtro flauta rapido  200lts 3w', '<p>Filtro flauta rapido 200lts</p><p>Potencia:3w</p><p>Voltaje: 110-120v</p><p>Medidas: 13 cm altura</p><p>Capacidad maxima:</p><p>Flujo: 200 L/H</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Filtro interno, robusto, confiable, silencioso y seguro, ahorrador de energía, muy eficiente.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\"> Incluye: esponja negra.</span></p>', 0, 280, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:10:18', '2023-11-21 14:36:05', NULL, 'Filtro-flauta-rapido--200lts-3w', 0, 0);
INSERT INTO `ecom_productos` VALUES (919, NULL, 'producto', 'CAMINILUN08', 0x43414D462D3038, 'PI0101-0013', 3.00, 'Cama antiestres mini para mascotas ', '<p>Cama antiestres mini para mascotas</p><p>Medidas: 35 x 10 cm (circuferencia x alto)</p><p>color: lunares</p><p><br></p><p>Descripción: confortable cama anti estrés, elegantes y comodas camas para perros pequeños, gatos, conejos, cuyo, uron, rata, puerco mini pig, etc. Elaboradas en el exterior MT, relleno delcron, 100% poliéster, forro interior de tiburón, lavable.</p><p><br></p><p>Tela super suavesita, calientita y confortable.</p><p><br></p>', 0, 240, NULL, 1, NULL, NULL, NULL, '2024-09-30 17:18:55', '2024-09-30 17:18:55', NULL, 'Cama-antiestres-mini-para-mascotas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (920, NULL, 'producto', 'FILFLAU02', 0x482D313030, 'H-100', 12.00, 'Filtro flauta rapido 200lts', '<p>Filtro flauta rapido 200lts</p><p>Potencia:2w</p><p>Voltaje: 110-120v</p><p>Medidas: 3.5 x 3.5 x 12.5 cm (largo x ancho x alto)</p><p>Capacidad maxima:20lts</p><p>Flujo: 200 L/H</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Filtro interno, robusto, confiable, silencioso y seguro, ahorrador de energía, muy eficiente.filtro rápido para acuarios Características: este filtro es Ideal para mantener limpio su hábitat ya que absorbe las partículas solidas que se encuentran suspendidas en el agua, generando una eficiente filtración biológica consta de una cabeza de poder y un cartucho cilíndrico con una esponja</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\"> Incluye: esponja negra.</span></p>', 0, 270, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:16:09', '2023-12-02 22:04:41', NULL, 'Filtro-flauta-rapido-200lts', 0, 0);
INSERT INTO `ecom_productos` VALUES (921, NULL, 'producto', 'RASCELEF02', 0x5241532D3032454C, 'PI0709-0346', 2.00, 'Rascadero colgante elefante ', '<p>Rascadero colgante elefante</p><p>Medidas: 42 x 12 x 1.5 cm (largo x ancho x alto)</p><p>Medidas con colgadera: 54 x 12 x 1.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios pequeños donde puedas colgar el rascadero en la silla, sillon, buro, puerta, pared en aquel espacio para colgar asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p><br></p><p>Material: Elaborado con MDF de 12 pulgadas tapizante y tela soft y yute, hechos con henequén.</p>', 0, 220, 124, 1, NULL, NULL, NULL, '2025-03-30 07:28:35', '2023-11-29 16:17:59', NULL, 'Rascadero-colgante-elefante-', 0, 0);
