INSERT INTO `ecom_productos` VALUES (935, NULL, 'producto', 'FILESPESQ01', 0x58592D32383931, 'XY-2891', 1.00, 'Filtro de esponja de esquina 10cm', '<p>Filtro de esponja de esquina 10cm</p><p>Medidas: 10<span style=\"color: rgba(0, 0, 0, 0.9);\">cm x 12cm (largo x alto)</span></p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(15, 17, 17);\">Filtro triangular de esponja biológica para acuario, perfecto para cualquier rincón, no ocupa demasiado espacio, adecuado para todo tipo de acuarios. Fácil de usar y mantener, las piezas son removibles, respetuosas con el medio ambiente y sin ruido. </span></p><p><br></p><p>Sugerencias:<span style=\"color: rgb(51, 51, 51);\">Exprime el aire cuando coloques la esponja bajo el agua, luego succiona el agua y manténgalo en la parte inferior.</span></p>', 0, 110, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:45:38', '2023-12-02 22:04:41', NULL, 'Filtro-de-esponja-de-esquina-10cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (936, NULL, 'producto', 'FILESPCIL-01', 0x58592D32383336, 'XY-2836', 2.00, 'Filtro de esponja cilindro', '<p>Filtro de esponja cilindro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(15, 17, 17);\">Filtro cilindrico de esponja biológica para acuario, no ocupa demasiado espacio, adecuado para todo tipo de acuarios. Fácil de usar y mantener, las piezas son removibles, respetuosas con el medio ambiente y sin ruido. </span></p><p><br></p><p>Sugerencias:<span style=\"color: rgb(51, 51, 51);\">Exprime el aire cuando coloques la esponja bajo el agua, luego succiona el agua y manténgalo en la parte inferior.</span></p>', 0, 115, NULL, 1, NULL, NULL, NULL, '2024-02-06 20:26:17', '2023-12-02 22:04:41', NULL, 'Filtro-de-esponja-cilindro', 0, 0);
INSERT INTO `ecom_productos` VALUES (937, NULL, 'producto', '7502211903208', 0x48424C2D373031, 'HBL-701', 1.00, 'Filtro cascada doble 600', '<p>Filtro Cascada (doble)</p><p>Medidas: <span style=\"color: rgba(0, 0, 0, 0.9);\"> 35</span><span style=\"color: rgb(102, 102, 102);\"> cm x 15 cm x 20 cm </span><span style=\"color: rgba(0, 0, 0, 0.9);\">(largo x ancho x alto)</span></p><p>Voltaje: 110-120 v</p><p>Flujo maximo 600 L/H</p><p>Potencia: 7 w</p><p>Para maximo: 160 lts</p><p><br></p><p>Descripción:</p><p>Con pipeta flotante desnatadora para mantener limpia la superficie del agua, filtración silenciosa fácil, efectiva para lograr un acuario saludable.</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Instrucciones:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Antes de encender el equipo (antes de conectarlo a la luz), es INDISPENSABLE llenar el compartimiento del cuerpo del filtro con la misma agua de la pecera, una vez instalado y llenado previamente conectar a la luz.</span></p>', 0, 800, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:47:14', '2023-12-02 22:04:41', NULL, 'Filtro-cascada-doble-600', 0, 0);
INSERT INTO `ecom_productos` VALUES (938, NULL, 'producto', 'ALIHAMSROS01', 0x434F4D492D303252, 'RJ539', 10.00, 'Comedero alimentador para hámster rosa ', '<p>Alimentador de hámster</p><p>Capacidad: 200 ml</p><p>Medidas: 12.5 x 7 x 13 cm (largo x ancho x alto)</p><p>Diámetro del clindro: 7.5cm</p><p>Color: rosa</p><p><br></p><p>Descripción:</p><p>Alimentador de hámster por gravedad conforme se alimenta baja sus semillas.</p><p><br></p>', 0, 120, NULL, 1, NULL, NULL, NULL, '2024-11-29 07:20:55', NULL, NULL, 'Comedero-alimentador-para-hamster-rosa-', 0, 0);
INSERT INTO `ecom_productos` VALUES (939, NULL, 'producto', 'TIBAÑHAMVER02', 0x54494E412D303248, 'RJ120', 5.00, 'Bañera casa para hámster verde ', '<p>Bañera casa para hámster</p><p>Medidas: 13 x 9 x 9 cm (largo x ancho x alto)</p><p>Colores:verde</p><p><br></p><p>Descripción: tina de baño para hámster cerrda para evitar derrames de polvo de baño al ellos bañarse dentro de ellas. o casa para ellos para estos frios.</p>', 0, 95, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:49:11', NULL, NULL, 'Banera-casa-para-hamster-verde-', 0, 0);
INSERT INTO `ecom_productos` VALUES (940, NULL, 'variante', 'BAÑOCONBL02', 0x434F4E2D3031, 'RJ125', 10.00, 'Esquinero baño rectagular  blanco', '<p>Esquinero baño para conejo</p><p>Medidas: 28 x 22 x 16 cm (largo x ancho x alto)</p><p><br></p><p>Descripción: Esquinero baño con rejilla para evitar el contacto de sus eses con sus patitas. baño para conejos, cuyos, hurones, chinchillas. capibaras. conejillode indias- y mas.</p>', 0, 250, 124, 1, NULL, NULL, NULL, '2025-12-09 09:21:21', '2025-12-09 09:21:21', NULL, 'Esquinero-bano-rectagular--blanco', 0, 0);
INSERT INTO `ecom_productos` VALUES (941, NULL, 'producto', 'RUEPLAAMA02', 0x5255452D303241, 'GPRH1', 5.00, 'Rueda para hámster con base amarilla', '<p>Rueda para hámster con base amarilla</p><p>Material: plástico</p><p>Diametro: 14cm</p><p><br></p><p>Descripción:</p><p>Rueda de plástico con separdor entre barrotes para que el hamter sujete sus patas, asi obteniendo que el hamster corra en la rueda y ejercite su cuerpo, destresa del hámster.</p>', 0, 135, NULL, 1, NULL, NULL, NULL, '2024-02-05 20:50:46', NULL, NULL, 'Rueda-para-hamster-con-base-amarilla', 0, 0);
