INSERT INTO `ecom_productos` VALUES (963, NULL, 'producto', 'MOFRIBACK05', 0x4D4F432D3035, 'PI2111-0362', 5.00, 'Mochila Fridback para mascotas', '<p>Mochila Fridback para mascotas</p><p>Medidas: 45 x 40cm (largo x ancho)</p><p><br></p><p>Descripción:</p><p>Elegante y resistente</p><p>mochila para que lleves a tu peludito a todos lados, te la puedes poner en la espalda o en el pecho.</p><p>Elaboradas en poliéster,</p><p>con malla respirable.</p>', 0, 499, 124, 1, NULL, NULL, NULL, '2025-06-09 07:52:06', NULL, NULL, 'Mochila-Fridback-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (964, NULL, 'producto', 'MOCHFRICA06', 0x4D4F432D3036, 'PI1121-0361', 3.00, 'Mochila fridcan para mascotas', '<p>Mochila Fridcan para mascotas</p><p>Medidas: 50 x 32 cm (largo x ancho)</p><p><br></p><p>Descripción:</p><p>Práctica y resistente mochila tipo cangurera, ideal para que te acompañe a todos lados sin que se lastime sus patitas.Correa ajustable</p><p>Elaboradas en poliéster con malla respirable.</p><p><br></p>', 0, 390, 124, 1, NULL, NULL, NULL, '2025-06-09 07:52:27', '2023-11-29 16:17:59', NULL, 'Mochila-fridcan-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (965, NULL, 'producto', 'FUNPRCOC-01', 0x5049303831302D30333036, 'PI0810-0306', 5.00, 'Funda protectora para asientos de coche', '<p>Funda protectora para asientos coche</p><p>Medidas: 145 x 145cm (largo x ancho)</p><p><br></p><p>Descripción:</p><p>Material Daning con cubiertaimpermeable.</p><p>Funciona para todos los autos que tengan descansa nucas en asientos traseros y delanteros.Cubre completamente los asientos y</p><p>las puertas traseras</p><p>Al ser un material impermeable, evita que el agua, lodo, y otros líquidos lleguen a los asientos.</p><p>Entre los asientos lleva una malla para</p><p>tranquilidad de la mascota, puede ver a su dueño en todo momento.</p><p>Incluye una funda.</p><p><br></p><p>&nbsp;&nbsp;</p><p><br></p>', 0, 799, NULL, 1, NULL, NULL, NULL, '2024-10-30 09:19:30', NULL, NULL, 'Funda-protectora-para-asientos-de-coche', 0, 0);
INSERT INTO `ecom_productos` VALUES (966, NULL, 'variante', 'RASMICHSE07', 0x5241532D3037, 'PI0709-0305', 0.00, 'Rascadero mich sencillo', '<p>Rascadero mich sencillo</p><p>Medidas: 50 x 35cm (largo x ancho)</p><p>Medidas del poste: 56cm altura</p><p><br></p><p>Descripción:</p><p>Rascador resistente elaborado con Henequén 100 % fibra natural, MDF de 12 mm textil angora y MT.</p><p>Los peces tienen cascabel</p><p>Rascadero fabricado especial para espacios vacios donde puedas colocar el rascadero entre salas, cuartos, etc.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p><br></p>', 0, 595, 124, 1, NULL, NULL, NULL, '2026-03-07 08:30:14', '2026-03-07 08:30:14', NULL, 'Rascadero-mich-sencillo', 0, 0);
INSERT INTO `ecom_productos` VALUES (967, NULL, 'variante', 'RASDOBMEI05', 0x5241532D3035, 'P10709-0342', 0.00, 'Rascador mich doble ', '<p>Rascadero mich doble</p><p>Medidas: 50 x 35cm (largo x ancho)</p><p>Medidas del poste: 56cm altura</p><p><br></p><p>Descripción:</p><p>Rascador resistente elaborado con Henequén 100 % fibra natural, MDF de 12 mm textil angora y MT.</p><p>Los peces tienen cascabel</p><p>Rascadero fabricado especial para espacios vacios donde puedas colocar el rascadero entre salas, cuartos, etc. rascador con doble poste.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p><br></p>', 0, 850, 124, 1, NULL, NULL, NULL, '2026-03-07 08:30:42', '2026-03-07 08:30:42', NULL, 'Rascador-mich-doble-', 0, 0);
INSERT INTO `ecom_productos` VALUES (968, NULL, 'variante', 'RASBANGRI06', 0x5241532D3036, 'P10709-0342', 0.00, 'Rascadero banco gris ', '<p>Rascadero Banco gris</p><p>Medidas: 44cm x 50cm (diámetro x alto)</p><p><br></p><p>Descripción:</p><p>Resistente y elegante</p><p>rascadero que funciona como banco o como cama para Gato, elaborado con Henequén 100 % fibra natural, MDF de 12 mm, textil Oslo.</p><p>El banco es resiste a una persona sentada.</p><p>Incluye: cojín</p><p><br></p><p>Color: gris</p>', 0, 1300, 124, 1, NULL, NULL, NULL, '2025-09-02 22:19:14', '2025-09-02 22:19:14', NULL, 'Rascadero-banco-gris-', 0, 0);
