INSERT INTO `ecom_productos` VALUES (988, NULL, 'variante', '6932102450138', 0x41524F2D31375645, 'SH-230133', 5.00, 'Arenero aqua verde', '<p>Arenero aqua</p><p>Medidas: 45 x 34 x 39 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero de material de calidad de facil traslado de un lugar a otro, un baño elegante y muy amplio para gatos.</p><p>Desmontable con doble puerta intergrada una con puerta y la otra sin para que facil salga con lipiador de patas.</p><p>Absorbe malos olores y evita q se propagen al exterior</p><p>Compatible con cualquier tipo de arena, facil armado y limpieza con diseño vanguardista y exclusivo adaptable a cualquier espacio.</p><p><br></p><p>Incluye:</p><p>Puerta abatible</p><p>Pala</p><p>Charola extraible</p><p><br></p><p>Colres: rosa gris, azul ( sujetos a disponibilidad)</p>', 0, 820, NULL, 1, NULL, NULL, NULL, '2025-06-03 23:19:23', '2025-06-03 23:19:23', NULL, 'Arenero-aqua-verde', 0, 0);
