INSERT INTO `ecom_productos` VALUES (1010, NULL, 'producto', 'PASTDPE01', 0x44454E2D3032, 'FL3907', 5.00, 'Pasta dental para perro 90 grs', '<p>Pasta dental para perro</p><p>Cantidad: 90 grs</p><p><br></p><p>Descripción:</p><p>Óptima saluddental.</p><p>Reduce la formación del sarro y placa bacteriana.</p><p>Mejora el aliento.</p><p>Sabor hierbabuena. Beneficios: Conoce la línea completa para el cuidado dental FANCYPETS. El cepillado dental reduce el riesgo de desarrollar enfermedades bucodentales, éstas pueden ocasionar serios problemas de salud en los perros. Establece una rutina diaria de cuidado dental puede extender la vida de nuestra mascota.</p>', 0, 70, NULL, 1, NULL, NULL, NULL, '2024-02-05 22:25:02', NULL, NULL, 'Pasta-dental-para-perro-90-grs', 0, 0);
INSERT INTO `ecom_productos` VALUES (1011, NULL, 'producto', '7501556477368', 0x5445522D3031, 'FL7736', 2.00, 'Calentador fijo mini 35w', '<p>Calentador fijo mini</p><p>Potencia: 35w</p><p>Volts: 110-120v</p><p>Medidas:20cm</p><p>Diámetro: 1 cm</p><p>Volumen minimo de agua 10lts a 35 lts</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">brindan una temperatura constante al acuario. La temperatura es un factor importante debido a que los peces son animales de sangre fría y mantienen la temperatura de su cuerpo igual a la del medio ambiente.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Los cambios repentinos pueden causar estrés y provocar enfermedades.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Mantiene la temperatura constante (35 °C).</span></p><p><span style=\"color: rgb(102, 102, 102);\"> Ideal para acuarios de 35 litros (con base en la regla 1 watt por cada litro de agua).</span></p><p><span style=\"color: rgb(102, 102, 102);\"> Fácil de instalar.</span></p><p><br></p>', 0, 96, NULL, 1, NULL, NULL, NULL, '2024-02-05 22:26:00', '2023-12-02 22:04:41', NULL, 'Calentador-fijo-mini-35w', 0, 0);
INSERT INTO `ecom_productos` VALUES (1012, NULL, 'producto', 'BECOLI50003', 0x434F4C494E45432D3031, 'FL9221', 5.00, 'Bebedero para colibrí con néctar ', '<p>Bebedero de colibrí con néctar</p><p>Capacidad: 500 ml liquido</p><p>Capacidad bebedero: 300 ml</p><p><br></p><p>Descripción:Proporciona néctar al colibrí de forma fácil.</p><p><span style=\"color: rgb(102, 102, 102);\">Néctar en color rojo con un agradable sabor para el ave. Ventajas:</span></p><p><span style=\"color: rgb(102, 102, 102);\">El bebedero es fácil de llenar, lavar e instalar, mientras que el néctar por su presentación liquida es mas fácil, practico y rápido</span></p><p><span style=\"color: rgb(102, 102, 102);\">de servir porque esta listo para usarse.</span></p><p><br></p><p><br></p>', 0, 99, NULL, 1, NULL, NULL, NULL, '2024-02-02 14:17:02', NULL, NULL, 'Bebedero-para-colibri-con-nectar-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1013, NULL, 'producto', 'ALIGATNUPI01', 0x4E5550492D3031, 'NUPI-01', 10.00, 'Alimento para gato adulto indoor nupec 3kg', '<p>Alimento para gato indoor adulto nupec</p><p>Cantidad: 3 kgrs</p><p><br></p><p>Descripción:</p><p>Vitaminas del complejo B y romero que regulan el sistema nervioso y controlan el estrés</p><p>Contribuye al desarollo ocualr fortaleciendo la visión</p><p>Reduce presencia de malos olores en las heces</p><p>Control adecuado de pH para prevención de cálculos en vejiga</p><p>Carne de pollo y salmón fresco de alta digestibilidad</p><p>Prebioticos que promueven una microflora saludable</p><p>Pelaje hermoso y piel sana</p><p>Con antioxidantes que previenen el envejecimiento celular.</p><p><br></p>', 0, 499, 124, 1, NULL, NULL, NULL, '2025-09-23 23:47:00', NULL, NULL, 'Alimento-para-gato-adulto-indoor-nupec-3kg', 0, 0);
