INSERT INTO `ecom_productos` VALUES (1043, NULL, 'producto', ' 7501556485066', 0x4A55472D3230, 'FL8506', 5.00, 'Juguete circulo colores para perro', '<p>Juguete para perro engranes de colores</p><p>Medidas:11cm</p><p><br></p><p>Descripcion:</p><p><span style=\"color: rgb(33, 37, 41);\">Juguete con bordes limpiadores para promover la salud dental del perro, sirve para morder, entretener e interactuar y al mismo tiempo limpiar los dientes, además de ofrecer un suave masaje a las encías, gracias a su diseño. Ideal para cachorros y perros de raza pequeña. </span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Ventajas:</span></p><p>Ayuda a mantener limpios los dientes.</p><p>El perro se distrae, hace ejercicio y ejercita la mandíbula.</p><p>Material lavable.</p><p><br></p><p>Material: TPR 100%</p><p><br></p>', 0, 38, NULL, 1, NULL, NULL, NULL, '2024-07-09 06:17:14', NULL, NULL, 'Juguete-circulo-colores-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (1044, NULL, 'producto', ' 7501556471595', 0x4A55472D3231, 'FL7159', 5.00, 'Juguete pelota biocolor grande para perro', '<p>Juguete pelota bicolor para perro</p><p>Medidas:11cm</p><p><br></p><p>Descripción:</p><p>Pelota grande de tenis bicolor. Juguete clásico para lanzar, atrapar e interactuar por horas. Agradable para los perros por su textura. Ideal para razas grandes y gigantes.<span style=\"color: rgb(33, 37, 41);\">&nbsp;Al jugar, interaccionas con tu perro y estimulas su instinto de caza</span></p><p><br></p><p>Material: 70 %caucho 30% poliéster</p><p><br></p>', 0, 70, NULL, 1, NULL, NULL, NULL, '2024-04-29 21:25:30', NULL, NULL, 'Juguete-pelota-biocolor-grande-para-perro', 0, 0);
