INSERT INTO `ecom_productos` VALUES (1048, NULL, 'producto', ' 7501556482317', 0x4A5547472D3037, 'FL8231', 5.00, 'Juguete caña hueso para gato', '<p>Juguete caña hueso para gato</p><p>Medidas:42 cm</p><p>Descripcion:</p><p><br></p><p>Estimula curiosidad del gato, así como su instinto de persecución y exploración. Diseñado para satisfacer las necesidades de juego del gato.</p><p>Te permite interactuar con el gato.</p><p>El minino se mantendrá entretenido y hará ejercicio.</p><p>Disminuye la ansiedad, el estrés y el aburrimiento.</p><p><br></p>', 0, 60, NULL, 1, NULL, NULL, NULL, '2024-07-09 06:16:39', NULL, NULL, 'Juguete-cana-hueso-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1049, NULL, 'producto', '7501556436297', 0x504F4C4F2D3031, 'FL3629', 5.00, 'Polvo antipulgas para perros y gatos', '<p>Polvo antipulgas para perros y gatos</p><p><br></p><p>Descripción:</p><p>Es un parasticida de uso extremo, recomendado para el control y tramientode infestaciones por pulgas, garrapatas, ácaros, piojos en perros y gatos.</p><p><br></p><p><br></p>', 0, 150, NULL, 1, NULL, NULL, NULL, '2024-04-10 19:33:14', NULL, NULL, 'Polvo-antipulgas-para-perros-y-gatos', 0, 0);
