INSERT INTO `ecom_productos` VALUES (1053, NULL, 'producto', '8003507971806', 0x4D49442D3031, '96180', 5.00, 'Transportadora mid mediana gris ', '<p>Transportadora mid gris</p><p><br></p><p>Descripción:</p><p>Transportadora <span style=\"color: rgb(102, 102, 102);\">Conejos, Gatos, Cuyos, Chinchilla, Ardilla, etc. Es el accesorio perfecto para viajar con tu mascota de manera cómoda y segura. Con un diseño de alta calidad,cuenta con ventilación para asegurar una correcta circulación de aire durante el viaje, brindando comodidad y bienestar a tu mascota. Además, es apta para cabinas de avión, lo que te permite llevar a tu compañero peludo contigo en tus viajes en avión sin preocupaciones.</span></p><p><br></p><p>Colores: Gris con blanco, gris con azul(sujetos a disponiblidad)</p><p>Peso maximo que soporta:5 kgr</p>', 0, 480, NULL, 1, NULL, NULL, NULL, '2024-03-24 19:53:02', '2024-03-24 13:53:02', NULL, 'Transportadora-mid-mediana-gris-', 0, 0);
