INSERT INTO `ecom_productos` VALUES (1055, NULL, 'producto', '8003507961906', 0x4D49442D3033, '96190', 5.00, 'Transportadora mid chica gris ', '<p>Transportadora mid chica gris</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Es el práctico y versátil transportín ideal para aves o roedores pequeños como Hámster, cuyo, erizo, reptiles, etc. Incorpora una práctica asa y cubierta superior transparente que se puede abrir. Los numerosos agujeros en la cubierta garantizan una correcta ventilación interior y el techo transparente permite que la luz penetre más fácil.</span></p><p><br></p><p>Colores: Gris con blanco, gris con azul(sujetos a disponiblidad)</p><p>Peso maximo que soprta: 2.5 kgr</p>', 0, 410, NULL, 1, NULL, NULL, NULL, '2024-01-31 23:52:05', NULL, NULL, 'Transportadora-mid-chica-gris-', 0, 0);
