INSERT INTO `ecom_productos` VALUES (1061, NULL, 'producto', 'AREFONICO40', 0x41524F2D3430, 'SH-230924', 0.00, 'Arenero fonico ', '<p>Arenero olimpo</p><p>Medidas: 48.5 x 36 x 38cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Arenero cerrado para evitar derrames de arena fuera del arenero con doble salida baño para gatos.Cuenta con cajon que facilita la tarea de limpieza Amplio para gatos grandes con diseño vanguardista y exclusivo.</p><p>Incluye: pala</p><p><br></p><p>Colores: gris, verde, rosa( sujetos a disponibilidad)</p>', 0, 980, 124, 1, NULL, NULL, NULL, '2025-06-03 23:18:35', NULL, NULL, 'Arenero-fonico-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1062, NULL, 'producto', '4602533782239', 0x4241C3914F2D3032, '4602533782239', 0.00, 'Arena de baño one para mamíferos ', '<p>Arena de baño one para mamíferos</p><p><br></p><p>Descripción:</p><p>Arena de baño para baños es la forma mas higiénica de cuidar el pelaje de su mascota. Los granulos de arena blanda y suave proporcionan al espeso pelaje de las chinchillas, hámster, ardilla, cuyo, erizo, Huron, y otras mascotas una limpieza intesa y eliminan el agua condesada y la grasa. la arena no araña la piel y es facil de quitar por lo que le ayudara a que su mascota luzca un pelaje elegante y brillante.</p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-03-13 12:03:39', NULL, NULL, 'Arena-de-bano-one-para-mamiferos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1063, NULL, 'producto', '8413856519374', 0x434F4D452D3031, '51937', 5.00, 'Comedero 6 para aves, hámster', '<p>Comedero para aves o hámster</p><p><br></p><p>Descripción:</p><p>Comedero<span style=\"color: rgb(102, 102, 102);\"> ideal para proporcionar alimento a tus aves de manera cómoda y segura. Su diseño práctico y resistente permite una fácil limpieza y rellenado, garantizando la higiene y salud de tus aves.</span></p><p><br></p>', 0, 85, NULL, 1, NULL, NULL, NULL, '2024-11-12 07:47:51', NULL, NULL, 'Comedero-6-para-aves,-hamster', 0, 0);
