INSERT INTO `ecom_productos` VALUES (1089, NULL, 'producto', '8420717305151', 0x414C4948412D3036, '30515', 0.00, 'Alimento MAX para hámster', '<p><span style=\"color: rgb(102, 102, 102);\">Es un alimento extra completo con mezcla de semillas para hámsters con gránulos vitaminados.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Es un alimento ideal para que tu pequeña mascota roedora consuma diariamente para mantenerse fuerte, energizado y siempre saludable. Contiene una selección de semillas con gránulos 100% naturales, potenciados con vitaminas, minerales y proteínas.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Contiene pellet para hámster (a base de germen de maíz, carbonato cálcico, harina de trigo, aceite de girasol, soja, pulpa de remolacha). Maíz, Trigo duro, Guisantes verdes, Pipas de girasol, Pipas de girasol blancas.</span></p>', 0, 145, 124, 1, NULL, NULL, NULL, '2026-04-06 08:03:55', NULL, NULL, 'Alimento-MAX-para-hamster', 0, 0);
INSERT INTO `ecom_productos` VALUES (1090, NULL, 'producto', 'JAUHMA22ROS', 0x4A48412D3232, 'DY415B', 0.00, 'Jaula hamster tubu ', '<p>Jaula hámster residencial</p><p>Medidas: 35 x 28 x 37 cm (largo x ancho x alto)</p><p>Color: rosa</p><p><br></p><p>Incluye:</p><p>Rueda 13cm</p><p>Tubulares</p><p>Tazon para alimento</p><p>Asa de sujetación en medio</p><p>Bebedero 80 ml</p><p><br></p><p><br></p>', 0, 780, 124, 1, NULL, NULL, NULL, '2026-03-16 07:56:01', NULL, NULL, 'Jaula-hamster-tubu-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1091, NULL, 'producto', '7501325468542', 0x4A434F2D3139, 'DYR3H', 5.00, 'Jaula para mamíferos III', '<p>Jaulas para mamíferos 1 nivel</p><p>Medidas: 84 x 49 x 45 cm <span style=\"color: rgb(94, 98, 120);\">(largo x ancho x alto)</span></p><p><span style=\"color: rgb(94, 98, 120);\">﻿</span></p><p>Descripción: jaula para roedores, mamíferos, con barrote amplio como hasta para un uron y mas dandole un espacio amplio a su entorno de facil limpieza al desprender la charola, con nivel montables y desmotables para posicionar mas cercanos o lejos entre ellos.</p><p><br></p><p>Para: rata, conejo, cuyo, chinchilla, erizo, ardilla, uron, etc.</p><p><br></p><p>Incluye:</p><p><span style=\"color: rgb(75, 86, 107);\">Incluye un nivel con rampa</span></p><p><span style=\"color: rgb(75, 86, 107);\">Color blanco/gris. Pintura libre de plomo, por lo que no es tóxica.</span></p><p><br></p>', 0, 2100, NULL, 1, NULL, NULL, NULL, '2024-02-17 03:07:52', NULL, NULL, 'Jaula-para-mamiferos-III', 0, 0);
INSERT INTO `ecom_productos` VALUES (1092, NULL, 'producto', '8420717025516', 0x43414C4B492D3031, '8420717025509', 5.00, 'Calcio para todo tipo de roedores', '<p>Calcio para tipo de roedores</p><p>Peso: 200 grs</p><p>Color: blanco</p><p><br></p><p>Descripción: Pienso complemetario para todo tipon de roedores como hámster, cuyo, conejo. erizo, chinchilla, cobaya, colocar en la jsula en una zona accesible para que pueda roerlo comodamente.</p><p><span style=\"color: rgb(102, 102, 102);\">Bloque duro con calcio, minerales y oligoelementos para roedores. Alimento complementario natural con vitaminas y minerales en un bloque duro para que los roedores desgasten sus dientes a la vez que reciben un aporte extra de minerales. Bloque tónico con calcio, minerales y oligoelementos vitales, que satisface el instinto natural de los roedores de roer, protegiendo, cuidado y fortaleciendo sus dientes.</span></p><p><br></p><p><br></p>', 0, 60, NULL, 1, NULL, NULL, NULL, '2024-02-17 18:53:48', NULL, NULL, 'Calcio-para-todo-tipo-de-roedores', 0, 0);
INSERT INTO `ecom_productos` VALUES (1093, NULL, 'producto', '7502271350554', 0x4341522D3033, '10049', 5.00, 'Carda de goma almo', '<p>Carda de goma para mascotas</p><p>Para: perro, gato, conejo, uron, chichilla, cuyo, etc.</p><p><br></p><p>Descripciòn:Las cardas están diseñadas con cerdas de goma flexibles recomienda su uso para pelajes enmarañados o enrredados.</p><p>Su mango flexible adapatable a su mano permite que el cepillado sea más cómodo y sencillo.</p><p>Ideal para razas de pelo medio, corto.</p><p>ideal para remover el pelo suelto y muerto de mascotas sus puntas de goma masajean, estimulan la producciòn de aceites naturales de la piel y la circulaciòn sanguìnea`la flexibilidad de la carda permite adecuarse al cuerpo de la mascota.</p>', 0, 80, NULL, 1, NULL, NULL, NULL, '2024-03-23 18:01:48', NULL, NULL, 'Carda-de-goma-almo', 0, 0);
