INSERT INTO `ecom_productos` VALUES (1110, NULL, 'producto', '7501556423068', 0x4A55472D3235, 'FL9306', 5.00, 'Juguete huedo para perro ', '<p>Juguete huedo de bambu chico</p><p>Sabor: tocino</p><p>Medidas:13 cm</p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Características:</span></p><p><span style=\"color: rgb(33, 37, 41);\">· Juguete masticable en forma de hueso, ideal para satisfacer el instinto de morder de los perros.</span></p><p><span style=\"color: rgb(33, 37, 41);\">· Gracias a su material de fabricación con fibra de bambú, proporciona textura y consistencia como si mordiera una rama de árbol.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Satisface el instinto natural de masticación al mismo tiempo que su textura limpia los dientes.</span></p><p><br></p><p>Material: <span style=\"color: rgb(0, 0, 0);\">70% Polipropileno + 30% fibra de bambú.</span></p>', 0, 90, NULL, 1, NULL, NULL, NULL, '2024-04-01 20:00:17', NULL, NULL, 'Juguete-huedo-para-perro-', 0, 0);
