INSERT INTO `ecom_productos` VALUES (1114, NULL, 'producto', '7501556471717', 0x5441502D3036, 'FL7171', 10.00, 'Tapete entrenador desechable soft 7 pza para mascotas', '<p>Tapete entrenador desechable y absorbente soft para mascotas</p><p>Contenido: 7 tapetes</p><p>Medidas: 56 X 56 cm</p><p><br></p><p>Descripcion:</p><p>Ahora con parches adhesivos y 5 capas</p><p>Contiene atrayente para facilitar el entrenamiento</p><p>Con cubierta antiderrames</p><p>Sin malos olores gracias a su rapida asorbcion y accion desodorante</p><p>Se adiere a pisos y superficies</p><p><br></p><p>Sugerencia para:</p><p><span style=\"color: rgb(33, 37, 41);\">Facilita el entrenamiento de tu perro a la hora de ir al baño ideal para todas las razas </span></p><p><span style=\"color: rgb(33, 37, 41);\">Utiliza el tapete para los cachorros y perros que están solos en casa </span></p><p><span style=\"color: rgb(33, 37, 41);\">Para perros que está en edad avanzada o en recuperación de alguna cirugía práctico y seguro fácil de limpiar y Para educar a tu amigo de forma gradual. </span></p>', 0, 85, 124, 1, NULL, NULL, NULL, '2026-04-01 07:36:56', NULL, NULL, 'Tapete-entrenador-desechable-soft-7-pza-para-mascotas', 0, 0);
