INSERT INTO `ecom_productos` VALUES (1119, NULL, 'producto', '7501556461206', 0x4152452D3032, 'FL4120', 5.00, 'Arena sin aroma fancy 7kg para gatos', '<p>Arena para gatos fancy</p><p><br></p><p>Descripción:</p><p>Podrás minimizar los olores de las heces de tu gato, es fácil de limpiar gracias a sus alto nivel de aglutinamiento y bajo nivel de polvo.</p><p><br></p><p>Hecha de bentonita granulada, ideal para que se aglutine con las heces u orina de la mascota. Fácil de retirar los residuos y mantener la casa más limpia</p><p>Alto nivel de aglutinamiento</p><p>Diariamente, retire los terrones que se forman al encapsularse las heces y orina del gato y deposítelos en la basura, jamás en el inodoro</p><p><br></p><p><br></p>', 0, 178, 124, 1, NULL, NULL, NULL, '2026-03-07 05:55:12', NULL, NULL, 'Arena-sin-aroma-fancy-7kg-para-gatos', 0, 0);
