INSERT INTO `ecom_productos` VALUES (1127, NULL, 'producto', '7501556438543', 0x455350412D3031, 'FL3854', 0.00, 'Espuma para baño en seco para gato', '<p>Espuma para baño em seco para gato</p><p><br></p><p>Descripción:</p><p>Está formulado para brindar una limpieza rápida y efectiva a los gatos sin mojar su pelaje. Elimina suciedad, exceso de grasa, malos olores y contiene proteínas vegetales de soya, avena y trigo para resaltar el brillo, suavidad y color natural del pelo dejando una agradable fragancia.</p><p><br></p>', 0, 198, 124, 1, NULL, NULL, NULL, '2025-12-26 08:37:22', NULL, NULL, 'Espuma-para-bano-en-seco-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1128, NULL, 'producto', '7501556438536', 0x455350412D3032, 'FL3853', 5.00, 'Espuma repelente para baño en seco para perro', '<p>Espuma para baño em seco para gato</p><p><br></p><p>Descripción:</p><p>Está formulado para brindar una limpieza rápida y efectiva al perro sin mojar su pelaje. Elimina suciedad, así como para repepeler las pulgas gracias al extracto de neem contenido dejando una agradable fragancia.</p><p><br></p>', 0, 280, 124, 1, NULL, NULL, NULL, '2025-12-26 08:38:00', NULL, NULL, 'Espuma-repelente-para-bano-en-seco-para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (1129, NULL, 'producto', '7501556439960', 0x455350412D3033, 'FL3996', 0.00, 'Baño en seco espuma para perros y gatos ', '<p>Baño en seco espuma para perros y gatos</p><p><br></p><p>Descripción:</p><p>Está formulado para brindar una limpieza rápida y efectiva a los gatos y perros sin mojar su pelaje. Elimina suciedad, exceso de grasa, malos olores y contiene fitoceramidas para un brillo deslumbrante.dejando una agradable fragancia.</p><p><br></p>', 0, 190, 124, 1, NULL, NULL, NULL, '2025-12-26 08:38:50', NULL, NULL, 'Bano-en-seco-espuma-para-perros-y-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1130, NULL, 'producto', '7501556439090', 0x524550452D3033, 'FL3909', 5.00, 'Repelente dry entrenador para perro ', '<p>Repelente dry entrenador para perro</p><p><br></p><p>Descripción:</p><p>Uso de interiores eficaz para delimitar las áreas que el perro debe respetar, evita que el perro orine o defeque en una área prohibida para irlos entrenando.</p>', 0, 70, NULL, 1, NULL, NULL, NULL, '2024-04-04 22:48:59', NULL, NULL, 'Repelente-dry-entrenador-para-perro-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1131, NULL, 'producto', '7501556498639', 0x544152452D3031, 'FL9861', 0.00, 'Tapete refrescante mediano ', '<p>Tapete refrescante mediano</p><p><br></p><p>Descripción:</p><p>Tapete refrescante mediano cool auto enfriamiento. no necesita refrigeración fácil de transportar y de limpiar no toxixo doble vista.</p><p>Gira el tapete o suspende su uso unos minutos cuando pierda frescura para que vuelva a enfriarse o colócalo en el refrigerador para enfriarlo aún más.</p><p>Puedes utilizar el tapete en la cama de tu mascota, la transportadora, sillones, piso, asiento del auto, entre otros, de fácil limpieza y mantenimiento.</p><p><br></p>', 0, 350, 0, 1, NULL, NULL, NULL, '2025-03-06 12:23:14', NULL, NULL, 'Tapete-refrescante-mediano-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1132, NULL, 'producto', '7501556498622', 0x544152452D3032, 'FL9862', 5.00, 'Tapete refrescante chico', '<p>Tapete refrescante mediano</p><p><br></p><p>Descripción:</p><p>Tapete refrescante mediano cool auto enfriamiento. no necesita refrigeración fácil de transportar y de limpiar no toxixo doble vista.</p><p>Gira el tapete o suspende su uso unos minutos cuando pierda frescura para que vuelva a enfriarse o colócalo en el refrigerador para enfriarlo aún más.</p><p>Puedes utilizar el tapete en la cama de tu mascota, la transportadora, sillones, piso, asiento del auto, entre otros, de fácil limpieza y mantenimiento.</p><p><br></p>', 0, 240, 0, 1, NULL, NULL, NULL, '2025-03-06 12:51:07', NULL, NULL, 'Tapete-refrescante-chico', 0, 0);
