INSERT INTO `ecom_productos` VALUES (1134, NULL, 'producto', '7501325468542', 0x504150492D3035, '8436539505136-800', 0.00, 'Alimento Pasta Legazin Procría para pajaros', '<p><span style=\"color: rgb(102, 102, 102);\">PASTA PARA LA ACTIVIDAD DE CRIA O REPORDUCCION DE AVES DE ORNATO</span></p><p><span style=\"color: rgb(102, 102, 102);\">IDEAL PARA PERIQUITOS Y CANARIOS</span></p><p><span style=\"color: rgb(102, 102, 102);\">NO DA COLOR, NO PIGMENTA PLUMAS</span></p><p><span style=\"color: rgb(102, 102, 102);\">NO CONFUNDIR: ESTE PRODUCTO NO ES UNA PASTA PARA EMBUCHAR CRIAS DE AVES.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">PASTA DE CRIA LEGAZIN / IMPORTADA DE ESPAÑA</span></p><p><span style=\"color: rgb(102, 102, 102);\">PROTEINA BRUTA 21.5%</span></p><p><span style=\"color: rgb(102, 102, 102);\">CADUCIDAD: MARZO 2024.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Pasta para Canarios ideal para complementar su alimentanción en época de Postura y Muda por su alto aporte proteínico. Hecha de los mejores cereales, semillas, productos de panadería, extracto de proteína vegetal, grasas, aceites, lisina, meteonina, ajo, y AMINESENT que es una mezcla única de extractos de plantas naturales con efectos terapéuticos y aminoácidos esenciales. Estos últimos son necesarios para todos los procesos físicos que afectan al organismo de nuestras aves, entre ellos: crecimiento muscular, producción de energía, formación de la pluma y buen funcionamiento del sistema nervioso.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">MODO DE EMPLEO: Administrar a libre disposición durante la temporada de cría o como aporte extra alimentario. CONSERVAR EN LUGAR FRESCO Y SECO.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">VITAMINAS:A, D3, E, K, B1, B2, B6, B12, C, Biotina, Cobre, Acido Fólico, Acido Nicótico, Acido Pantoténico y Cloruro de Colina. OLIGOELEMENTOS:Hierro, Yodo, Cobalto, Magnesio, Zinc y Selenio. AMINOACIDOS:Isoleucina, Valina, Leucina, Metionina, Lisina, Tritofano, Fenilalanina y Treonina. HECHO EN ESPAÑA.</span></p>', 0, 225, 124, 1, NULL, NULL, NULL, '2026-04-08 07:37:38', NULL, NULL, 'Alimento-Pasta-Legazin-Procria-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1135, NULL, 'producto', '4602533783465', 0x414C412D3131, '4602533783465', 0.00, 'Alimento Balanceado Rio Para Cotorrita, Ninfa y Agaporni 1kg', '<p><span style=\"color: rgb(102, 102, 102);\">Alimento Balanceado Para Loros Medianos, Cotorritas, Ninfas y Agapornis De Talla Mediana 1 Kilo. MARCA: RIO</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">RIO Alimento para Loros medianos. Alimento diario — es una mezcla especialmente seleccionada de granos y semillas saludables que gusta mucho a los periquitos, cacatúas y otro tipo de aves grandes. La amplia variedad de ingredientes garantiza que los pájaros obtengan todas las sustancias nutricionales necesarias.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">INGREDIENTES: mijo amarillo, mijo rojo, alpiste ,avena pelada, alforfón, sorgo blanco, cártamo, pipas de girasol, arroz paddy, mijo negro, semillas de lino, avena, semillas de negrillo, semillas saludables, bayas de serbal deshidratadas, zanahoria seca, algas, gluconato de calcio.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">INSTRUCCIONES:</span></p><p><span style=\"color: rgb(102, 102, 102);\">- La dosis diaria del alimento RIO para Loros medianos es de 20-30 g.</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Recuerde que durante la muda el ave necesita una dieta especial</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Guardar en un lugar seco.</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Importante: Además de los alimentos principales, los pájaros necesitan una mezcla constante de arenas y minerales (utiliza la mezcla de arenilla y minerales de RIO para todo tipo de pájaros).</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Asegúrate de que tu pájaro tiene suficiente comida y agua fresca.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">HECHO EN ALEMANIA.</span></p>', 0, 185, 124, 1, NULL, NULL, NULL, '2025-07-17 08:28:39', NULL, NULL, 'Alimento-Balanceado-Rio-Para-Cotorrita,-Ninfa-y-Agaporni-1kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1136, NULL, 'producto', '7501325468542', 0x414C412D3132, '4602533784370', 0.00, 'Palanqueta Barra De Frutas para pajaros ', '<p><span style=\"color: rgb(102, 102, 102);\">RIO Barritas para Loros grandes con fruta y bayas</span></p><p><span style=\"color: rgb(102, 102, 102);\">2 piezas de 90 gramos cada una.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">La golosina, premio, snack para loros grandes con fruta y bayas.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">INGREDIENTES: mijo amarillo, girasol, alpiste, mijo blanco, productos de panadería, avena pelada, conchas de ostras molidas, frutas deshidratadas (plátano, manzana, piña, naranja), panizo rojo, alforfón, semillas saludables, cártamo, bayas (pasas, enebro), derivados de origen vegetal, mijo rojo, sorgo, cacahuetes, trigo, inulina, vitamina A, vitamina D3 y vitamina E.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">VENTAJAS:</span></p><p><span style=\"color: rgb(102, 102, 102);\">- No aportan azúcar dañina pues NO TIENEN MIEL</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Ingredientes de alta calidad para una dieta balanceada especial para nuestras aves</span></p><p><span style=\"color: rgb(102, 102, 102);\">- 6 veces horneadas para obtener una textura crujiente.</span></p><p><span style=\"color: rgb(102, 102, 102);\">- 6 capas para un mayor gusto y placer de la mascota</span></p><p><span style=\"color: rgb(102, 102, 102);\">- El centro es una rama redondeada de haya dura para el cuidado del pico</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Embalaje hermético y caja para mayor protección</span></p><p><span style=\"color: rgb(102, 102, 102);\">- Con gancho. Montaje conveniente para cualquier jaula .</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">HECHO EN ALEMANIA.</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-01-28 23:09:54', NULL, NULL, 'Palanqueta-Barra-De-Frutas-para-pajaros-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1137, NULL, 'producto', '7501325468542', 0x434F4D452D3032, 'LINLIN57218', 1.00, 'Comedero tolva Para Aves, Canarios, Periquitos', '<p><span style=\"color: rgb(102, 102, 102);\">COMEDERO TOLVA KIKI KOMODHOR</span></p><p><span style=\"color: rgb(102, 102, 102);\">CON CHAROLA PARA RESIDUOS / CASCARAS DE SEMILLAS</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Este comedero tipo tolva es apto tanto para interiores como para exteriores. Cuenta con ganchos de pasta en la parte posterior que permiten encajarlo dentro de cualquier jaula o pajarera. En la parte frontal, tiene otros dos soportes para encajarlo en cualquier puerta o hueco que disponga la jaula en la parte exterior.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Es ideal para aves de ornato de talla pequeña, como Canarios, Jilgueros, Periquitos australianos y finches.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Este comedero es muy popular y está fabricado en España.</span></p>', 0, 165, NULL, 1, NULL, NULL, NULL, '2024-11-12 07:53:26', NULL, NULL, 'Comedero-tolva-Para-Aves,-Canarios,-Periquitos', 0, 0);
INSERT INTO `ecom_productos` VALUES (1138, NULL, 'producto', '8413856517608-b1', 0x434F4D452D3033, '52208', 5.00, 'Comedero Para aves con Enganche De Alambre', '<p><span style=\"color: rgb(102, 102, 102);\">Comedero plástico para aves medianas o grandes hecho de plástico virgen con enganche de alambre adaptable a cualquier tipo de jaula.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para aves medianas y grandes. Perfecto para Loros.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Medidas:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Frente 10cm Fondo 7,5cm alto 6cm</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">IMPORTADO DE ESPAÑA</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-11-12 08:12:53', NULL, NULL, 'Comedero-Para-aves-con-Enganche-De-Alambre', 0, 0);
INSERT INTO `ecom_productos` VALUES (1139, NULL, 'producto', '7501325468542', 0x434F4D452D3034, '8413856522084', 6.00, 'Comedero para aves Universal Interno/externo ', '<p><span style=\"color: rgb(102, 102, 102);\">COMEDERO UNIVERSAL</span></p><p><br></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Su característica es ser universal ya que es apropiado para cualquier tipo de Jaula. Se puede colocar e manera externa colgado de alguna puerta o ventana o de manera interna con sus ganchos plásticos. Tiene posaderas para mayor comodidad de tu ave y lleva una tapa para evitar que tu ave entre al comedero y tire o ensucie su comida.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Adecuado para: Pequeños periquitos australianos, canarios, jilgueros, finches, pinzones, diamantes, lady gouldain aves de talla XS-S</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">SIN DUDA, EL COMEDERO MAS VENDIDO.</span></p><p><span style=\"color: rgb(102, 102, 102);\">HECHO EN ESPAÑA.</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-11-12 08:00:47', NULL, NULL, 'Comedero-para-aves-Universal-Internoexterno-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1140, NULL, 'producto', '7502261581838', 0x464649502D3131, 'OCL-1500', 5.00, 'Filtro interno 1500 ', '<p>Filtro interno cabeza de poder 1500</p><p><br></p><p>Descripción:</p><p>Filtro interno cabeza de poder 1500</p>', 0, 399, NULL, 1, NULL, NULL, NULL, '2024-11-12 08:53:12', NULL, NULL, 'Filtro-interno-1500-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1141, NULL, 'producto', '7501325468542', 0x414C49582D3033, 'TP-11614', 3.00, 'Alimento axolotl para ajolote135gr', '<p><span style=\"color: rgb(102, 102, 102);\">AXOLOTL STICKS alimento para el axolote </span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">y otros anfibios acuáticos.Alimento especial, con alto contenido de proteínas en forma de los sticks que se hunden, destinado para el axolote mexicano, gallipato, rana africana de uñas y otros anfibios acuáticos, cuya dieta se conforma de carne de animales. La riqueza de los ingredientes de origen animal son peces, moluscos y crustáceos y constituyen una fuente de proteínas de alta calidad fácilmente digerible. La composición equilibrada de vitaminas y microelementos, hace que el alimento AXOLOTL STICKS, suministrado de forma regular garantice adecuado crecimiento y desarrollo de los anfibios. El suplemento de astaxantina y extracto del pimentón intensifican la coloración de los animales. El enriquecimiento de los alimentos con inmunoestimulador natural – beta glucano, mejora el sistema inmunológico de los anfibios, ayuda en los procesos de regeneración en caso de mordidas por cualquier especie del acuario.</span></p>', 0, 270, 124, 1, NULL, NULL, NULL, '2025-08-26 18:20:29', NULL, NULL, 'Alimento-axolotl-para-ajolote135gr', 0, 0);
