INSERT INTO `ecom_productos` VALUES (1150, NULL, 'producto', 'ALIP01AZ80118', 0x414C492D30314D49, 'AZ80118', 5.00, 'Alimento micropélet flotante Azoo 2 en 1 mediano', '<p>Micropélet flotante Azoo 2 en 1 mediano</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripción:</p><p>Los peces de pequeño tamaño precisan unas condicciones de nutrición propias, siendo sus peculiaridades más notables su acelerado metabolismo y unas bocas tamaño muy pequeño. se adapta con éxito a estas necesidades, teniendo un comportamiento flotate en el agua para maximizar las probabilidades de que el máximo de partículas sean engullidas.</p>', 0, 86, NULL, 1, NULL, NULL, NULL, '2024-04-13 13:54:28', NULL, NULL, 'Alimento-micropelet-flotante-Azoo-2-en-1-mediano', 0, 0);
INSERT INTO `ecom_productos` VALUES (1151, NULL, 'producto', 'ALIP01AZ80083', 0x414C492D30314D49, 'AZ80083', 5.00, 'Alimento micropélet flotante Azoo 2 en 1 chico', '<p>Micropélet flotante Azoo 2 en 1 chico</p><p>Cantidad: 30 ml</p><p><br></p><p>Descripción:</p><p>Los peces de pequeño tamaño precisan unas condicciones de nutrición propias, siendo sus peculiaridades más notables su acelerado metabolismo y unas bocas tamaño muy pequeño. se adapta con éxito a estas necesidades, teniendo un comportamiento flotate en el agua para maximizar las probabilidades de que el máximo de partículas sean engullidas.</p>', 0, 55, NULL, 1, NULL, NULL, NULL, '2024-04-13 13:52:11', NULL, NULL, 'Alimento-micropelet-flotante-Azoo-2-en-1-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (1152, NULL, 'producto', '7501556484649', 0x5241532D3038, 'FL8464', 2.00, 'Rascadero mueble ankara 240cm', '<p><span style=\"color: rgb(50, 51, 56);\">Los muebles para gato o conocido como (arbol) están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Ajuste correctamente cada apartado del mueble. Limpie con regularidad, puede usar un limpiador enzimático de limpieza superior.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">• El enriquecimiento ambiental permite estimular cognitivamente a los gatos </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El gato podrá rascar para afilar sus garras </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El juego ayudará al instinto de caza </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Las casas brindan zonas de descanso y protección solar. </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Se puede rociar con catnip para estimular el juego y la curiosidad</span></p><p><br></p><p>Características</p><p><strong>Especie</strong></p><p>Gatos</p><p><strong>Medidas</strong></p><p>60 cm x 40 cm x 240cm</p>', 0, 3550, 124, 1, NULL, NULL, NULL, '2026-01-27 09:03:47', NULL, NULL, 'Rascadero-mueble-ankara-240cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1153, NULL, 'producto', '7501325468542', 0x5241532D3039, 'FL8462', 3.00, 'Rascadero mueble tripoli 143cm ', '<p><span style=\"color: rgb(50, 51, 56);\">Los muebles para gato conociodo como (arbol) están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Ajuste correctamente cada apartado del mueble. Limpie con regularidad, puede usar un limpiador enzimático de limpieza superior.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">• El enriquecimiento ambiental permite estimular cognitivamente a los gatos </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El gato podrá rascar para afilar sus garras </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El juego ayudará al instinto de caza </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Las casas brindan zonas de descanso y protección solar. </span></p><p><span style=\"color: rgb(50, 51, 56);\">﻿• Se puede rociar con catnip para estimular el juego y la curiosidad</span></p><p><br></p><p>Características</p><p><strong>Especie</strong></p><p>Gatos</p><p><br></p>', 0, 1899, 124, 1, NULL, NULL, NULL, '2025-12-05 07:44:37', NULL, NULL, 'Rascadero-mueble-tripoli-143cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1154, NULL, 'producto', '7501325468542', 0x5241532D3130, 'FL8461', 3.00, 'Rascadero de mueble para gato 140cm ', '<p><span style=\"color: rgb(50, 51, 56);\">Los muebles o conocico como (arbol) para gato están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Ajuste correctamente cada apartado del mueble. Limpie con regularidad, puede usar un limpiador enzimático de limpieza superior.</span></p><p><span style=\"color: rgb(50, 51, 56);\">• El enriquecimiento ambiental permite estimular cognitivamente a los gatos </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El gato podrá rascar para afilar sus garras </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El juego ayudará al instinto de caza </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Las casas brindan zonas de descanso y protección solar. </span></p><p><span style=\"color: rgb(50, 51, 56);\">﻿• Se puede rociar catnip para gatos para estimular el juego y la curiosidad</span></p><p><br></p><p>Características</p><p><strong>Especie</strong></p><p>Gatos</p><p><br></p>', 0, 1799, 124, 1, NULL, NULL, NULL, '2025-03-30 22:09:13', NULL, NULL, 'Rascadero-de-mueble-para-gato-140cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1155, NULL, 'producto', '7501556411560', 0x4E45552D3033, 'FL1119', 5.00, 'Neutra betta chico', '<p>Neutra betta chico</p><p><br></p><p>Descripción:</p><p><br></p><p>Neutra Beta, acondicionador para agua dulce</p><p>Elimina cloro, protege las mucosas de los peces y detoxifica metales pesados</p><p>Agregue 1 ml por cada 10 litros de agua (2 gotas por litro).Para restablecer las mucosas dañadas de los peces, agregue 2 ml por cada 10 litros de agua (4 gotas por litro) excelente para la adaptación de peces de agua dulce</p><p>Úselo al instalar en un nuevo acuario y con cada cambio de agua</p><p>Rango de edad: Todas las etapas de la vida</p><p><br></p>', 0, 25, NULL, 1, NULL, NULL, NULL, '2024-04-11 20:20:25', NULL, NULL, 'Neutra-betta-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (1156, NULL, 'producto', 'BAC05EXTRA', 0x4241432D3035, 'BAC-05', 2.00, 'Bacteria co extra grande', '<p>Bacteria co extra grande</p><p>Cantidad: 480 ml</p><p><br></p><p>Descripción:</p><p>Es un producto diseñado para ayudarlo con un ciclo biológico y de esta forma prevenir mortandad y mejorar el entorno de sus peces.</p><p><br></p><p>Ciclo es una forma de ayudarlo a mantener su ciclo bacteriano de forma estable ya que es un compendio de aminoácidos, enzimas, bacterias y toda una gama de compuestos enfocados a un pronto proliferación bacteriana.</p><p><br></p><p>Agítese antes de usar, use una tapita 5 ml cada 40 Lts 2 o tres veces por semana al hacer cambios de agua o al iniciar con una nueva pecera.</p><p><br></p>', 0, 0, NULL, 0, NULL, NULL, NULL, '2024-04-11 20:53:05', NULL, NULL, '', 0, 0);
INSERT INTO `ecom_productos` VALUES (1157, NULL, 'producto', '7502278912007', 0x4149522D3035, '4261', 0.00, 'Bomba de aire doble salida aqua', '<p>Bomba de aire oxigeno doble salida aqua</p><p>Voltaje:110- 120 v</p><p>Potencia: 4.2 w</p><p>Frecuencia: 50-60 Hz</p><p><br></p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Silenciosa con alta tecnología, Incrementando la oxigenación del acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alto rendimiento con diseño ultra compacto de fácil colocación con salida unica.</span></p><p><br></p><p>Modo de empleo:</p><p><span style=\"color: rgb(102, 102, 102);\">No sumerja la bomba de aire, dentro del agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Debe ser colocada por encima del nivel del agua.</span></p>', 0, 220, 124, 1, NULL, NULL, NULL, '2026-03-03 23:06:38', NULL, NULL, 'Bomba-de-aire-doble-salida-aqua', 0, 0);
INSERT INTO `ecom_productos` VALUES (1158, NULL, 'producto', '7501556491166', 0x4149522D3036, 'FL8916', 5.00, 'Bomba de aire de baterías', '<p>Bomba de aire oxigeno de</p><p>Baterias: 2 tamaño D (no incluidas)</p><p><br></p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Silenciosa con alta tecnología, Incrementando la oxigenación del acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alto rendimiento con diseño ultra compacto de fácil colocación con una salioda unica.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Incluye: Manguera de silicón 50cm de largo</span></p><p>Piedra aireadora: 2.5cm de largo</p><p><br></p><p>Modo de empleo:</p><p><span style=\"color: rgb(102, 102, 102);\">No sumerja la bomba de aire, dentro del agua.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Debe ser colocada por encima del nivel del agua.</span></p>', 0, 245, 124, 1, NULL, NULL, NULL, '2025-03-22 06:14:30', NULL, NULL, 'Bomba-de-aire-de-baterias', 0, 0);
INSERT INTO `ecom_productos` VALUES (1159, NULL, 'producto', '7502234335109', 0x414C492D313042, 'TP-3510', 20.00, 'Alimento betta sun', '<p>Alimento pra betta</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Alimentación más nutritiva para tu pez betta.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Es recomendable para cuando se quiere reproducir al pez, en especial para la hembra.</span></p><p><br></p>', 0, 25, 124, 1, NULL, NULL, NULL, '2025-07-11 13:27:07', NULL, NULL, 'Alimento-betta-sun', 0, 0);
INSERT INTO `ecom_productos` VALUES (1161, NULL, 'producto', '015561108010', 0x4149522D3038, 'HA801', 5.00, 'Bomba de aire 801', '<p>Bomba de aire 801</p><p>Salidas: 1</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Las bombas de aire elite son una fuente confiable de aire para artículos operados por aire como las rocas vivas ELITE, las burbujas de aire elite, los adornos accionados por aire, o los separadores de urea que funcionan con aire para añadir movimiento u oxigeno a cualquier acuario.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Cubierta para amortiguar el ruido con la placa de la base impide la vibración y el movimiento de la bomba.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Bobinas que no se calientan de larga vida útil.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Bisagra de brazo oscilante integrada al ensamble del diafragma Tensible Flex.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ensamble de la salida de aire integrado al cuerpo de la válvula.</span></p>', 0, 270, 124, 1, NULL, NULL, NULL, '2025-12-26 09:06:00', NULL, NULL, 'Bomba-de-aire-801', 0, 0);
