INSERT INTO `ecom_productos` VALUES (1164, NULL, 'producto', '01556117868', 0x4B4950482D3031, 'KIPH-01', 5.00, 'Kit medidor de ph para acuario ', '<p>Medidor de ph para acuario</p><p><br></p><p>Descripción:</p><p>El pH del agua es uno de los parámetros más importantes que influyen en la salud del acuario.</p><p>Numerosos procesos biológicos dependen de este valor.</p><p>El pH desempeña una importante función en los sistemas sanguíneos de los organismos acuáticos.</p><p>Las fluctuaciones muy marcadas pueden afectar gravemente.</p><p>Es recomendable analizar el agua semanalmente a diferentes horas para detectar cambios que puedan afectar el bienestar de los habitantes del acuario y la mejor manera es con este medidor de pH de Hagen. Analice siempre el pH antes de introducir nuevos peces.</p><p><br></p>', 0, 310, NULL, 1, NULL, NULL, NULL, '2024-04-11 23:23:47', NULL, NULL, 'Kit-medidor-de-ph-para-acuario-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1165, NULL, 'producto', '7502217850186', 0x414C49544F2D3132, 'B-300', 5.00, 'Alimento mini bolitas para tortuga ', '<p>Alimento mini bolitas para tortuga</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Alimento para tortugas gdes a xl. Características: tortugueta jumbo es un alimento balanceado, especialmente formulado para proporcionar todos los nutrientes esenciales para las tortugas acuáticas. esta elaborado con ingredientes 100 % naturales para evitar las enfermedades mas típicas observadas en estos animalitos.</span></p>', 0, 35, 124, 1, NULL, NULL, NULL, '2025-08-24 14:00:46', NULL, NULL, 'Alimento-mini-bolitas-para-tortuga-', 0, 0);
