INSERT INTO `ecom_productos` VALUES (1167, NULL, 'producto', '7500211004673', 0x414C49434F2D3230, 'Q829', 5.00, 'Alimento de hojuela color flakes 20gr', '<p>Alimento de hojuela color flakes</p><p><br></p><p>Descripción:</p><p>Alimento en hojuelas color flakes ha sido formulado para intensificar los vivos colores de los peces de acuario, los ingredientes especiales del alimento hacen de este la vía segura para que sus peces adquieran el máximo brillo e intensidad en los colores propios de su especie.</p>', 0, 60, 124, 1, NULL, NULL, NULL, '2025-08-24 15:29:58', NULL, NULL, 'Alimento-de-hojuela-color-flakes-20gr', 0, 0);
