INSERT INTO `ecom_productos` VALUES (1169, NULL, 'producto', '7501556479713', 0x464C43432D, 'FL7971', 5.00, 'Filtro interno Aqua flow 10 ', '<p>Filtro interno flow 10</p><p>Medidas: 12 x 6 x 20cm</p><p>Potencia: 5 w</p><p>Voltaje:110- 120 v</p><p>Frecuencia: 60Hz</p><p>Capacidad: 450 l/h</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Diseño compacto, completamente sumergible, proporciona filtración mecánica y biológica, montura ajustable para cualquier acuario, cartucho modular expandible, para uso en acuarios de agua dulce o marinos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendado para acuarios de 20 a 60 litros.</span></p>', 0, 260, NULL, 1, NULL, NULL, NULL, '2024-04-16 22:30:51', NULL, NULL, 'Filtro-interno-Aqua-flow-10-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1170, NULL, 'producto', '7501556479720', 0x464C43432D, 'FL7972', 5.00, 'Filtro interno flow 20', '<p>Filtro interno flow 20</p><p>Medidas:</p><p>Potencia: 6.5 w</p><p>Voltaje:127 v</p><p>Frecuencia: 60Hz</p><p>Capacidad: 750 l/h</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Diseño compacto, completamente sumergible, proporciona filtración mecánica y biológica, montura ajustable para cualquier acuario, cartucho modular expandible, para uso en acuarios de agua dulce o marinos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendado para acuarios de 60 a 150 litros.</span></p>', 0, 375, NULL, 1, NULL, NULL, NULL, '2024-04-19 19:51:02', NULL, NULL, 'Filtro-interno-flow-20', 0, 0);
INSERT INTO `ecom_productos` VALUES (1171, NULL, 'producto', '7501556479737', 0x464C4343, 'FL7973', 5.00, 'Filtro interno flow 30', '<p>Filtro interno flow 30</p><p>Medidas: </p><p>Potencia: 19 w</p><p>Voltaje:120 v</p><p>Frecuencia: 60Hz</p><p>Capacidad: 1500 l/h</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Diseño compacto, completamente sumergible, proporciona filtración mecánica y biológica, montura ajustable para cualquier acuario, cartucho modular expandible, para uso en acuarios de agua dulce o marinos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Recomendado para acuarios de 150 a 400 litros.</span></p>', 0, 450, NULL, 1, NULL, NULL, NULL, '2024-04-12 00:42:56', NULL, NULL, 'Filtro-interno-flow-30', 0, 0);
INSERT INTO `ecom_productos` VALUES (1172, NULL, 'producto', '04679816159', 0x414C492D5445473735, 'AQ-16159', 0.00, 'Alimento granulado tetra color para peces', '<p>Alimento tetra color granulado</p><p>Cantidad:75 gramos</p><p><br></p><p>Descripción:</p><p>Fórmula patentada ProCare que favorece el buen funcionamiento del sistema inmunológico del pez para una salud óptima y larga vida. Mezcla científicamente desarrollada de ingredientes altamente nutritivos, con vitaminas y minerales. Las hojuelas TetraMin de Tetra han sido desarrolladas especialmente para una fácil ingesta, gracias a su forma, textura y sabor. Dieta diseñada especialmente para resaltar los colores rosa, rojo y naranja de los peces de agua dulce.</p><p><br></p><p>Características</p><p>Fórmula avanzada, enriquecida con vitaminas y minerales.</p><p>Excelente textura y palatabilidad.</p><p>Perfeccionado para la óptima nutrición de peces.</p><p>Favorece la coloración intensa de los peces.</p><p>Alta digestibilidad.</p><p>No enturbia el agua.</p>', 0, 265, 124, 1, NULL, NULL, NULL, '2025-08-24 15:18:59', NULL, NULL, 'Alimento-granulado-tetra-color-para-peces', 0, 0);
INSERT INTO `ecom_productos` VALUES (1173, NULL, 'producto', '7501556461268', 0x5348412D3131, 'FL4126', 5.00, 'Shampoo con aromaterapia serenidad para perros ', '<p>Shampoo con aromaterapia serenidad</p><p>Cantidad: 250 ml</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Este shampoo con aromaterapia es ideal para situaciones de ansiedad, estrés o miedo en tu mascota. Su fórmula especial ayuda a calmar comportamientos causados por estímulos como ruidos fuertes o falta de sueño, proporcionando un baño de bienestar, equilibrio y tranquilidad.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Sin sulfatos ni parabenos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Hipoalergénico y de baja irritación.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Ingredientes suaves para el cuidado de la piel y el pelaje.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Sin fragancias sintéticas ni colorantes.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Contribuye a manejar reacciones ante estímulos externos intensos.</span></p><p><br></p>', 0, 155, NULL, 1, NULL, NULL, NULL, '2024-04-13 19:10:21', NULL, NULL, 'Shampoo-con-aromaterapia-serenidad-para-perros-', 0, 0);
