INSERT INTO `ecom_productos` VALUES (1181, NULL, 'producto', '7501556440768', 0x414C49424F2D3031, 'FL4076', 5.00, 'Snack botana para aves ', '<p>snack botana para aves</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">La mezcla de semillas, fruta y verdura de Redkite es un complemento adecuado para la alimentación de las aves de ornato, proporcionándoles un producto natural que les agrada y les aporta nutrientes beneficiosos.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Adicionado con pellets fortificados con vitaminas y minerales.</span></p>', 0, 116, NULL, 1, NULL, NULL, NULL, '2024-04-13 21:22:49', NULL, NULL, 'Snack-botana-para-aves-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1182, NULL, 'producto', '7501556440096', 0x414C494348492D3031, 'FL4009', 5.00, 'Alimento para chinchilla red ', '<p>Alimento para chichilla</p><p><br></p><p>Descripción:</p><p>Alimento para chinchilla RedKite, aporta los nutrientes necesarios para el óptimo desarrollo del roedor.</p><p>Adicionado con vitaminas y minerales para reforzar el sistema inmune y beneficiar la salud general de tu mascota.</p><p>Nutrición y sabor en un solo alimento balanceado que, sin duda, le encantará a la chinchilla.Harina de alfalfa como fuente de carbohidratos para un alto nivel de energía.</p><p>Alimento en forma de pellets balanceados para chinchilla.</p><p>Nutrición 100% completa para tu chinchilla.</p><p><br></p>', 0, 130, NULL, 1, NULL, NULL, NULL, '2024-04-13 21:20:29', NULL, NULL, 'Alimento-para-chinchilla-red-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1183, NULL, 'producto', 'TERA01METROCH', 0x544552412D3031, 'TERA-01', 5.00, 'Terrario suntu 100cm largo 30cm alto', '<p>Terrario de un metro suntu</p><p>Espesor: 6 mm</p><p>Marcos: aluminio</p><p>Material: cristal</p><p><br></p><p>Descripción:</p><p>Terrario de un metro bajito para iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha o izquierda para fácil limpieza y parte superior de malla metálica no corrosiva.</p>', 0, 2000, 124, 1, NULL, NULL, NULL, '2025-07-11 13:33:56', NULL, NULL, 'Terrario-suntu-100cm-largo-30cm-alto', 0, 0);
