INSERT INTO `ecom_productos` VALUES (1208, NULL, 'producto', '7501556439427', 0x455350412D3034, 'FL3942', 5.00, 'Espuma para baño en seco essential', '<p>Espuma para baño en seco essential</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">Es ideal cuando las mascotas que por muchas razones no pueden utilizar el agua en el baño. Es fácil y rápido de aplicar dejando el pelo de su mascota limpio y con un aroma agradable. El producto puede ser empleado en animales recién nacidos, cachorros, geriátricos, con cirugía, enfermos, con miedo al agua o incluso en épocas de frío. Este producto no sustituye el baño con agua.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Deja el pelo limpio y con aroma agradable.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No necesita agua para su uso.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Contiene extracto de Aloe vera para cuidar la piel de la mascota.</span></p><p><span style=\"color: rgb(33, 37, 41);\">No es tóxico.</span></p>', 0, 198, 124, 1, NULL, NULL, NULL, '2025-12-26 08:39:46', NULL, NULL, 'Espuma-para-bano-en-seco-essential', 0, 0);
INSERT INTO `ecom_productos` VALUES (1209, NULL, 'producto', '7501556490312', 0x524543542D3031, 'FL9031', 5.00, 'Correa rectractil grande ', '<p>Correa rectractil grande</p><p><br></p><p>Descripción:</p><p>Incluye botón de seguridad en el mango para ajustar la cuerda, bloqueando y desbloqueando su prolongación de acuerdo con las necesidades del paseo.</p><p>Mango y asa de plástico cómodas al manejo.</p><p>Cuerda de nailon de 5 m de longitud con resistencia a la tensión, durable.</p><p>Gancho metálico.</p><p>Hasta para 25 kg de peso.&nbsp;</p>', 0, 478, NULL, 1, NULL, NULL, NULL, '2024-04-26 23:20:28', NULL, NULL, 'Correa-rectractil-grande-', 0, 0);
