INSERT INTO `ecom_productos` VALUES (1211, NULL, 'producto', '7501556490213', 0x524543542D3033, 'FL9021', 5.00, 'Correa rectractil chica ', '<p>Correa rectractil chica</p><p><br></p><p>Descripción:</p><p>Incluye botón de seguridad en el mango para ajustar la cuerda, bloqueando y desbloqueando su prolongación de acuerdo con las necesidades del paseo.</p><p>Mango y asa de plástico cómodas al manejo.</p><p>Cuerda de nailon de 3 m de longitud con resistencia a la tensión, durable.</p><p>Gancho metálico.</p><p>Hasta para 12 kg de peso.&nbsp;</p>', 0, 358, NULL, 1, NULL, NULL, NULL, '2024-08-30 08:50:51', NULL, NULL, 'Correa-rectractil-chica-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1212, NULL, 'producto', '7501556491913', 0x4A5547472D3130, 'FL9191', 5.00, 'Paleta de catnip pluma', '<p>Paleta de catnip pluma</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">son uno de los juguetes naturales para gatos más exclusivos que puedes ofrecerle a tu felino. Los palitos de matatabi contienen aceites esenciales, que pueden liberar reacciones que estimula la secreción de hormonas en los gatos, haciéndolos más tranquilos, relajados y apetitosos. En conjunto con el catnip y las plumas, estimularán el juego y la curiosidad, liberando su estrés a través del juego.</span></p>', 0, 85, NULL, 1, NULL, NULL, NULL, '2024-04-29 19:42:49', NULL, NULL, 'Paleta-de-catnip-pluma', 0, 0);
INSERT INTO `ecom_productos` VALUES (1213, NULL, 'producto', '7501556487824', 0x4A55472D3332, 'FL8782', 5.00, 'Juguete pelota masticable geobola ', '<p>Pelota masticable geobola</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">Juguete masticable, suave y resistente, en forma de balón de futbol americano, ideal para satisfacer el instinto de morder de los perros. Posee un agradable textura, la cual fomenta su aceptación, que masajea sutilmente las encías y dientes mientras el perro lo manipula. Gracias a su material de fabricación, también es flotante, añadiendo diversión si le gusta jugar en el agua. Beneficios: Este juguete es ideal para perros activos, que requieren ejercitarse o que disfrutan de morder objetos.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Material: 100% TPR.</span></p>', 0, 140, NULL, 1, NULL, NULL, NULL, '2024-04-29 21:24:18', NULL, NULL, 'Juguete-pelota-masticable-geobola-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1214, NULL, 'producto', '7501556487763', 0x4A55472D3333, 'FL8776', 5.00, 'Juguete aro chico ', '<p>Pelota masticable geobola</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">Juguete masticable, suave y resistente, en forma de balón de futbol americano, ideal para satisfacer el instinto de morder de los perros. Posee un agradable textura, la cual fomenta su aceptación, que masajea sutilmente las encías y dientes mientras el perro lo manipula. Gracias a su material de fabricación, también es flotante, añadiendo diversión si le gusta jugar en el agua. Beneficios: Este juguete es ideal para perros activos, que requieren ejercitarse o que disfrutan de morder objetos.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Material: 100% TPR.</span></p>', 0, 157, NULL, 1, NULL, NULL, NULL, '2024-04-29 21:37:04', NULL, NULL, 'Juguete-aro-chico-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1215, NULL, 'producto', '750155472820', 0x4A55472D3334, 'FL7282', 5.00, 'Juguete de hilo con agarradera y pelota ', '<p>Juguete de hilo con agarradera y pelota </p><p><br></p><p>Descripción: Juguete<span style=\"color: rgb(33, 37, 41);\"> de hilo de algodón multicolor, con pelota tipo tenis, trenzado en la parte media y con agarradera de plástico. Fabricado de algodón que ejercita la mandíbula, fortalece las encías, limpia los dientes y entretiene a la mascota. Tiene agarradera de plástico que le permite interactuar con el perro, previniendo el estrés y el problema de mordisquear. con ventajas r</span>esistente, no tóxico, duradero, lavable.</p><p>Ayuda a la mascota a tener mayor actividad física y a eliminar la ansiedad de la detención de los cachorros.</p><p><br></p>', 0, 90, NULL, 1, NULL, NULL, NULL, '2024-04-29 21:53:14', NULL, NULL, 'Juguete-de-hilo-con-agarradera-y-pelota-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1216, NULL, 'producto', '750155472349', 0x4A55472D3335, 'FL7234', 5.00, 'Juguete de cuerda doble pelota ', '<p>Juguete de cuerda doble pelota </p><p><br></p><p>Descripción: Juguete<span style=\"color: rgb(33, 37, 41);\"> de hilo de algodón multicolor, con pelota tipo tenis, trenzado en la parte media y con agarradera de plástico. Fabricado de algodón que ejercita la mandíbula, fortalece las encías, limpia los dientes y entretiene a la mascota. Tiene agarradera de plástico que le permite interactuar con el perro, previniendo el estrés y el problema de mordisquear. con ventajas r</span>esistente, no tóxico, duradero, lavable.</p><p>Ayuda a la mascota a tener mayor actividad física y a eliminar la ansiedad de la detención de los cachorros.</p><p><br></p>', 0, 85, NULL, 1, NULL, NULL, NULL, '2024-04-29 21:59:24', NULL, NULL, 'Juguete-de-cuerda-doble-pelota-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1217, NULL, 'producto', '750155472868', 0x4A55472D3336, 'FL7282', 5.00, 'Juguete de hilo con soporte ', '<p>Juguete con hilo con soporte</p><p><br></p><p>Descripción: Juguete<span style=\"color: rgb(33, 37, 41);\"> de hilo de algodón multicolor, con pelota tipo tenis, trenzado en la parte media y con agarradera de plástico. Fabricado de algodón que ejercita la mandíbula, fortalece las encías, limpia los dientes y entretiene a la mascota. Tiene agarradera de plástico que le permite interactuar con el perro, previniendo el estrés y el problema de mordisquear. con ventajas r</span>esistente, no tóxico, duradero, lavable.</p><p>Ayuda a la mascota a tener mayor actividad física y a eliminar la ansiedad de la detención de los cachorros.</p><p><span style=\"color: rgb(33, 37, 41);\">.</span></p>', 0, 87, NULL, 1, NULL, NULL, NULL, '2024-04-29 22:37:18', NULL, NULL, 'Juguete-de-hilo-con-soporte-', 0, 0);
