INSERT INTO `ecom_productos` VALUES (1219, NULL, 'producto', '7501556498677', 0x544152452D3034, 'FL9867', 5.00, 'Tapete refrescante grande sandia ', '<p>Tapete refrescante grande sandia</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">para perros son una excelente opción para mantener a tu mascota fresca y cómoda en los días calurosos. Estos tapetes están diseñados con un material especial que ayuda a disipar el calor corporal de tu perro y a mantenerlo fresco, sin ser necesario el uso de enfriadores extras pero si lo requieres puede ser refrigerado. Además, son fáciles de limpiar y se pueden usar tanto en interiores como exteriores.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios </span></p><p><span style=\"color: rgb(33, 37, 41);\">Auto enfriamiento</span></p><p><span style=\"color: rgb(33, 37, 41);\">Práctico de transportar y limpiar</span></p><p><span style=\"color: rgb(33, 37, 41);\">No tóxico</span></p><p><span style=\"color: rgb(33, 37, 41);\">Brinda comodidad y frescura</span></p>', 0, 550, 0, 1, NULL, NULL, NULL, '2025-03-06 12:54:17', NULL, NULL, 'Tapete-refrescante-grande-sandia-', 0, 0);
