INSERT INTO `ecom_productos` VALUES (1311, NULL, 'producto', '7501556482782', 0x4A55472D3338, 'FL8278', 2.00, 'Juguete pelotas de tenis con squeaker ', '<p>Pelota de tennis con diseño mediana</p><p><br></p><p>Descripción:</p><p>Pelotas de tennis deportivas set de pelotas con divertidos diseños que podrán a prueba las habilidades y agilidad de tu canino, con su alto impacto lo tendránatento a todo momento. Adecuadas para juegos de búsqueda qué ejerciten sus músculos y destreza con sonido al apretar o morder la pelota.</p><p><br></p>', 0, 440, NULL, 1, NULL, NULL, NULL, '2024-07-09 06:06:12', NULL, NULL, 'Juguete-pelotas-de-tenis-con-squeaker-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1312, NULL, 'producto', '7501556484991', 0x4A55472D3339, 'FL8499', 2.00, 'Juguete tablero interactivo ', '<p>Juguete tablero interactivo</p><p><br></p><p>Descripción:</p><p>Es un juguete para mascotas tablero interactico para poner premios que ayuda a mejorar su destreza mental. El juguete ofrece la oprtunidad de buscar premios debajo de las piezas, lo que lo hace divertido y estimulate, es una excelente manera de mantener a tu mascota entretenido y activo, además de fomentar su destreza cognitiva guiado por sus sentidos.</p><p><br></p><p><br></p>', 0, 299, NULL, 1, NULL, NULL, NULL, '2024-07-09 06:55:16', NULL, NULL, 'Juguete-tablero-interactivo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1313, NULL, 'producto', '7501556439748', 0x5348412D3133, 'FL3974', 5.00, 'Shampoo con acondiccionador 2 en 1 grande ', '<p>Shampoo y acondiccionador 2 en 1 grande</p><p><br></p><p>Descripción:</p><p>El shampoo y acondiccionador 2 en 1 limpia y suaviza el pelo al mismo tiempo, proporcionándole brillo y sedosidad al tacto. no irrita a piel ni los ojos del perro.</p><p><br></p><p>Ventajas: limpia y suaviza facilitando el cepillado proporciona brillo y sedosidad.</p><p><br></p>', 0, 100, NULL, 1, NULL, NULL, NULL, '2024-08-17 00:23:39', NULL, NULL, 'Shampoo-con-acondiccionador-2-en-1-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1314, NULL, 'producto', '7501556439649', 0x5348412D3134, 'FL3964', 5.00, 'Shampoo con acondiccionador 2 en 1 chico', '<p>Shampoo y acondiccionador 2 en 1 chico</p><p><br></p><p>Descripción:</p><p>El shampoo y acondiccionador 2 en 1 limpia y suaviza el pelo al mismo tiempo, proporcionándole brillo y sedosidad al tacto. no irrita a piel ni los ojos del perro.</p><p><br></p><p>Ventajas: limpia y suaviza facilitando el cepillado proporciona brillo y sedosidad.</p><p><br></p>', 0, 60, NULL, 1, NULL, NULL, NULL, '2024-08-17 00:23:55', NULL, NULL, 'Shampoo-con-acondiccionador-2-en-1-chico', 0, 0);
