INSERT INTO `ecom_productos` VALUES (1320, NULL, 'producto', '7501556439007', 0x524547412D3031, 'FL3900', 5.00, 'Repelente natural para gatos', '<p>Repelente natural para gatos</p><p><br></p><p><span style=\"color: rgb(94, 98, 120);\">Descripción:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Evita que los gatos orinen para marcar territorio. Puede aplicarse sobre superficies, jardineras, macetas, alfombras y telas naturales o sintéticas.</span></p><p><span style=\"color: rgb(33, 37, 41);\">Fórmula especial con aceites naturales para uso en exteriores, telas y madera. No daña el ambiente Auxiliar en el entrenamiento de tu gato</span></p><p><br></p><p><br></p><p><br></p>', 0, 190, NULL, 1, NULL, NULL, NULL, '2024-07-26 08:02:01', NULL, NULL, 'Repelente-natural-para-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (1321, NULL, 'producto', '7501556466010', 0x4A55472D3339, 'FL9601', 5.00, 'Juguete de peluche castor', '<p>Juguete de peluche castor</p><p><br></p><p><span style=\"color: rgb(94, 98, 120);\">Descripción:</span></p><p><span style=\"color: rgb(33, 37, 41);\">Juguete de peluche para perros con diseños de animales del bosque son una excelente opción para mantener entretenidas a nuestras mascotas. Estos juguetes son coloridos y suaves, lo que los hace perfectos para que los perros jueguen y se diviertan. Además, al ser de peluche, son seguros para morder y jugar sin riesgo de lastimarse.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios:</span></p><p><span style=\"color: rgb(33, 37, 41);\">• Ayuda a mantenerlos entretenidos al masticar, lamer, arrastrar y jugar con ellos. Estimulan su curiosidad con el squeaker de una manera segura de jugar</span></p>', 0, 90, NULL, 1, NULL, NULL, NULL, '2024-07-26 08:21:33', NULL, NULL, 'Juguete-de-peluche-castor', 0, 0);
