INSERT INTO `ecom_productos` VALUES (1326, NULL, 'producto', '7501556439885', 0x534841552D3031, 'FL3988', 0.00, 'Shampoo para hurón', '<p>Shampoo para hurón</p><p><br></p><p>Descripción:</p><p>Shampoo para hurón con extractos naturalez, ayuda a mantener el pelaje limpio y suave, elimina los malos olores naturalmente con aroma a toronja.</p><p><br></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2025-12-10 07:50:11', NULL, NULL, 'Shampoo-para-huron', 0, 0);
INSERT INTO `ecom_productos` VALUES (1327, NULL, 'producto', '7501556465723', 0x414C49552D3032, 'WAT572', 5.00, 'Alimento para hurón fortificada ', '<p>Alimento para hurón</p><p><br></p><p>Descripción:</p><p>Alimento para hurón fortificada con vitaminas y minerales elaborado con carne de pollo y pescado, lo que proporciona gran sabor de cada bocado</p>', 0, 180, NULL, 1, NULL, NULL, NULL, '2024-08-09 00:09:57', NULL, NULL, 'Alimento-para-huron-fortificada-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1328, NULL, 'producto', '7501556439670', 0x5348412D3135, 'FL3967', 5.00, 'Shampoo antipulgas chico ', '<p>Shampoo antipulgas para perro</p><p>Cantidad: 250 ml</p><p><br></p><p>Descripción:</p><p>El Shampoo con ingredientes que cuidan su piel y proporcionan sedosidad facilitando el cepillado.</p><p>Elaborado con extracto de D-limoneo</p><p>Proporciona limpieza</p><p>Repele y aleja a las pulgas</p>', 0, 60, NULL, 1, NULL, NULL, NULL, '2024-08-17 00:30:13', NULL, NULL, 'Shampoo-antipulgas-chico-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1329, NULL, 'producto', '841386490376', 0x4A41524F2D3130, '8413856490376', 0.00, 'Jaula zin con divisiones para pajaros ', '<p>Jaula zin con divisiones para pajaros</p><p>Color: gris</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Podrás tener un hábitat para tus canarios y en época de cria usa las divisiones opacas y tipo rejilla que vienen incluidas para separar a tus aves con 3 divisiones para convertir una jaula en 4 espacios para ellos, o tener distintas variedades de aves en una sola jaula con charolas extraibles para fácil limpieza.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Incluye:</span></p><p><span style=\"color: rgb(102, 102, 102);\"> 2 cajones para jaula </span></p><p><span style=\"color: rgb(102, 102, 102);\">4 comederos largos </span></p><p><span style=\"color: rgb(102, 102, 102);\"> 8 palos plásticos </span></p><p><span style=\"color: rgb(102, 102, 102);\">3 separadores de plástico</span></p><p><span style=\"color: rgb(102, 102, 102);\">2 asas,</span></p><p><span style=\"color: rgb(102, 102, 102);\">1 Parrilla plástica</span></p><p><span style=\"color: rgb(102, 102, 102);\">2 Asas para transportar</span></p>', 0, 2790, 124, 1, NULL, NULL, NULL, '2025-09-23 18:05:01', NULL, NULL, 'Jaula-zin-con-divisiones-para-pajaros-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1330, NULL, 'producto', '4602533783113', 0x415245412D3031, '4602533783113', 0.00, 'Arena para pajaros baño en seco', '<p>Arena para pajaros baño en seco</p><p><br></p><p>Descripción:</p><p>Arena para aves con extracto de eucalipto y cáscaras. Es un metodo perfecto para asegurar que la jaula se mantega limpia y fresca, el extracto de eucalipto aporta un mayor control higienico, ya que posee propiedades curativas y tiene efectos antiflamatorios, germicidas y desifectantes, se trata de evitar quq las bacterías y parásitos (garrapatas, piojos de los pájaros) se multipliquen en el cuerpo de los pájaros. Tambien ayudan a neutralizar los olores desagradables. el color blanco de la arena ayuda a las aves a conservar su color. Extender sobre el suelo de la jaula en una capa de 1 cm de espesor ca,mbiar despues de que se ensucia una o dos veces a la semana.</p><p><br></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2026-03-24 07:55:19', NULL, NULL, 'Arena-para-pajaros-bano-en-seco', 0, 0);
INSERT INTO `ecom_productos` VALUES (1331, NULL, 'producto', '7501556494693', 0x4A55472D3435, 'FL9469', 5.00, 'Juguete pez globo para perro ', '<p>Juguete pez globo para perro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Son juguetes para perros que tienen una necesidad natural de morder y masticar para mantener sus dientes y encías saludables, así como para liberar estrés. Son juguetes con texturas y materiales resistentes pueden ayudar a satisfacer esta necesidad de morder de manera segura, con un squeaker integrado puede proporcionar entretenimiento adicional, ya que el sonido puede atraer su atención.</span></p>', 0, 150, NULL, 1, NULL, NULL, NULL, '2024-10-11 23:45:02', NULL, NULL, 'Juguete-pez-globo-para-perro-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1332, NULL, 'producto', '7501556440447', 0x544F4E492D3031, 'FL4044', 5.00, 'Tonico para aves postura ', '<p>Tonico para aves postura</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Es un suplemento que estimula la reproducción y apareamiento de las aves, además de favorecer la fertilidad y la postura. L</span><span style=\"color: rgb(50, 51, 56);\">a fertilidad - Favorece la postura- Para todo tipo de aves de ornato y canoras</span></p><p><br></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-09-12 23:43:45', NULL, NULL, 'Tonico-para-aves-postura-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1333, NULL, 'producto', '7501556440454', 0x544F4E492D3032, 'FL4045', 5.00, 'Tonico para aves catarro', '<p>Tonico para aves catarro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">es una fórmula especializada con ingredientes que coadyuvan al alivio y prevención de las enfermedades respiratorias como el catarro y la tos en las aves, especialmente en épocas de lluvias y frío.</span><span style=\"color: rgb(50, 51, 56);\"> Para todo tipo de aves de ornato y canoras.</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-09-12 23:46:48', NULL, NULL, 'Tonico-para-aves-catarro', 0, 0);
INSERT INTO `ecom_productos` VALUES (1334, NULL, 'producto', '7501556440423', 0x544F4E492D3033, 'FL4042', 5.00, 'Tonico para aves multivitaminas', '<p>Tonico para aves multivitaminas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Es un suplemento que mantiene y conserva la salud a las aves, además de estimular el canto y la fertilidad</span><span style=\"color: rgb(50, 51, 56);\">.Para todo tipo de aves de ornato y canoras</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-09-12 23:47:58', NULL, NULL, 'Tonico-para-aves-multivitaminas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1335, NULL, 'producto', 'GAMBIAS00201', 0x4741592D3031, 'AS002', 5.00, 'Camaroncitos gambitas para tortuga y peces chico', '<p>Camaroncitos gambitas para tortuga y peces</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Lo hace ser un alimento muy completo ya que es alto en proteínas al ser alimento vivo deshidratado, practico Ideal para tortugas, peces de agua dulce y salada. </span></p>', 0, 45, 124, 1, NULL, NULL, NULL, '2026-03-27 07:03:18', NULL, NULL, 'Camaroncitos-gambitas-para-tortuga-y-peces-chico', 0, 0);
