INSERT INTO `ecom_productos` VALUES (1338, NULL, 'producto', '7502271354712', NULL, '50422', 5.00, 'Dispensador hueso de bolsas sanitarias ', '<p>Dispensador hueso de bolsas sanitarias </p><p><br></p><p>Descripción:</p><p>Dispensador de bolsas sanitarias para eses de tu mascota con un diseño discreto y elegante.</p><p><br></p><p>Incluye: 2 cartucho de bolsas</p><p><br></p>', 0, 60, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Dispensador-hueso-de-bolsas-sanitarias-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1339, NULL, 'producto', '7502278916456', 0x4445532D3031, '10015', 10.00, 'Deslanador quita pelo grande ', '<p>Deslanador quita pelo grande</p><p><br></p><p>Descripción:</p><p>Libera el pelo de la mascota de manera fácil através del botón limpiador con mango ergonómico para agrre firme y cómodo, la cuchilla tiene la función de quitar el pelaje para adelgazar y desenredar sin dañar el pelaje o cortar la piel. Para todo tipo de pelo (largo corto grueso delgado). Elimina enredos, suciedad y pelo muerto.</p>', 0, 199, 124, 1, NULL, NULL, NULL, '2025-07-14 17:51:42', NULL, NULL, 'Deslanador-quita-pelo-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1340, NULL, 'producto', '7502278916432', 0x4445532D3032, '10013', 5.00, 'Deslanador quita pelo chico', '<p>Deslanador quita pelo chico</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Libera el pelo de la mascota de manera fácil através del botón limpiador con mango ergonómico para agrre firme y cómodo, la cuchilla tiene la función de quitar el pelaje para adelgazar y desenredar sin dañar el pelaje o cortar la piel. Para todo tipo de pelo (largo corto grueso delgado). Elimina enredos, suciedad y pelo muerto.</span></p>', 0, 160, 124, 1, NULL, NULL, NULL, '2025-07-14 17:50:49', NULL, NULL, 'Deslanador-quita-pelo-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (1341, NULL, 'producto', '7502271350509', 0x4445532D3033, '10020', 5.00, 'Deslanador rompe nudos ', '<p>Deslanador rompe nudos</p><p><br></p><p>Descripción:</p><p>Libera el pelo de la mascota de manera fácil para agarre firme y cómodo, la cuchilla tiene la función de quitar el pelaje para cortar el nudo.</p>', 0, 99, NULL, 1, NULL, NULL, NULL, '2024-09-13 01:14:07', NULL, NULL, 'Deslanador-rompe-nudos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1342, NULL, 'producto', '7500211001108', 0x414C49504F2D3031, 'Q117', 5.00, 'Alimento pleco sticks 80g', '<p>Alimento pleco chico</p><p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(70, 71, 74);\">Pleco Sticks es un alimento peletizado compacto y de hundimiento rápido, formulado con ingredientes vegetales de excelente calidad, que queda a disposición de los peces que se alimentan en el fondo del acuario de manera inmediata. Alimento en pellets para plecostomus.</strong></p>', 0, 55, 124, 1, NULL, NULL, NULL, '2025-08-26 18:23:19', NULL, NULL, 'Alimento-pleco-sticks-80g', 0, 0);
INSERT INTO `ecom_productos` VALUES (1343, NULL, 'producto', '7500211001115', 0x414C49504F2D3032, 'Q118', 5.00, 'Alimento pleco sticks 160gr', '<p>Alimento pleco chico</p><p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(70, 71, 74);\">Pleco Sticks es un alimento peletizado compacto y de hundimiento rápido, formulado con ingredientes vegetales de excelente calidad, que queda a disposición de los peces que se alimentan en el fondo del acuario de manera inmediata. Alimento en pellets para plecostomus.</strong></p>', 0, 80, 124, 1, NULL, NULL, NULL, '2025-08-26 18:24:43', NULL, NULL, 'Alimento-pleco-sticks-160gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1344, NULL, 'producto', '7502261583474', 0x524545532D3031, 'OCL-500R', 10.00, 'Repuesto de esponja para ocl-500/750', '<p>Alimento pleco chico</p><p>Contenido: 2 pza </p><p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(70, 71, 74);\">Pleco Sticks es un alimento peletizado compacto y de hundimiento rápido, formulado con ingredientes vegetales de excelente calidad, que queda a disposición de los peces que se alimentan en el fondo del acuario de manera inmediata. Alimento en pellets para plecostomus.</strong></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-09-13 01:44:33', NULL, NULL, 'Repuesto-de-esponja-para-ocl-500750', 0, 0);
INSERT INTO `ecom_productos` VALUES (1345, NULL, 'producto', '8420717001275', 0x50415A492D3031, '8420717001275', 0.00, 'Panizo en espiga chico alimento para aves ', '<p>Panizo en espiga chico</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">está diseñado para ofrecer una experiencia de alimentación divertida y nutritiva. Con espigas que varían entre 20 y 28 cm de largo, tus pájaros podrán disfrutar de más, mientras fortalecen su musculatura al rebuscar entre las ramas. Este alimento es perfecto para una amplia variedad de especies, incluyendo agapornis, australianos, canarios, finches, gouldian, lady, loritos y periquitos. Cada envase contiene una unidad de 1kg, garantizando calidad europea de importación y frescura. Proporciona a tus aves un alimento que no solo es nutritivo, sino que también les permite jugar y explorar, promoviendo su bienestar y felicidad.</span></p>', 0, 135, 124, 1, NULL, NULL, NULL, '2026-02-17 08:25:19', NULL, NULL, 'Panizo-en-espiga-chico-alimento-para-aves-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1346, NULL, 'producto', '8420717142527', 0x50415A492D3032, '8420717142527', 0.00, 'Panizo en espiga grande alimento para aves ', '<p>Panizo en espiga grande</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">está diseñado para ofrecer una experiencia de alimentación divertida y nutritiva. Con espigas que varían entre 20 y 28 cm de largo, tus pájaros podrán disfrutar de más de 60.000 granos mientras fortalecen su musculatura al rebuscar entre las ramas. Este alimento es perfecto para una amplia variedad de especies, incluyendo agapornis, australianos, canarios, finches, gouldian, lady, loritos y periquitos. Cada envase contiene una unidad de 1kg, garantizando calidad europea de importación y frescura. Proporciona a tus aves un alimento que no solo es nutritivo, sino que también les permite jugar y explorar, promoviendo su bienestar y felicidad.</span></p>', 0, 699, 124, 1, NULL, NULL, NULL, '2025-07-17 08:41:00', NULL, NULL, 'Panizo-en-espiga-grande-alimento-para-aves-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1347, NULL, 'producto', '7502278911321', 0x4E414E4F2D3038, '4063', 2.00, 'Acuario de coliseo 70 lts con mueble ', '<p>Acuario coliseo con mueble</p><p>Capacidad: 70 lts</p><p>Potencia: 15 w</p><p>Filtro: 1000 L/H</p><p>Medidas del mueble: 60 x 23 x 65 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Está elaborado con vidrio de alta calidad, proporcionando resistencia y una vista clara.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Sus dimensiones: 54 cm de altura, 60 cm de ancho, 23 cm de profundidad.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Garantizando un ambiente limpio y saludable para sus peces.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Además, incluye una esponja para facilitar la filtración y una lámpara con 34 LEDs de 7 watts.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La lámpara ofrece tres modos de luz cambiables, adaptándose a diferentes necesidades de iluminación.</span></p><p><br></p>', 0, 6200, 124, 1, NULL, NULL, NULL, '2025-11-07 07:58:31', NULL, NULL, 'Acuario-de-coliseo-70-lts-con-mueble-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1348, NULL, 'producto', 'ISA01COLLAR', 0x4953412D3031, 'FL8570', 5.00, 'Collar isabelino talla 0', '<p>Collar isabelino talla 0</p><p>Circunferencia del cuello: 18 cm</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Se adecuan alrededor del cuello de los perros o gatos gracias a su velcro ajustable. Son útiles como método de contención cuando nuestra mascota ha sido operada o tiene alguna herida a la que no queremos que acceda, evitando así que se lama, rasque, muerda o autolesione, que podría provocar infecciones y evitar la cicatrización. Razas recomendadas para cada talla:</span></p><p><br></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 0 (18 cm): Gato, razas pequeñas</span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 1 (22 cm): Chihuahua, Pequeño Lebrel Italiano.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 2 (25 cm): Maltés, Pomeranian, Pekinés. </span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 3 (29 cm): Shih Tzu, Papillón, Terrier.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 4 (32 cm): Bull Dog Francés, Pug, Boston Terrier.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 5 (36 cm): Cocker Spaniel, Fox Terrier, Lakeland Terrier.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 6 (42 cm): Beagle, Schnauzer Standard, Basset Hound. </span></p><p><span style=\"color: rgb(0, 0, 0);\">Talla 7 (46 cm): Pastor Alemán, Labrador, Pastor Inglés.</span></p>', 0, 55, NULL, 1, NULL, NULL, NULL, '2024-10-12 00:16:26', NULL, NULL, 'Collar-isabelino-talla-0', 0, 0);
