INSERT INTO `ecom_productos` VALUES (1369, NULL, 'variante', 'AS07GRNMICH', 0x5241532D303747, 'PI0710-0264', 0.00, 'Rascadero mich sencillo gris', '<p>Rascadero mich sencillo</p><p>Medidas: 50 x 35cm (largo x ancho)</p><p>Medidas del poste: 56cm altura</p><p>Color: gris con negro</p><p><br></p><p>Descripción:</p><p>Rascador resistente elaborado con Henequén 100 % fibra natural, MDF de 12 mm textil angora y MT.</p><p>Los peces tienen cascabel</p><p>Rascadero fabricado especial para espacios vacios donde puedas colocar el rascadero entre salas, cuartos, etc.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p><br></p>', 0, 595, 124, 1, NULL, NULL, NULL, '2026-03-07 08:30:14', '2026-03-07 08:30:14', NULL, 'Rascadero-mich-sencillo-gris', 0, 0);
