INSERT INTO `ecom_productos` VALUES (1371, NULL, 'producto', 'TERA052040', 0x544552412D3035, 'TERA-05', 5.00, 'Terrario relu 20 cm largo 40cm altura', '<p>Terrario relu de 20cm</p><p>Espesor: 3 mm</p><p>Marcos: Plástico</p><p>Material: cristal</p><p><br></p><p>Descripción:</p><p>Terrario para iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha o izquierda para fácil limpieza y parte superior de malla metálica no corrosiva.</p>', 0, 480, NULL, 1, NULL, NULL, NULL, '2024-12-04 07:51:25', NULL, NULL, 'Terrario-relu-20-cm-largo-40cm-altura', 0, 0);
