INSERT INTO `ecom_productos` VALUES (1374, NULL, 'producto', '7502211902904', 0x444946552D3131, 'HA-118C', 5.00, 'Aireador piedra difusora de aire tortuga', '<p>Difusor de aire tortuga</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(146, 146, 159);\">Conectar la piedra porosa aireadora con maguera a la bomba de aire para que se realize el flujo de aire y genere burbujas. Este a su vez incrementa la circulación y oxigenación del agua de su pecera para sus peces.</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-11-12 07:00:52', NULL, NULL, 'Aireador-piedra-difusora-de-aire-tortuga', 0, 0);
INSERT INTO `ecom_productos` VALUES (1375, NULL, 'producto', 'DIAIHA203C', 0x444946552D3132, 'HA-203C', 5.00, 'Piedra difusor de aire circular', '<p>Aireador difusor de aire circular</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(146, 146, 159);\">Conectar la piedra porosa aireadora con maguera a la bomba de aire para que se realize el flujo de aire y genere burbujas. Este a su vez incrementa la circulación y oxigenación del agua de su pecera para sus peces.</span></p>', 0, 65, NULL, 1, NULL, NULL, NULL, '2024-11-12 07:11:28', NULL, NULL, 'Piedra-difusor-de-aire-circular', 0, 0);
INSERT INTO `ecom_productos` VALUES (1376, NULL, 'producto', '8413856517578', 0x434F4D452D3036, '51757', 5.00, 'Comedero de aves exterior con tapa roja', '<p>Comedero de aves exterior con tapa roja</p><p><br></p><p>Descripción:</p><p>Es apropiado para cualquier tipo de jaula con avertura en barrotes tipo \"( )\". Con una tapa para evitar que tu ave entre al comedero tire o ensucie su comida.</p><p>Adecuado para: <span style=\"color: rgb(102, 102, 102);\">Canarios, jilgueros, finches, pinzones, diamantes, lady gouldain aves de talla XS-S</span></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-11-12 08:27:53', NULL, NULL, 'Comedero-de-aves-exterior-con-tapa-roja', 0, 0);
INSERT INTO `ecom_productos` VALUES (1377, NULL, 'producto', '8413856517776', 0x434F4D452D3035, '51777', 5.00, 'Comedero de aves interior estilo cristal', '<p>Comedero de aves interior estilo critsal</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Este comedero garantiza la durabilidad y resistencia necesarias para el uso diario. Su diseño interno evita que las semillas y el agua se derramen, manteniendo el entorno limpio y ordenado. Además, su función de bebedero asegura que tus aves siempre tengan acceso a agua fresca y limpia. Recomendado para especies como canarios, finches, ninfas y pinzones,</span></p>', 0, 35, NULL, 1, NULL, NULL, NULL, '2024-11-12 08:13:34', NULL, NULL, 'Comedero-de-aves-interior-estilo-cristal', 0, 0);
INSERT INTO `ecom_productos` VALUES (1378, NULL, 'producto', 'HEAL01PACA', 0x414C4948412D3031, 'ALIHA-01', 10.00, 'Heno de alfalfa natural por paca ', '<p><br></p><p>Heno de alfalfa alimento por paca</p><p>Cantidad: 22 kgrs aproximadamente</p><p>Para: conejos, cuyos, conejillo de indias, chinchilla, hámster, gerbos, ratas, tortugas sulcatas, degus, cerdos, ovejas, cabras, caballos, vacas y mas.</p><p><br></p><p><br></p><p>Descipción:</p><p>El heno de alfalfa constituye a la alimentación de su mascota, es uno de los henos mas adecuados para ayudar al desgaste de los dientes y a mejorar la digestón. El heno <span style=\"color: rgb(102, 102, 102);\">lleva un proceso de deshidratación y secado lento en sombra para que conserve sus nutrientes, aroma y sobre todo su hoja.</span></p><p><span style=\"color: rgb(15, 17, 17);\">el heno Alfalfa tiene una alta proporción de proteínas, fibra, calcio y grasas saludables que apoyan el crecimiento muscular y óseo de los animales jóvenes heno naturalmente dulce es muy agradable para los animales y sus fitonutrientes promueve un apetito saludable y satisface las necesidades de dieta de tu pequeña mascota de rápido crecimiento.</span></p><p><br></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">.</span></p><p><br></p><p><br></p>', 0, 650, NULL, 1, NULL, NULL, NULL, '2024-11-13 07:49:15', NULL, NULL, 'Heno-de-alfalfa-natural-por-paca-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1379, NULL, 'producto', 'HEAL01CUBO', 0x414C4841432D3031, 'ALHAC-01', 10.00, 'Heno de alfalfa natural en cubos por costal', '<p><br></p><p>Heno de alfalfa alimento en cubos</p><p>Cantidad: 22 kgrs aproximadamente</p><p>Para: conejos, cuyos, conejillo de indias, chinchilla, hámster, gerbos, ratas, tortugas sulcatas, degus, cerdos, ovejas, cabras, caballos, vacas y mas.</p><p><br></p><p><br></p><p>Descipción:</p><p>El heno de alfalfa constituye a la alimentación de su mascota, es uno de los henos mas adecuados para ayudar al desgaste de los dientes y a mejorar la digestón. El heno <span style=\"color: rgb(102, 102, 102);\">lleva un proceso de deshidratación y secado lento en sombra para que conserve sus nutrientes, aroma y sobre todo su hoja.</span></p><p><span style=\"color: rgb(15, 17, 17);\">el heno Alfalfa tiene una alta proporción de proteínas, fibra, calcio y grasas saludables que apoyan el crecimiento muscular y óseo de los animales jóvenes heno naturalmente dulce es muy agradable para los animales y sus fitonutrientes promueve un apetito saludable y satisface las necesidades de dieta de tu pequeña mascota de rápido crecimiento.</span></p><p><br></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">.</span></p><p><br></p><p><br></p>', 0, 1540, 124, 1, NULL, NULL, NULL, '2025-09-23 12:42:38', NULL, NULL, 'Heno-de-alfalfa-natural-en-cubos-por-costal', 0, 0);
INSERT INTO `ecom_productos` VALUES (1380, NULL, 'producto', 'CUVFUG01RE', 0x4355562D303146, 'CUV-01F', 5.00, 'Cueva de resina roctu fuego', '<p>Cueva de resina roctu</p><p><br></p><p>Decripción:</p><p>Figura de resina en forma de cueva puede ser para peceras con agua o terrarios escondites para tu reptiles como serpientes chicas iguanas, arañas, ranas, grecko, tarantulas, dragon del desierto y más. Un perfecto espacio amplio para ocultarse de los demás del exterior.</p><p><br></p>', 0, 250, NULL, 1, NULL, NULL, NULL, '2024-11-14 23:01:33', NULL, NULL, 'Cueva-de-resina-roctu-fuego', 0, 0);
