INSERT INTO `ecom_productos` VALUES (1392, NULL, 'producto', 'RAS02VACACOL', 0x5241532D30325641, 'RAS-02VA', 5.00, 'Rascadero colgante vaca', '<p>Rascadero colgante vaca</p><p>Medidas: 42 x 12 x 1.5 cm (largo x ancho x alto)</p><p>Medidas con colgadera: 54 x 12 x 1.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios pequeños donde puedas colgar el rascadero en la silla, sillon, buro, puerta, pared en aquel espacio para colgar asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p><br></p><p>Material: Elaborado con MDF de 12 pulgadas tapizante y tela soft y yute, hechos con henequén.</p>', 0, 220, 124, 1, NULL, NULL, NULL, '2025-03-30 07:30:02', NULL, NULL, 'Rascadero-colgante-vaca', 0, 0);
INSERT INTO `ecom_productos` VALUES (1393, NULL, 'producto', 'RAS02PIGCOL', 0x5241532D30325049, 'RAS-02', 5.00, 'Rascadero colgante mini pig', '<p>Rascadero colgante vaca</p><p>Medidas: 42 x 12 x 1.5 cm (largo x ancho x alto)</p><p>Medidas con colgadera: 54 x 12 x 1.5 cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p>Rascadero fabricado especial para espacios pequeños donde puedas colgar el rascadero en la silla, sillon, buro, puerta, pared en aquel espacio para colgar asi obteniendo una rascada a gatos.</p><p>Puedes usar catnip (hierba gatera para estimularlo a acaercarse.</p><p><br></p><p>Beneficios:</p><p>Ayuda liberar el estrés y mantenerlo relajado.</p><p>Es una forma de juego donde tu gato puede entretenerse por mucho tiempo.</p><p>Por instinto, tu gato necesita limar sus uñas y afilarlas, esta práctica le ayudará a ejercitarse también.</p><p><br></p><p>Material: Elaborado con MDF de 12 pulgadas tapizante y tela soft y yute, hechos con henequén.</p>', 0, 220, 124, 1, NULL, NULL, NULL, '2025-03-30 07:29:24', NULL, NULL, 'Rascadero-colgante-mini-pig', 0, 0);
INSERT INTO `ecom_productos` VALUES (1394, NULL, 'producto', '7503040428559', 0x4A55502D3035, 'SP-2855', 5.00, 'Juguete canasta para pajaros  ', '<p>Juguete canasta para pajaros</p><p><br></p><p>Descripción:<span style=\"color: rgb(15, 17, 17);\">el tablero está diseñado con una superficie de espejo, para que el pájaro pueda verse a sí mismo en el espejo, lo que ayuda a atraer la atención del pájaro. Estimula el pensamiento y las habilidades motoras de tu ave para mantener a tu ave activa y saludable.</span></p><p><br></p>', 0, 99, 124, 1, NULL, NULL, NULL, '2026-03-03 05:53:59', NULL, NULL, 'Juguete-canasta-para-pajaros--', 0, 0);
INSERT INTO `ecom_productos` VALUES (1395, NULL, 'producto', 'PER20CMRDI14', 0x504552412D4232303230, 'PERA-B2020', 5.00, 'Pecera rectangular 20 x 11 x 20 cm altura con división 4 litros 3 mm', '<p>Pecera rectangular 20 cm con división</p><p>Capacidad: 4 L</p><p>Grosor: 3 mm</p><p><br></p><p>Descripción: pecera medida estandar para peces pequeños o betta con marcos de plastico. con división extraible para dividir espacio y formar un 2 lugares para betta o una sola al quitar la división.</p><p><br></p>', 0, 160, 124, 1, NULL, NULL, NULL, '2026-05-25 10:06:36', NULL, NULL, 'Pecera-rectangular-20-x-11-x-20-cm-altura-con-division-4-litros-3-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1396, NULL, 'producto', '7501556482607', 0x4A5547472D3130, 'FL-8260', 5.00, 'Juguete raton arcoiris para gato ', '<p>Juguete raton arcoiris para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Diseñado para saciar el instinto cazador de tu gato, que como depredador se encuentra siempre al acecho. Ayudará a disminuir el aburrimiento, a mejorar su comportamiento y a fortalecer el vínculo con su dueño</span></p><p><br></p>', 0, 50, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:38:34', NULL, NULL, 'Juguete-raton-arcoiris-para-gato-', 0, 0);
