INSERT INTO `ecom_productos` VALUES (1398, NULL, 'producto', '7501556482652', 0x4A5547472D3132, 'FL-8265', 5.00, 'Juguete pelota enjaulada para gato', '<p>Juguete pelota enjaulada para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Diseñados para saciar el instinto curioso de tu gato. Ayudarán a disminuir el aburrimiento, a mejorar su comportamiento y a fortalecer el vínculo con su dueño. Las pelotas enjauladas estimulan la curiosidad del gato y su instinto felino.</span></p>', 0, 30, NULL, 1, NULL, NULL, NULL, '2024-11-23 06:50:14', NULL, NULL, 'Juguete-pelota-enjaulada-para-gato', 0, 0);
