INSERT INTO `ecom_productos` VALUES (1403, NULL, 'producto', '7501556470215', 0x434550492D3031, 'FL-8311', 5.00, 'Cepillo doble 2 en 1  para perro', '<p>Cepillo doble 2 en 1 para perro</p><p>Color: azul</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Cepillo doble 2 en 1 combinado con cerdas y púas de acero. Para el cepillado general de la mayoría de las razas. El cepillo estimula la producción de aceites naturales protectores en la piel del perro al mismo tiempo que quita el pelo muerto, promueve un pelaje sano y brillante.</span></p>', 0, 210, NULL, 1, NULL, NULL, NULL, '2024-11-23 07:22:05', NULL, NULL, 'Cepillo-doble-2-en-1--para-perro', 0, 0);
INSERT INTO `ecom_productos` VALUES (1404, NULL, 'producto', '7501556470277', 0x434550492D3032, 'FL-8317', 5.00, 'Guante de goma para cepillar ', '<p>Guante de goma para cepillar</p><p>Color: verde</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">Guante para cepillar al perro de pelo corto y suave. Ideal para quitar pelo muerto y suelto. Se recomienda para acicalar y en el proceso de limpieza del perro. </span><span style=\"color: rgb(50, 51, 56);\">Acaricie a su perro con el guante puesto aplicando ligera presión. Se puede cepillar a contra pelo o dirección al pelaje. El perro sentirá un leve masaje y no se perturbara por el cepillado.</span></p>', 0, 125, NULL, 1, NULL, NULL, NULL, '2024-11-23 07:36:58', NULL, NULL, 'Guante-de-goma-para-cepillar-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1405, NULL, 'producto', '7501556439021', 0x524550452D3036, 'FL3902', 5.00, 'Repelente granulado para perro y gato', '<p>Repelente granulado para perro y gato</p><p>Contenido: 1 kgr</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">El repelente granulado es una alternativa rápida para evitar que tu perro o gato se acerquen a los jardines que suelen ser destruidos por su juego o por marcaje. El repelente en forma granulada, es la alternativa sencilla que no daña a tus plantas y no afecta su crecimiento.</span></p><p><span style=\"color: rgb(50, 51, 56);\">Para mejor resultado espolvoree 20 gramos de producto por metro cuadrado diariamente hasta acabar con el mal hábito de la mascota.nSi desea evitar que perros y gatos ajenos defequen en su jardín, utilícelo regularmente mientras sea necesario. Aleje el producto del alcance de los niños y las mascotas. Únicamente para uso exterior. No utilizar en plantas destinadas para el consumo como hortalizas y arboles frutales.nnEVITE EL CONTACTO CON LA PIEL, OJOS Y MUCOSAS.nNO INGERIR.</span></p>', 0, 240, NULL, 1, NULL, NULL, NULL, '2024-11-23 09:02:29', NULL, NULL, 'Repelente-granulado-para-perro-y-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1406, NULL, 'producto', 'TERA104040CUB', 0x544552412D3130, 'TERA-10', 7.00, 'Terrario cublok 40 cm largo 40cm altura', '<p>Terrario cublok 40cm</p><p>Espesor: 3 mm</p><p>Marcos: plástico</p><p>Material: cristal</p><p><br></p><p><br></p><p>Descripción:</p><p>Terrario cubico para iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p><p><br></p>', 0, 850, NULL, 1, NULL, NULL, NULL, '2024-12-04 07:53:26', NULL, NULL, 'Terrario-cublok-40-cm-largo-40cm-altura', 0, 0);
INSERT INTO `ecom_productos` VALUES (1407, NULL, 'producto', 'TERA130REMI', 0x544552412D3131, 'TERA-11', 7.00, 'Terrario remin 30cm largo 20cm altura', '<p>Terrario remin 30 cm largo</p><p>Espesor: 3 mm</p><p>Marcos: plástico</p><p>Material: cristal</p><p><br></p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p><p><br></p>', 0, 395, NULL, 1, NULL, NULL, NULL, '2024-12-04 07:54:08', NULL, NULL, 'Terrario-remin-30cm-largo-20cm-altura', 0, 0);
