INSERT INTO `ecom_productos` VALUES (1412, NULL, 'producto', '015561221887', 0x464C4F522D3131, 'PT2188', 5.00, 'Foco UVB 13w desierto', '<p>Foco UVB desierto</p><p>Potencia: 13 w</p><p>Repti Glo 10.0</p><p>Ideal para todo reptil habitante de desierto</p><p>Alta producción de UVB</p><p>Elevada conversión de D3</p><p>Efectiva hasta 30 cm&nbsp;</p><p>Suministra los rayos UVB necesarios para el metabolismo óptimo del calcio</p><p>Recomendada para terrarios con pantallas densas</p><p>Se combina con&nbsp;la luz natural para la producción óptima de luz visible</p><p>El Exo Terra Reptile UVB150 tiene una potencia UVB muy alta similar a la luz solar en los desiertos. Estos lugares reciben más luz solar directa, por lo tanto, los reptiles de desierto están mas expuestos a radiaciones UV que cualquier otro tipo de reptil. Esta lámpara también se puede utilizar en terrarios con pantallas más densas para asegurar la penetración UVB suficiente. Las pantallas densas pueden filtrar hasta el 50% de los rayos UVB. El alto índice de vitamina D3 garantiza el rendimiento de la fotosíntesis de vitamina D3 para ayudar a la absorción de calcio y prevenir enfermedades metabólicas.</p>', 0, 690, 0, 1, NULL, NULL, NULL, '2025-03-30 13:37:21', NULL, NULL, 'Foco-UVB-13w-desierto', 0, 0);
INSERT INTO `ecom_productos` VALUES (1413, NULL, 'producto', 'TERA12SUMAK', 0x544552412D3132, 'TERA-12', 5.00, 'Terrario sumak 40cm largo 40 cm altura', '<p>Terrario sumak 40 cm largo 40 altura</p><p>Espesor: 3 mm</p><p>Marcos: plástico</p><p>Material: cristal</p><p><br></p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p><p><br></p>', 0, 600, NULL, 1, NULL, NULL, NULL, '2024-12-04 07:57:34', NULL, NULL, 'Terrario-sumak-40cm-largo-40-cm-altura', 0, 0);
