INSERT INTO `ecom_productos` VALUES (1416, NULL, 'producto', '7502261581876', 0x414C41552D3031, 'OF-01', 10.00, 'Alimentador automático ocean para peces', '<p>Alimentador automático ocean </p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Equipo diseñado para alimentar a los peces de su acuario de forma automática</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Se puede programar para alimentar 1 vez al día (cada 24hrs.) o 2 veces al día (cada 12hrs.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Utiliza 2 pilas AA</span></p>', 0, 499, 124, 1, NULL, NULL, NULL, '2026-05-17 22:32:52', '2026-05-17 22:32:52', NULL, 'Alimentador-automatico-ocean-para-peces', 0, 0);
INSERT INTO `ecom_productos` VALUES (1417, NULL, 'producto', 'TERAMADERA01', 0x544552414D2D3031, 'TERAM-01', 5.00, 'Terrario esply de madera chico', '<p>Terrario esply 40 cm largo 40.5 altura</p><p>Marcos: madera</p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de mdera con tela de lona forrrado con adaptacio de soquet para foco y latereles de malla de tela, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p>', 0, 680, 124, 1, NULL, NULL, NULL, '2026-02-24 08:07:50', NULL, NULL, 'Terrario-esply-de-madera-chico', 0, 0);
