INSERT INTO `ecom_productos` VALUES (1419, NULL, 'producto', 'TERAMADERA03', 0x544552414D2D3033, 'TERAM-03', 5.00, 'Terrario bellin 60 x 30 x 60cm alto malla de tela ', '<p>Terrario bellin 60 cm largo 30cm ancho</p><p>Marcos: madera</p><p>Malla: tela</p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de mdera con tela de lona forrrado con adaptacio de soquet para foco y latereles de malla de tela, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p>', 0, 1100, 124, 1, NULL, NULL, NULL, '2026-05-04 08:16:55', NULL, NULL, 'Terrario-bellin-60-x-30-x-60cm-alto-malla-de-tela-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1420, NULL, 'producto', 'Acimperia00', 0x4E414E4F2D3039, 'NANO-09', 5.00, 'Acuario imperio con mueble 100 Lts ', '<p>Acuario imperio con mueble</p><p>Capacidad: 100 lts</p><p>Potencia: 15 w</p><p>Filtro: 1000 L/H</p><p>Medidas del mueble: 80 x 26.5 x 124cm (largo x ancho x alto)</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Está elaborado con vidrio de alta calidad, proporcionando resistencia y una vista clara.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Sus dimensiones: 54cm de altura, 80cm de ancho, 26.5cm de profundidad.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Garantizando un ambiente limpio y saludable para sus peces.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Además, incluye una esponja para facilitar la filtración y una lámpara con 34 LEDs de 7 watts.</span></p><p><span style=\"color: rgb(102, 102, 102);\">La lámpara ofrece tres modos de luz cambiables, adaptándose a diferentes necesidades de iluminación.</span></p>', 0, 8500, NULL, 1, NULL, NULL, NULL, '2025-01-10 12:09:41', NULL, NULL, 'Acuario-imperio-con-mueble-100-Lts-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1421, NULL, 'producto', '7501325468542', 0x4853542D3235304752, 'HST-250GR', 5.00, 'Heno avena Timothy 250 gr para desgaste dental ', '<p>Heno para mamíferos roedores</p><p>Cantidad: 250 gr</p><p><br></p><p>Descripción:</p><p>Alimento natural de heno de avena</p><p>Ideal para desgaste natural</p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-08 07:26:40', NULL, NULL, 'Heno-avena-Timothy-250-gr-para-desgaste-dental-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1422, NULL, 'producto', '7500211004390', 0x414C4953552D353030, 'Q818', 5.00, 'Alimento para peces super flakes 500 grs ', '<p>Alimento hojuelas para peces super flakes grande</p><p>Cantidad: 500 grs</p><p><br></p><p>Descripción:</p><p>Para todas las estapas de la vida</p><p><span style=\"color: rgb(64, 43, 64);\">Es una mezcla de hojuelas de colores rojo, verde y amarillo, con olor a camarón y de textura quebradiza, diseñado para ajustarse a las necesidades nutricionales de la mayoría de los peces tropicales y de agua dulce.&nbsp;</span></p><p><br></p><p><span style=\"color: rgb(64, 43, 64);\">﻿Las hojuelas están diseñadas para fortalecer a tus peces en dos vías. Primero la adición de Beta-glucanos estimula la inmunidad celular en la línea de glóbulos blancos encargados de la producción de anticuerpos. Segundo, la incorporación de glucomananos favorece la implantación de una flora microbiana robusta de especies bacterianas benéficas que impiden el establecimiento de patógenos a lo largo del tracto digestivo y por si fuera poco, mejoran significativamente la absorción de los nutrientes.</span></p><p><br></p><p>Ingredientes especiales: Con prebióticos y probióticos</p>', 0, 390, 124, 1, NULL, NULL, NULL, '2025-10-01 17:40:09', NULL, NULL, 'Alimento-para-peces-super-flakes-500-grs-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1423, NULL, 'producto', 'COR03GILL7499', 0x434F522D3033, '7499', 5.00, 'Cortauñas de gilltonina para mascotas ', '<p>Cortauñas de gillotina para mascotas</p><p>Incluye: lima</p><p><br></p><p>Descripción:</p><p>Cortauñas profesional para perros y gatos, afilado para un corte preciso y seguro.</p>', 0, 170, 124, 1, NULL, NULL, NULL, '2025-03-22 06:49:54', NULL, NULL, 'Cortaunas-de-gilltonina-para-mascotas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1424, NULL, 'producto', '7501556420210', 0x414C495350492D333530, 'FL2121', 5.00, 'Alimento para peces spirulina boots 350g', '<p>Alimento espirulina boots 350g</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">En formato de bolitas, ideal para la nutrición de peces herbívoros.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Alimento Premium para peces herbívoros Spirulina Boost, es un alimento vegetal para peces herbívoros formulado con un alto contenido de alga espirulina para mejorar el color y estimular el crecimiento adicionado con vitamina C estabilizada y un suplemento multivitamínico, Spirulina Boost acentúa el color y promueve el crecimiento de los peces japoneses, cíclidos africanos y peces vivíparos (molies, platties y espadas).</span></p>', 0, 120, 124, 1, NULL, NULL, NULL, '2025-12-26 08:40:46', NULL, NULL, 'Alimento-para-peces-spirulina-boots-350g', 0, 0);
INSERT INTO `ecom_productos` VALUES (1425, NULL, 'producto', 'PT218711FLOR', 0x464C4F522D3131, 'PT2187', 5.00, 'Foco para reptil UVB 100 26w', '<p>Foco para reptil UVB 100</p><p>Luz: blanco neutro</p><p>Voltaje: 120v</p><p>Watts: 26 w</p><p>Indice de UVB: 5</p><p><br></p><p>Caracteristicas:</p><p><span style=\"color: rgb(102, 102, 102);\">Ideal para reptiles tropicales y subtropicales.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Alta producción de radiación UVB.</span></p><p><span style=\"color: rgb(102, 102, 102);\">Efectivo por encima de los 30 cm (12 \").</span></p><p><span style=\"color: rgb(102, 102, 102);\">Proporciona los necesarios rayos UVB para un óptimo metabolismo del calcio, Estimula el apetito, actividad y comportamiento reproductivo por medio de la radiación UVA. Es recomendable en combinación con Repti Glo 2.0 para una producción de luz visible.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Ventajas:</span></p><p><span style=\"color: rgb(102, 102, 102);\">Exo Terra Repti Glo emite la radiación UVB similar a los ambientes sombreados tales como</span></p><p><span style=\"color: rgb(102, 102, 102);\">bosques lluviosos y otras localidades tropicales. </span></p>', 0, 790, 124, 1, NULL, NULL, NULL, '2025-10-02 16:11:32', NULL, NULL, 'Foco-para-reptil-UVB-100-26w', 0, 0);
