INSERT INTO `ecom_productos` VALUES (1427, NULL, 'producto', 'CAMDOB02ME', 0x43414D444F2D3032, 'CAMDO-02', 5.00, 'Cama doble vista chica ', '<p>Cama doble vista</p><p>Talla: mediana</p><p><br></p><p>Descripción:</p><p>Cama doble vista donde un lado es de tela calientita y del otro es de tela fresca con dos tonos distintos en cada lado y diseño. cama para razas pequeñas, medianas perros gatos, mini pig. hurones.conejos y más. ligera y fácil de de llevar contigo.</p><p><br></p><p>Color y diseño: sujetos a disponibilidad pregunta por la gran variedad.</p>', 0, 299, 0, 1, NULL, NULL, NULL, '2025-03-22 08:00:12', NULL, NULL, 'Cama-doble-vista-chica-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1428, NULL, 'producto', 'CAMDOB03GR', 0x43414D444F2D3033, 'CAMDO-03', 5.00, 'Cama doble vista grande ', '<p>Cama doble vista</p><p>Talla: grande </p><p><br></p><p>Descripción:</p><p>Cama doble vista donde un lado es de tela calientita y del otro es de tela fresca con dos tonos distintos en cada lado y diseño. cama para razas medianas, grande perros, gatos y más. ligera y fácil de de llevar contigo.</p><p><br></p><p>Color y diseño: sujetos a disponibilidad pregunta por la gran variedad.</p>', 0, 499, 0, 1, NULL, NULL, NULL, '2025-03-22 08:04:46', NULL, NULL, 'Cama-doble-vista-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1429, NULL, 'producto', 'RAS11MEDCAF', 0x5241532D3131, 'RAS-11', 5.00, 'Rascadero mei mediano cafe ', '<p>Rascadero mei mediano</p><p>Color: Cafe</p><p><br></p><p>Descripción:</p><p>Rascador resistente elaborado con henequén 100% fibra natural, MDF de 12 mm textil M. ¡Facil de armar! tu gato lo amara por su tela suvesita peluda y con su bolita colgante que contiene un cascabel para generar sonido que le les atraera y encatara.</p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Los muebles para gato están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p>Incluye: instructivo y llaven alen</p>', 0, 2500, 124, 1, NULL, NULL, NULL, '2025-12-05 07:14:00', '2025-12-05 07:14:00', NULL, 'Rascadero-mei-mediano-cafe-', 0, 0);
