INSERT INTO `ecom_productos` VALUES (1435, NULL, 'producto', 'JAUORBE11', 0x4A41524F2D3131, 'SP-2825', 5.00, 'Jaula de pajaro orbe mediana ', '<p>Jaula de pajaro orbe mediana</p><p>Color: blanca</p><p>Charola: gris claro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con dos tazones de alimento y dos soportes de percha. incluye un columpio que proporcionará horas de entretenimiento y ejercicio. Fácil de transportar: Con una puerta y un asa robusta, podrás mover la jaula con facilidad. </span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza extraíble hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no se salga mientras limpia la bandeja </span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: Metal y bandeja plastico</span></p>', 0, 899, 124, 1, NULL, NULL, NULL, '2025-03-30 11:54:42', NULL, NULL, 'Jaula-de-pajaro-orbe-mediana-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1436, NULL, 'producto', 'JAUORBE12', 0x4A41524F2D3132, 'SP-2824', 5.00, 'Jaula de pajaro orbe chica', '<p>Jaula de pajaro orbe chica</p><p>Color: blanca</p><p>Charola: cafe claro</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con dos tazones de alimento y dos soportes de percha. incluye un columpio que proporcionará horas de entretenimiento y ejercicio. Fácil de transportar: Con una puerta y un asa robusta, podrás mover la jaula con facilidad. </span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza extraíble hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no se salga mientras limpia la bandeja </span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: Metal y bandeja plastico</span></p>', 0, 650, 124, 1, NULL, NULL, NULL, '2025-06-16 13:39:39', NULL, NULL, 'Jaula-de-pajaro-orbe-chica', 0, 0);
INSERT INTO `ecom_productos` VALUES (1437, NULL, 'producto', 'JAMAYOR13', 0x4A41524F2D3133, 'SP-2820', 5.00, 'Jaula de pajaro mayor mediana ', '<p>Jaula de pajaro orbe mediana</p><p>Color: negra</p><p>Charola: negra</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con cuatro tazones de alimento y tres soportes de percha. incluye un columpio que proporcionará horas de entretenimiento y ejercicio. Fácil de transportar: Con seis puertas y un asa , podrás mover la jaula con facilidad. </span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza extraíble hace que el aseo de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no se salga mientras limpia la bandeja </span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: Metal y bandeja plastico</span></p>', 0, 1600, 124, 1, NULL, NULL, NULL, '2025-06-09 09:24:49', NULL, NULL, 'Jaula-de-pajaro-mayor-mediana-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1438, NULL, 'producto', 'JAMAYOR14', 0x4A41524F2D3134, 'SP-2821', 5.00, 'Jaula de pajaro mayor grande', '<p>Jaula de pajaro orbe grande</p><p>Color: negra</p><p>Charola: negra</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con seis tazones de alimento y tres soportes de percha. que proporcionará horas de entretenimiento y ejercicio. Fácil de transportar: Con nueve puertas y llantas así podrás mover la jaula con facilidad. </span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza extraíble hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no se salga mientras limpia la bandeja.</span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: Metal y bandeja plastico</span></p>', 0, 2590, 124, 1, NULL, NULL, NULL, '2025-10-20 22:01:37', NULL, NULL, 'Jaula-de-pajaro-mayor-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (1439, NULL, 'producto', 'RAS13ROJO92', 0x5241532D3133, 'FL8460', 5.00, 'Rascadero torre tunel 92cm', '<p>Rascadero torre tunel</p><p>Color: rojo</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(50, 51, 56);\">Los muebles o conocico como (arbol) para gato están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Ajuste correctamente cada apartado del mueble. Limpie con regularidad, puede usar un limpiador enzimático de limpieza superior.</span></p><p><span style=\"color: rgb(50, 51, 56);\">• El enriquecimiento ambiental permite estimular cognitivamente a los gatos </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El gato podrá rascar para afilar sus garras </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El juego ayudará al instinto de caza </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Las casas brindan zonas de descanso y protección solar. </span></p><p><span style=\"color: rgb(50, 51, 56);\">﻿• Se puede rociar catnip para gatos para estimular el juego y la curiosidad</span></p><p><br></p><p>Características</p><p><strong>Especie</strong></p><p>Gatos</p>', 0, 1280, 124, 1, NULL, NULL, NULL, '2025-03-30 22:31:47', NULL, NULL, 'Rascadero-torre-tunel-92cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1440, NULL, 'producto', '015561221320', 0x464C4F522D3132, 'PT2132', 5.00, 'Foco para reptil daylight basking spot 75w ', '<p>Foco para reptil</p><p><br></p><p>Descripción:</p><p>Lámpara de amplio espectro para terrarios.</p><p>Crea un área de calentamiento para la termo-regulación.</p><p>Aumenta la temperatura del aire.</p><p>Estimula el comportamiento reproductivo de los reptiles mediante luz ultravioleta “A”.</p><p>Se puede combinar con Daytime Heat Lamp o Night Heat Lamp por un ciclo de 24 hora</p><p><br></p><p>Rendimientos:</p><p>Ventajas: Una lámpara diurna de neodimio de amplio espectro.</p><p>El espectro es ideal para la fotosíntesis de las plantas y la luz ultravioleta “A” contribuyen con el bienestar fisiológico delos reptiles.</p><p>La luz concentrada permite enfocar el calor y la luz en cierta dirección para así crear lugares para el calentamiento en el terrario.</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Bombilla para el cuidado de mascotas ¡para uso exclusivo de reptiles, anfibios e invertebrados!</span></p>', 0, 240, 124, 1, NULL, NULL, NULL, '2025-04-05 07:19:13', NULL, NULL, 'Foco-para-reptil-daylight-basking-spot-75w-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1441, NULL, 'producto', 'ROCALI013591', 0x524F432D3031, '3591', 5.00, 'Rocaliente para reptiles ', '<p>Rocaliente para reptiles</p><p><br></p><p>Descripción:</p><p>Roca caliente para reptiles como iguanas, serpientes, grecko, camaleon, etc.</p><p><br></p>', 0, 225, 124, 1, NULL, NULL, NULL, '2025-04-05 07:07:25', NULL, NULL, 'Rocaliente-para-reptiles-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1442, NULL, 'producto', '015561221337', 0x464C4F522D3133, 'PT2133', 5.00, 'Foco reptil daylight basking spot 100w ', '<p>foco reptil Daylight basking spot 100w</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(12, 11, 11);\">Una lámpara diurna de neodimio de amplio espectro. El espectro es ideal para la fotosíntesis de las plantas y la luz ultravioleta “A” contribuyen con el bienestar fisiológico de los reptiles. La luz concentrada permite enfocar el calor y la luz en cierta dirección para así crear lugares para el calentamiento en el terrario.</span></p><p><br></p><p>Proporciona calor y luz diurnos para Terrarios.</p><p>Crea una zona de asoleamiento para la termorregulación.</p><p>Aumenta la temperatura del aire ambiente.</p><p>Estimula el comportamiento reproductor.</p><p>Puede combinarse con la Night Heat Lamp para crear un ciclo día/noche de 24 horas.</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Bombilla para el cuidado de mascotas ¡para uso exclusivo de reptiles, anfibios e invertebrados!</span></p><p><br></p><p><br></p>', 0, 320, 124, 1, NULL, NULL, NULL, '2025-10-02 16:05:22', NULL, NULL, 'Foco-reptil-daylight-basking-spot-100w-', 0, 0);
