INSERT INTO `ecom_productos` VALUES (1469, NULL, 'producto', '7501556421200', 0x414C4945532D3031, 'FL2120', 5.00, 'Alimento para pez spirulina boots 70 gr', '<p>Alimento espirulina boots 70g</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.9);\">En formato de bolitas, ideal para la nutrición de peces herbívoros.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Alimento Premium para peces herbívoros Spirulina Boost, es un alimento vegetal para peces herbívoros formulado con un alto contenido de alga espirulina para mejorar el color y estimular el crecimiento adicionado con vitamina C estabilizada y un suplemento multivitamínico, Spirulina Boost acentúa el color y promueve el crecimiento de los peces japoneses, cíclidos africanos y peces vivíparos (molies, platties y espadas).</span></p>', 0, 35, 124, 1, NULL, NULL, NULL, '2025-10-01 16:00:42', NULL, NULL, 'Alimento-para-pez-spirulina-boots-70-gr', 0, 0);
