INSERT INTO `ecom_productos` VALUES (1472, NULL, 'producto', '7501556440041', 0x414C49452D3037, 'FL4004', 10.00, 'Alimento para erizo select 800gr', '<p>Alimento para erizo</p><p><br></p><p><br></p><p><strong>sabor</strong></p><p>tenebrio, grillo y larva de mosca soldado</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">stá especialmente formulado para el sano crecimiento de erizos en cualquier etapa de desarrollo. Con ingredientes que cubren todos sus requerimientos nutricionales. Fortificado con vitaminas y minerales indispensables para el buen funcionamiento del organismo de su erizo, e ingredientes que ayudan a fortalecer su sistema inmunológico.&nbsp;</span></p>', 0, 199, 124, 1, NULL, NULL, NULL, '2026-02-17 07:56:52', NULL, NULL, 'Alimento-para-erizo-select-800gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1473, NULL, 'producto', '7501556438680', 0x4C4543482D3031, 'FL3868', 10.00, 'Leche para cachorrros ', '<p>Sustituto de leche para cachorros</p><p><br></p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">El sustituto de leche para cachorros de Naturance es una fórmula en polvo especializada que está recomendada para hembras gestantes y lactantes, en perros cachorros se usa como suplemento de leche materna, en casos de falta de producción de la madre o en camadas huérfanas. Es fácil de disolver y preparar. Incluye cuchara dosificadora.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Cubre las necesidades de alimentación de cachorros •Auxiliar en la alimentación de perros senior que se les complica masticar alimentos secos •Se disuelve adecuadamente, sin grumos.</span></p>', 0, 290, 124, 1, NULL, NULL, NULL, '2025-06-05 11:56:25', NULL, NULL, 'Leche-para-cachorrros-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1474, NULL, 'producto', '7502278911307', 0x4E414E4F2D3130, '4066', 5.00, 'Acuario glin 42 lts ', '<p>Acuario glin</p><p>Capacidad: 42 litros</p><p>Medidas puro acuario: 50 x 21 x 50 cm (largo x ancho x alto)</p><p>Medidas con mueble: 50x 21 x 115 cm (largo x ancho x alto)</p><p>Lampara potencia: 5w</p><p>Voltaje: 110/120v</p><p>Cabeza de poder flujo maximo: 500l/h</p><p><br></p><p>Descrpción:</p><p>Acuario panoramico curvo puede montarse como acuarios de agua dulce cuenta con filtro superior en forma de cascada para todo el acuario con lámpara led de bajo consumo y tapa de plástico. Es ideal para peces tropicales, peces japoneces, betas, y mas elegante, sofisticado de tamaño precenciable de instalación rápida y fácil mantenimiento.</p><p><br></p><p>Incluye:</p><p>Tapa con luz</p><p>Mubele de madera mdf</p><p>filtro interno</p>', 0, 4000, 124, 1, NULL, NULL, NULL, '2026-05-12 07:38:02', NULL, NULL, 'Acuario-glin-42-lts-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1475, NULL, 'producto', 'CORRA03SU608', 0x434F5252412D3033, 'SP-2802', 5.00, 'Corral sun 60 x 60cm 8 paneles ', '<p>Corral sun</p><p>Cantidad: 8 paneles</p><p>Medida de cada panel:61 x 61 cm (largo x alto)</p><p>Material: metalico </p><p>Color: gris con negro</p><p><br></p><p>Descripciòn:</p><p>Corral plegable con 8 paneles para conejo, cuyo, cachorros, mini pig y mas etc. i<span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos.</span></p><p><br></p><p>Incluye:</p><p>Puerta abatible con doble pasador</p><p>Pintura resistente a la corrosiòn</p><p>3 bandolas de seguridad</p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Configuarción de armado: Óctagono 180 x 60cm, Cuadrado 60 x 60 cm, rectangular 180 x 60 cm, o de valla 480 cm</span></p><p><br></p>', 0, 950, 124, 1, NULL, NULL, NULL, '2026-03-02 06:00:38', NULL, NULL, 'Corral-sun-60-x-60cm-8-paneles-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1476, NULL, 'producto', '7501556490770', 0x41524F2D3432, 'FL9077', 5.00, 'Arenero eston rosa ', '<p>Arenero eston</p><p>Color: rosa</p><p><br></p><p>Descripción:Arenero con cubierta para evitar desbordes de arena. <span style=\"color: rgb(50, 51, 56);\">&nbsp;Decide si deseas usarlo completamente cerrado o con la tapa a media altura.Coloca el filtro de carbón activado en el compartimiento de ventilación para el control de olores</span></p><p><span style=\"color: rgb(50, 51, 56);\">El escalón limpia patitas minimiza la cantidad de arena que tu gato arrastra al salir, evitando suciedad en el hogar. Versatilidad y comodidad: Su tapa desmontable permite ajustar la altura del arenero según las preferencias de tu gato, brindándole un espacio cómodo y adaptable. Fácil acceso y limpieza: La puerta abatible facilita la entrada y salida del gato, mientras que su estructura desmontable y la pala incluida hacen más sencilla la limpieza diaria. Mayor privacidad para tu gato: Su diseño cerrado ofrece un entorno seguro y tranquilo, ideal para gatos que prefieren hacer sus necesidades en un espacio discreto.</span></p><p><br></p><p><br></p>', 0, 400, 124, 1, NULL, NULL, NULL, '2025-12-10 07:16:03', '2025-12-10 07:16:03', NULL, 'Arenero-eston-rosa-', 0, 0);
