INSERT INTO `ecom_productos` VALUES (1480, NULL, 'variante', 'ARE43MORA', 0x41524F2D34334D4F, 'ARO-43MO', 5.00, 'Arenero blak morado', '<p>Arenero blak</p><p>Color: morado con negro</p><p><br></p><p>Descripción:Arenero con cubierta para evitar desbordes de arena. <span style=\"color: rgb(50, 51, 56);\">&nbsp;Decide si deseas usarlo completamente cerrado o con la tapa a media altura.Coloca el filtro de carbón activado en el compartimiento de ventilación para el control de olores</span></p><p><span style=\"color: rgb(50, 51, 56);\">El escalón limpia patitas minimiza la cantidad de arena que tu gato arrastra al salir, evitando suciedad en el hogar. Versatilidad y comodidad: Su tapa desmontable permite ajustar la altura del arenero según las preferencias de tu gato, brindándole un espacio cómodo y adaptable. Fácil acceso y limpieza: La puerta abatible facilita la entrada y salida del gato, mientras que su estructura desmontable y la pala incluida hacen más sencilla la limpieza diaria. Mayor privacidad para tu gato: Su diseño cerrado ofrece un entorno seguro y tranquilo, ideal para gatos que prefieren hacer sus necesidades en un espacio discreto.</span></p><p><br></p><p><br></p>', 0, 290, 124, 1, NULL, NULL, NULL, '2025-12-10 07:13:48', '2025-12-10 07:13:48', NULL, 'Arenero-blak-morado', 0, 0);
INSERT INTO `ecom_productos` VALUES (1481, NULL, 'producto', '7503040428191', 0x4A41524F2D3136, 'SP-2819', 8.00, 'Jaula pajaro monarca ', '<p>Jaula de pajaro monarca</p><p>Color: blanca</p><p>Charola: blanca</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con cuatro tazones de alimento y dos soportes de percha. que proporcionará horas de entretenimiento y ejercicio. Fácil de transportar.</span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza es desmontable hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no tenga contacto con sus eses el ave.</span></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: Metal y bandeja plastico</span></p>', 0, 1350, 124, 1, NULL, NULL, NULL, '2026-03-03 08:23:09', NULL, NULL, 'Jaula-pajaro-monarca-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1482, NULL, 'producto', '5900469011539', 0x414C494152542D3031, '01153', 5.00, 'Alimento para peces artemia deshidratadaFd brine shrimp ', '<p>Alimento para peces artemia deshidratada fd brine shrimp</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Un alimento natural en forma de trozos para peces omnívoros y carnívoros, obtenido por liofilización de la artemia adulta (Artemia salina).</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Un alimento recogido con gusto por los peces.Una fuente de proteínas de fácil digestión, quitina y colorantes naturales. Pero en forma fresca, e incluso congelada, puede ser una fuente de patógenos, peligrosos para los peces.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">El proceso de liofilización elimina con eficacia todos los organismos que en el acuario podrían ser una causa de enfermedades de los peces. Liofilización permite al mismo tiempo conservación de vitaminas delicadas, ácidos grasos no saturados, proteínas y otros complementos alimenticios de la artemia, que hacen que esto es un alimento precioso y natural para peces ornamentales.</span></p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-06-16 14:20:45', NULL, NULL, 'Alimento-para-peces-artemia-deshidratadaFd-brine-shrimp-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1483, NULL, 'producto', '5900469011331', 0x414C49545542492D3031, '01133', 5.00, 'Alimento para peces tubifex  tubi-cubi ', '<p>Alimento para peces tubifex tubi-cubi</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">Un alimento natural en forma de cubitos, para peces omnívoros y carnívoros; Es un alimento recogido con gusto por peces y tortugas del agua. Una fuente de proteínas de fácil digestión. Pero en forma fresca.</p><p class=\"ql-align-justify\">TUBI CUBI para peces ornamentales. Materias primas para la alimentación animal: lombrices oligoquetos secas congeladas (Tubifex tubifex). Componentes analíticos: proteína bruta 55,0%, aceites y grasas brutos 5,0%, fibras brutas 3,0%, humedad 10,0%.</p><p><br></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2025-06-16 14:19:00', NULL, NULL, 'Alimento-para-peces-tubifex--tubi-cubi-', 0, 0);
