INSERT INTO `ecom_productos` VALUES (1487, NULL, 'producto', '7503040428238', 0x4A41524F2D3137, 'SP-2823', 5.00, 'Jaula para aves maxi ', '<p>Jaula para aves maxi</p><p><br></p><p>Descripción:</p><p>Jaula para aves con dos comederos, palo de de sujetación, charola extraible, gancho de sujetación para colgar y columpio para aves para que tengan un rato de juego y entretenimiento.</p>', 0, 590, 124, 1, NULL, NULL, NULL, '2026-06-02 20:28:46', '2026-06-02 20:28:46', NULL, 'Jaula-para-aves-maxi-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1488, NULL, 'producto', '7503048378399', 0x414C495645522D3031, 'TP-7839', 5.00, 'Alimento para agapornis y ninfas monteverde ', '<p>Alimento para agapornis y ninfas monteverde</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(49, 34, 55);\">Esta mezcla premium de&nbsp;</span><strong style=\"color: rgb(49, 34, 55);\">mijo amarillo, cártamo, linaza, trigo, alpiste y hasta frijol mungo</strong><span style=\"color: rgb(49, 34, 55);\">&nbsp;es el menú perfecto para mantenerlos felices, activos y con un plumaje tan brillante que parecerán listos para una sesión de fotos.</span></p><p><span style=\"color: rgb(49, 34, 55);\">Sus minerales como el&nbsp;</span><strong style=\"color: rgb(49, 34, 55);\">hierro, fósforo y magnesio</strong><span style=\"color: rgb(49, 34, 55);\">&nbsp;fortalecen el sistema inmunológico, mientras que los&nbsp;</span><strong style=\"color: rgb(49, 34, 55);\">ácidos grasos saludables</strong><span style=\"color: rgb(49, 34, 55);\">&nbsp;protegen la piel y previenen la obesidad.&nbsp;</span></p>', 0, 98, 124, 1, NULL, NULL, NULL, '2025-07-11 14:04:41', NULL, NULL, 'Alimento-para-agapornis-y-ninfas-monteverde-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1489, NULL, 'producto', '7503013897016', 0x414C4948552D3031, '7503013897016', 5.00, 'Alimento para hurón mazuri ', '<p>Alimento para hurón mazuri</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Diseñada para hurónes en cualquier etapa de vida.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Proporcionar una dieta insectívora con gran variedad de ingredientes de origen natural propios de insectívoros.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Apoyar el crecimiento y el desarrollo gracias a la vitamina E y ácidos grasos en su formulación.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Altamente palatable.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Sin sabores artificiales añadidos.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Contiene fuentes naturales de ácidos grasos esenciales</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- No es necesario suplementar con otros productos</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Apropiado para hurónes hamster, cuyo, conejillo de indias, etc.</span></p><p><br></p><p>La cantidad real de alimento de los animales consuman variára segun la espcie, la edad, el tamaño corporal y el esatdo reproductivo fisiológico. en el caso de los hurones se calcula que, pesando entre 900 gr a 1.8 kg consumirán alrededor del 6% de su peso corporal al día. (1/2 a 3/4 taza aproximadamente), y en el caso de las hembras lactantes o gestantes, se calcula un consumo de 3/4 a 1 taza aproximadamente al día, no es necesario proporcionar suplementos u otros alimentos, esta es una dieta completa para todas las etapas de la vida.</p><p><br></p><p><br></p>', 0, 490, 124, 1, NULL, NULL, NULL, '2025-07-14 15:45:02', NULL, NULL, 'Alimento-para-huron-mazuri-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1490, NULL, 'producto', '7503013897207', 0x414C4943552D3036, '7503013897207', 5.00, 'Alimento para cuyo mazuri', '<p>Alimento para cuyo mazuri</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Mazuri Guinea Pig Diet, cuyo, cobaya, simula la típica dieta alta en proteínas y fibra que requiere tu cuyo. Siéntete libre de complementar los insectos en la dieta de tu cuyo con este alimento altamente saludable.</span></p><p><br></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Beneficios</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Diseñada para cuyos en cualquier etapa de vida.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Proporcionar una dieta insectívora con gran variedad de ingredientes de origen natural propios de insectívoros.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Apoyar el crecimiento y el desarrollo gracias a la vitamina E y ácidos grasos en su formulación.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Altamente palatable.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Sin sabores artificiales añadidos.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Contiene fuentes naturales de ácidos grasos esenciales</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- No es necesario suplementar con otros productos</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Apropiado para hamster, cuyo, conejillo de indias, etc.</span></p><p><br></p>', 0, 295, 124, 1, NULL, NULL, NULL, '2026-04-08 06:56:25', NULL, NULL, 'Alimento-para-cuyo-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1491, NULL, 'producto', '7503013897351', 0x414C494348492D3035, '7503013897351', 5.00, 'Alimento para chinchilla mazuri', '<p>Alimento para chinchilla mazuri</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">El alimento de Mazuri Chinchilla Diet, hará que las chinchillas disfruten este alimento, por su sabor y olor agradables, y tú también lo disfrutaras porque verás que mantiene a tus chinchillas sanas y felices en todas las etapas de su vida, con la nutrición balanceada que necesitan. Este pellet está hecho con múltiples fuentes de fibra incluido el heno Timothy, además, linaza como fuente de ácidos grasos omega 3 y probióticos para promover la salud gastrointestinal.</p><p class=\"ql-align-justify\"><br></p><p><br></p><p class=\"ql-align-justify\">Dieta ideal para chinchillas.</p><p class=\"ql-align-justify\">Olor dulce, altamente palatable.</p><p class=\"ql-align-justify\">Nutricionalmente completo, no se necesitan suplementos.</p><p class=\"ql-align-justify\">Sin colorantes ni sabores artificiales.</p><p class=\"ql-align-justify\">Contiene probióticos vivos para apoyar la salud gastrointestinal.</p><p class=\"ql-align-justify\">Contiene linaza, una fuente de ácidos grasos Omega 3.</p><p><br></p>', 0, 260, 124, 1, NULL, NULL, NULL, '2026-04-08 07:25:21', NULL, NULL, 'Alimento-para-chinchilla-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1492, NULL, 'producto', '7503013897313', 0x414C49434F2D3037, '7503013897313', 5.00, 'Alimento para conejo mazuri', '<p>Alimento para conejo mazuri</p><p><br></p><p>Descripción:</p><p>Guarda el alimento para conejo Mazuri Timothy a temperatura ambiente.</p><p>2. Alimente la comida a conejos de todas las etapas de la vida sin la necesidad de suplementos vitamínicos o minerales adicionales.</p><p>3. Las instrucciones de alimentación y las cantidades específicas pueden variar según el tamaño, la edad y el estado de salud del conejo; consulte las pautas de alimentación proporcionadas por el fabricante o consulte a un veterinario para obtener recomendaciones personalizadas.</p>', 0, 230, 124, 1, NULL, NULL, NULL, '2026-04-08 07:11:56', NULL, NULL, 'Alimento-para-conejo-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1493, NULL, 'producto', '7503013897221', 0x414C4948412D3037, '7503013897221', 5.00, 'Alimento para hámster y ratones mazuri', '<p>Alimento para hámster y ratones mazuri</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">Mazuri Rodent es una dieta completa especialmente formulada para cubrir los requerimientos nutricionales de ratas y ratones en todas las etapas de vida. Algunas características y beneficios de este alimento es que contiene extracto seco de yuca para ayudar a reducir el mal olor, sobre todo el olor a amoniaco. Gracias a su forma y textura de bloque grande, le ayudara a estimular la masticación y ayudar a mantener la salud dental. Este producto es una dieta nutricionalmente completa, no se necesitan suplementos adicionales, además es libre de colorantes y sabores artificiales.</p><p><br></p><p class=\"ql-align-justify\">Dieta ideal para roedores, como ratas, ratones, etc.</p><p class=\"ql-align-justify\">Forma de bloque grande para estimular la masticación.</p><p class=\"ql-align-justify\">Nutricionalmente completo, no se necesitan suplementos.</p><p class=\"ql-align-justify\">Sin colorantes ni sabores artificiales.</p><p class=\"ql-align-justify\">Contiene extracto seco de yuca para ayudar a reducir el mal olor.</p><p class=\"ql-align-justify\">Ayuda a mantener la salud dental.</p><p><br></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-06 08:04:25', NULL, NULL, 'Alimento-para-hamster-y-ratones-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1494, NULL, 'producto', '5900469531211', 0x414C4943552D3037, '53121', 5.00, 'Alimento para cuyo tropifit 500gr', '<p>Alimento para cuyo tropifit</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Los componentes básicos son gránulos de remolacha, alfafa e hierba obtenidos por extrusión, que favorece la digestión y la asimilación de los nutrientes. La tecnología de extrusión elimina bacterias y hongos existentes en las materias primas.</span></p><p><br></p><p class=\"ql-align-justify\"><span style=\"color: rgba(0, 0, 0, 0.55);\">El adecuado tamaño y forma de los granos ayudan a desgastar los dientes y garantizan una una correcta higiene oral. La variedad de nutrientes, vitaminas, macronutrientes y oligoelementos de fuentes naturales así como la adición de vitamina C, asegura una excelente condición física, un hermoso pelaje y aporta mucha energía, indispensable para las actividades diarias.</span></p><p><br></p>', 0, 145, 124, 1, NULL, NULL, NULL, '2026-04-23 08:57:27', NULL, NULL, 'Alimento-para-cuyo-tropifit-500gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1495, NULL, 'producto', '7501556441727', 0x4C4543482D3031, 'FL4172', 5.00, 'Leche para conejos y roedores ', '<p>Sustituto de leche para conejos y roedores</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(61, 7, 11);\">l sustituto de leche para Conejos y roedores de RedKite es una formula nutritiva especialmente diseñada para conejos y pequeños roedores. Ideal para suplementar la leche materna en camadas huérfanas, conejos destetados prematuramente o en situaciones de falta de producción de la madre. Con una composición enriquecida con prebióticos, probióticos, nucleótidos y enzimas digestivas, esta fórmula promueve un crecimiento saludable, una digestión eficiente y el fortalecimiento del sistema inmunológico de los conejos</span></p><p><br></p><p><span style=\"color: rgb(61, 7, 11);\">Disolver 1 cucharada sopera rasa (5 g) de Redkite® Sustituto de Leche en 2 cucharadas o 15 ml de agua hervida y caliente (60°C). Brindar de 10 a 20 ml a 38°C por cada 140 g de peso vivo al día. Alrededor de la sexta semana de edad es adecuado iniciar la transición al alimento sólido.Hembras en gestación y lactancia: Espolvorear 1 cucharada sopera rasa (5 g) de Redkite® Sustituto de Leche por cada kg de peso en el alimento seco y suministrar una vez al día, 20 días antes del parto y hasta 2 meses después.No sobrealimente, puede ser perjudicial para la salud de la mascota. Consulte al Médico Veterinario para asegurarse del óptimo crecimiento. Una vez diluido el sustituto, debe mantenerse en refrigeración por máximo 24 horas; después de ese tiempo, deseche el sobrante. No usar el microondas para calentar la fórmula preparada; en su lugar, caliente en baño maría. Una vez abierto el producto, consérvelo en su recipiente original correctamente cerrado. Si observa un cambio de color u olor, deséchelo</span></p>', 0, 258, 124, 1, NULL, NULL, NULL, '2025-09-15 17:51:56', NULL, NULL, 'Leche-para-conejos-y-roedores-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1496, NULL, 'producto', '7501556440799', 0x414C4950412D3032, 'FL4079', 5.00, 'Alimento mezcla de semillas loros y cacatúas', '<p>Alimento mezcla de semillas loros y cacatúas</p><p>Para: Loros cacatúas y conuros</p><p>Cantidad:1 kg</p><p>Descripción: Este alimento elaborado para aves adultas con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá</p><p>Fortificado con vitaminas y minerales.</p><p>Fórmula 100% natural balanceada</p><p>Coloque diariamente el alimento en un recipiente limpio y seco.</p><p><br></p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-07-17 17:16:50', NULL, NULL, 'Alimento-mezcla-de-semillas-loros-y-cacatuas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1497, NULL, 'producto', '7503013897252', 0x414C4950412D3033, '7503013897252', 5.00, 'Alimento loros y guacamayas mazuri', '<p>Alimento mazuri</p><p>Para: Loros y guacamayas</p><p><br></p><p>Descripción:</p><p>Mazuri Parrot Diet es una dieta completa para psitácidos grandes con diversos tamaños de partículas que beneficia a aves como loros, guacamayas, ninfas, entre otros.</p><p><br></p><p>Esta dieta está formulada para aves no reproductoras (aves jóvenes después de la primera muda hasta la edad reproductiva y para aves mantenidas en situaciones no reproductivas). No es adecuada para polluelos en crecimiento.</p><p><br></p><p>Beneficios:</p><p>• Formulado para una nutrición equilibrada - Se utiliza como la dieta principal para aves no reproductoras.</p><p>• Nutrición completa - No requiere mezcla ni suplementos.</p><p>• Forma extruida de varios tamaños - Las partículas variables proporcionan enriquecimiento. La forma extruida evita la clasificación de los ingredientes y ayuda a reducir el riesgo de deficiencias de nutrientes.</p><p>• Menos finos y mayor digestibilidad que los pellets.</p><p>• Menos residuos que las semillas (el 20-50% del peso de las semillas son los cascos).</p><p>• Preparación reducida de la dieta - Menos tiempo para picar frutas y verduras.</p><p>• La formulación permite la suplementación con alimentos adecuados para cada especie. Puede incluir hasta un 20% (en peso) de dieta como producto, semillas, etc. para fomentar comportamientos naturales de alimentación y para entrenamiento y enriquecimiento.</p><p>• Sin colorantes ni sabores artificiales.</p><p>• Fuentes naturales de pigmentos, antioxidantes y ácidos grasos Omega-3.</p>', 0, 320, 124, 1, NULL, NULL, NULL, '2025-07-17 17:19:22', NULL, NULL, 'Alimento-loros-y-guacamayas-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1498, NULL, 'producto', '7503013897269', 0x414C4950412D3034, '7503013897269', 5.00, 'Alimento periquitos ninfas y agapornis mazuri', '<p>Alimento mazuri</p><p>Para: Periquitos ninfas y agapornis</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Forma extruida de varios tamaños: las partículas variables proporcionan enriquecimiento. La forma extruida evita la clasificación de los ingredientes y ayuda a reducir el riesgo de deficiencias nutricionales.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- La formulación permite la suplementación con alimentos apropiados para la especie: puede incluir hasta un 20 % (por peso) de la dieta como productos, semillas, etc. para fomentar los comportamientos de alimentación natural y para el entrenamiento y el enriquecimiento.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Sin colorantes ni sabores artificiales.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Fuentes naturales de pigmentos y antioxidantes.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">- Forma del producto: Alimento extruido: 2 tamaños de partíc</span></p>', 0, 199, 124, 1, NULL, NULL, NULL, '2025-07-17 17:22:15', NULL, NULL, 'Alimento-periquitos-ninfas-y-agapornis-mazuri', 0, 0);
INSERT INTO `ecom_productos` VALUES (1499, NULL, 'producto', '7502278916449', 0x646573, '10014', 5.00, 'Deslanador quita pelo mediano', '<p>Deslanador quita pelo mediano</p><p><br></p><p>Descripción:</p><p>Libera el pelo de la mascota de manera fácil através del botón limpiador con mango ergonómico para agrre firme y cómodo, la cuchilla tiene la función de quitar el pelaje para adelgazar y desenredar sin dañar el pelaje o cortar la piel. Para todo tipo de pelo (largo corto grueso delgado). Elimina enredos, suciedad y pelo muerto.</p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-09-15 17:45:54', NULL, NULL, 'Deslanador-quita-pelo-mediano', 0, 0);
INSERT INTO `ecom_productos` VALUES (1500, NULL, 'producto', '7503048378313', 0x414C4947552D3033, 'SFF-305', 5.00, 'Alimento iguana sunny ', '<p>Alimento iguana sunny</p><p><br></p><p>Descripción:</p><p>Los&nbsp;<strong style=\"background-color: initial;\">Iguana Sticks</strong>&nbsp;son un alimento especialmente formulado para iguanas verdes y otros reptiles herbívoros como tortugas terrestres, geckos y dragones barbudos. Elaborados a base de alfalfa rica en fibra, estos palitos contienen ingredientes vegetales esenciales que garantizan un desarrollo óptimo, excelente condición física y salud duradera. Su proporción adecuada de calcio y fósforo ayuda a prevenir el raquitismo, asegurando huesos fuertes y sanos.</p><p>Enriquecido con&nbsp;<strong style=\"background-color: initial;\">beta caroteno</strong>&nbsp;y&nbsp;<strong style=\"background-color: initial;\">vitaminas D3 y E</strong>, este alimento ofrece los nutrientes necesarios para mantener a tus reptiles activos y saludables. Ideal para aquellos reptiles que disfrutan de una dieta rica en fibra y baja en proteínas animales.</p>', 0, 95, 124, 1, NULL, NULL, NULL, '2025-07-17 17:23:47', NULL, NULL, 'Alimento-iguana-sunny-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1501, NULL, 'producto', '7503013897238', 0x414C49544F2D3134, '7503013897238', 5.00, 'Alimento para tortuga mazuri ', '<p>Alimento para tortuga mazuri</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">Es un alimento completo para tortugas de agua dulce, como las tortugas pintadas, de orejas rojas, en todas las etapas de la vida. Este alimento flotante en pellets para tortugas está diseñado para ser arrojado al agua y así alentar a las tortugas a salir a la superficie para alimentarse. Con altos niveles de pescado y proteína animal, esta dieta de tortuga satisface las necesidades de las especies carnívoras.</p><p><br></p><p class=\"ql-align-justify\">Nutricionalmente completo.</p><p class=\"ql-align-justify\">No se requieren suplementos vitamínicos o minerales.</p><p class=\"ql-align-justify\">Dieta flotante, para el comportamiento de alimentación natural.</p><p class=\"ql-align-justify\">Alto nivel de pescado y proteína animal.</p><p class=\"ql-align-justify\">Satisface las necesidades de las especies carnívoras.</p><p class=\"ql-align-justify\">Contiene vitamina E natural.</p><p><br></p><p><br></p>', 0, 360, 124, 1, NULL, NULL, NULL, '2025-08-24 14:02:40', NULL, NULL, 'Alimento-para-tortuga-mazuri-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1502, NULL, 'producto', '7503013897245', 0x414C49544F2D3135, '7503013897245', 5.00, 'Alimento para tortuga del desierto mazuri ', '<p>Alimento para tortuga del desierto mazuri</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">Tortoise Diet de Mazuri es un alimento extruido, balanceado y nutricionalmente completo para tortugas herbívoras terrestres. Fórmula mejorada con mayor contenido de fibra y suplementada con probióticos, yucca shidigera y extracto de romero. nuestros gránulos contienen la nutrición que sus tortugas necesitan para apoyar la salud de los ojos, la piel y el tracto gastrointestinal, y el crecimiento normal. Con un sabor que a tu tortuga le encantará, sabes que estarán sanas y felices.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Nutrición completa, no se necesitan suplementos de vitaminas o minerales.</p><p class=\"ql-align-justify\">Nivel alto de fibra y almidón bajo.</p><p class=\"ql-align-justify\">Dieta basada en el heno de hierba.</p><p class=\"ql-align-justify\">Contiene vitamina E natural</p><p class=\"ql-align-justify\">Fuente natural de antioxidantes</p><p class=\"ql-align-justify\">Forma de pellets extruida, minimiza los residuos y crea un ambiente de alimentación más natural.</p><p class=\"ql-align-justify\">Contiene cultivos de probióticos vivos ayuda el desarrollo del tracto gastrointestinal.</p><p class=\"ql-align-justify\">Contiene extracto de yucca shidigera que se utiliza para reducir el olor a amoníaco.</p><p class=\"ql-align-justify\"><br></p>', 0, 250, 124, 1, NULL, NULL, NULL, '2025-08-24 14:35:21', NULL, NULL, 'Alimento-para-tortuga-del-desierto-mazuri-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1503, NULL, 'producto', '7503013897122', 0x414C4947552D3034, '7503013897122', 5.00, 'Alimento para iguana mazuri ', '<p>Alimento para iguana mazuri</p><p><br></p><p>Descripción:</p><p class=\"ql-align-justify\">Mazuri Iguana Diet Alimento Para Iguana de 450 gramos, tiene un bajo contenido de almidón y alto contenido de fibra diseñado para Reptiles Herbívoros u Omnívoros terrestres. Adecuada para Iguanas, Uromastyx, Tortugas Pequeñas y Tortugas Omnívoras, esta versátil dieta para Reptiles no solo es un alimento completo para Iguanas, sino que también se puede utilizar como la parte vegetal de una dieta para Reptiles insectívoros. Además de ser nutricionalmente completo, este alimento contiene yuca para ayudar a reducir los olores del amoníaco.</p><p><br></p><p><br></p><p class=\"ql-align-justify\">Alto nivel de fibra.</p><p class=\"ql-align-justify\">Bajo contenido de almidón.</p><p class=\"ql-align-justify\">Se utilizan múltiples fuentes de fibra para simular dietas naturales.</p><p class=\"ql-align-justify\">Ayuda a mantener la digestión.</p><p class=\"ql-align-justify\">Formulado con vitamina A y E, para mantener la salud de los ojos y la piel.</p><p class=\"ql-align-justify\">Partícula extruida, mas pequeña.</p><p class=\"ql-align-justify\">Minimiza los desechos.</p><p class=\"ql-align-justify\">Contiene cultivos de probióticos vivos, para mantener la salud gástrica.</p><p class=\"ql-align-justify\"><br></p>', 0, 260, 124, 1, NULL, NULL, NULL, '2025-07-17 17:28:00', NULL, NULL, 'Alimento-para-iguana-mazuri-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1504, NULL, 'producto', '7503013897344', 0x414C4947452D3031, '7503013897344', 5.00, 'Alimento para dragon barbudo y geckos mazuri ', '<p>Alimento para dragon barbudo y geckos mazuri</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Alimente a libre acceso a los animales insectivoros tanto adultos como juveniles. Los Dragos Barbados jóvenes deben deben tener acceso libre al alimento, mientras que los adultos suelen comer 1 cucharada (6-8g) por día.</span></p><p><br></p><p class=\"ql-align-justify\"><span style=\"color: rgba(0, 0, 0, 0.55);\">Este alimento contiene harina de subproductos de aves, cascarilla de soya molida, trigo molido, pulpa de remolacha seca, arroz integral molido, harina de soya descascarillada, huevo deshidratado...</span></p>', 0, 350, 124, 1, NULL, NULL, NULL, '2025-07-17 17:29:18', NULL, NULL, 'Alimento-para-dragon-barbudo-y-geckos-mazuri-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1505, NULL, 'producto', 'TERRA0412050', 0x544552414D2D30344D, 'TERAM-04M', 5.00, 'Terrario magno 50 x 50 x 120 cm de altura malla metalica', '<p>Terrario magno 50 largo 120 alto</p><p>Marcos: madera</p><p>Malla: metalica no corrosiva</p><p><br></p><p>Descripción:</p><p>Terrario vertical amplio y grande para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de mdera con tela de lona forrrado con adaptacio de soquet para foco y latereles de malla de metal no corrosiva para mayor seguridad, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p><p><br></p><p><br></p>', 0, 2750, 124, 1, NULL, NULL, NULL, '2026-04-23 21:46:34', NULL, NULL, 'Terrario-magno-50-x-50-x-120-cm-de-altura-malla-metalica', 0, 0);
