INSERT INTO `ecom_productos` VALUES (1507, NULL, 'producto', 'TER05MET303050', 0x544552414D2D30354D, 'TERAM-05M', 5.00, 'Terrario blim 50cm de altura malla metalica ', '<p>Terrario blim</p><p>Marcos: madera</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario vertical amplio y grande para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de madera con tela de lona forrrado con adaptacion de soquet para foco y latereles de malla de metalica para mayor seguridad y contencion de tu mascota, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p><p><br></p>', 0, 790, 124, 1, NULL, NULL, NULL, '2026-02-24 07:45:40', NULL, NULL, 'Terrario-blim-50cm-de-altura-malla-metalica-', 0, 0);
