INSERT INTO `ecom_productos` VALUES (1509, NULL, 'producto', '7502217850513', 0x414C49492D3035, 'B703', 5.00, 'Alimento iguana bits 300gr', '<p>Alimento iguana bits</p><p>Contenido: 300grs</p><p>Esferas: 4.5 mm</p><p><br></p><p>Descripción: <span style=\"color: rgb(102, 102, 102);\">alimento para iguanas de todos los tamaños, especialmente formulado para proporcionar todos los nutrientes esenciales para las iguanas verdes</span></p><p><br></p><p>Ingredientes: harinas de alfalfa, trigo, sorgo y arroz; complementos vitaminicos y minerales, vitamina c ortofosfatos y carbonato de calcio</p>', 0, 155, 124, 1, NULL, NULL, NULL, '2025-08-24 13:18:51', NULL, NULL, 'Alimento-iguana-bits-300gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1510, NULL, 'producto', '7502217850513', NULL, 'B703', 5.00, 'ali', '<p>Alimento iguana bits</p><p>Contenido: 300grs</p><p>Esferas: 4.5 mm</p><p><br></p><p>Descripción: <span style=\"color: rgb(102, 102, 102);\">alimento para iguanas de todos los tamaños, especialmente formulado para proporcionar todos los nutrientes esenciales para las iguanas verdes</span></p><p><br></p><p>Ingredientes: harinas de alfalfa, trigo, sorgo y arroz; complementos vitaminicos y minerales, vitamina c ortofosfatos y carbonato de calcio</p>', 0, 155, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'ali', 0, 0);
INSERT INTO `ecom_productos` VALUES (1511, NULL, 'producto', '7501556460551', 0x414C49544F2D3136, 'WAT055', 5.00, 'Alimento tortuga sticks 1.5 kg ', '<p>Alimento tortuga sticks</p><p>Contenido: 1.5 kg</p><p><br></p><p>Descripción:</p><p>Aporta vitaminas, minerales y aminoácidos esenciales para una óptima nutrición y en c<span style=\"color: rgb(15, 17, 17);\">antidades óptimas para el correcto desarrollo del caparazón de las tortugas.</span></p><p><br></p>', 0, 340, 124, 1, NULL, NULL, NULL, '2025-08-24 14:35:47', NULL, NULL, 'Alimento-tortuga-sticks-1.5-kg-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1512, NULL, 'producto', '046798161622', 0x414C4954452D323030, 'AQ-16162', 5.00, 'Alimento hojuela tetra color 200 gr para peces ', '<p>Alimento hojuela tetra color para peces</p><p>Cantidad: 200 gramos</p><p><br></p><p>Descripción:</p><p>Fórmula patentada ProCare que favorece el buen funcionamiento del sistema inmunológico del pez para una salud óptima y larga vida. Mezcla científicamente desarrollada de ingredientes altamente nutritivos, con vitaminas y minerales. Las hojuelas TetraMin de Tetra han sido desarrolladas especialmente para una fácil ingesta, gracias a su forma, textura y sabor. Dieta diseñada especialmente para resaltar los colores rosa, rojo y naranja de los peces de agua dulce.</p><p><br></p><p>Características</p><p>Fórmula avanzada, enriquecida con vitaminas y minerales.</p><p>Excelente textura y palatabilidad.</p><p>Perfeccionado para la óptima nutrición de peces.</p><p>Favorece la coloración intensa de los peces.</p><p>Alta digestibilidad.</p><p>No enturbia el agua.</p>', 0, 660, 124, 1, NULL, NULL, NULL, '2025-08-24 15:27:11', NULL, NULL, 'Alimento-hojuela-tetra-color-200-gr-para-peces-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1513, NULL, 'producto', '7500211004888', 0x414C49434F2D3430, 'Q840', 5.00, 'Alimento hojuela color falkes 40gr para peces ', '<p>Alimento hojuela color flakes para peces</p><p>Cantidad:40 gramos</p><p><br></p><p>Descripción:</p><p>Alimento en hojuelas color flakes ha sido formulado para intensificar los vivos colores de los peces de acuario, los ingredientes especiales del alimento hacen de este la vía segura para que sus peces adquieran el máximo brillo e intensidad en los colores propios de su especie.</p>', 0, 99, 124, 1, NULL, NULL, NULL, '2025-08-24 15:39:35', NULL, NULL, 'Alimento-hojuela-color-falkes-40gr-para-peces-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1514, NULL, 'producto', '7500211001481', 0x414C49434F522D3530, 'Q162', 5.00, 'Alimento rainbow color bites para peces 50gr', '<p>Alimento rainbow color bites para peces</p><p>Cantidad: 50gramos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">fórmula capaz de suplir las necesidades dietéticas de cada especie, favoreciendo que sus peces expresen a plenitud su colorido natural. Los ingredientes con los que se elabora Rainbow Color Bites son de origen natural y 100% seguros para la salud de sus peces. El color de los peces esta dado por sus caracterísiticas genéticas propias de cada especie, no obstante, los peces de colores requieren en su alimentación de ciertos compuestos químicos que acumulan en sus cromatóforos, eritróforos, los que almacenan pigmentos rojos, melanóforos que almacenan pigmentos obscuros y cianóforos almacenan pigmentos azules.&nbsp;</span></p>', 0, 75, 124, 1, NULL, NULL, NULL, '2025-09-15 16:55:55', NULL, NULL, 'Alimento-rainbow-color-bites-para-peces-50gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1515, NULL, 'producto', '7500211004376', 0x414C4953552D3430, 'Q816', 5.00, 'Alimento hojuelas super flakes 40 gr', '<p>Alimento hojuelas super flakes</p><p>Cantidad: 40 grs</p><p><br></p><p>Descripción:</p><p>Para todas las estapas de la vida</p><p><span style=\"color: rgb(64, 43, 64);\">Es una mezcla de hojuelas de colores rojo, verde y amarillo, con olor a camarón y de textura quebradiza, diseñado para ajustarse a las necesidades nutricionales de la mayoría de los peces tropicales y de agua dulce.&nbsp;</span></p><p><span style=\"color: rgb(64, 43, 64);\">Las hojuelas están diseñadas para fortalecer a tus peces en dos vías. Primero la adición de Beta-glucanos estimula la inmunidad celular en la línea de glóbulos blancos encargados de la producción de anticuerpos. Segundo, la incorporación de glucomananos favorece la implantación de una flora microbiana robusta de especies bacterianas benéficas que impiden el establecimiento de patógenos a lo largo del tracto digestivo y por si fuera poco, mejoran significativamente la absorción de los nutrientes.</span></p><p><br></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2025-08-26 16:18:30', NULL, NULL, 'Alimento-hojuelas-super-flakes-40-gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1516, NULL, 'producto', '04679829252', 0x414C49544F2D3137, 'AQ-29252', 5.00, 'Alimento para tortuga reptomin sticks 55gr', '<p>Alimento para tortuga reptomin sticks</p><p>Cantidad: 55gr</p><p><br></p><p>Descripcion:</p><p>Alimento flotante en palitos para todas las tortugas acuáticas, ranas de árbol y salamandras</p><p>Con un alto valor nutricional y fabricados según estrictas normas de calidad</p><p>Enriquecido con vitaminas y calcio, ReptoMin es un alimento formulado científicamente y rico en proteínas</p>', 0, 120, 124, 1, NULL, NULL, NULL, '2025-08-26 16:36:38', NULL, NULL, 'Alimento-para-tortuga-reptomin-sticks-55gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1517, NULL, 'producto', '04679829252', 0x414C49544F2D3138, 'AQ-29254', 5.00, 'Alimento para tortuga reptomin sticks 105gr', '<p>Alimento para tortuga reptomin sticks</p><p>Cantidad: 105gr</p><p><br></p><p>Descripcion:</p><p>Alimento flotante en palitos para todas las tortugas acuáticas, ranas de árbol y salamandras</p><p>Con un alto valor nutricional y fabricados según estrictas normas de calidad</p><p>Enriquecido con vitaminas y calcio, ReptoMin es un alimento formulado científicamente y rico en proteínas</p>', 0, 210, 124, 1, NULL, NULL, NULL, '2025-08-26 17:06:01', NULL, NULL, 'Alimento-para-tortuga-reptomin-sticks-105gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1518, NULL, 'producto', '7500211001726', 0x636C6F, 'Q202', 5.00, 'Anticloro clorkrill 125ml', '<p>Clorokrill agente anticloro</p><p><br></p><p>Descripción:</p><p>Elimina Cloro, cloraminas y halógenos</p><p>Inmediatamente convierte segura el agua del acuario</p><p><br></p>', 0, 55, 124, 1, NULL, NULL, NULL, '2025-09-15 16:44:46', NULL, NULL, 'Anticloro-clorkrill-125ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (1519, NULL, 'producto', '7500211001825', 0x50454E2D3033, 'Q221', 5.00, 'Pentabiocare acondicionador 1 lts ', '<p>Clorokrill agente anticloro</p><p><br></p><p>Descripción:</p><p>Pentabiocare para gua dulce y marinos, Acondicionador multifuncional</p><p>Neutraliza los metales pesados</p><p>Protege la piel de los peces</p><p>Ayuda a que los peces soporten mejor las condiciones de estrés</p><p>Elimina el cloro, las cloraminas y otros halógenos</p><p><br></p>', 0, 250, 124, 1, NULL, NULL, NULL, '2025-08-26 17:35:37', NULL, NULL, 'Pentabiocare-acondicionador-1-lts-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1520, NULL, 'producto', 'MOC11TRARO', 0x4D4F432D3131, 'MOC-11', 5.00, 'Mochila transportadora catmo ', '<p>Mochila catmo para mascotas</p><p>Medidas: 33 x 25 x 41cm (largo x ancho x alto)</p><p><br></p><p>Descripción: Malla transpirable y refrescante integrada, resistente a desgaste y arañazos, duradera y elástica, cintas ajustables con parte trasera alchonada para mayor comodidad al cargar, con compartimentos adaptables a tus accesorios de tu mascota, tapete sanitario, gancho a collar o pechera y cómoda para un paseo agradable para perros pequeños, gatos, mini pig, cuyos, conejos, chinchillas, pajaros pequeños, urones, ratas, etc,</p><p><br></p><p>color: rosa, azul verde, morado (colores sujetos a disponibilidad)</p>', 0, 350, 124, 1, NULL, NULL, NULL, '2025-09-02 06:20:08', NULL, NULL, 'Mochila-transportadora-catmo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1521, NULL, 'producto', 'MOC12TRAROS', 0x4D4F432D3132, 'MOC-12', 5.00, 'Mochila transportadora maleti', '<p>Mochila catmo para mascotas</p><p>Medidas: (largo x ancho x alto)</p><p><br></p><p>Descripción: Malla transpirable y refrescante integrada, resistente a desgaste, arañazos y elástica, cintas ajustables con parte trasera alchonada para mayor comodidad al cargar, con compartimentos adaptables a tus accesorios de tu mascota, tapete sanitario, gancho para collar o pechera y cómoda para un paseo agradable para perros pequeños, gatos, mini pig, cuyos, conejos, chinchillas, pajaros pequeños, urones, ratas, etc,</p><p><br></p><p>color: rosa, azul verde, morado (colores sujetos a disponibilidad)</p>', 0, 350, 124, 1, NULL, NULL, NULL, '2025-09-15 16:39:47', NULL, NULL, 'Mochila-transportadora-maleti', 0, 0);
INSERT INTO `ecom_productos` VALUES (1522, NULL, 'producto', 'JAULAHA25', 0x4A48412D3235, 'SP-3635', 5.00, 'Jaula divi para hámster ', '<p>Jaula divi para hámster</p><p>Color: azul cielo</p><p><br></p><p>Incluye:</p><p>Rueda 14 cm</p><p>Tazon para alimento</p><p>Asa de sujetación en medio</p><p>Panel divisor</p><p>Doble puerta</p><p>Bebedero 60 ml</p>', 0, 490, 124, 1, NULL, NULL, NULL, '2025-09-02 07:02:45', NULL, NULL, 'Jaula-divi-para-hamster-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1523, NULL, 'producto', 'COLCA01', 0x434F4C43412D3031, 'COLCA-01', 10.00, 'Cama colchon spri chico', '<p>Cama colchon spri chico</p><p><br></p><p>Descripción:</p><p>Cama colchon que brimda soporte comodidad al dormir o descansar tu mascota. Esta compuesto por un núcleo o alma que proporciona apoyo y tejidos que ofrcen confort, adaptabilidad, transpirabilidad al cuerpo de tu mascota.</p><p>Para perros pequeños, gatos, mini pig, hurones, conejos y mas.</p><p><br></p>', 0, 490, 124, 1, NULL, NULL, NULL, '2025-09-02 07:19:05', NULL, NULL, 'Cama-colchon-spri-chico', 0, 0);
INSERT INTO `ecom_productos` VALUES (1524, NULL, 'producto', 'COLCA0280100', 0x434F4C43412D3032, 'COLCA-02', 10.00, 'Cama colchon spri grande', '<p>Cama colchon spri grande</p><p><br></p><p>Descripción:</p><p>Cama colchon que brimda soporte comodidad al dormir o descansar tu mascota. Esta compuesto por un núcleo o alma que proporciona apoyo y tejidos que ofrcen confort, adaptabilidad, transpirabilidad al cuerpo de tu mascota.</p><p>Para razas pequeñas, medianas y grandes perros, gatos, mini pig, hurones, conejos.</p><p><br></p>', 0, 950, 124, 1, NULL, NULL, NULL, '2025-09-03 06:47:09', NULL, NULL, 'Cama-colchon-spri-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (1525, NULL, 'producto', 'CASIMP08', 0x4341532D3038, 'CAS-08', 10.00, 'Casa impermeable inter chica azul', '<p>Casa inter chica</p><p>Color: azul</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;<strong>razas extrachicas</strong>.</p><p>Perfecta para perros mini como chihuahua, pomerania, yorkshire, pug o gatitos tambien mini pig, patos, gallinas y más.</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p><p><br></p>', 0, 590, 124, 1, NULL, NULL, NULL, '2025-12-09 08:27:22', NULL, NULL, 'Casa-impermeable-inter-chica-azul', 0, 0);
INSERT INTO `ecom_productos` VALUES (1526, NULL, 'producto', 'CAS09INTER', 0x4341532D3039, 'CAS-09', 10.00, 'Casa impermeable inter mediana rosa ', '<p>Casa inter rosa</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;<strong>razas extrachicas chicas </strong></p><p>Perfecta para perros mini como chihuahua, pomerania o yorkshire, pug,fox terrier, boder collie, beagle. y mas</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p><p><br></p>', 0, 990, 124, 1, NULL, NULL, NULL, '2025-09-03 07:26:00', NULL, NULL, 'Casa-impermeable-inter-mediana-rosa-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1527, NULL, 'producto', 'CAS10IMP', 0x4341532D3130, 'CAS-10', 5.00, 'Casa impermeable inter grande verde', '<p>Casa inter grande verde</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;<strong>razas extrachicas chicas, medianas, grandes.</strong></p><p>Perfecta para perros mini como chihuahua, pomerania o yorkshire, pug, fox terrier, boder collie, beagle, pastor aleman, bóxer, akita, labrador, cocker y mas.</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p><p><br></p>', 0, 1650, 124, 1, NULL, NULL, NULL, '2025-09-03 07:26:54', NULL, NULL, 'Casa-impermeable-inter-grande-verde', 0, 0);
INSERT INTO `ecom_productos` VALUES (1528, NULL, 'producto', 'CAS11IMPE', 0x4341532D3131, 'CAS-11', 5.00, 'Casa impermeable inter extragrande roja ', '<p>Casa inter extragrande roja</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;<strong>razas extrachicas chicas, medianas, grandes.</strong></p><p>Perfecta para perros mini como chihuahua, pomerania o yorkshire, pug, fox terrier, boder collie, beagle, pastor aleman, bóxer, akita, labrador, cocker y mas.</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p><p><br></p>', 0, 2990, 124, 1, NULL, NULL, NULL, '2025-09-03 07:27:35', NULL, NULL, 'Casa-impermeable-inter-extragrande-roja-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1529, NULL, 'producto', '7503026084335', 0x4C41542D3031, 'LAT-01', 3.00, 'Lata Nupec Digestivo con Pescado Alimento húmedo ', '<p>Lata nupec digestivo con pescado alimento humedo</p><p><br></p><p>Descripción:</p><p>Tamaño de la raza: Todos los tamaños.</p><p>Tipo de comida para mascotas: Alimento Humedo</p><p>Peso de la unidad: 100 g</p><p>Sabor: Pescado</p><p>Es protector de la salud bucal.</p><p>Necesidades especiales: digestive.</p><p><br></p><p><br></p>', 0, 480, 124, 1, NULL, NULL, NULL, '2025-09-23 23:02:36', NULL, NULL, 'Lata-Nupec-Digestivo-con-Pescado-Alimento-humedo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1530, NULL, 'producto', '7730997410973', 0x5041532D3031, 'PAS-01', 5.00, 'Tableta masticable nexgard  2-3.5kg para pulgas y garrapatas', '<p><br></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Nexgard spectra Merial es un desparasitante y anti pulgas y garrapatas, todo en uno. Tu perro está protegido por 1 mes contra pulgas, garrapatas y parásitos internos. Sarnas, áscaris, anquilostomas y tricocéfalos. Nexgard Spectra utiliza los ingredientes activos Milbemicina Oxima y Afoxolaner para protegerlo.</span></p><p><br></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Elimina los parásitos internos y externos más comunes</span></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Duración de 30 días protegido</span></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Alta Palatabilidad y fácil administración</span></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Nexgard Spectra es un masticable que será del total agrado de tu mascota porque tiene un delicioso sabor a carne de res.&nbsp;</span></p><p><br></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Nexgard Spectra puede utilizarse sin problemas en caninas en gestación o lactancia.</span></p><p><br></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">* Para elegir la tableta adecuada es importante que conozcas el peso de tu perrito.</span></p><p><span style=\"background-color: rgb(245, 245, 245); color: rgb(51, 62, 72);\">Consulte a su medico veterinario﻿</span></p><p><br></p>', 0, 385, 124, 1, NULL, NULL, NULL, '2025-09-23 14:33:51', NULL, NULL, 'Tableta-masticable-nexgard--2-3.5kg-para-pulgas-y-garrapatas', 0, 0);
