INSERT INTO `ecom_productos` VALUES (1546, NULL, 'producto', 'TERAL014040', 0x544552414C2D3031, 'TERAL-01', 5.00, 'Terrario cuba puertas delizables 40 x 40cm ', '<p>Terrario cuba puertas deslizables</p><p>Espesor vidrio: 6 mm</p><p>Marcos: Aluminio</p><p>Malla metalica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario cubo cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza, en ambas puertas cuenta con cerradura de pasador para mayor seguridad y en la parte superior de malla metálica no corrosiva. El cuál no solo lo puedes usar como terrario sino formar tambien hasta un paludario. </span></p>', 0, 1599, 124, 1, NULL, NULL, NULL, '2026-05-18 14:22:33', NULL, NULL, 'Terrario-cuba-puertas-delizables-40-x-40cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1547, NULL, 'producto', 'TERAL024040100', 0x544552414C2D3032, 'TERAL-02', 5.00, 'Terrario enor puertas delizables 80 x 40 x 50cm ', '<p>Terrario enor puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario rectangualr de cristal con alumnio para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva.</span></p>', 0, 3750, 124, 1, NULL, NULL, NULL, '2026-03-13 07:30:28', NULL, NULL, 'Terrario-enor-puertas-delizables-80-x-40-x-50cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1548, NULL, 'producto', 'TERAL03603030', 0x544552414C2D3033, 'TERAL-03', 5.00, 'Terrario recon puertas delizables 60 x 30 cm ', '<p>Terrario cuba puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal: 4mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario rectangular cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva.</span></p>', 0, 1750, 124, 1, NULL, NULL, NULL, '2026-01-05 21:29:10', NULL, NULL, 'Terrario-recon-puertas-delizables-60-x-30-cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1549, NULL, 'producto', 'TERAL04404080', 0x544552414C2D3034, 'TERAL-04', 5.00, 'Terrario selet puerta abatible 45 x 80cm ', '<p>Terrario selec puerta abatible</p><p>Marcos: aluminio</p><p>Espesor cristal: 6 mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario cubo alto con cristal para reptiles pequeños, medianos como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta en la parte frontal que se puede abrir hacia la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva, laterales y parte frontal inferior. Con sistema puch para facil sistema de abrir y cerrar.</p><p><br></p><p><br></p>', 0, 3500, 124, 1, NULL, NULL, NULL, '2025-09-24 13:03:11', NULL, NULL, 'Terrario-selet-puerta-abatible-45-x-80cm-', 0, 0);
