INSERT INTO `ecom_productos` VALUES (1551, NULL, 'producto', 'TERA13202020', 0x544552412D3133, 'TERA-13', 5.00, 'Terrario cuby con puerta deslizable 20 x 20cm ', '<p>Terrario cuby puerta abatible</p><p>Espesor cristal: 3mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario cubo de cristal para reptiles pequeños, medianos como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta en la parte frontal que se puede abrir hacia la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p><p><br></p><p><br></p>', 0, 390, 124, 1, NULL, NULL, NULL, '2025-09-24 13:25:50', NULL, NULL, 'Terrario-cuby-con-puerta-deslizable-20-x-20cm-', 0, 0);
