INSERT INTO `ecom_productos` VALUES (1553, NULL, 'producto', 'PERMUE0190', 0x5045524D2D3031, 'PERM-01', 5.00, 'Pecera imen con mueble con marcos aleman ', '<p>Pecera imen con meuble con marcos aleman</p><p>Espesor cristal: 6mm</p><p>Medidas pecera: 90 x 35 x 40cm </p><p>Medidas mueble: 93.5 x 37 x 92cm</p><p><br></p><p>Descripción:</p><p>Pecera rectangular para peces, reptiles, roedores, con gran espacio para ellos con marcos aleman sin marcos para mayor visibilidad, con base metálica forrada de madera para mayor calidad y elegancia un acuario para tu hogar oficina y mas.</p>', 0, 6950, 124, 1, NULL, NULL, NULL, '2025-09-24 13:54:34', NULL, NULL, 'Pecera-imen-con-mueble-con-marcos-aleman-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1554, NULL, 'producto', 'TERAM066040M', 0x544552414D2D30364D, 'TERAM-06M', 5.00, 'Terrario delmy 80cm de largo malla metalica', '<p>Terrario delmy</p><p>Marcos: madera</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario horizontal amplio y grande para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de madera con tela de lona forrrado con adaptacion de soquet para foco y latereles de malla de metalica para mayor seguridad y contención de tu mascota, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p>', 0, 1700, 124, 1, NULL, NULL, NULL, '2026-05-04 08:10:38', NULL, NULL, 'Terrario-delmy-80cm-de-largo-malla-metalica', 0, 0);
