INSERT INTO `ecom_productos` VALUES (1556, NULL, 'producto', '7501325468542', 0x4E5543324B, 'NUC2K', 5.00, 'Nupec Croqueta Costal Cachorro Nutrición Canina Científica 2 kg', '<h3><strong>BENEFICIOS</strong></h3><p>Nutrientes funcionales de acuerdo a las necesidades de tu cachorro.</p><p><br></p><p>Omega 3 y 6 para la protección de la piel y el pelaje.</p><p>Balance mineral para el desarrollo de huesos y dientes fuertes.</p><p>Vitamina E y selenio para fortalecer el sistema inmune.</p><p><br></p><h3>¿Por qué&nbsp;<strong>NUPECMR&nbsp;Cachorro</strong>?</h3><p><br></p><p>En NUPECMR&nbsp;estamos conscientes de las necesidades específicas de un cachorro.</p><p>Sabemos que se encuentra en desarrollo y necesita el doble de energía que un adulto del mismo peso, por ello hemos diseñado un alimento con el balance de vitaminas, minerales, grasas, proteínas y energía adecuados para esta etapa de vida que definirá su calidad de vida adulta.</p>', 0, 315, 124, 1, NULL, NULL, NULL, '2025-09-25 00:17:54', NULL, NULL, 'Nupec-Croqueta-Costal-Cachorro-Nutricion-Canina-Cientifica-2-kg', 0, 0);
