INSERT INTO `ecom_productos` VALUES (1561, NULL, 'producto', '7501325468542', 0x4E554353324B, 'NUCS2K', 5.00, 'Nupec Croqueta Costal Senior Nutrición Para Mascotas Especiales 2 kg', '<h3><strong>BENEFICIOS</strong></h3><p><br></p><p><strong>Promueve la salud articular.</strong></p><p><strong>Ayuda en el mantenimiento de la masa ósea y muscular.</strong></p><p><strong>Favorece la respuesta del sistema inmunológico.</strong></p><p><br></p><h3>¿Por qué&nbsp;<strong>NUPECMR&nbsp;Senior</strong>?</h3><p><br></p><p>En NUPECMR&nbsp;estamos conscientes de que el metabolismo de un canino senior requiere de una nutrición formulada específicamente para cubrir las necesidades propias de un adulto en etapa madura. Por ello hemos desarrollado un alimento con los nutrientes esenciales para retrasar el envejecimiento del organismo, fortaleciendo el sistema inmune y las articulaciones, manteniéndolo activo y sano por más tiempo.</p>', 0, 435, 124, 1, NULL, NULL, NULL, '2025-09-25 00:19:37', NULL, NULL, 'Nupec-Croqueta-Costal-Senior-Nutricion-Para-Mascotas-Especiales-2-kg', 0, 0);
