INSERT INTO `ecom_productos` VALUES (1563, NULL, 'producto', '7501325468542', 0x4E5543435250324B, 'NUCCRP2K', 5.00, 'Nupec Croqueta Costal Cachorro Razas pequeñas Nutrición Canina Científica 2 kg', '<h3><strong>BENEFICIOS</strong></h3><p>Ingredientes funcionales de acuerdo con las necesidades del cachorro de raza pequeña.</p><p><br></p><p><strong>Omega 3 y 6 para la protección de la piel y el pelaje.</strong></p><p><strong>Balance mineral para el desarrollo de huesos y dientes fuertes.</strong></p><p><strong>Vitamina E y selenio para fortalecer el sistema inmune.</strong></p><p><br></p><h3>¿Por qué&nbsp;<strong>NUPECMR&nbsp;Cachorro raza pequeña</strong>?</h3><p><br></p><p>En NUPECMR&nbsp;estamos conscientes de que un cachorro de raza pequeña alcanza su etapa adulta en menor tiempo (de 7 a 12 meses), y que tiene un tracto digestivo con una capacidad limitada. Por ello hemos diseñado un alimento con la densidad nutricional y energética que les ayuda a potencializar el crecimiento que definirá su calidad de vida adulta.</p>', 0, 385, 124, 1, NULL, NULL, NULL, '2025-09-25 00:20:21', NULL, NULL, 'Nupec-Croqueta-Costal-Cachorro-Razas-pequenas-Nutricion-Canina-Cientifica-2-kg', 0, 0);
