INSERT INTO `ecom_productos` VALUES (1565, NULL, 'producto', '7503008553248', 0x4E5543415250324B, 'NUCARP2K', 10.00, 'Nupec Croqueta Costal Adulto Razas pequeñas Nutrición Canina Científica 2 kg', '<h3><strong>BENEFICIOS</strong></h3><p><br></p><p><strong>Omega 3 y 6 para una piel saludable y pelaje radiante.</strong></p><p><strong>Extracto de raíz de achicoria como prebiótico para una excelente digestión.</strong></p><p><strong>Balance de aminoácidos para una condición óptima</strong></p><p><br></p><h3>¿Por qué&nbsp;<strong>NUPECMR&nbsp;Adulto Raza Pequeña</strong>?</h3><p><br></p><p>En NUPECMR&nbsp;estamos conscientes de las necesidades específicas de un perro adulto de razas pequeñas.</p><p>Sabemos que tiene dientes más pequeños, por ello hemos diseñado una croqueta con la forma y textura adecuada para facilitar su prehensión y masticación. Un canino de raza pequeña es más activo; sin embargo, la capacidad de su tracto digestivo es limitada, por ello necesitan un alimento con una densidad nutricional y energética adecuada para conservar su masa muscular y vitalidad.</p>', 0, 335, 124, 1, NULL, NULL, NULL, '2025-09-29 14:30:01', NULL, NULL, 'Nupec-Croqueta-Costal-Adulto-Razas-pequenas-Nutricion-Canina-Cientifica-2-kg', 0, 0);
