INSERT INTO `ecom_productos` VALUES (1579, NULL, 'producto', '7503038261267', 0x43524F4E552D3031, 'CRONU-01', 5.00, 'Croqueta nucan cachorro razas medianas y grandes ', '<p>Croqueta nucan cachorro razas medinas y grandes</p><p><br></p><p>Descripción:</p><p>Alimento balanceado formulado para cachorros de un mes de nacidos hasta un año de edad, hembras gestantes y lactantes.</p><p>Croquetas deliciosas verdaderamente nutritivas con ingredientes de alta calidad que ofrecen a tu mascota una vida sana y plena.</p><p>Para crecer sano y fuerte.</p><p>Para tener una vida llena de vitalidad.</p><p>Con el óptimo balance de grasa, proteína y fibra.</p><p><br></p>', 0, 55, 124, 1, NULL, NULL, NULL, '2025-09-29 12:29:08', NULL, NULL, 'Croqueta-nucan-cachorro-razas-medianas-y-grandes-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1580, NULL, 'producto', '7503038261212', 0x43524F4E552D3032, 'CRONU-02', 5.00, 'Croqueta nucan adulto razas medianas y grandes ', '<p>Croqueta nucan adulto razas medinas y grandes</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Nucan by Nupec son croquetas deliciosas y verdaderamente nutritivas con ingredientes de alta calidad que ofrecen a tu mascota una vida sana, plena y feliz. Gran alimentación a un precio que te va a encantar.</span></p><p><br></p><p>Alimento balanceado formulado para perros adultos de un año en adelante.</p><p>Croquetas deliciosas verdaderamente nutritivas con ingredientes de alta calidad que ofrecen a tu mascota una vida sana y plena.</p><p>Para una mascota sana y que te acompañe mucho tiempo.</p><p>Con más proteína para fortalecer sus músculos.</p><p>Con 21% proteína y 9% grasa.</p><p><br></p>', 0, 50, 124, 1, NULL, NULL, NULL, '2025-09-29 13:27:19', NULL, NULL, 'Croqueta-nucan-adulto-razas-medianas-y-grandes-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1581, NULL, 'producto', '7503038261311', 0x43524F4E552D3033, 'CRONU-03', 5.00, 'Croqueta nucan senior todas las razas', '<p>Croqueta nucan senior todas las razas</p><p><br></p><p>Descripción:</p><p>Proteína bruta del 24% que apoya el mantenimiento muscular de perros senior.</p><p>Contiene glucosamina y condroitina para articulaciones sanas.</p><p>Enriquecido con vitaminas y minerales para un sistema inmunológico fuerte.</p><p>Incluye ácidos grasos Omega 3 y 6 que favorecen piel y pelaje.</p><p>Fórmula con fibras y prebióticos que promueven una digestión saludable.</p><p><br></p><p><br></p>', 0, 55, 124, 1, NULL, NULL, NULL, '2025-09-29 13:25:48', NULL, NULL, 'Croqueta-nucan-senior-todas-las-razas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1582, NULL, 'producto', '7503038261090', NULL, 'CRONU-04', 5.00, 'Croqueta nucan cachorro razas pequeñas', '<p>Croqueta nucan cachorro razas pequeñas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Perfecta para cuidar la alimentación de tu mascota. Diseñado específicamente para cachorros de razas pequeñas, este alimento seco de alta calidad contiene ingredientes premium como carne, aceite de ave, maíz y vegetales, garantizando una nutrición balanceada y deliciosa, con un atractivo sabor a frutos rojos. Su fórmula aporta un 27% de proteína bruta, el nivel óptimo para el crecimiento saludable de tu perrito. Además, su contenido de fibra cruda mínima del 4% favorece una digestión efectiva.</span></p><p><br></p>', 0, 55, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Croqueta-nucan-cachorro-razas-pequenas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1583, NULL, 'producto', '7503038261090', 0x43524F4E552D3034, 'CRONU-04', 5.00, 'Croqueta nucan cachorro razas pequeñas', '<p>Croqueta nucan cahorro razas pequeñas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">perfecta para cuidar la alimentación de tu mascota. Diseñado específicamente para cachorros de razas pequeñas, este alimento seco de alta calidad contiene ingredientes premium como carne, aceite de ave, maíz y vegetales, garantizando una nutrición balanceada y deliciosa, con un atractivo sabor a frutos rojos. Su fórmula aporta un 27% de proteína bruta, el nivel óptimo para el crecimiento saludable de tu perrito.</span></p>', 0, 55, 124, 1, NULL, NULL, NULL, '2025-09-29 13:24:37', NULL, NULL, 'Croqueta-nucan-cachorro-razas-pequenas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1584, NULL, 'producto', '7503038261076', 0x43524F4E552D3035, 'CRONU-05', 5.00, 'Croqueta nucan adulto razas pequeñas', '<p>Croqueta nucan adulto razas pequeñas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Nucan Adulto Raza Pequeña, con un peso neto de 1.8 kg, está diseñado específicamente para perros de raza pequeña, asegurando que reciban la nutrición que necesitan en esta etapa de su vida. Con un porcentaje de proteína bruta del 23%, nuestros ingredientes de alta calidad, que incluyen carne, maíz, vegetales y aceite de ave, brindan un sabor irresistible de frutos rojos. Además, este alimento seco no solo mejora su vitalidad y bienestar, sino que también actúa como protector de la salud oral, garantizando un cuidado integral.</span></p>', 0, 50, 124, 1, NULL, NULL, NULL, '2025-09-29 13:31:27', NULL, NULL, 'Croqueta-nucan-adulto-razas-pequenas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1585, NULL, 'producto', 'SUBEBAJA01ROS', 0x5355422D3031, 'RJ197', 10.00, 'Tunel para hámster sube y baja', '<p>Tunel para hámster sube y baja</p><p><br></p><p>Descripción:</p><p>Tunel para hámster subi baja con dos orificos juegute para desestres y disversión de tu mamífero roedor.</p>', 0, 125, 124, 1, NULL, NULL, NULL, '2025-10-02 17:24:17', NULL, NULL, 'Tunel-para-hamster-sube-y-baja', 0, 0);
INSERT INTO `ecom_productos` VALUES (1586, NULL, 'producto', '7503020053313', 0x52454C41582D3031, 'RELAX-01', 10.00, 'Premio para perro relax nupec ', '<p>Premio para perro relax nupec</p><p><br></p><p>Descripción:</p><p>Premio para perros con ingredientes funcionales auxiliar en el manejo de ansiedad y estrés.</p><p>En NUPEC estamos conscientes de que el estilo de vida actual expone a nuestras mascotas a ciertos niveles de estrés. Por ello que hemos desarrollado un premio con ingredientes funcionales que ayudan a disminuir la ansiedad de tu mascota, mejorando su calidad de vida.</p><p>BENEFICIOS: Con Passiflora incarnata, que genera un efecto relajante. Contiene complejo B, esencial para mantener saludables las funciones del sistema nervioso central.</p><p><br></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2025-10-02 17:45:02', NULL, NULL, 'Premio-para-perro-relax-nupec-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1587, NULL, 'producto', '77982176423688', 0x504947412D3031, 'PIGA01', 5.00, 'Pipeta protech antipulgas antiparasitaria para gatos de 1 a 5kg', '<p>Pipeta protech antipulgas antiparasitaria para gatos</p><p>Edad: 1 a 5 años</p><p><br></p><p>Descripción:</p><p>Protech Gatos, pipeta antiparasitaria con acción ambiental.</p><p>Permite tratar, controlar y prevenir las infestaciones en los gatos causadas por pulgas y garrapatas.</p><p>Formulación con potente efecto pulguicida sobre el animal, rápido poder de volteo y control ambiental fotoestable, con efecto residual y acumulativo.</p><p>Protech Gatos actúa directamente sobre las formas inmaduras de parásitos externos que se encuentran en el hogar (pisos, camas, alfombras, sillones, etc.).</p><p>Previene la proliferación de vectores y las enfermedades transmitidas por ellos.</p><p><br></p>', 0, 210, 124, 1, NULL, NULL, NULL, '2025-10-08 14:49:32', NULL, NULL, 'Pipeta-protech-antipulgas-antiparasitaria-para-gatos-de-1-a-5kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1588, NULL, 'producto', '7798176423671', 0x504947412D3032, 'PIGA-02', 5.00, 'Pipeta protech antipulgas antiparasitaria para gatos para mas de 5 kg', '<p>Pipeta protech antipulgas antiparasitaria para gatos</p><p>Edad: mas de 5 kg</p><p><br></p><p>Descripción:</p><p>Protech Gatos, pipeta antiparasitaria con acción ambiental.</p><p>Permite tratar, controlar y prevenir las infestaciones en los gatos causadas por pulgas y garrapatas.</p><p>Formulación con potente efecto pulguicida sobre el animal, rápido poder de volteo y control ambiental fotoestable, con efecto residual y acumulativo.</p><p>Protech Gatos actúa directamente sobre las formas inmaduras de parásitos externos que se encuentran en el hogar (pisos, camas, alfombras, sillones, etc.).</p><p>Previene la proliferación de vectores y las enfermedades transmitidas por ellos.</p>', 0, 230, 124, 1, NULL, NULL, NULL, '2026-03-04 20:44:23', NULL, NULL, 'Pipeta-protech-antipulgas-antiparasitaria-para-gatos-para-mas-de-5-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1589, NULL, 'producto', 'antipulg', NULL, 'br', 5.00, 'Tableta masticable bravecto 4.5-10kg', '<p>Tableta masticable bracvecto </p><p>Para: pulgas, garrapatas y ácaros</p><p>Peso: 4.5 -10 kg</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(23, 23, 23);\">Tabletas masticables a base de fluralaner para el tratamiento de infestaciones por garrapatas, pulgas y ácaros de la sarna demodécica e infestaciones por ácaros Otodectes cynotis, también evita la transmisión de Dipylidium caninum en perros durante 37 días</span></p><p><br></p><p><br></p>', 0, 325, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Tableta-masticable-bravecto-4.5-10kg', 0, 0);
