INSERT INTO `ecom_productos` VALUES (1595, NULL, 'producto', '892383002005', 0x424F4E532D3031, '1124197', 10.00, 'Smartbones de pechuga de pollo ', '<p>Smartbomnes de pechuga de pollo</p><p>Cantidad: 8 pza</p><p><br></p><p>Descripción:</p><p>Fáciles de digerir ya que están hechos con pollo y vegetales</p><p>Libre de cuero crudo</p><p>Hecho con pollo y vegetales</p><p>REAL CHICKEN: Made with a vegetable outside wrapped around real chicken inside</p><p>Enriquecidos con vitamina B12 que fortalece el sistema nervioso de tu perro y vitamina e para mantener su piel saludable, dientes limpios y pelo brillante</p><p>Mantienen los dientes y encías saludables ya que ayudan a remover el sarro</p><p>Vitaminas y minerales enriquecidos</p><p><br></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2025-10-11 07:52:23', NULL, NULL, 'Smartbones-de-pechuga-de-pollo-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1596, NULL, 'producto', '810833020003', 0x424F4E532D3032, '1124186', 10.00, 'Smartbones de camote', '<p>Smartbomnes de camote</p><p>Cantidad: 8 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Hecho con vegetales, pollo y camote</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">contiene clorofila para refrescar el aliento y bicarbonato de sodio que ayuda a blanquear los dientes y evitar la acumulación del sarro,</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Fácil de digerir</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Enriquecido con vitaminas y minerales</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Ayudan a mantener dientes y encías sanas.</span></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2025-10-11 07:40:03', NULL, NULL, 'Smartbones-de-camote', 0, 0);
INSERT INTO `ecom_productos` VALUES (1597, NULL, 'producto', '892383002104', 0x424F4E532D3033, '1124187', 10.00, 'Smartbones de mantequilla de maní', '<p>Smartbomnes de mantequilla de maní</p><p>Cantidad: 8 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(51, 51, 51);\">Consiente a tu mascota con este delicioso premio en forma de huesito con Sabor a Crema de Cacahuate. Son premios masticables hechos con verduras y pechuga de pollo. Es la alternativa saludable para consentir a tu perro elaborada sin carnaza, por lo que ayudará a tu mascota a mantener dientes y encías saludables. Este delicioso premio vegetal está enriquecido con vitaminas y minerales, además de que por sus ingredientes son fáciles de digerir. El tamaño de este hueso es ideal y recomendado para razas mini.</span></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2025-10-11 07:45:30', NULL, NULL, 'Smartbones-de-mantequilla-de-mani', 0, 0);
INSERT INTO `ecom_productos` VALUES (1598, NULL, 'producto', '892383002203', 0x424F4E532D3034, '1124184', 10.00, 'Smartbones dental con vegetales y pollo', '<p>Smartbomnes dental con vegetales y pollo</p><p>Cantidad: 8 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Contribuyen a la salud dental de los perros, reduciendo el sarro, manteniendo los dientes blancos y mejorando el aliento.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Smart Bones Dental son beneficiosos para el aliento fresco, dientes más claros y menor acumulación de sarro gracias a la masticación. Estos huesos mini están elaborados con vegetales y filete de pollo, y contienen bicarbonato de sodio y clorofila para un sabor irresistible.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Ideales para perros con necesidad de masticar, estos premios también promueven la higiene oral. Se recomienda ofrecer una pieza diariamente y desechar restos.</span></p>', 0, 110, 124, 1, NULL, NULL, NULL, '2025-10-11 07:51:28', NULL, NULL, 'Smartbones-dental-con-vegetales-y-pollo', 0, 0);
INSERT INTO `ecom_productos` VALUES (1599, NULL, 'producto', '850030015549', 0x4348552D3530, 'USA654', 5.00, 'Churu premios para gato ', '<p>Churru premios para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">la irresistible Variedad de Churu Recetas de Atún! El snack perfecto que lo hará ronronear de felicidad! Este delicioso mix de premios en forma de puré, incluye 4 deliciosas recetas: Atún, Atún con Vieira, Atún con sabor a Almejas y Atún con sabor a Cangrejo, brindando a tu felino una experiencia única de sabor. Con su textura cremosa y delicioso sabor, estos snacks libres de granos, saborizantes, colorantes ni conservadores artificiales son ideales para consentir a tu gatito y promover su bienestar.&nbsp;</span></p>', 0, 790, 124, 1, NULL, NULL, NULL, '2025-10-11 13:13:08', NULL, NULL, 'Churu-premios-para-gato-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1600, NULL, 'producto', 'TOR19HEXAALT', NULL, 'TOR-19', 5.00, 'Tortuguero hexagonal alto', '<p><br></p><p>Descripción:</p><p>Tortuguero hexagonal alto con isla para toprtugas chicas, medianas con zona seca para ellas, para que tengan un amplio espacio para nadar.</p><p><br></p><p>Color: azul, cafe blanco, azul, cacahuate y más (color sujeto a disponibilidad) puede escoger colores.</p>', 0, 980, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Tortuguero-hexagonal-alto', 0, 0);
INSERT INTO `ecom_productos` VALUES (1601, NULL, 'producto', 'TORCUA404020', 0x544F522D3230, 'TOR-20', 7.00, 'Tortuguero cuadrado 40 x 40 x 20cm', '<p>Tortuguero cuadrado</p><p>Espesor: 3 mm</p><p>Marcos: Plástico</p><p><br></p><p>Descripción: con distintos diseños la forma de la isla de cistal para tortugas pequeñas y medinas con rampa para que la totuga suba su zona seca.</p><p>Incluye:</p><p>Isla</p><p>Planta artificial mini</p><p><br></p><p>Colores: azul cielo, azul marino, rosa , verde, naranja, roja, cafe, arena, blanca, negra, y mas (colores sujetos a disponibilidad). puede escpger color.</p><p><br></p>', 0, 599, 124, 1, NULL, NULL, NULL, '2026-01-05 22:24:30', NULL, NULL, 'Tortuguero-cuadrado-40-x-40-x-20cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1602, NULL, 'producto', '7502271353913', 0x48554D492D3031, '5050', 5.00, 'Humidificador generador de niebla y humedad ultrasonic fogger', '<p>Generador de niebla y huamedad</p><p>Medidas: 4cm diámetro 2.4cm altura</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Genera niebla atomizada y ionizada y es ideal para buen efecto decorativo para terrarios, efectos de vapor, proyectos de ciencia, fuentes, ayuda acrear una sensación de niebla y humedad similar al hábitad de diversos reptiles, anfibios, crustáceos y démas especies que requieran un ambiente con relativa concentración de humedad.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Características técnicas:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Cabezal de atomización: Luces de colores: 12 LED (alternando rojo, amarillo y azul) Diámetro de la cabeza de atomización: 16MM Frecuencia de funcionamiento: 50- 60 Hz.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Voltaje de entrada: 24V</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Corriente de entrada: 1A</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Cantidad de atomización: 350ML / H</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Sensor de nivel de agua: alto 15MM</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Profundidad de trabajo: 4-9cm</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Rango de temperatura de</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">trabajo: 10-30 °c</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Consumo de agua:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">80ml / h</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Potencia:16 w </span></p><p><br></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Fuente de alimentación:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Voltaje de salida: 24V</span></p><p>Voltaje: 110-120 v</p>', 0, 599, 124, 1, NULL, NULL, NULL, '2025-10-16 14:41:24', NULL, NULL, 'Humidificador-generador-de-niebla-y-humedad-ultrasonic-fogger', 0, 0);
INSERT INTO `ecom_productos` VALUES (1603, NULL, 'producto', 'CAMPA01ALU', 0x43414D2D3031, 'CAM-01', 5.00, 'Campana aluminio con gancho ', '<p>Campana de aluminio con gancho</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Base de lámpara 150 W</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Material: cerámica, NiCrAl</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Volt: 110-120 V</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Vatio: 150 W (E26)</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Color: Negro</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Diámetro de la superficie de calentamiento: 75 mm</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Diámetro 8.5 \" </span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Altura: 100 mm</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Soporte para bombillas de calor, focos de calor para reptiles con gancho de presión para fácil agarre con boton de encendido y apagado </span></p><p><br></p>', 0, 790, 124, 1, NULL, NULL, NULL, '2025-10-20 07:55:47', NULL, NULL, 'Campana-aluminio-con-gancho-', 0, 0);
