INSERT INTO `ecom_productos` VALUES (1606, NULL, 'producto', '7501325468542', NULL, 'CGMPA', 5.00, 'Minino Plus Croqueta Costal Adultos Pollo, res, pavo y atún 10 kg', '<p><span style=\"color: rgb(33, 25, 22);\">Minino Plus® cuenta con una fórmula diseñada sin colorantes artificiales y con 32% de proteína que ayuda al mantenimiento de gatos adultos.</span></p><p><br></p><h2>Análisis garantizado</h2><p><img src=\"https://www.minino.com/wp-content/uploads/2022/10/proteina-9.png\" height=\"53\" width=\"53\"></p><p><strong>32%</strong></p><p>Proteína cruda min</p><p><img src=\"https://www.minino.com/wp-content/uploads/2022/10/grasas-1.png\" height=\"53\" width=\"53\"></p><p><strong>11%</strong></p><p>Grasa cruda min</p><p><img src=\"https://www.minino.com/wp-content/uploads/2022/10/humedad-2.png\" height=\"53\" width=\"53\"></p><p><strong>11%</strong></p><p>Humedad máx</p><p><img src=\"https://www.minino.com/wp-content/uploads/2022/10/fibra-4.png\" height=\"53\" width=\"53\"></p><p><strong>4%</strong></p><p>Fibra cruda máx</p><p><br></p><h2>Ingredientes</h2><p>Harinas de carne y/o derivados de pollo, res, pavo y atún, harinas de maíz, trigo y arroz, derivados de cereales, gluten de maíz, pastas de semillas oleaginosas, grasa animal estabilizada (ave y/o bovino y/o cerdo), concentrados de proteína y/o saborizantes naturales de pollo y/o cerdo, extracto seco de levadura de cerveza (<em>Saccharomyces cerevisiae</em>). Vitaminas: A,D,E,K,B1 (tiamina), B3 (niacina), B5 (ácido pantoténico), B6 (piridoxina), B7 (biotina), B9 (ácido fólico), B12 (cianocobalamina), colina. Minerales: bisulfato de sodio y/o ácido fosfórico, carbonato de calcio, cloruro de potasio, sulfato ferroso, cloruro de sodio, fosfato de calcio, selenito de sodio, óxido de manganoso, yodo (EDDI), carbonato de cobalto, aluminosilicatos de calcio y sodio, lactato y/o propionato de calcio. Minerales orgánicos: glicinato de zinc, proteinato de selenio, glicinato de cobre. Derivados lácteos, almidones y fibras vegetales, color natural café caramelo. Aminoácidos: taurina,&nbsp;DL-metionina y L-lisina.<em>&nbsp;Bacillus amyloliquefaciens</em>&nbsp;(1×106&nbsp;UFC/g), harina de algas marinas (fuente natural de ácidos grasos omega 3:DHA) y aceite vegetal (fuente natural de ácidos grasos omega 6:linoleico), saborizante natural y/o artificial a hígado.</p><p><br></p><h2 class=\"ql-align-center\">Beneficios</h2><p><img src=\"https://www.minino.com/wp-content/uploads/2024/05/1-2-1.png\" height=\"200\" width=\"200\"></p><h4 class=\"ql-align-center\">Corazón saludable</h4><p class=\"ql-align-center\">Con Taurina para favorecer al correcto funcionamiento del corazón y visión.</p><p><img src=\"https://www.minino.com/wp-content/uploads/2024/05/2-4.png\" height=\"200\" width=\"200\"></p><h4 class=\"ql-align-center\">Control de PH</h4><p class=\"ql-align-center\">Con Calcio, Fósforo y Magnesio para el control del PH urinario.</p><p><img src=\"https://www.minino.com/wp-content/uploads/2024/05/3-4.png\" height=\"200\" width=\"200\"></p><h4 class=\"ql-align-center\">Salud Intestinal</h4><p class=\"ql-align-center\">Con probióticos para promover la salud intestinal.</p><p><img src=\"https://www.minino.com/wp-content/uploads/2024/05/4-4.png\" height=\"200\" width=\"200\"></p><h4 class=\"ql-align-center\">Pelaje saludable</h4><p class=\"ql-align-center\">Con Omega 3, Biotina, Cobre y Zinc que fomentan la salud de piel y pelaje.</p><p><br></p>', 0, 850, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Minino-Plus-Croqueta-Costal-Adultos-Pollo,-res,-pavo-y-atun-10-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1607, NULL, 'producto', '7501325468542', NULL, 'CGDCA', 5.00, 'Diamond Croqueta Maintenance Cat Costal Adultos 18.14 kg (40 LBS)', '<h1>Maintenance Cat</h1><h2>Ideal para gatos adultos con actividad moderada y baja</h2><p><br></p><ul><li>Altamente digestible.</li><li>Óptimo balance de ácidos Omega 3 y 6 para un hermoso pelo y una piel saludable.</li><li>Incluye antioxidantes y minerales quelados que ayudan a la salud y bienestar general de tu gato adulto.</li></ul><p><br></p><h2 class=\"ql-align-center\">Ingredientes</h2><p class=\"ql-align-justify\">Harina de subproducto de pollo, granos enteros de maíz molidos, harina de trigo, grasa de pollo (preservada con mezcla de tocoferoles), harina de gluten de maíz, arroz blanco molido, pulpa de remolacha deshidratada, saborizante natural (pollo), linaza, harina de pescado, bisulfato de sodio, cloruro de potasio, cloruro de colina, DL-metionina, taurina, producto de fermentación de Lactobacillus plantarum secos, producto de fermentación de Bacillus subtilis secos, producto de fermentación de Lactobacillus Acidophilus secos, producto de fermentación de Enterococcus faecium secos, producto de fermentación de Bifidobacterium animalis secos, proteinato de zinc, suplemento de vitamina E, niacina, proteinato de manganeso, proteinato de cobre, sulfato de zinc, sulfato de manganeso, sulfato de cobre, mononitrato de tiamina, suplemento de vitamina A, biotina, yoduro de potasio, pantotenato de calcio, riboflavina, clorhidrato de piridoxina (vitamina B6), suplemento de vitamina B12, óxido de manganeso, selenito de sodio, suplemento de vitamina D, ácido fólico.</p><p><br></p>', 0, 1350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Diamond-Croqueta-Maintenance-Cat-Costal-Adultos-18.14-kg-(40-LBS)', 0, 0);
INSERT INTO `ecom_productos` VALUES (1608, NULL, 'producto', '7501325468542', NULL, 'CPDCA', 5.00, 'Diamond Croqueta Maintenance Dog Costal Adultos 18.14 kg (40 LBS)', '<h1>Maintenance Dog</h1><h2>Ideal para perros adultos moderadamente activos</h2><h2><br></h2><p><br></p><ul><li>Fórmula diseñada para la mayor parte de la vida de tu perro adulto moderadamente activo.</li><li>Esta es una dieta completa y equilibrada con grandes beneficios para promover una buena salud y una larga vida a tu compañero.</li><li>Equilibrio de omegas 3 y 6 para piel y pelaje hermosos.</li><li>3.9 estrellas de calificación en Dog Food Advisor.</li></ul><p><br></p><p><br></p><h2 class=\"ql-align-center\">Ingredientes</h2><p class=\"ql-align-justify\">Harina de subproductos de pollo, harina de trigo, granos enteros de maíz molidos, salvado de arroz, pulpa de remolacha deshidratada, grasa de pollo (preservada con tocoferoles mixtos), mijo, arroz blanco molido, harina de pescado, producto de huevo de gallina, linaza, saborizante natural (pollo), cloruro de potasio, sal, cloruro de colina, producto de fermentación de Lactobacillus plantarum secos, producto de fermentación de Bacillus subtilis secos, producto de fermentación de Lactobacillus Acidophilus secos, producto de fermentación de Enterococcus faecium secos, producto de fermentación de Bifidobacterium animalis secos, suplemento de vitamina E, proteinato de hierro, proteinato de zinc, proteinato de cobre, sulfato ferroso, sulfato de zinc, sulfato de cobre, yoduro de potasio, mononitrato de tiamina, proteinato de manganeso, óxido de manganeso, acido ascórbico, suplemento de vitamina A, botina, niacina, pantotenato de calcio, sulfato de manganeso, selenito de sodio, clorhidrato de piridoxina (vitamina B6), suplemento de vitamina B12, riboflavina, suplemento de vitamina D, ácido fólico.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 1350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Diamond-Croqueta-Maintenance-Dog-Costal-Adultos-18.14-kg-(40-LBS)', 0, 0);
INSERT INTO `ecom_productos` VALUES (1609, NULL, 'producto', '7501325468542', NULL, 'CPDCPAC', 5.00, 'Diamond Croqueta Premium Costal Adultos activos y Cachorros 18.14 kg (40 LBS)', '<h1>Premium</h1><h2>Ideal para perros adultos activos y cachorros</h2><h2><br></h2><h2><br></h2><p><br></p><ul><li>Diseñado especialmente para perros activos y atléticos, ya que le proporciona el soporte alimenticio que necesita para permanecer en máxima condición física.</li><li>Fórmula precisa con un equilibrio de alta calidad de proteína y grasa para conservar sano el tejido muscular y aportar una alta dosis de energía.</li><li>3.9 estrellas de calificación en Dog Food Advisor.</li></ul><p><br></p><p><br></p><p><br></p><h2 class=\"ql-align-center\">Ingredientes</h2><p class=\"ql-align-justify\">Harina de subproducto de pollo, granos enteros de maíz molidos, harina de trigo, grasa de pollo (preservada con tocoferoles mixtos), pulpa de remolacha deshidratada, productos de huevo de gallina, linaza, saborizante natural (pollo), harina de pescado, aceite de salmón (una fuente de DHA), cloruro de potasio, sal, cloruro de colina, producto de fermentación de Lactobacillus plantarum secos, producto de fermentación de Bacillus subtilis secos, producto de fermentación de Lactobacillus Acidophilus secos, producto de fermentación de Enterococcus faecium secos, producto de fermentación de Bifidobacterium animalis secos, suplemento de vitamina E, proteinato de hierro, proteinato de zinc, proteinato de cobre, sulfato ferroso, sulfato de zinc, sulfato de cobre, yoduro de potasio, mononitrato de tiamina, proteinato de manganeso, óxido de manganeso, ácido ascórbico, suplemento de vitamina A, biotina, niacina, pantotenato de calcio, sulfato de manganeso, selenito de sodio, clorhidrato de piridoxina (vitamina B6), suplemento de vitamina B12, riboflavina, suplemento de vitamina D, ácido fólico.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 1910, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Diamond-Croqueta-Premium-Costal-Adultos-activos-y-Cachorros-18.14-kg-(40-LBS)', 0, 0);
INSERT INTO `ecom_productos` VALUES (1610, NULL, 'producto', '7501325468542', NULL, 'CPDCP', 5.00, 'Diamond Croqueta Puppy Costal Cachorros y Perras lactando o gestando 18.14 kg (40 LBS)', '<h1>Puppy</h1><h2>Ideal para cachorros y perras lactando o gestando</h2><h2><br></h2><h2><br></h2><h2><br></h2><p><br></p><ul><li>Equilibrio correcto de grasa, proteína y otros elementos esenciales para que tu cachorro reciba los nutrientes necesarios para crecer fuerte y sano.</li><li>Ideal para alimentar perras gestantes, en periodo de lactancia o para perros adultos enfermos.</li><li>3.9 estrellas de calificación en Dog Food Advisor.</li></ul><p><br></p><p><br></p><p><br></p><p><br></p><h2 class=\"ql-align-center\">Ingredientes</h2><p class=\"ql-align-justify\">Harina de subproductos de pollo, granos enteros de maíz molidos, harina de trigo, grasa de pollo (preservada tocoferoles mixtos), pulpa de remolacha deshidratada, producto de huevo de gallina, linaza, saborizante natural (pollo), harina de pescado, aceite de salmón (fuente de DHA), cloruro de potasio, sal, cloruro de colina, producto de fermentación de Lactobacillus plantarum secos, producto de fermentación de Bacillus subtilis secos, producto de fermentación de Lactobacillus Acidophilus secos, producto de fermentación de Enterococcus faecium secos, producto de fermentación de Bifidobacterium animalis secos, suplemento de vitamina E, proteinato de hierro, proteinato de zinc, proteinato de cobre, sulfato ferroso, sulfato de zinc, sulfato de cobre, yoduro de potasio, mononitrato de tiamina, proteinato de manganeso, óxido de manganeso, acido ascórbico, suplemento de vitamina A, biotina, niacina, pantotenato de calcio, sulfato de manganeso, selenito de sodio, clorhidrato de piridoxina (vitamina B6), suplemento de vitamina B12, riboflavina, suplemento de vitamina D, ácido fólico.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 2010, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Diamond-Croqueta-Puppy-Costal-Cachorros-y-Perras-lactando-o-gestando-18.14-kg-(40-LBS)', 0, 0);
INSERT INTO `ecom_productos` VALUES (1611, NULL, 'producto', '7501325468542', NULL, 'STD1KG', 5.00, 'Snack Traquea deshidratada de res 1 kg', '<p>La tráquea deshidratada para perros&nbsp;es un snack natural hecho de tráquea de res que, al ser masticada, ayuda a mantener la salud dental y de las articulaciones debido a su contenido de colágeno, glucosamina y condroitina.&nbsp;Su textura crujiente y su naturaleza 100% natural, sin conservantes ni aditivos artificiales, la hacen ideal para perros de todos los tamaños, aunque siempre se debe supervisar su consumo.&nbsp;</p><p><br></p><p>Descripción y beneficios</p><ul><li><strong>Salud dental:</strong>&nbsp;Funciona como un cepillo de dientes natural, ayudando a limpiar y prevenir la acumulación de sarro.&nbsp;</li><li><strong>Salud articular:</strong>&nbsp;Es una fuente rica de condroitina, glucosamina y colágeno, que ayudan a mantener las articulaciones, el cartílago y la movilidad saludables.&nbsp;</li><li><strong>Textura:</strong>&nbsp;Tiene una textura semidura y crujiente que ayuda a mantener al perro entretenido, satisface su necesidad de masticar y evita que muerda objetos inapropiados.&nbsp;</li><li><strong>Digestión:</strong>&nbsp;Es fácilmente digestible, lo que la hace adecuada incluso para perros con estómagos sensibles.&nbsp;</li><li><strong>Natural y segura:</strong>&nbsp;Está hecha de ingredientes 100% naturales, sin cereales, aditivos ni conservantes artificiales.&nbsp;</li><li><strong>Versatilidad:</strong>&nbsp;Se puede usar como recompensa, para calmar la ansiedad o incluso rellenar con otras comidas para mayor diversión.&nbsp;</li></ul><p>Consideraciones</p><ul><li><strong>Supervisión:</strong>&nbsp;Siempre se recomienda dar este tipo de premios bajo supervisión para asegurar que el perro lo consuma de forma segura.&nbsp;</li><li><strong>Presentación:</strong>&nbsp;Viene en diferentes tamaños y formas, como aros, para adaptarse a perros de diferentes razas.&nbsp;</li><li><strong>Almacenamiento:</strong>&nbsp;Después de abierto, se debe guardar en un lugar fresco y seco, manteniendo el empaque bien cerrado.&nbsp;</li></ul><h1><br></h1><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Snack-Traquea-deshidratada-de-res-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1612, NULL, 'producto', '7501325468542', NULL, 'SPD1KG', 5.00, 'Snack Pezuña deshidratada 1 kg', '<p>Una pezuña deshidratada para perros&nbsp;es un masticable natural de ganado vacuno, duradero y resistente, que ayuda a mantener la salud dental, reduce el estrés y la ansiedad, y proporciona nutrientes como colágeno.&nbsp;Al roerla, el perro limpia su sarro, fortalece sus encías y libera energía acumulada.&nbsp;Es una alternativa saludable a los premios con químicos y puede ser rellenada con otros alimentos para mayor entretenimiento.&nbsp;</p><p><br></p><p>Características principales</p><ul><li><strong>Natural y duradero:</strong>&nbsp;Es un premio 100% natural, sin conservantes ni aditivos, hecho de pezuñas de res deshidratadas.&nbsp;Su resistencia la hace ideal para masticadores intensos.&nbsp;</li><li><strong>Beneficios dentales:</strong>&nbsp;Su dureza ayuda a eliminar el sarro y la placa dental, además de fortalecer las encías, lo que la convierte en una buena alternativa si el perro no se deja cepillar los dientes.&nbsp;</li><li><strong>Salud y relajación:</strong>&nbsp;Masticar la pezuña ayuda a liberar el estrés y la ansiedad al estimular el movimiento de la mandíbula.&nbsp;Es una forma saludable de que los perros se entretengan y se relajen.&nbsp;</li><li><strong>Nutrientes:</strong>&nbsp;Es una fuente de colágeno, beneficioso para la piel y las articulaciones, y puede aportar otros nutrientes como calcio y fósforo.&nbsp;</li><li><strong>Variedad:</strong>&nbsp;Algunas pezuñas pueden estar rellenas de hígado de res u otros premios para hacerlas más atractivas y duraderas.&nbsp;</li></ul><p>Consideraciones importantes</p><ul><li><strong>Supervisión:</strong>&nbsp;Siempre se recomienda dar este tipo de premios bajo supervisión, especialmente si el perro tiene problemas dentales o no está acostumbrado.&nbsp;</li><li><strong>A quién va dirigido:</strong>&nbsp;Es ideal para perros adultos o cachorros a partir de los 3 o 6 meses, una vez que ya han mudado sus dientes de leche.&nbsp;</li><li><strong>Olor:</strong>&nbsp;Tienen un olor fuerte a vaca o carne seca que a algunos perros les encanta, pero a otros no.&nbsp;</li></ul><h1><br></h1><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Snack-Pezuna-deshidratada-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1613, NULL, 'producto', '7501325468542', NULL, 'SOVD1KG', 5.00, 'Snack Oreja de vaca deshidratada 1 kg', '<p>La oreja de vaca deshidratada para perros&nbsp;es un snack natural y saludable, elaborado 100% con oreja de vacuno, que ofrece beneficios como la higiene dental y la satisfacción de su instinto de masticar.&nbsp;Puede ser ofrecida con o sin pelo;&nbsp;la versión con pelo añade fibra para ayudar a la digestión.&nbsp;</p><p><br></p><p>Características principales</p><ul><li><strong>100% natural</strong>:&nbsp;Elaborado solo con orejas de vaca deshidratadas, sin aditivos, colorantes, conservantes ni químicos.&nbsp;</li><li><strong>Fuente de proteína</strong>:&nbsp;Contiene un alto porcentaje de proteína, lo que ayuda a mantener la salud muscular, de huesos, piel y pelaje.&nbsp;</li><li><strong>Baja en grasa</strong>:&nbsp;Generalmente es un snack bajo en grasa, lo que lo hace adecuado para perros con sensibilidades o para dietas de control de peso.&nbsp;</li><li><strong>Textura y dureza</strong>:&nbsp;Posee una textura firme y una dureza media-alta que proporciona un desafío para la masticación, ideal para perros que disfrutan de roer.&nbsp;</li><li><strong>Variedad con pelo</strong>:&nbsp;La versión con pelo es rica en fibra, la cual actúa como un \"limpiador\" natural del tracto digestivo y ayuda a la regulación intestinal y a la eliminación de parásitos.&nbsp;</li></ul><p>Beneficios</p><ul><li><strong>Salud dental</strong>:&nbsp;La masticación ayuda a eliminar el sarro y la placa dental de forma natural, mejorando la salud de dientes y encías.&nbsp;</li><li><strong>Alivio del estrés</strong>:&nbsp;Funciona como un pasatiempo saludable que puede ayudar a reducir la ansiedad, el estrés, el aburrimiento y comportamientos destructivos.&nbsp;</li><li><strong>Salud digestiva</strong>:&nbsp;Especialmente la versión con pelo, ya que la fibra contribuye a una mejor digestión y a la limpieza del intestino.&nbsp;</li></ul><p>Consideraciones de uso</p><ul><li><strong>Supervisión</strong>:&nbsp;Es crucial supervisar al perro, especialmente la primera vez, para asegurarse de que no se atragante o muerda trozos demasiado grandes.&nbsp;</li><li><strong>Ajuste de tamaño</strong>:&nbsp;Para perros pequeños o aquellos con mordida potente, puede ser necesario cortar la oreja en trozos más pequeños para evitar riesgos de asfixia.&nbsp;</li><li><strong>Duración</strong>:&nbsp;La duración varía según el tamaño del perro y sus hábitos.&nbsp;Se puede guardar la porción restante en un lugar fresco y seco para dársela en otra ocasión.&nbsp;</li></ul><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Snack-Oreja-de-vaca-deshidratada-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1614, NULL, 'producto', '7501325468542', NULL, 'SPPD1KG', 5.00, 'Snack Pata de Pollo deshidratada 1 kg', '<p>Las patas de pollo deshidratadas para perros&nbsp;son un snack natural, crujiente y seguro, rico en colágeno, glucosamina y condroitina, que fortalece las articulaciones, la piel y el pelo.&nbsp;Además de ser una fuente de proteína y calcio, ayudan en la salud dental al promover la limpieza mecánica de los dientes y también pueden reducir el estrés al satisfacer el instinto de masticación.&nbsp;</p><p><br></p><p>Beneficios</p><ul><li><strong>Salud articular:</strong>&nbsp;Son ricas en colágeno, glucosamina y condroitina, esenciales para fortalecer articulaciones, cartílagos y huesos.&nbsp;</li><li><strong>Salud dental:</strong>&nbsp;La masticación ayuda a limpiar los dientes de forma natural.&nbsp;</li><li><strong>Nutrición:</strong>&nbsp;Proporcionan proteínas de alta calidad, calcio y fósforo.&nbsp;</li><li><strong>Pelo y piel:</strong>&nbsp;Los ácidos grasos y el colágeno favorecen un pelaje sano y brillante.&nbsp;</li><li><strong>Entretenimiento:</strong>&nbsp;Satisfacen el instinto natural de masticar, lo que puede reducir el estrés y la ansiedad.&nbsp;</li><li><strong>Seguridad:</strong>&nbsp;Al ser deshidratadas a baja temperatura, no se astillan como las cocidas, lo que las hace seguras para masticar y tragar.&nbsp;</li><li><strong>Aptas para alergias:</strong>&nbsp;No contienen aditivos, conservantes, granos ni azúcares, lo que las hace aptas para perros con intolerancias alimentarias.&nbsp;</li></ul><p>Características</p><ul><li><strong>100% naturales:</strong>&nbsp;Elaboradas con ingredientes 100% naturales, sin químicos ni conservadores.&nbsp;</li><li><strong>Baja en grasa:</strong>&nbsp;Son bajas en grasa pero ricas en proteínas y nutrientes beneficiosos.&nbsp;</li><li><strong>Dureza:</strong>&nbsp;Tienen una dureza media o alta, ideal para perros medianos y grandes.&nbsp;</li><li><strong>Proceso:</strong>&nbsp;Se deshidratan a baja temperatura para conservar al máximo sus propiedades.&nbsp;</li><li><br></li></ul><p class=\"ql-align-justify\"><br></p><p><br></p>', 0, 350, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Snack-Pata-de-Pollo-deshidratada-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1615, NULL, 'producto', '7501325468542', 0x43434E4132354B47, 'CCNA25KG', 5.00, 'Nucan by Nupec Croqueta Costal Adulto 25 kg', '<p><a href=\"https://nucan.com.mx/Home\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(52, 59, 78);\"><img src=\"https://nucan.com.mx/assets/img/logo/logo_nucan_light.png\" alt=\"Nucan Logo\"></a></p><p><span style=\"color: rgb(79, 22, 87); background-color: rgb(255, 219, 41);\">Nucan by NUPEC</span></p><h1><strong style=\"color: rgb(255, 255, 255);\">NUCAN</strong>&nbsp;NUCAN Adulto</h1><ul><li>Todo Súper Nucan requiere una alimentación balanceada que no solo les brinde el mejor sabor, también la calidad de nutrientes que necesitan para una vida sana y en bienestar.</li></ul><p><br></p><p><span style=\"color: rgb(79, 22, 87);\">Fórmula Súper Nucan</span></p><h4 class=\"ql-align-center\">Alimento especialmente para que tu can adulto tenga mucha vitalidad y salud. Una fórmula con ingredientes de calidad y gran sabor.</h4><p>Antioxidantes celulares, salud digestiva, apoyo al metabolismo y fortaleza muscular, gran sabor y palatabilidad</p><p class=\"ql-align-justify\"><br></p><p><img src=\"https://nucan.com.mx/assets/img/adulto/Adulto_plato.png\" alt=\"image\"></p><p><span style=\"color: rgb(79, 22, 87);\">Nueva formulación</span></p><h4 class=\"ql-align-center\">UNA NUEVA FÓRMULA PARA QUE TU SÚPER NUCAN ESTE LLENO DE SALUD Y BIENESTAR</h4><p class=\"ql-align-center\"><br></p><p><span style=\"background-color: rgb(79, 22, 87); color: rgb(52, 59, 78);\"><img src=\"https://nucan.com.mx/assets/img/icon/Lightning.svg\"></span></p><h3>Vitamina E y Selenio</h3><p>Disminuye el daño celular en los tejidos, brindándole más salud y vitalidad, necesario para todo Súper Nucan.</p><p><span style=\"background-color: rgb(79, 22, 87); color: rgb(52, 59, 78);\"><img src=\"https://nucan.com.mx/assets/img/icon/Stomach.svg\"></span></p><h3>Pulpa de Remolacha</h3><p>Favorece la salud del sistema digestivo de tu Súper Nucan.</p><p><span style=\"background-color: rgb(79, 22, 87); color: rgb(52, 59, 78);\"><img src=\"https://nucan.com.mx/assets/img/icon/Inmune.svg\"></span></p><h3>Vitaminas del Complejo B</h3><p>Apoya su metabolismo energético, previniendo enfermedades.</p><p><span style=\"background-color: rgb(79, 22, 87); color: rgb(52, 59, 78);\"><img src=\"https://nucan.com.mx/assets/img/icon/Running_dog.svg\"></span></p><h3>+ Proteína de origen animal</h3><p>Ayuda a que tu Súper Nucan mantenga músculos sanos y fuertes.</p>', 0, 1150, 124, 1, NULL, NULL, NULL, '2025-10-21 23:07:03', NULL, NULL, 'Nucan-by-Nupec-Croqueta-Costal-Adulto-25-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1616, NULL, 'producto', '8713184301222', NULL, 'BRA-04', 5.00, 'Tableta masticable bravecto para peso de 2 a 4.5kg', '<p>Tableta masticable bracvecto</p><p>Para: pulgas, garrapatas y ácaros</p><p>Peso: 2 - 4.5 kg</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(23, 23, 23);\">Tabletas masticables a base de fluralaner para el tratamiento de infestaciones por garrapatas, pulgas y ácaros de la sarna demodécica e infestaciones por ácaros Otodectes cynotis, también evita la transmisión de Dipylidium caninum en perros durante 37 días</span></p><p><br></p>', 0, 310, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Tableta-masticable-bravecto-para-peso-de-2-a-4.5kg', 0, 0);
