INSERT INTO `ecom_productos` VALUES (1620, NULL, 'producto', 'PERE40111720', 0x504552412D4234303230, 'PERA-B4020', 10.00, 'Pecera bettera con dos divisiones  40 x 11 x 20 cm altura 9 litros 3 mm', '<p>Pecera bettera con dos divisones</p><p>Capacidad: 8.5 litros</p><p>Medidas: 40 x 11 x 20 cm (largo x ancho x alto)</p><p>Espesor: 3 mm</p><p><br></p><p>Descripción: pecera medida estandar para peces medianos, pequeños, con marcos de plástico un acaurio elegante y a lo alto.</p>', 0, 260, 124, 1, NULL, NULL, NULL, '2026-05-25 10:08:43', NULL, NULL, 'Pecera-bettera-con-dos-divisiones--40-x-11-x-20-cm-altura-9-litros-3-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1621, NULL, 'producto', 'PECU202040', 0x504552412D4332323430, 'PERA-C2240', 10.00, 'Pecera cubo 22 X 22 x 40 cm altura 18 litros 3 mm', '<p>Pecera cubo 20 x 40cm</p><p>Capacidad: 16 litros</p><p>Espesor: 3 mm</p><p>Marcos: plástico</p><p><br></p><p>Descripción: Acuario a lo alto estéticamente elegante, pecera medida estándar para peces medianos, pequeños, o bettas con marcos de plástico.</p>', 0, 320, 124, 1, NULL, NULL, NULL, '2026-05-25 10:09:34', NULL, NULL, 'Pecera-cubo-22-X-22-x-40-cm-altura-18-litros-3-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1622, NULL, 'producto', '7501556488982', 0x4241C391452D3031, 'FL8898', 5.00, 'Bañera para chinchilla', '<p>Bañera para chinchilla</p><p><br></p><p>Descripción:</p><p>Bañera para chinchilla con d<span style=\"color: rgba(0, 0, 0, 0.55);\">iseño confortable y espacioso para un baño placentero.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Su tapa reduce la fuga de polvo.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Fácil acceso a través de la puerta abatible.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Fácil de limpiar y guardar.</span></p><p><br></p><p>Recomendaciónes:</p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Baña a tu chinchilla 2 o 3 veces a la semana de 10 a 15 minutos. Si su manto es muy graso o vives en un lugar con humedad alta, báñala más seguido. Por el contrario, si tu chinchilla presenta resequedad en la piel o se rasca constantemente, disminuye la frecuencia de los baños.</span></p>', 0, 390, 124, 1, NULL, NULL, NULL, '2025-11-03 07:40:35', NULL, NULL, 'Banera-para-chinchilla', 0, 0);
INSERT INTO `ecom_productos` VALUES (1623, NULL, 'producto', 'CORTRA04GAL', 0x434F5252412D3034, 'CORRA-04', 10.00, 'Corral gala 60 x 60cm de 6 paneles', '<p>Corral gala </p><p>Cantidad: 6 paneles</p><p>Medida de cada panel:60 x 60 cm (largo x alto)</p><p>Material: metálico </p><p>Color: gris natural del material galvanizado</p><p><br></p><p>Descripciòn:</p><p>Corral plegable con 6 paneles para conejo, cuyo, cachorros, mini pig y mas etc. i<span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos.</span></p><p><br></p><p>Incluye:</p><p>Puerta abatible con doble pasador</p><p>2 bandolas de seguridad</p><p><br></p><p>Configuarción de armado: hexagono 120cm x 60cm, Cuadrado 60 x 60 cm, rectangular 120 x 60 cm, o de valla 360 cm</p>', 0, 530, 124, 1, NULL, NULL, NULL, '2026-03-02 06:19:20', NULL, NULL, 'Corral-gala-60-x-60cm-de-6-paneles', 0, 0);
