INSERT INTO `ecom_productos` VALUES (1630, NULL, 'producto', 'TERAL0610040', 0x544552414C2D3036, 'TERAL-06', 10.00, 'Terrario imperio 100 x 40 x 40cm', '<p>Terrario imperio puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metalica</p><p><br></p><p><br></p><p>Descripción:</p><p>Terrario rectangular de cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva. amplio para reptiles de chicos hasta grandes.</p>', 0, 3950, 124, 1, NULL, NULL, NULL, '2026-03-13 07:24:43', NULL, NULL, 'Terrario-imperio-100-x-40-x-40cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1631, NULL, 'producto', 'TERAL07102650', 0x544552414C2D3037, 'TERAL-07', 10.00, ' Terrario cosmo 100 x 26 x 50', '<p>Terrario cosmo con puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario rectangular de cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con dos puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva. Para reptiles de tamaños chicos hasta ya grandes.</p>', 0, 3600, 124, 1, NULL, NULL, NULL, '2026-03-13 07:23:53', NULL, NULL, '-Terrario-cosmo-100-x-26-x-50', 0, 0);
INSERT INTO `ecom_productos` VALUES (1632, NULL, 'producto', 'TERAL081002630', 0x544552414C2D3038, 'TERAL-08', 10.00, 'Terrario zon 100 x 26 x 30 cm', '<p>Terrario zon puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario rectangular de cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva. amplio para reptiles de chicos hasta grandes.</p>', 0, 2800, 124, 1, NULL, NULL, NULL, '2026-03-13 07:33:39', NULL, NULL, 'Terrario-zon-100-x-26-x-30-cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1633, NULL, 'producto', 'TERA151203050', 0x544552412D3135, 'TERA-15', 10.00, 'Terrario gala 120 x 50 cm', '<p>Terrario gala puerta deslizable</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metalica</p><p><br></p><p>Descripción:</p><p>Terrario rectangular de cristal para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir hacia la derecha se puede estraer toda la puerta hacia lado derecho sin alumnio en la parte de en medias para mayor visibilidad de tu reptil y en la parte superior de malla metálica no corrosiva. amplio para reptiles de chicos hasta grandes.</p>', 0, 2950, 124, 1, NULL, NULL, NULL, '2026-03-13 07:39:52', NULL, NULL, 'Terrario-gala-120-x-50-cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1634, NULL, 'producto', 'RAS14BAMBU', 0x5241532D3134, 'RAS-14', 5.00, 'Rascadero bambu ', '<p>Rcascadero bambu</p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Los muebles para gato conociodo como (arbol) están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. Ayuda a evitar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">Ajuste correctamente cada apartado del mueble. Limpie con regularidad, puede usar un limpiador enzimático de limpieza superior.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56);\">• El enriquecimiento ambiental permite estimular cognitivamente a los gatos </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El gato podrá rascar para afilar sus garras </span></p><p><span style=\"color: rgb(50, 51, 56);\">• El juego ayudará al instinto de caza </span></p><p><span style=\"color: rgb(50, 51, 56);\">• Las casas brindan zonas de descanso y protección solar. </span></p><p><span style=\"color: rgb(50, 51, 56);\">﻿• Se puede rociar con catnip para estimular el juego y la curiosidad</span></p><p><br></p><p>Características</p><p><strong>Especie g</strong>atos, de madera mdf para aquellos q no les gusta que sten forrados de tela cuemta con tapetes montables y demontables para facil limpieza.</p><p><br></p>', 0, 1750, 124, 1, NULL, NULL, NULL, '2025-12-05 09:09:41', NULL, NULL, 'Rascadero-bambu-', 0, 0);
