INSERT INTO `ecom_productos` VALUES (1638, NULL, 'producto', 'JAU', 0x4A4155, 'JAU', 5.00, 'Jaula galaxia un nivel 80cm ', '<p>Jaula galaxia un nivel 80cm</p><p>Medidas:</p><p><br></p><p>Incluye:</p><p>1 plataformas</p><p>2 Tuneles</p><p>2 puertas</p><p>Medida entre barrotes</p><p><br></p><p>Descripción: jaula para roedores, mamíferos, con barrote amplio como hasta para un uron y mas dandole un espacio amplio a su entorno de facil limpieza al desprender la charola, con niveles montables y desmotables para posicionar mas cercanos o lejos entre ellos.</p><p><br></p><p>Para: rata, conejo, cuyo, chinchilla, erizo, ardilla, hurón, etc.</p>', 0, 2800, 124, 1, NULL, NULL, NULL, '2025-12-05 09:54:49', NULL, NULL, 'Jaula-galaxia-un-nivel-80cm-', 0, 0);
