INSERT INTO `ecom_productos` VALUES (1640, NULL, 'producto', 'TOR100404021', 0x544F522D3231, 'TOR-21', 5.00, 'Tortuguero 100 x 40 x 40cm  ', '<p>Tortuguero rectangular 1 metro</p><p>Capacidad: 160 lts varia dependiendo de la cantidad que se le ponga</p><p>Medidas: 100 x 40 x 40 cm (largo x ancho x alto)</p><p>Grosor: 6 mm</p><p><br></p><p>Descripción:</p><p>Pecera con isla de cristal para que tengan su zona seca y puedan descansar un lugar sin agua. </p>', 0, 2850, 124, 1, NULL, NULL, NULL, '2026-03-30 07:45:42', NULL, NULL, 'Tortuguero-100-x-40-x-40cm--', 0, 0);
