INSERT INTO `ecom_productos` VALUES (1642, NULL, 'producto', 'PER181004035', 0x504552412D38303335, 'PERA-8035', 10.00, 'Pecera rectangular 80 x 40 x 35 cm altura 112 litros 6 mm', '<p>Pecera rectangular</p><p>Capacidad: 112 litros</p><p>Medidas: 80 x 40 x 35 cm (largo x ancho x alto)</p><p>Grosor: 6 mm</p><p><br></p><p>Descripción:pecera rectangular para peces, reptiles, roedores, con gran espacio para ellos con marcos de aluminio. Acuarios grandes para peces grandes o hacer una pecera comunitaria donde puedas tener mas de una especie de pez con gran variedad aparte con un espacio amplio para que la puedas decorar hermosa y brindarles un espacio amplio comodo y natural a tus peces.</p><p><br></p><p><br></p><p><br></p>', 0, 1750, 124, 1, NULL, NULL, NULL, '2026-05-25 10:10:23', NULL, NULL, 'Pecera-rectangular-80-x-40-x-35-cm-altura-112-litros-6-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1643, NULL, 'producto', 'CASAMIN01', 0x434153492D3031, 'CASI-01', 10.00, 'Casa minu impermeable chica', '<p>Casa minu impermeable chica</p><p>Color: rosa (colores sujetos a disponibilidad)</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;hámster, cuyo, ratas, grecko, iguana, camaleon y mas mascotas mini</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p>', 0, 150, 124, 1, NULL, NULL, NULL, '2025-12-09 08:09:44', NULL, NULL, 'Casa-minu-impermeable-chica', 0, 0);
INSERT INTO `ecom_productos` VALUES (1644, NULL, 'producto', 'CASIMED02', 0x434153492D3032, 'CASI-02', 10.00, 'Casa minu impermeale mediana ', '<p>Casa minu impermeable mediana</p><p>Color: azul (colores sujetos a disponibilidad)</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;hámster, cuyo, ratas, conejo, chinchilla, erizo, grecko, iguana, camaleon y mas mascotas mini</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p>', 0, 250, 124, 1, NULL, NULL, NULL, '2025-12-09 08:21:07', NULL, NULL, 'Casa-minu-impermeale-mediana-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1645, NULL, 'producto', 'CASAGRA03', 0x434153492D3033, 'CASI-03', 10.00, 'Casa minu impermeable grande ', '<p>Casa minu impermeable grande</p><p>Color: (colores sujetos a disponibilidad)</p><p><br></p><p>Descripción:</p><p>Diseño compacto ideal para&nbsp;<strong>razas extrachicas</strong>.</p><p>Perfecta para perros mini como chihuahua, pomerania o yorkshire o gatito.</p><p>Diseño compacto ideal para&nbsp;hámster, cuyo, ratas, grecko, iguana, camaleon y mas mascotas mini</p><p><strong>Proporción adecuada</strong>&nbsp;para su descanso y protección.</p><p>Resistente al sol y la lluvia. Fabricada con polietileno bicapa de alta durabilidad,&nbsp;<strong>soporta condiciones exteriores sin deformarse ni deteriorarse.</strong></p><p><strong>Fácil de limpiar y mantener</strong>&nbsp;gracias a su superficie lisa. Puede lavarse fácilmente con agua y jabón.</p><p>Fabricada en una sola pieza, con estructura robusta&nbsp;<strong>sin necesidad de ensamblar</strong>, lo que la hace más&nbsp;<strong>segura, estable y práctica.</strong></p><p><strong>Ideal para patios, terrazas o jardines.</strong>&nbsp;Diseñada para uso exterior, ofrece un refugio cómodo y protegido para tu mascota en todo momento.</p>', 0, 350, 124, 1, NULL, NULL, NULL, '2025-12-09 08:24:51', NULL, NULL, 'Casa-minu-impermeable-grande-', 0, 0);
