INSERT INTO `ecom_productos` VALUES (1647, NULL, 'producto', 'TORRE24201115', 0x544F522D3234, 'TOR-24', 10.00, 'Tortuguero 20 x 11 x 15cm', '<p>Tortuguero 20 x 11 x 15cm</p><p>Capacidad: 100 lts varia dependiendo de la cantidad que se le ponga</p><p>Medidas: 50 x 50 x 40 cm (largo x ancho x alto)</p><p>Grosor: 6 mm</p><p><br></p><p>Descripción:</p><p>Pecera con isla de cristal para que tengan su zona seca y puedan descansar en un lugar sin agua.</p>', 0, 280, 124, 1, NULL, NULL, NULL, '2026-03-27 07:44:04', NULL, NULL, 'Tortuguero-20-x-11-x-15cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1648, NULL, 'producto', 'ARO42GRIS', 0x41524F2D343247, 'ARO-42G', 5.00, 'Arenero eston gris', '<p>Arenero eston</p><p>Color: gris</p><p><br></p><p>Descripción:Arenero con cubierta para evitar desbordes de arena. <span style=\"color: rgb(50, 51, 56);\">&nbsp;Decide si deseas usarlo completamente cerrado o con la tapa a media altura.Coloca el filtro de carbón activado en el compartimiento de ventilación para el control de olores</span></p><p><span style=\"color: rgb(50, 51, 56);\">El escalón limpia patitas minimiza la cantidad de arena que tu gato arrastra al salir, evitando suciedad en el hogar. Versatilidad y comodidad: Su tapa desmontable permite ajustar la altura del arenero según las preferencias de tu gato, brindándole un espacio cómodo y adaptable. Fácil acceso y limpieza: La puerta abatible facilita la entrada y salida del gato, mientras que su estructura desmontable y la pala incluida hacen más sencilla la limpieza diaria. Mayor privacidad para tu gato: Su diseño cerrado ofrece un entorno seguro y tranquilo, ideal para gatos que prefieren hacer sus necesidades en un espacio discreto.</span></p>', 0, 400, 124, 1, NULL, NULL, NULL, '2025-12-10 07:15:32', NULL, NULL, 'Arenero-eston-gris', 0, 0);
INSERT INTO `ecom_productos` VALUES (1649, NULL, 'producto', '7500211000385', 0x534841532D3032, 'H522', 10.00, 'Shampoo para hámster 125 ml', '<p>Shampoo para hámster</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(51, 51, 51);\">&nbsp;formulado con ingredientes especiales biodegradables de la más alta calidad, para lograr una limpieza profunda tratando con suavidad la piel y el pelo de su mascota. Los componentes del Shampoo para Hámster no irritan ni resecan las manos.</span></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2025-12-10 07:48:37', NULL, NULL, 'Shampoo-para-hamster-125-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (1650, NULL, 'producto', '3400161804977', 0x534841552D3032, 'SHAU-02', 10.00, 'Shampoo para hurón 250 ml', '<p>Shampoo para hurón</p><p><br></p><p>Descripción:</p><p>Shampoo suave y control de olor especial para hurón, aplique sobre el pelo húmedo masajear y deje actuar de 3 a 5 minutos y enjuague.</p>', 0, 80, 124, 1, NULL, NULL, NULL, '2025-12-10 07:49:44', NULL, NULL, 'Shampoo-para-huron-250-ml', 0, 0);
INSERT INTO `ecom_productos` VALUES (1651, NULL, 'producto', '7500211004970', 0x47414C4C2D3036, 'P101', 10.00, 'Premios snack a´ bite sabor chorizo', '<p>Premios snack a´ bite sabor chorizo</p><p><br></p><p>Descripción:</p><p>Bocadillos para perros de todas las razas, cachorros y adultos. ofrezca un bocado de premios a su perro durante el proceso de entrenamiento, deberá obedecer cualquier orden antes de recibir el bocado.</p><p><br></p><p><br></p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-12-26 08:27:50', NULL, NULL, 'Premios-snack-a´-bite-sabor-chorizo', 0, 0);
INSERT INTO `ecom_productos` VALUES (1652, NULL, 'producto', '7500211005021', 0x47414C4C2D3037, 'P102', 10.00, 'Premios snack a´ bite sabor tocino', '<p>Premios snack a´ bite sabor tocino</p><p><br></p><p>Descripción:</p><p>Bocadillos para perros de todas las razas, cachorros y adultos. ofrezca un bocado de premios a su perro durante el proceso de entrenamiento, deberá obedecer cualquier orden antes de recibir el bocado.</p><p><br></p><p><br></p>', 0, 180, 124, 1, NULL, NULL, NULL, '2025-12-26 08:28:02', NULL, NULL, 'Premios-snack-a´-bite-sabor-tocino', 0, 0);
INSERT INTO `ecom_productos` VALUES (1653, NULL, 'producto', 'SILLOPLE01', 0x53494C4C2D3031, 'SILL-01', 10.00, 'Sillon abatible a cama', '<p>Sillon abatible</p><p>Descripción:</p><p>Sofá para mascotas como perros, gatos, mini pig, hurón y más. Con diseño compacto y plegable para covertirce en cama para una o mas mascotas un espacio acogedor suave amplio y de tela impermeable con tela lisa para posibles arañasos no se generen en su sofá asi mismo para que no se adiera cabello que sulten las mascotas fácil de limpar y con funda extraible con cierre para lavar.</p>', 0, 2590, 124, 1, NULL, NULL, NULL, '2025-12-10 09:08:44', NULL, NULL, 'Sillon-abatible-a-cama', 0, 0);
INSERT INTO `ecom_productos` VALUES (1654, NULL, 'producto', 'HENERAMM01', 0x48454E452D3031, 'HENE-01', 10.00, 'Henera y comdero para roedor mediana', '<p>Henera y comdero para roedor mediana</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Descripción:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Esta Henera con rejilla de madera con diseño especial mantiene el heno en su lugar, los mantiene limpios y frescos en todo momento, no más líos y minimizando residuos. Mantiene un generoso suministro de heno en un alimentador limpio y organizado. tambien para que a tu roedor en la parte de adelante trae un cajoncito como comedero para que coloques ahi su conejina, semillas, u otro tipo de alimento seco.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">fabricado con madera mdf , no tóxico, elegante, y al mismo timpo si la llegasen a morder les ayuda al desgaste dental natural de tu roedor mamífero. Esta henera es de ensable y sellada, perfecta para conejo, chinchilla y cuyos.</span></p><p><br></p><p><br></p><p><br></p>', 0, 135, 124, 1, NULL, NULL, NULL, '2025-12-18 08:11:36', NULL, NULL, 'Henera-y-comdero-para-roedor-mediana', 0, 0);
INSERT INTO `ecom_productos` VALUES (1655, NULL, 'producto', 'HENERAMM02', 0x48454E452D3032, 'HENE-02', 10.00, 'Henera y comdero para roedor chica', '<p>Henera y comdero para roedor chica</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Descripción:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Esta Henera con rejilla de madera con diseño especial mantiene el heno en su lugar, los mantiene limpios y frescos en todo momento, no más líos y minimizando residuos. Mantiene un generoso suministro de heno en un alimentador limpio y organizado.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">fabricado con madera mdf , no tóxico, elegante, y al mismo timpo si la llegasen a morder les ayuda al desgaste dental natural de tu roedor mamífero. Esta henera es de ensable y sellada, perfecta para conejo, chinchilla y cuyos.</span></p><p><br></p><p><br></p><p><br></p>', 0, 89, 124, 1, NULL, NULL, NULL, '2025-12-18 08:14:52', NULL, NULL, 'Henera-y-comdero-para-roedor-chica', 0, 0);
INSERT INTO `ecom_productos` VALUES (1656, NULL, 'producto', 'RAPACHIM02', 0x524150412D3032, 'RAPA-02', 10.00, 'Rampa nivel con cueva chica para roedores ', '<p>Rampa nivel con cueva mediana para roedores</p><p>Medidas de plataforma: 24 x 14 x 18cm</p><p>Medidas de la rampa: 35 x 9.5cm</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Descripción:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Este nivel de plataforma con rampa y rejilla de madera con diseño especial mantiene a tu roedor en un lugar seguro y elevado. Es un espacio adecuado para que tu pequeño cuyo, chinchilla o conejo se pueda sentir cómodo y seguro, debido a sus materiales de fabricación permite sea sencilla la limpieza y la transportación. Brindarles lugares seguros a tus mascotas ayudará con su adaptación al nuevo hogar.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">fabricado con madera mdf , no tóxico, elegante, y al mismo timpo si la llegasen a morder les ayuda al desgaste dental natural de tu roedor mamífero. Esta plataforma es de ensable y sellada, perfecta para conejo, chinchilla, erizo y cuyos.</span></p><p><br></p><p>Esta plataforma fue diseñada para jaulas que miden 47 cm largo x 30 cm ancho.</p><p><br></p><p><br></p><p><br></p>', 0, 250, 124, 1, NULL, NULL, NULL, '2025-12-18 08:38:27', NULL, NULL, 'Rampa-nivel-con-cueva-chica-para-roedores-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1657, NULL, 'producto', 'RAPAMEDM01', 0x524150412D3031, 'RAPA-01', 10.00, 'Rampa nivel con cueva mediana para roedores ', '<p>Rampa nivel con cueva mediana para roedores</p><p>Medidas de plataforma: 24 x 24 x 18cm</p><p>Medidas de la rampa: 45 x 9.5cm</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Descripción:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Este nivel de plataforma con rampa y rejilla de madera con diseño especial mantiene a tu roedor en un lugar seguro y elevado. Es un espacio adecuado para que tu pequeño cuyo, chinchilla o conejo se pueda sentir cómodo y seguro, debido a sus materiales de fabricación permite sea sencilla la limpieza y la transportación. Brindarles lugares seguros a tus mascotas ayudará con su adaptación al nuevo hogar.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">fabricado con madera mdf , no tóxico, elegante, y al mismo timpo si la llegasen a morder les ayuda al desgaste dental natural de tu roedor mamífero. Esta plataforma es de ensable y sellada, perfecta para conejo, chinchilla, erizo y cuyos.</span></p><p><br></p><p>Esta plataforma fue diseñada para jaulas que miden 60 cm largo x 35 cm ancho.</p><p><br></p>', 0, 299, 124, 1, NULL, NULL, NULL, '2025-12-18 08:45:42', NULL, NULL, 'Rampa-nivel-con-cueva-mediana-para-roedores-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1658, NULL, 'producto', 'FLOR', NULL, 'FLOR', 10.00, 'Foco sun ', '<p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(19, 17, 4);\">Una lámpara de luz diurna de amplio espectro con una funda de neodimio. El espectro es ideal para la fotosíntesis de la planta y la luz UVA (ultravioleta A) contribuye al bienestar fisiológico de los reptiles. Otro factor importante es el calor emitido por esta bombilla para aumentar la temperatura ambiente general en el terrario.</strong></p><p><br></p><p><strong style=\"color: rgb(19, 17, 4);\">- Lámpara de luz diurna de amplio espectro para terrarios- Crea gradientes de calor para la termorregulación</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Aumenta la temperatura</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">del aire ambiente- Estimula el comportamiento de reproducción a través de los rayos UVA</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Se puede combinar con Night Glo o Heat Glo durante un ciclo</strong></p><p><br></p><p>Bombilla para el cuidado de mascotas, sólo para uso con reptiles, anfibios e invertebrados.</p>', 0, 175, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Foco-sun-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1659, NULL, 'producto', 'FLOR', NULL, 'FLOR', 10.00, 'Foco sun ', '<p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(19, 17, 4);\">Una lámpara de luz diurna de amplio espectro con una funda de neodimio. El espectro es ideal para la fotosíntesis de la planta y la luz UVA (ultravioleta A) contribuye al bienestar fisiológico de los reptiles. Otro factor importante es el calor emitido por esta bombilla para aumentar la temperatura ambiente general en el terrario.</strong></p><p><br></p><p><strong style=\"color: rgb(19, 17, 4);\">- Lámpara de luz diurna de amplio espectro para terrarios- Crea gradientes de calor para la termorregulación</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Aumenta la temperatura</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">del aire ambiente- Estimula el comportamiento de reproducción a través de los rayos UVA</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Se puede combinar con Night Glo o Heat Glo durante un ciclo</strong></p><p><br></p><p>Bombilla para el cuidado de mascotas, sólo para uso con reptiles, anfibios e invertebrados.</p>', 0, 175, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Foco-sun-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1660, NULL, 'producto', 'FLOR', NULL, 'FLOR', 10.00, 'Foco sun ', '<p><br></p><p>Descripción:</p><p><strong style=\"color: rgb(19, 17, 4);\">Una lámpara de luz diurna de amplio espectro con una funda de neodimio. El espectro es ideal para la fotosíntesis de la planta y la luz UVA (ultravioleta A) contribuye al bienestar fisiológico de los reptiles. Otro factor importante es el calor emitido por esta bombilla para aumentar la temperatura ambiente general en el terrario.</strong></p><p><br></p><p><strong style=\"color: rgb(19, 17, 4);\">- Lámpara de luz diurna de amplio espectro para terrarios- Crea gradientes de calor para la termorregulación</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Aumenta la temperatura</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">del aire ambiente- Estimula el comportamiento de reproducción a través de los rayos UVA</strong></p><p><strong style=\"color: rgb(19, 17, 4);\">- Se puede combinar con Night Glo o Heat Glo durante un ciclo</strong></p><p><br></p><p>Bombilla para el cuidado de mascotas, sólo para uso con reptiles, anfibios e invertebrados.</p>', 0, 175, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Foco-sun-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1661, NULL, 'producto', '01556122189', 0x464C4F522D3137, 'PT2189', 10.00, 'Foco uvb desierto 26 w', '<p>Foco uvb desierto 26 w</p><p>Descripción:</p><p>Foco UVB desierto</p><p>Potencia: 26 w</p><p>Repti Glo 10.0</p><p>Ideal para todo reptil habitante de desierto</p><p>Alta producción de UVB</p><p>Elevada conversión de D3</p><p>Efectiva hasta 30 cm&nbsp;</p><p>Suministra los rayos UVB necesarios para el metabolismo óptimo del calcio</p><p>Recomendada para terrarios con pantallas densas</p><p>Se combina con&nbsp;la luz natural para la producción óptima de luz visible</p><p>El Exo Terra Reptile UVB150 tiene una potencia UVB muy alta similar a la luz solar en los desiertos. Estos lugares reciben más luz solar directa, por lo tanto, los reptiles de desierto están mas expuestos a radiaciones UV que cualquier otro tipo de reptil. Esta lámpara también se puede utilizar en terrarios con pantallas más densas para asegurar la penetración UVB suficiente. Las pantallas densas pueden filtrar hasta el 50% de los rayos UVB. El alto índice de vitamina D3 garantiza el rendimiento de la fotosíntesis de vitamina D3 para ayudar a la absorción de calcio y prevenir enfermedades metabólicas.</p>', 0, 790, 124, 1, NULL, NULL, NULL, '2025-12-26 22:08:51', NULL, NULL, 'Foco-uvb-desierto-26-w', 0, 0);
INSERT INTO `ecom_productos` VALUES (1662, NULL, 'producto', '015561221382', 0x464C4F522D3138, 'PT2138', 10.00, 'Foco intense basking spot 100w', '<p><span style=\"color: rgba(0, 0, 0, 0.55);\">Foco intense basking spot 100w </span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Características:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Aumento del 35% de luz y calor.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Luz corta/Irradia calor.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Incrementa la intensidad luminosa.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Gran concentración térmica</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Realza la coloración del animal.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Crea un área de calentamiento para la termo-regulación.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Aumenta la temperatura del aire.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Estimula el comportamiento reproductivo mediante luz ultravioleta “A”.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">•Se puede combinar con el Night Heat Lamp o Infrared Basking Spot por un ciclo de 24 horas.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Ventajas:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55);\">Bombilla especialmente diseñada como una lámpara de luz concentrada. El rayo de luz puede enfocarse precisamente en un área para crear un sitio adecuado para el calentamiento. La luz y el calor aumentan en un 35% permitiendo así una mayor separación entre la fuente luminosa y el sitio elegido para el calentamiento. La luz ultravioleta “A” estimula el comportamiento reproductivo de los reptiles</span></p>', 0, 255, 124, 1, NULL, NULL, NULL, '2025-12-26 22:37:09', NULL, NULL, 'Foco-intense-basking-spot-100w', 0, 0);
INSERT INTO `ecom_productos` VALUES (1663, NULL, 'producto', '7502271350059', 0x5445522D3032, 'ART.1805', 5.00, 'Termometro electrónico para agua dulce o salda ', '<p>Termómetro digital</p><p>Rango de temperatura de 0 - 50°c</p><p><br></p><p>Descripción:</p><p>Termómetro digital sumergible para agua dulce y salda con ventosa para adherirse al cristal de tu pecera, estanque, y más.</p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-01-05 22:02:54', NULL, NULL, 'Termometro-electronico-para-agua-dulce-o-salda-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1664, NULL, 'producto', '7501556436273', 0x414345492D3031, 'FL3627', 5.00, 'Aceite de salmon ', '<p>Aceite de salmón</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0);\">El aceite de Salmón es un suplemento alimenticio que contiene ácidos grasos como DHA y EPA. Éstos pueden proporcionar una serie de beneficios, incluyendo la mejora de piel y pelaje. Contribuyendo al sistema nervioso, previene enfermedades y fortalece el sistema inmune, dismiyue infecciones cutáneas como tamabien promueve el funcionamiento del sistema digestivo y circulatorio. Además de brindar un mejor sabor a las croquetas.</span></p><p><br></p><p><br></p>', 0, 220, 124, 1, NULL, NULL, NULL, '2026-01-05 22:17:43', NULL, NULL, 'Aceite-de-salmon-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1665, NULL, 'producto', 'TERMOEMTRO', 0x746F72, 'tor', 5.00, 'Tortuguero 30 x 30 x 20cm ', '<p>Tortuguero cuadrado 30 x 30</p><p>Espesor: 3 mm</p><p>Marcos: Plástico</p><p><br></p><p>Descripción: con distintos diseños la forma de la isla de cistal para tortugas pequeñas y medinas con rampa para que la totuga suba su zona seca.</p><p>Incluye:</p><p>Isla</p><p>Planta artificial mini</p><p><br></p><p>Colores: azul cielo, azul marino, rosa , verde, naranja, roja, cafe, arena, blanca, negra, y mas (colores sujetos a disponibilidad). puede escpger color.</p><p><br></p><p><br></p>', 0, 490, 124, 1, NULL, NULL, NULL, '2026-01-05 22:31:34', NULL, NULL, 'Tortuguero-30-x-30-x-20cm-', 0, 0);
