INSERT INTO `ecom_productos` VALUES (1734, NULL, 'producto', '7501556484663', 0x5241532D3138, 'FL8466', 20.00, 'Rascadero de arbol tulum', '<p>Rascadero de arbol o torre tulum</p><p>Color: rosa</p><p><br></p><p>Descripción:</p><p>Rascadero de arbol, torre, mueble de salto para gato están diseñados para brindarle a tu gato un espacio para ejercitarse y liberar estrés, así como para delimitar su territorio, descansar, saltar, jugar y perfeccionar su habilidad de caza. ayuda a eviatar que el gato dañe los muebles del hogar y tenga un lugar dónde pueda rascar adecuadamente sus garras.</p><p><br></p><p>Beneficios:</p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">El enriquecimiento ambiental permite estimular cognitivamente a los gatos</span></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">El gato podrá rascar para afilar sus garras</span></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">El juego ayudará al instinto de caza</span></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">Las casas brindan zonas de descanso y protección solar, se puede rociar catnip para gatos&nbsp;para estimular el juego y la curiosidad.</span></p>', 0, 2850, 124, 1, NULL, NULL, NULL, '2026-01-27 09:16:02', NULL, NULL, 'Rascadero-de-arbol-tulum', 0, 0);
