INSERT INTO `ecom_productos` VALUES (1748, NULL, 'producto', '7501556441741', 0x414C49532D3036, 'FL4174', 20.00, 'Premios fun bites para aves ', '<p>Premios fun bites para aves&nbsp;</p><p>para: aves canarios y finches y más especies</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Para canarios y finches es la botana perfecta para consentir a tus aves granívoras. Elaborada con una mezcla balanceada de semillas seleccionadas, brinda la nutrición esencial que necesitan para mantenerse activas, saludables y con un comportamiento natural de forrajeo. Su delicioso sabor y la variedad de texturas estimulan su curiosidad y promueven el enriquecimiento ambiental, convirtiendo cada bocado en un momento de juego y bienestar. Además, contribuye el mantenimiento natural del pico, favoreciendo su desgaste saludable. Ideal para canarios, jilgueros, pinzones, gorriones y otras aves granívoras, FunBites transforma la alimentación diaria en una experiencia nutritiva y divertida</span></p>', 0, 75, 124, 1, NULL, NULL, NULL, '2026-01-28 23:09:25', NULL, NULL, 'Premios-fun-bites-para-aves-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1749, NULL, 'producto', '7501325468542', 0x414C49582D3034, 'FL4524', 10.00, 'Alimento para ajolotes ajolostix', '<p>Alimento para ajolotes ajolostix</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Ajolostix es un alimento formulado para el cuidado nutricional de ajolotes y otras salamandras acuáticas en cautiverio. Diseñado de acuerdo con las necesidades fisiológicas de estos fascinantes anfibios, ofrece una fórmula equilibrada que combina harina de pescado y harina de pollo como fuentes principales de proteína de alta calidad – esenciales para el crecimiento, la regeneración tisular y la salud general de los ajolotes adultos. Cada stick está enriquecido con un complejo de vitaminas y minerales esenciales y oligoelementos que apoyan el sistema inmunológico, el metabolismo y el desarrollo óptimo. Su presentación en sticks flotantes de 2.5mm x 12mm facilita la ingesta controlada y evita el desperdicio, manteniendo el agua del hábitat más limpia. Más que un alimento, Ajolostix es una opción pensada para el cuidado responsable de los ajolotes en cautiverio. Su fórmula complementa una dieta variada que incluya alimento vivo (lombrices, larvas, gusanos, pequeños peces, etc) tal como lo requiere su naturaleza carnívora.</span></p>', 0, 35, 124, 1, NULL, NULL, NULL, '2026-01-31 07:05:21', NULL, NULL, 'Alimento-para-ajolotes-ajolostix', 0, 0);
INSERT INTO `ecom_productos` VALUES (1750, NULL, 'producto', '7501556486520', 0x4D4544552D3031, 'FL8652', 10.00, 'Alimento para ajolotes ajolostix', '<p>Alimento para ajolotes ajolostix</p><p>Colores: verde, naranja, rosa, morada, azul (colores sujetos a disponibilidad)</p><p>Tamaño: grande </p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Medusa de silicón fluorescente, que sirve de adorno para decorar acuarios, ya sea de agua dulce o salada, la medusa flotará, sin perder sus colores.</span><span style=\"background-color: rgb(255, 255, 255); color: rgb(50, 51, 56);\">Decoración casi real simulando este animal flotante para acuario• Brindando asi comodidad a algunos peces de Material suave y No tóxico</span></p>', 0, 135, 124, 1, NULL, NULL, NULL, '2026-01-31 07:03:33', NULL, NULL, 'Alimento-para-ajolotes-ajolostix', 0, 0);
INSERT INTO `ecom_productos` VALUES (1751, NULL, 'producto', '7501556441758', 0x524550412D3031, 'FL4175', 10.00, 'Repelente para ácaros y piojos de aves ', '<p>Repelente para ácaros y piojos de aves&nbsp;</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Solución ideal para proteger a tus aves de ornato contra plagas molestas como ácaros y piojos. Formulado con extracto de neem, este repelente actúa de manera natural, interfiriendo en el ciclo de vida de los parásitos, previniendo su reproducción y eliminándolos sin recurrir a químicos agresivos.Diseñado para ser efectivo en todo tipo de aves, este producto ofrece una protección confiable mientras cuida el bienestar y salud de tus mascotas.</span></p>', 0, 135, 124, 1, NULL, NULL, NULL, '2026-01-31 07:32:34', NULL, NULL, 'Repelente-para-acaros-y-piojos-de-aves-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1752, NULL, 'producto', '7501556441758', 0x435544412D3031, 'FL9702', 10.00, 'Cueva dona cama para gatos ', '<p>Cueva dona cama para gatos&nbsp;</p><p>Color: gris oxford</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Dale a tu gato el refugio perfecto con la Cueva Dona de Fancy Pets. Accesorio multifuncional diseñado para satisfacer el instinto de escondite de cualquier gato. Fabricada con fieltro resistente y transpirable, esta cueva ofrece un espacio acogedor y seguro para descansar, jugar y relajarse. Su innovador diseño circular, con forma de dona que evita que se colapse, la hace ideal para hogares con uno o varios gatos. Gracias a sus dos túneles semicirculares unidos por una cremallera plástica, puedes transformar fácilmente el accesorio: úsalo como una cueva cerrada para brindar privacidad, o desarmarlo para convertirlo en una cama abierta y cómoda. Su diseño minimalista y en tonos neutros se adapta perfectamente a la decoración de cualquier hogar.</span></p>', 0, 400, 124, 1, NULL, NULL, NULL, '2026-01-31 07:43:12', NULL, NULL, 'Cueva-dona-cama-para-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1753, NULL, 'producto', '7501556441758', 0x435544412D3032, 'FL9701', 10.00, 'Cueva dona cama para gatos gris', '<p>Cueva dona cama para gatos&nbsp;</p><p>Color: gris</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Dale a tu gato el refugio perfecto con la Cueva Dona de Fancy Pets. Accesorio multifuncional diseñado para satisfacer el instinto de escondite de cualquier gato. Fabricada con fieltro resistente y transpirable, esta cueva ofrece un espacio acogedor y seguro para descansar, jugar y relajarse. Su innovador diseño circular, con forma de dona que evita que se colapse, la hace ideal para hogares con uno o varios gatos. Gracias a sus dos túneles semicirculares unidos por una cremallera plástica, puedes transformar fácilmente el accesorio: úsalo como una cueva cerrada para brindar privacidad, o desarmarlo para convertirlo en una cama abierta y cómoda. Su diseño minimalista y en tonos neutros se adapta perfectamente a la decoración de cualquier hogar.</span></p>', 0, 400, 124, 1, NULL, NULL, NULL, '2026-01-31 07:49:34', NULL, NULL, 'Cueva-dona-cama-para-gatos-gris', 0, 0);
INSERT INTO `ecom_productos` VALUES (1754, NULL, 'producto', '037461416361', 0x535553502D3032, '416361', 10.00, 'Sustrato de papel uber rosa con blanco 36 L para roedor ', '<p>Sustrato de papel para roedores</p><p>Color: rosa con blanco</p><p>Medidas: 22 x 10 x 40cm</p><p>Rinde: 36 L</p><p><br></p><p>Descripción:</p><p>Control de olor 14 dias su cama de papel de larga duración mantiene la jaula de su mascota fresca hasta por dos semanas, el sustrato de papel hace una cama acogedora y suave es un papael triturado virgen apto para uso alimentario; cómodo y encajable para animales pequeños 99.9% libre de polvo y sin aditivos químicos para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p>', 0, 495, 124, 1, NULL, NULL, NULL, '2026-01-31 08:53:13', NULL, NULL, 'Sustrato-de-papel-uber-rosa-con-blanco-36-L-para-roedor-', 0, 0);
