INSERT INTO `ecom_productos` VALUES (1756, NULL, 'producto', '037461413285', 0x535553502D3035, '413285', 10.00, 'Sustrato de papel uber cafe 28 L para roedor ', '<p>Sustrato de papel para roedores</p><p>Color: cafe</p><p>Medidas: 22 x 10 x 40cm</p><p>Rinde: 28 L</p><p><br></p><p>Descripción:</p><p>Control de olor 14 dias su cama de papel de larga duración mantiene la jaula de su mascota fresca hasta por dos semanas, el sustrato de papel hace una cama acogedora y suave es un papael triturado virgen apto para uso alimentario; cómodo y encajable para animales pequeños 99.9% libre de polvo y sin aditivos químicos para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p>', 0, 395, 124, 1, NULL, NULL, NULL, '2026-01-31 08:54:20', NULL, NULL, 'Sustrato-de-papel-uber-cafe-28-L-para-roedor-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1757, NULL, 'producto', '037461413285', 0x535553562D3031, '215032', 10.00, 'Sustrato de viruta natural 24 L para roedor ', '<p>Sustrato de papel para roedores</p><p>Color: cafe madera</p><p>Medidas: 23 x 10 x 40cm</p><p>Rinde: 24 L</p><p><br></p><p>Descripción:</p><p>Unidades por pack: 1.</p><p>Formato de venta: Unidad.</p><p>Volumen neto: 24 L.</p><p>Hecho de pino 100% natural, seguro para tus mascotas.</p><p>Adecuado para una variedad de mascotas pequeñas como chinchillas, conejos, cuyos, erizos, huerones y hámsters.</p><p>Material absorbente que ayuda a mantener el espacio de tu mascota limpio y fresco.</p><p>Permite a las mascotas hacer túneles y anidar.</p><p>Proporciona un aroma fresco de forma natural, sin aromas añadidos ni aceites aromáticos.</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">&nbsp;Nuestras virutas de pino tienen una fragancia natural y se producen mediante un proceso respetuoso con el medio ambiente. Nuestro lecho de pino está hecho de madera natural de alta calidad secada al horno, lo que permite a las mascotas construir túneles y anidar cómodamente.</span></p><p><br></p>', 0, 160, 124, 1, NULL, NULL, NULL, '2026-01-31 08:51:03', NULL, NULL, 'Sustrato-de-viruta-natural-24-L-para-roedor-', 0, 0);
