INSERT INTO `ecom_productos` VALUES (1769, NULL, 'producto', '7503038122001', 0x504150492D3031, 'PAPI-01', 10.00, 'Papilla para loros y periquitos alamazonas 250g ', '<p>Papilla para loros y periquitos alamazonas</p><p>Para: Loros, periquitos, agapornis, ninfas y psitácidos <a href=\"https://www.google.com/search?q=Psittacidae&amp;sca_esv=f85aee35ab456974&amp;biw=2560&amp;bih=1305&amp;sxsrf=ANbL-n538qB3WCJ3V8-zGLPtcaOkl7kbwA%3A1771335316918&amp;ei=lG6UafnpN4aO8L0Pxs2CgAE&amp;ved=2ahUKEwjrotnQ0uCSAxX5JUQIHeu3G6MQgK4QegQIARAD&amp;uact=5&amp;oq=como+se+llaman+las+aves+consideradas+loros&amp;gs_&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCMx2Vcp8uRPn1nrN3lEmP6ai8GvPJrtvY2cPc3v1UNGIhVTTM6lgeV2NFksBuXdJOVcr6kvkWm17BQLHCkrAPp0DPZzAuAIU0R6flGtRxd0o7HIc5L7f9rNxuxDkXiswqOIgu7j6TtVIK9gJ3avMcHXsOsNXmC5OWX32UFdHfpdOY0X7r5Qz_uWFZi4WkriUcZiguVUVSdWAk0fdSm0t0tDV98aiQDm-OE7SNmONcnDVRVUw7LdCHAcLHg0RlJTf3Slnd05seXxBuyUkjr6i60&amp;csui=3\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: unset;\">Psittacidae</a>&nbsp;(loros verdaderos, papagayos, cotorras, guacamayos),&nbsp;<a href=\"https://www.google.com/search?q=Cacatuidae&amp;sca_esv=f85aee35ab456974&amp;biw=2560&amp;bih=1305&amp;sxsrf=ANbL-n538qB3WCJ3V8-zGLPtcaOkl7kbwA%3A1771335316918&amp;ei=lG6UafnpN4aO8L0Pxs2CgAE&amp;ved=2ahUKEwjrotnQ0uCSAxX5JUQIHeu3G6MQgK4QegQIARAE&amp;uact=5&amp;oq=como+se+llaman+las+aves+consideradas+loros&amp;gs_&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCMx2Vcp8uRPn1nrN3lEmP6ai8GvPJrtvY2cPc3v1UNGIhVTTM6lgeV2NFksBuXdJOVcr6kvkWm17BQLHCkrAPp0DPZzAuAIU0R6flGtRxd0o7HIc5L7f9rNxuxDkXiswqOIgu7j6TtVIK9gJ3avMcHXsOsNXmC5OWX32UFdHfpdOY0X7r5Qz_uWFZi4WkriUcZiguVUVSdWAk0fdSm0t0tDV98aiQDm-OE7SNmONcnDVRVUw7LdCHAcLHg0RlJTf3Slnd05seXxBuyUkjr6i60&amp;csui=3\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: unset;\">Cacatuidae</a>&nbsp;(cacatúas) y&nbsp;<a href=\"https://www.google.com/search?q=Strigopidae&amp;sca_esv=f85aee35ab456974&amp;biw=2560&amp;bih=1305&amp;sxsrf=ANbL-n538qB3WCJ3V8-zGLPtcaOkl7kbwA%3A1771335316918&amp;ei=lG6UafnpN4aO8L0Pxs2CgAE&amp;ved=2ahUKEwjrotnQ0uCSAxX5JUQIHeu3G6MQgK4QegQIARAF&amp;uact=5&amp;oq=como+se+llaman+las+aves+consideradas+loros&amp;gs_&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCMx2Vcp8uRPn1nrN3lEmP6ai8GvPJrtvY2cPc3v1UNGIhVTTM6lgeV2NFksBuXdJOVcr6kvkWm17BQLHCkrAPp0DPZzAuAIU0R6flGtRxd0o7HIc5L7f9rNxuxDkXiswqOIgu7j6TtVIK9gJ3avMcHXsOsNXmC5OWX32UFdHfpdOY0X7r5Qz_uWFZi4WkriUcZiguVUVSdWAk0fdSm0t0tDV98aiQDm-OE7SNmONcnDVRVUw7LdCHAcLHg0RlJTf3Slnd05seXxBuyUkjr6i60&amp;csui=3\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: unset;\">Strigopidae</a>&nbsp;(loros de Nueva Zelanda)<span style=\"color: rgb(230, 232, 240); background-color: rgb(31, 31, 31);\">.</span></p><p><br></p><p>Descripción:</p><p>NUTRICIÓN ESPECIALIZADA | Fórmula enriquecida para más de 50 especies de aves incluyendo loros, periquitos y agapornis, promueve un desarrollo sano.</p><p>CRECIMIENTO Y PLUMAJE BRILLANTE | Ayuda a los polluelos a crecer más rápido y a desarrollar un plumaje brillante y saludable.</p><p>FÁCIL PREPARACIÓN | Solo necesita agua tibia para preparar una papilla suave que es fácilmente consumible por aves jóvenes y adultos.</p><p><br></p>', 0, 145, 124, 1, NULL, NULL, NULL, '2026-02-17 07:37:54', NULL, NULL, 'Papilla-para-loros-y-periquitos-alamazonas-250g-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1770, NULL, 'producto', '7503039448766', 0x504150492D3032, '22A18', 10.00, 'Papilla para canarios alamazonas 250g', '<p>Papilla para canarios alamazonas</p><p><br></p><p>Descripción:</p><p>FORMULACIÓN ESPECIALIZADA | Diseñada para aves de la familia de los fringílidos, como los canarios, proporcionando una alimentación completa desde el nacimiento hasta la independencia.</p><p>INGREDIENTES DE CALIDAD | Elaborada con ingredientes de primera calidad, sin aditivos artificiales, garantizando una nutrición adecuada para tus aves.</p><p>FÁCIL PREPARACIÓN | Mezcla 3 partes de agua purificada tibia a 35°C con 1 parte de papilla para obtener la consistencia de un yogurt batido. Evita el uso de microondas para calentar la papilla.</p><p>VERSÁTIL Y PRÁCTICA | Ideal para la cría manual de polluelos y para la alimentación de adultos en tratamiento o recuperación.</p><p><br></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-02-17 07:39:36', NULL, NULL, 'Papilla-para-canarios-alamazonas-250g', 0, 0);
INSERT INTO `ecom_productos` VALUES (1771, NULL, 'producto', '7503039448803', 0x504150492D3033, '22A22', 10.00, 'Papilla para aves silvestres alamazonas 250g ', '<p>Papilla para aves silvestres alamazonas</p><p>Para: rapaces (águilas, búhos), acuáticas (patos, garzas), cantoras (jilgueros, gorriones) y exóticas (tucanes, guacamayas)<span style=\"background-color: rgb(31, 31, 31); color: rgb(230, 232, 240);\">. Ejemplos comunes incluyen colibríes, golondrinas, cuervos, loros, vencejos, zorzales y gaviotas</span></p><p><br></p><p>Descripción:</p><p>FÓRMULA ESPECIALIZADA | Nuestra papilla está formulada para satisfacer las necesidades nutricionales de las aves silvestres en todas las etapas de crecimiento, desde el nacimiento hasta la independencia.</p><p>INGREDIENTES DE CALIDAD | Elaborada con ingredientes de primera calidad, esta papilla garantiza una nutrición óptima para tus aves silvestres.</p><p>FÁCIL PREPARACIÓN | Mezcla 3 partes de agua purificada tibia a 35°C con 1 parte de papilla para obtener la consistencia de un yogurt batido. Evita el uso de microondas para calentar la papilla.</p><p>VERSÁTIL Y PRÁCTICA | Ideal para criar manualmente aves silvestres y para alimentar a adultos en tratamiento o recuperación.</p><p><br></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-02-17 07:38:01', NULL, NULL, 'Papilla-para-aves-silvestres-alamazonas-250g-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1772, NULL, 'producto', '7503053543126', 0x414C492D314741, 'ALI-1GA', 10.00, 'Alimento para carpas koi goldfish 1kg', '<p>Alimento para carpas koi goldfish</p><p><br></p><p>Descripción:</p><p>PELLETS FLOTANTES 4.5 MM | Se mantienen en la superficie para observar el consumo y evitar restos en el fondo que enturbian el agua.</p><p>FÓRMULA DE ALTA DIGESTIBILIDAD | Mezcla equilibrada de proteínas, lípidos y fibra que aporta energía y favorece el color natural de carpas koi y goldfish.</p><p>USO DIARIO FÁCIL | Ofrece la porción que los peces coman en 3-5 minutos, una o dos veces al día; ideal para estanques y acuarios al aire libre.</p><p>INGREDIENTES SELECCIONADOS | Sin subproductos de bajo valor; pellets firmes que no se deshacen y ayudan a mantener el agua limpia por más tiempo.</p><p><br></p>', 0, 159, 124, 1, NULL, NULL, NULL, '2026-02-17 08:07:40', NULL, NULL, 'Alimento-para-carpas-koi-goldfish-1kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1773, NULL, 'producto', '7503050602871', 0x414C49452D3038, 'ALIE-08', 10.00, 'Alimento para erizo alamazonas 1kg', '<p>Alimento para carpas koi goldfish</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.75); background-color: rgb(255, 255, 255);\">una opción naturalmente completa y saludable diseñada para satisfacer las necesidades nutricionales de tu mascota. Nuestro alimento está formulado con un alto contenido de proteínas, utilizando tenebrios (gusano de la harina) como fuente principal, junto con ingredientes de calidad seleccionados cuidadosamente.</span></p><p><br></p><p>ingredientes:</p><p><span style=\"color: rgba(0, 0, 0, 0.75); background-color: rgb(255, 255, 255);\">Tenebrio deshidratado (Tenebrio molitor): una fuente rica en proteínas y nutrientes esenciales.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.75); background-color: rgb(255, 255, 255);\">Harina de carne y aceite de pescado: fuentes adicionales de proteínas y ácidos grasos esenciales.</span></p>', 0, 349, 124, 1, NULL, NULL, NULL, '2026-02-17 08:08:55', NULL, NULL, 'Alimento-para-erizo-alamazonas-1kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1774, NULL, 'producto', '7503050602888', 0x414C4953552D3031, 'ALISU-01', 10.00, 'Alimento para sugar glider (petauros) alamazonas 1kg', '<p>Alimento para sugar glider (petauros) alamazonas</p><p><br></p><p>Descripción:</p><p>Naturalmente completa y saludable diseñada para satisfacer las necesidades dietéticas específicas de tu adorable Sugar Glider. Nuestro alimento está cuidadosamente formulado con un alto contenido de proteínas, frutas exóticas y tenebrios (gusano de la harina) deshidratados para ofrecer una dieta balanceada y deliciosa.</p><p>Ingredientes de calidad:</p><p>Frutas deshidratadas: piña, papaya, fresa, arándano, manzana y kiwi proporcionan una variedad de sabores y nutrientes esenciales.</p><p>Tenebrio deshidratado: una fuente natural de proteínas y otros nutrientes vitales para la salud de tu mascota.</p><p>Harina de carne y aceite de pescado: proporcionan proteínas de alta calidad y ácidos grasos esenciales.</p>', 0, 350, 124, 1, NULL, NULL, NULL, '2026-02-17 08:10:06', NULL, NULL, 'Alimento-para-sugar-glider-(petauros)-alamazonas-1kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1775, NULL, 'producto', 'PANIZO031KG', 0x50415A492D3033, 'PAZI-03', 5.00, 'Panizo natural en espiga 1kg', '<p>Panizo natural en espiga 1kg</p><p><br></p><p><br></p><p>Descripción:</p><p>&nbsp;planta gramínea (normalmente&nbsp;<em>Setaria italica</em>) cuyas semillas en rama son un alimento muy apetecible, energético y bajo en grasas para aves como loros, agapornis y canarios<span style=\"color: rgb(230, 232, 240); background-color: rgb(31, 31, 31);\">. Es rico en carbohidratos, ideal para el destete, entrenamiento y estimulación del forrajeo.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Para las aves enfermas ademas de colocarles su alimento habitual, debemos colocar una rama de panizo cada dos días, ya que estas resultan muy apetecibles y abren el apetito de nuestro loro.</span></p>', 0, 900, 124, 1, NULL, NULL, NULL, '2026-02-17 08:38:45', NULL, NULL, 'Panizo-natural-en-espiga-1kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1776, NULL, 'producto', 'HUJIB01KG', 0x4A49422D3031, 'JIB-01', 5.00, 'Hueso de jibia (sepia) natural por 1kg', '<p>Hueso de jibia (sepia) natural 1kg</p><p><br></p><p>Descripción:</p><p>La jibia natural (o sepia) o jibión es un&nbsp;molusco marino cefalópodo rico en proteínas, yodo y minerales<span style=\"background-color: rgb(31, 31, 31); color: rgb(230, 232, 240);\">, muy apreciado en gastronomía. Su esqueleto interno, conocido como «</span><a href=\"https://www.google.com/search?q=hueso+de+jibia&amp;sca_esv=8f0cf4c20e082887&amp;sxsrf=ANbL-n7-v7YfOGqrmWGtH1vlYsSs2dOonA%3A1771339175696&amp;ei=p32Uad2bKoGZkPIP_9LxqQE&amp;biw=2560&amp;bih=1305&amp;ved=2ahUKEwixpqXX4OCSAxUgIkQIHU-pLkEQgK4QegQIARAC&amp;uact=5&amp;oq=jibia+natural&amp;gs_lp=Egxnd3Mtd2l6LXNlcnAiDWppYmlhIG5hdHVyYWwyBhAAGBYYHjIGEAAYFhgeMgUQABjvBTIFEAAY7wUyBRAAGO8FMggQABiABBiiBEilJVC8AVjOInABeAGQAQCYAWmgAaoGqgEDMy41uAEDyAEA-AEBmAIJoALMBsICChAAGLADGNYEGEfCAg0QABiABBiwAxhDGIoFwgIOEAAYsAMY5AIY1gTYAQHCAhMQLhiABBiwAxhDGMgDGIoF2AEBwgIKEAAYgAQYQxiKBcICBRAAGIAEwgIJEAAYgAQYChgLwgIIEAAYgAQYywGYAwCIBgGQBhK6BgYIARABGAmSBwMyLjegB4ElsgcDMS43uAfHBsIHBTAuNi4zyAcWgAgA&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfAd0OdfmxjWZuO-P80gK0VD3PZz2gsqMWwlCyXi-8Qh1dIlV-vgbfETRxHs4OBmbN-zRop2iud1zt0m6ENTiqEdSZEJoQSKOEmjwBG1U1vsa1i1KbhN1EzTMYdoYbmcpNBzCfjyGgG1SZupsht6_s6d0lXxdTTYduU0Ujt4_1MyvvW6dpEKYSO6az0d5VAUnDzoMlTT6WOph7l7XHivNn2JF9C-X0UG0EMECI21q5L5ZEFXuwYTGqdosqEivIeWiKyZM7_YmmBhKopPb98SXflj&amp;csui=3\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(31, 31, 31); color: unset;\">hueso de jibia</a><span style=\"background-color: rgb(31, 31, 31); color: rgb(230, 232, 240);\">», es un suplemento de calcio natural esencial para aves de jaula, hámsters y reptiles, ayudando a fortalecer sus huesos, mejorar la puesta de huevos y desgastar el pico.</span></p><p><br></p><p><strong>Periquitos Exóticos pequeños:</strong>&nbsp;Pinzones, diamantes mandarines, isabelitas, <strong>canarios, agapornis (inseparables) y ninfas u otras aves:</strong>&nbsp;Cotorras y loros de pequeño/mediano tamaño</p><p><br></p><p><strong style=\"background-color: rgb(44, 48, 61);\">Reptiles:</strong><span style=\"background-color: rgb(44, 48, 61);\">&nbsp;Tortugas (terrestres y acuáticas), principalmente para fortalecer su caparazón y esqueleto, aportando el calcio necesario en cautiverio.</span></p><p><strong style=\"background-color: rgb(44, 48, 61);\">Caracoles:</strong><span style=\"background-color: rgb(44, 48, 61);\">&nbsp;Muy utilizada en caracoles terrestres (como el caracol gigante africano) para el fortalecimiento y reparación de su concha.</span></p><p><strong style=\"background-color: rgb(44, 48, 61);\">Roedores:</strong><span style=\"background-color: rgb(44, 48, 61);\">&nbsp;Cobayas, chinchillas, hámsters y ratones, que pueden roerla para desgastar sus dientes.</span>&nbsp;</p><p><br></p><p><br></p><p><strong>Fuente de Calcio:</strong>&nbsp;Es rico en carbonato cálcico, esencial para fortalecer huesos, la formación de la cáscara de los huevos y la salud de las uñas.</p><p><strong>Desgaste del pico:</strong>&nbsp;Evita que el pico crezca descontroladamente y ayuda a limarlo.</p><p><strong>Muda de pluma:</strong>&nbsp;Fortalece la estructura de las nuevas plumas.</p><p><br></p>', 0, 1400, 124, 1, NULL, NULL, NULL, '2026-02-17 09:21:07', NULL, NULL, 'Hueso-de-jibia-(sepia)-natural-por-1kg', 0, 0);
