INSERT INTO `ecom_productos` VALUES (1805, NULL, 'producto', 'TERAM09303030', 0x544552414D2D3039, 'TERAM-09', 10.00, 'Terrario indi 30cm x 30cm malla tela', '<p>Terrario indi 30cm x 30cm malla tela</p><p>Marcos: madera</p><p>Malla: tela</p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de mdera con tela de lona forrrado con adaptacio de soquet para foco y latereles de malla de tela, piso de madera forrado de tela de lona con decoración de tronco fijo.</p>', 0, 490, 124, 1, NULL, NULL, NULL, '2026-03-03 08:41:11', NULL, NULL, 'Terrario-indi-30cm-x-30cm-malla-tela', 0, 0);
INSERT INTO `ecom_productos` VALUES (1806, NULL, 'producto', 'TERAM093030M', 0x544552414D2D30394D, 'TERAM-09M', 10.00, 'Terrario indi 30cm x 30cm malla metálica', '<p>Terrario indi 30cm x 30cm malla tela</p><p>Marcos: madera</p><p>Malla: metálitca</p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de mdera con tela de lona forrrado con adaptacio de soquet para foco y latereles de malla de tela, piso de madera forrado de tela de lona con decoración de tronco fijo.</p>', 0, 590, 124, 1, NULL, NULL, NULL, '2026-03-04 07:30:29', NULL, NULL, 'Terrario-indi-30cm-x-30cm-malla-metalica', 0, 0);
INSERT INTO `ecom_productos` VALUES (1807, NULL, 'producto', 'CORRA083030AR', 0x434F5252412D3038, 'CORRA-08', 10.00, 'Corral  armin rejilla cuadrada 30 x 30cm 12 paneles', '<p>Corral armin rejilla cuadrada</p><p>Cantidad: 12 paneles</p><p>Medida de cada panel: 30 x 30 cm (largo x alto)</p><p>Material: metálico</p><p>Color: Negro</p><p><br></p><p>Descripciòn:</p><p>Corral plegable de 8 paneles para hamster, conejo, cuyo, perros pequeños, pollitos, patos, mini pig y mas etc. i<span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos. con rejilla cerrada opara que no se salgan los pequeños.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Configuarción de armado: Óctagono 90 cm, Cuadrado 60 x 60 cm, rectangular 90 x 30 cm, o de valla 240 cm</span></p>', 0, 690, 124, 1, NULL, NULL, NULL, '2026-03-04 07:35:11', NULL, NULL, 'Corral--armin-rejilla-cuadrada-30-x-30cm-12-paneles', 0, 0);
