INSERT INTO `ecom_productos` VALUES (1809, NULL, 'producto', 'TAPAGAL0160', 0x544147412D3031, 'TAGA-01', 20.00, 'Tapa galvanizada 60 cm x 60cm  para corrales', '<p>Corral armin rejilla cuadrada</p><p>Medidas: 60 x 60 cm (largo x ancho)</p><p>Material: metálico</p><p>Color: natural galvanizado</p><p><br></p><p>Descripciòn: Tapa metálica con 4 ganchos de seguridad para corrales que midan 60cm cada panel ya sea para corral de 4, 6 paneles poniendole 1 , 2 o mas tapas asi evitando que se salgan por la parte de arriba sea trepando o saltando porque cuenta con seguros la tapa para evitar que la abran o de la misma manera evitar que entren otros animales a ese espacio exclusivo para tu mascota. para gallos, conejo, cuyo, perros pequeños, pollitos, patos, mini pig y mas etc. i<span style=\"color: rgb(102, 102, 102);\">deal para entrenar cachorros, dividir espacios, separar camadas, aislar perritos enfermos, cuidados post quirúrgicos. para que no se salgan los pequeños.</span></p><p><br></p><p><span style=\"color: rgb(102, 102, 102);\">Para corral: Cuadrado 60 x 60 cm 1 tapa, rectangular 120 x 60cm 2tapas.</span></p>', 0, 100, 124, 1, NULL, NULL, NULL, '2026-03-04 07:56:27', NULL, NULL, 'Tapa-galvanizada-60-cm-x-60cm--para-corrales', 0, 0);
INSERT INTO `ecom_productos` VALUES (1810, NULL, 'producto', 'JARO172DIGAL', 0x4A41524F2D3137, 'JARO-17', 10.00, 'Jaula sefra 1 división  60 x 40cm', '<p>Jaula de pajaro monarca</p><p>Color: natural galvanizado</p><p>Charola: galvanizada</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves plegable para almacenar o llevar contogo sin ocupar tanto espacio al trasladar.</span></p><p><span style=\"color: rgb(70, 71, 74);\">Con charola extraible para un mantenimiento sencilloy fácil : La bandeja de limpieza es desmontable hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no tenga contacto con sus eses el ave, con panel disvisor para poner a dos aves distintas o separar camadas de aves </span></p><p>Con dos puertas frontales y una ventana en cada lateral</p>', 0, 790, 124, 1, NULL, NULL, NULL, '2026-03-04 08:00:30', NULL, NULL, 'Jaula-sefra-1-division--60-x-40cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1811, NULL, 'producto', 'JARO183DIGAL', 0x4A41524F2D3138, 'JARO-18', 10.00, 'Jaula sefra 2 divisiónes 90 x 40cm', '<p>Jaula sefra 2 divisiónes para pajaros</p><p>Color: natural galvanizado</p><p>Charola: galvanizada</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves plegable para almacenar o llevar contogo sin ocupar tanto espacio al trasladar.</span></p><p><span style=\"color: rgb(70, 71, 74);\">Con charola extraible para un mantenimiento sencilloy fácil : La bandeja de limpieza es desmontable hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no tenga contacto con sus eses el ave, con panel disvisor para poner a dos aves distintas o separar camadas de aves </span></p><p>Con tres puertas frontales y una ventana en cada lateral</p>', 0, 1200, 124, 1, NULL, NULL, NULL, '2026-03-04 08:09:10', NULL, NULL, 'Jaula-sefra-2-divisiones-90-x-40cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1812, NULL, 'producto', '7502211914372', 0x535553502D3036, 'CL005', 10.00, 'Suatrato de papel mini mypet para roedores', '<p>Sustrato de papel mypet para roedores</p><p>Color: blanco con naranja</p><p><br></p><p>Descripción:</p><p>Ayuda a disminuir los malos olores con su cama de papel mantiene la jaula de su mascota fresca , el sustrato de papel hace una cama acogedora y suave es un papael se expande de 4-5 veces de su tamaño original; cómodo y encajable para animales pequeños hecho con material de telas reciclado altamente absorbente para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p>', 0, 140, 124, 1, NULL, NULL, NULL, '2026-03-06 08:45:59', NULL, NULL, 'Suatrato-de-papel-mini-mypet-para-roedores', 0, 0);
INSERT INTO `ecom_productos` VALUES (1813, NULL, 'producto', '7502234336656', 0x4152452D3037, 'SP-3665', 15.00, 'Arena pawffy con aroma lavanada 5 kg para gato', '<p>Arena pawffy con aroma lavanada para gato</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">SUPER CONDENSACIÓN, FUERTE AROMA</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Utiliza sodio natural de la bentonita para solidificar rápidamente con heces y orina de gato.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">EL MÍNIMO POLVO Y AMIGABLE CON EL MEDIO AMBIENTE</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Adopta procesos avanzados de esterilización de polvo y esterilización a alta temperatura con bentonita de sodio natural pura.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">MENOR CONSUMO, FRAGANCIA NATURAL</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Las partículas de la arena son más gruesas, lo que permite un mejor rendimiento en la limpieza y ahorros significativos en el consumo. La arena no se sale fácilmente del arenero.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">En caso de que el gato no se acostumbre rápidamente a la arena, mezclar una pequeña porción de la arena anterior puede ayudar.</span></p>', 0, 120, 124, 1, NULL, NULL, NULL, '2026-03-07 05:50:46', NULL, NULL, 'Arena-pawffy-con-aroma-lavanada-5-kg-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1814, NULL, 'producto', '7502234336649', 0x4152452D3038, 'SP-3664', 15.00, 'Arena pawffy sin aroma de 5 kg para gato', '<p>Arena pawffy sin aroma para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">SUPER CONDENSACIÓN, FUERTE AROMA</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Utiliza sodio natural de la bentonita para solidificar rápidamente con heces y orina de gato.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">EL MÍNIMO POLVO Y AMIGABLE CON EL MEDIO AMBIENTE</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Adopta procesos avanzados de esterilización de polvo y esterilización a alta temperatura con bentonita de sodio natural pura.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">MENOR CONSUMO, FRAGANCIA NATURAL</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Las partículas de la arena son más gruesas, lo que permite un mejor rendimiento en la limpieza y ahorros significativos en el consumo. La arena no se sale fácilmente del arenero.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">En caso de que el gato no se acostumbre rápidamente a la arena, mezclar una pequeña porción de la arena anterior puede ayudar.</span></p>', 0, 95, 124, 1, NULL, NULL, NULL, '2026-03-07 05:51:35', NULL, NULL, 'Arena-pawffy-sin-aroma-de-5-kg-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1815, NULL, 'producto', '7502235337394', 0x4152452D3039, 'SP-3738', 5.00, 'Arena sunny aroma lavanda de 20 kg para gato ', '<p>Arena para gato aroma lavanda</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Con Aroma lavanda </span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium</span></p><p><span style=\"color: rgb(102, 102, 102);\">99% libre de polvo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Con Súper aglutinante</span></p><p><span style=\"color: rgb(102, 102, 102);\">Control de aroma 24hrs</span></p>', 0, 590, 124, 1, NULL, NULL, NULL, '2026-06-03 08:05:04', '2026-06-03 08:05:04', NULL, 'Arena-sunny-aroma-lavanda-de-20-kg-para-gato-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1816, NULL, 'producto', '7502234337370', 0x4152452D3130, 'SP-3737', 5.00, 'Arena sunny aroma limón de 20 kg para gato', '<p>Arena aroma limón para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Con Aroma lavanda </span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium</span></p><p><span style=\"color: rgb(102, 102, 102);\">99% libre de polvo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Con Súper aglutinante</span></p><p><span style=\"color: rgb(102, 102, 102);\">Control de aroma 24hrs</span></p>', 0, 550, 124, 1, NULL, NULL, NULL, '2026-03-07 06:10:10', NULL, NULL, 'Arena-sunny-aroma-limon-de-20-kg-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1817, NULL, 'producto', '7502234337387', 0x4152452D3131, 'SP-3738', 5.00, 'Arena sunny sin aroma de 20 kg para gato', '<p>Arena sin aroma para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(102, 102, 102);\">Con Aroma lavanda </span></p><p><span style=\"color: rgb(102, 102, 102);\">Calidad Premium</span></p><p><span style=\"color: rgb(102, 102, 102);\">99% libre de polvo</span></p><p><span style=\"color: rgb(102, 102, 102);\">Con Súper aglutinante</span></p><p><span style=\"color: rgb(102, 102, 102);\">Control de aroma 24hrs</span></p>', 0, 590, 124, 1, NULL, NULL, NULL, '2026-06-03 08:05:04', '2026-06-03 08:05:04', NULL, 'Arena-sunny-sin-aroma-de-20-kg-para-gato', 0, 0);
INSERT INTO `ecom_productos` VALUES (1818, NULL, 'producto', '7501556400526', 0x4152452D3132, 'FL9052', 5.00, 'Arena para gato soluble en agua costal de 4kg', '<p>Arena para gato soluble en agua</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(15, 17, 17);\">Está compuesta de materiales especiales que absorben la humedad y atrapan los olores, evitando que se dispersen en el ambiente. Es ideal ya que su capacidad para controlar el olor hace que el mantenimiento de la caja de arena sea más fácil y menos frecuente.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(15, 17, 17);\">Es segura para desechar en el inodoro, esta arena es altamente absorbente y controla eficazmente los olores, manteniendo el área de la caja de arena limpia y fresca. Su textura suave es cómoda para las patas de los gatos, y su capacidad para aglutinarse facilita la limpieza diaria.</span></p>', 0, 350, 124, 1, NULL, NULL, NULL, '2026-03-07 06:14:37', NULL, NULL, 'Arena-para-gato-soluble-en-agua-costal-de-4kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1819, NULL, 'producto', 'JERY01CSON', 0x4A4552592D3031, 'JERY-01', 5.00, 'Jeringa para embuchar 50 ml con sonda', '<p>Arena para gato soluble en agua</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">JERINGA PARA EMBUCHAR CON SONDA DE GRADO ALIMENTICIO </span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">IDEAL GUACAMAYAS Y LOROS GRANDES</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Las Jerigas con sondas son ideales para suministrar adecuadamente la papilla en loros y guacamayas. Gracias a la forma y el material permiten de manera atraumática alimentar a las aves papilleras.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Este método de alimentación permite alimentar a las aves papilleras de una manera sencilla y rápida y de manera higiénica.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">**Se recomiendan solamente para personas con experiencia utilizando jeringas con sonda para alimentación o estar adecuadamente asesorados ya que al utilizar sondas existe el riesgo de poder provocar broncoaspiración en las aves.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">MUY IMPORTANTE.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">La jeringa para papilla con sonda es reutilizable recuerde que después de cada uso es muy importante que enjuage abundantemente con agua y jabón deje escurrir para la siguiente dosis de alimento esto ayudara a evitar enfermedades en su lorito y alarga la vida útil de su jeringa.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">*Si muestra algún tipo de daño remplace inmediatamente.</span></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2026-03-07 07:45:31', NULL, NULL, 'Jeringa-para-embuchar-50-ml-con-sonda', 0, 0);
INSERT INTO `ecom_productos` VALUES (1820, NULL, 'producto', 'JERY02CPRIG', 0x4A4552592D3032, 'JERY-02', 5.00, 'Jeringa para embuchar con punta rigida 12ml ', '<p>Arena para gato soluble en agua</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">JERINGA PARA EMBUCHAR DE GRADO ALIMENTICIO </span></p><p><br></p><p>Jeringa con punta incorporada para embuchar pichones con comodidad.</p><p>A tener la punta incorporada faciita el embuche de pajaro y evita que se derrame la papilla.</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">son ideales para suministrar adecuadamente la papilla para canarios, finches, periquitos, agapornis, ninfas y loros pequeños. Cortar la punta a la apertura necesaria. Gracias a la forma y el material permiten de manera atraumática alimentar a las aves papilleras.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Este método de alimentación permite alimentar a las aves papilleras de una manera sencilla y rápida y de manera higiénica.</span></p><p><br></p>', 0, 50, 124, 1, NULL, NULL, NULL, '2026-03-07 07:46:20', NULL, NULL, 'Jeringa-para-embuchar-con-punta-rigida-12ml-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1821, NULL, 'producto', 'TAIMPER01CUD', 0x5441494D2D3031, 'TAIM-01', 20.00, 'Tapete impermeable doble vista para corral de 60 x 60cm ', '<p>Tapete impermeable doble vista para corral de 60 x 60cm&nbsp;</p><p><br></p><p>Descripción:</p><p>Tapete impermeable doble vista para corral de 60 x 60 cm el cual es fácil de instalar y desinstalar con un diseño compacto que genera poco espacio de alamacenaje, y ligero. asi a su vez fácil de limpiar y lavar.</p>', 0, 200, 124, 1, NULL, NULL, NULL, '2026-03-07 08:22:00', NULL, NULL, 'Tapete-impermeable-doble-vista-para-corral-de-60-x-60cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1822, NULL, 'producto', 'TAIMPER02REC', 0x5441494D2D3032, 'TAIM-02', 20.00, 'Tapete impermeable doble vista para corral de 60 x 120cm ', '<p>Tapete impermeable doble vista para corral de 60 x 120cm&nbsp;</p><p><br></p><p>Descripción:</p><p>Tapete impermeable doble vista para corral de 60 x 60 cm el cual es fácil de instalar y desinstalar con un diseño compacto que genera poco espacio de alamacenaje, y ligero. asi a su vez fácil de limpiar y lavar.</p>', 0, 400, 124, 1, NULL, NULL, NULL, '2026-03-07 08:23:52', NULL, NULL, 'Tapete-impermeable-doble-vista-para-corral-de-60-x-120cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1823, NULL, 'producto', '7501556496697', 0x5241532D3231, 'FL9669', 5.00, 'Rascador tapiz gris adherible  para gatos', '<p>Rascador tapiz gris adherible&nbsp;para gatos</p><p><br></p><p>Descripción:</p><p><br></p><p>Superficie del rascador hecho de poliéster.</p><p>Revestimiento del rascador hecho de poliéster.</p><p>Tipo de montaje: piso.</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">la solución perfecta para los dueños de gatos que buscan proteger sus muebles y, al mismo tiempo, proporcionar un área designada para rascar a sus amigos felinos.&nbsp;</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">son ideales para colocarlas en sofás o paredes, ya que garantizan que tus muebles permanezcan a salvo de marcas de garras no deseadas. El tipo de soporte en pasta permite una fácil aplicación, lo que facilita la fijación de las tablas en el lugar deseado.</span></p>', 0, 100, 124, 1, NULL, NULL, NULL, '2026-03-10 06:24:43', NULL, NULL, 'Rascador-tapiz-gris-adherible--para-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (1824, NULL, 'producto', '7502234337912', 0x5241532D3232, 'RAS-22', 5.00, 'Rascador rectangular de cartón para gatos', '<p>Rascador rectangular de cartón&nbsp;para gatos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">48.5 cm de largo x 12 cm de ancho x 5 cm de alto</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Elaborado con cartón corrugado</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Super resistente a mordidas y arañazos</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Ideal para eliminar capas muertas de piel en las garras y mejorar la apariencia de las uñas</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Incluye cat nip, para estimular el juego</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-03-10 07:11:19', NULL, NULL, 'Rascador-rectangular-de-carton-para-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (1825, NULL, 'producto', 'PER19RE1004040', 0x504552412D38303530, 'PERA-8050', 10.00, 'Pecera de 80 x 40 x 50 cm 160 litros 6 mm', '<p>Pecera rectangular</p><p>Capacidad: 160 litros</p><p>Grosor: 6 mm</p><p>Marcos: Aluminio</p><p><br></p><p>Descripción:pecera rectangular para peces, reptiles, roedores, con gran espacio para ellos con marcos de aluminio. Acuarios grandes para peces grandes o hacer una pecera comunitaria donde puedas tener mas de una especie de pez con gran variedad aparte con un espacio amplio para que la puedas decorar hermosa y brindarles un espacio amplio comodo y natural a tus peces.</p><p><br></p>', 0, 1850, 124, 1, NULL, NULL, NULL, '2026-05-25 10:17:24', '2026-05-25 10:17:24', NULL, 'Pecera-de-80-x-40-x-50-cm-160-litros-6-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1826, NULL, 'producto', 'TERAL09804035', 0x544552414C2D3039, 'TERAL-09', 10.00, 'Terrario calor 80 x 40 x 35cm ', '<p>Terrario calor puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metálica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario rectangualr de cristal con alumnio para reptiles pequeños como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva.</span></p>', 0, 3400, 124, 1, NULL, NULL, NULL, '2026-03-13 07:41:38', NULL, NULL, 'Terrario-calor-80-x-40-x-35cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1827, NULL, 'producto', 'TERA16201115', 0x544552412D3136, 'TERA-16', 10.00, 'Terrario petit 20 x 11 x 15 cm ', '<p>Terrario petit 20cm largo</p><p>Espesor: 3 mm</p><p>Marcos: plástico</p><p>Material: cristal</p><p><br></p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles pequeños como arañas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p>', 0, 295, 124, 1, NULL, NULL, NULL, '2026-03-13 07:55:16', NULL, NULL, 'Terrario-petit-20-x-11-x-15-cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1828, NULL, 'producto', '7501556436402', 0x5355452D3031, 'FL3640', 10.00, 'Suero oral electrolitos para perros sabor carne ', '<p><br></p><p><br></p><p>Descripción:</p><p>Hidratación rápida y efectiva: Fórmula líquida que ayuda a reponer electrolitos perdidos y mantener el equilibrio hídrico en perros adultos y cachorros.</p><p>Apoyo en situaciones de pérdida de líquidos: Ideal para días de calor, ejercicio intenso, paseos largos o viajes.</p><p>Energía adicional: Contiene glucosa que favorece la recuperación de energía y el bienestar general de tu mascota.</p><p>Minerales esenciales: Con sodio, potasio y magnesio que contribuyen al buen funcionamiento muscular y nervioso.</p><p>Sabor carne irresistible: Fácil de administrar gracias a su presentación líquida con un sabor atractivo para los perros.</p><p><br></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2026-03-14 08:05:50', NULL, NULL, 'Suero-oral-electrolitos-para-perros-sabor-carne-', 0, 0);
