INSERT INTO `ecom_productos` VALUES (1830, NULL, 'producto', '7501556436396', 0x5355452D3033, 'FL3639', 10.00, 'Suero oral electrolitos para perros sabor vainilla', '<p><br></p><p><br></p><p>Descripción:</p><p>Hidratación rápida y efectiva: Fórmula líquida que ayuda a reponer electrolitos perdidos y mantener el equilibrio hídrico en perros adultos y cachorros.</p><p>Apoyo en situaciones de pérdida de líquidos: Ideal para días de calor, ejercicio intenso, paseos largos o viajes.</p><p>Energía adicional: Contiene glucosa que favorece la recuperación de energía y el bienestar general de tu mascota.</p><p>Minerales esenciales: Con sodio, potasio y magnesio que contribuyen al buen funcionamiento muscular y nervioso.</p><p>Sabor vainilla irresistible: Fácil de administrar gracias a su presentación líquida con un sabor atractivo para los perros.</p><p><br></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2026-03-14 08:09:44', NULL, NULL, 'Suero-oral-electrolitos-para-perros-sabor-vainilla', 0, 0);
INSERT INTO `ecom_productos` VALUES (1831, NULL, 'producto', '7501556495232', 0x435245432D3031, 'FL4523', 10.00, 'Crema de cachuate para perros', '<p>Crema de cachuate para perros</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Delicioso snack cremoso con omega 3 y 6, proteínas y vitaminas. Ideal para consentir, entrenar y nutrir a tu perro de forma saludable.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Snack cremoso y saludable para perros con proteínas, grasas buenas, vitaminas y antioxidantes. Ideal como premio diario o durante el entrenamiento.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">¡Convierte cada momento con tu peludo en una experiencia deliciosa y saludable!</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">La crema de cacahuate Fancy Pets ha sido elaborada con ingredientes de alta calidad para brindarle a tu perro un premio irresistible que no solo le encantará, sino que aportará nutrientes esenciales para su bienestar.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Su textura cremosa es perfecta para untar en juguetes rellenables, lick mats o simplemente para premiar buenos comportamientos. Rica en proteínas, grasas saludables y omega 3 y 6, ayuda a fortalecer músculos, aporta energía sostenida y cuida la piel y el pelaje.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Ideal para perros activos, entrenamientos y momentos especiales.</span></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2026-03-14 08:19:49', NULL, NULL, 'Crema-de-cachuate-para-perros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1832, NULL, 'producto', 'filtro', NULL, 'fil', 5.00, 'Canister filtro extremo 800 l/h sunny', '<p>Canister filtro extremo 800 l/h sunny </p><p><br></p><p>Descripción:</p><p>Caudal máximo por hora: 1350 l/h.</p><p>Potencia: 32 W.</p><p>Capacidad máxima del filtro de 600 L para acuarios.</p><p>Tipo de filtro: Canister.</p><p>Modelo detallado: SCF-1000.</p><p><br></p>', 0, 2000, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Canister-filtro-extremo-800-lh-sunny', 0, 0);
INSERT INTO `ecom_productos` VALUES (1833, NULL, 'producto', '7501556496659', 0x434550492D3031, 'FL9665', 5.00, 'Cepillo expert con vaporizador para mascotas', '<p>Cepillo expert con vaporizador para mascotas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Innovador cepillo ergonómico y multifuncinal para el cuidado de mascotas incorpora un sistema de vapor frío que facilita la eliminación del pelo muerto, mejora la hidratación y suaviza el pelaje. Gracias a su depósito de agua integrado y el sistema de expulsión de vapor, el cepillo no solo elimina eficazmente el pelo suelto, sino que también proporciona un masaje relajante y mejora la circulación sanguínea de tu mascota.</span></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-03-14 09:47:45', NULL, NULL, 'Cepillo-expert-con-vaporizador-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1834, NULL, 'producto', '7501556496666', 0x434550492D3032, 'FL9666', 5.00, 'Cepillo rascador de silicón 3 en 1 para mascotas', '<p>Cepillo rascador de silicón 3 en 1 para mascotas</p><p><br></p><p>Descripción:</p><p>Diseño 3 en 1: Cepillo, masajeador y rascador fijo en un solo accesorio que facilita la rutina de cuidado y entretenimiento de tu mascota.</p><p>Material 100% silicón: Suave, flexible y duradero, ideal para cepillar y masajear sin irritar la piel.</p><p>Estimula la salud del pelaje: Las cerdas de silicón ayudan a remover el pelo muerto, distribuyen los aceites naturales y favorecen un pelaje más brillante y saludable.</p><p>Masaje relajante: Promueve la circulación sanguínea y genera una sensación de bienestar durante el cepillado.Rascador adaptable: Incluye correas elásticas ajustables que permiten colocarlo en patas de sillas o mesas, para que tu gato o perro se rasque de forma segura y natural.</p><p><br></p>', 0, 99, 124, 1, NULL, NULL, NULL, '2026-03-14 09:50:50', NULL, NULL, 'Cepillo-rascador-de-silicon-3-en-1-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1835, NULL, 'producto', '7501556483284', 0x434550492D3033, 'FL8328', 15.00, 'Cepillo con puntas redondas en diagonal para mascotas', '<p>Cepillo con puntas redondas en diagonal para mascotas</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Cepillo con púas de plástico redondeadas y flexibles para el cuidado diario del pelo de tu mascota.</span></p><p><span style=\"color: rgb(15, 17, 17); background-color: rgb(255, 255, 255);\">deal para cepillar a tu gato dejando su manto limpio y terso. Remueve los excedentes de pelo brindando suavidad. Su diseño ergonómico lo hace perfecto para el cepillado cotidiano. Se recomienda para gatos de pelo corto y no nada más para gatos tambien para, conejos, cuyos, hurones, hámster, chinchilla y mas; porque sus cerdas estan en diagonal con cerdas cortas suaves y juntas para un mejor, fácil y rapido cepillado.</span></p><p><br></p><p>- Cerdas de plástico flexibles.</p><p>- Puntas redondeadas.</p><p>- Mango ergonómico.</p><p><strong>Usos y beneficios:</strong></p><p>- Para el cepillado y cuidado diario del manto de tu mascota.</p><p>- Para todo tipo de manto (especialmente manto corto y medio).</p><p>- Por sus cerdas recubiertas, no irrita la piel de la mascota por el contacto.</p><p><br></p>', 0, 85, 124, 1, NULL, NULL, NULL, '2026-03-14 09:52:45', NULL, NULL, 'Cepillo-con-puntas-redondas-en-diagonal-para-mascotas', 0, 0);
INSERT INTO `ecom_productos` VALUES (1836, NULL, 'producto', '7501556497045', 0x4A5545, 'FL9704', 10.00, 'Juguete collar apuntador laser ajustable para gatos ', '<p>Juguete collar apuntador laser para gatos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Estimula el instinto natural de caza de tu gato con el juguete collar puntero laser. Este innovador accesorio, es una herramienta de entretenimiento que promueve la actividad física y mental de tu mascota de forma segura y autónoma. El laser proyecta un punto de luz roja que se mueve, incitando a tu gato a perseguirlo y cazarlo, manteniéndolo activo y entretenido.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">El juguete cuenta con dos modos de luz: fija e intermitente, para evitar el aburrimiento, tiene un modo de reposo automático que se activa cada 10 – 15 minutos para prevenir la sobre – estimulación. Además, es un producto práctico y ecológico con batería recargable vía USB tipo C, lo que elimina la necesidad de baterías desechables. El collar es ligero y ajustable, ideal para la comodidad de tu mascota.</span></p><p><br></p>', 0, 95, 124, 1, NULL, NULL, NULL, '2026-03-14 09:54:54', NULL, NULL, 'Juguete-collar-apuntador-laser-ajustable-para-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1837, NULL, 'producto', '7501556497052', 0x6A7565, 'FL9705', 10.00, 'Juguete pelota crazy electrica para gatos ', '<p>Juguete pelota crazy electrica para gatos</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Despierta el instinto cazador de tu gato con la pelota interactiva crazy de Fancy Pets. Este innovador juguete, con un cuerpo de ABS resistente y una cola de cordón que simula un ratón, está diseñado para mantener a tu felino activo y entretenido. Con solo presionar un botón, la pelota se moverá de forma aleatoria, girando y saltando para captar su atención e imitar el movimiento de una presa real.La pelota cuenta con tres modos de luz y movimiento que se activas con un solo toque: Luz verde: Movimiento dinámico con saltos. Luz Azul: Máxima velocidad para desafiar sus reflejos. Luz Morada: Movimiento suave, ideal para un juego relajado. Además, es recargable por USB, lo que hace práctica y ecológica y se detiene automáticamente después de 5 minutos para evitar la sobre estimulación. Un toque es suficiente para reactiva la diversión.</span></p>', 0, 100, 124, 1, NULL, NULL, NULL, '2026-03-14 09:56:30', NULL, NULL, 'Juguete-pelota-crazy-electrica-para-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1838, NULL, 'producto', '7501556498769', 0x42454245, 'FL9876', 5.00, 'Bebedero cubo automático para perros y gatos', '<p>Bebedero cubo autómatico para perros y gatos</p><p>Capacidad: 3 L</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Bebedero Automático para Perros y Gatos 3L – Con Filtro de Carbón y Recirculación de Agua</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Ofrece agua siempre limpia y fresca a tus mascotas con este bebedero automático de 3L. Ideal para perros y gatos, con filtro de carbón activado y diseño moderno.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Agua limpia y fresca todo el día para tus mascotas. Bebedero automático de 3L con filtro de carbón activado, ideal para perros y gatos. ¡Silencioso, moderno y fácil de limpiar!</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Dale a tu mascota lo mejor con el bebedero automático Cubo Negro de 3 litros, diseñado para mantener el agua siempre fresca, limpia y en movimiento. Gracias a su sistema de recirculación y su filtro de carbón activado, este bebedero elimina impurezas y malos olores, incentivando a perros y gatos a mantenerse bien hidratados.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Su diseño moderno y compacto se adapta perfectamente a cualquier rincón de tu hogar, mientras que su funcionamiento silencioso y eficiente lo convierte en la opción ideal para uso diario. Además, su capacidad de 3 litros reduce la necesidad de rellenarlo constantemente, ¡perfecto para hogares con varias mascotas!</span></p>', 0, 400, 124, 1, NULL, NULL, NULL, '2026-03-14 09:59:08', NULL, NULL, 'Bebedero-cubo-automatico-para-perros-y-gatos', 0, 0);
INSERT INTO `ecom_productos` VALUES (1839, NULL, 'producto', 'TERAL10603060', 0x544552414C2D3130, 'TERAL-10', 5.00, 'Terrario titan 60 x 30 x 60cm', '<p>Terrario titan puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metálica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario rectangualr de cristal con alumnio para reptiles pequeños a medianos como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva.</span></p>', 0, 1990, 124, 1, NULL, NULL, NULL, '2026-03-24 07:01:29', NULL, NULL, 'Terrario-titan-60-x-30-x-60cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1840, NULL, 'producto', 'TERAL11603050', 0x544552414C2D3131, 'TERAL-11', 5.00, 'Terrario ciclope 50 x 26 x 60cm', '<p>Terrario ciclope puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metálica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario rectangualr de cristal con alumnio para reptiles pequeños a medianos como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puertas corredizas en la parte frontal que se puede abrir hacia la derecha e izquiera para fácil limpieza y en la parte superior de malla metálica no corrosiva.</span></p>', 0, 1600, 124, 1, NULL, NULL, NULL, '2026-03-24 07:22:45', NULL, NULL, 'Terrario-ciclope-50-x-26-x-60cm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1841, NULL, 'producto', 'PECU08505040', 0x504552412D4335303430, 'PERA-C5040', 5.00, 'Pecera cubo 50 x 50 x 40 cm altura 100 litros 6 mm', '<p>Pecera cubo</p><p>Capacidad: 100 litros</p><p>Grosor: 6 mm</p><p>Marcos: Aluminio</p><p><br></p><p>Descripción:pecera cubo para peces, reptiles, roedores, con gran espacio para ellos con marcos de aluminio. Acuarios grandes para peces medianos chicos y grandes o para hacer una pecera comunitaria donde puedas tener mas de una especie de pez con gran variedad aparte con un espacio amplio para que la puedas decorar hermosa y brindarles un espacio amplio comodo y natural a tus peces.</p><p><br></p><p><br></p><p><br></p>', 0, 1350, 124, 1, NULL, NULL, NULL, '2026-05-25 10:20:41', '2026-05-25 10:20:41', NULL, 'Pecera-cubo-50-x-50-x-40-cm-altura-100-litros-6-mm', 0, 0);
INSERT INTO `ecom_productos` VALUES (1842, NULL, 'producto', '7503040428382', 0x414C5345412D3031, 'SP-2838', 5.00, 'Alimentador de semillas farolito para aves 6 estaciónes', '<p>Alimentador de semillas para aves 6 estaciónes</p><p>Capacidad: 360 gr</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Seis estaciones de alimentación con percha, ideales para atraer diversas especies de aves. Su diseño colgante permite una fácil instalación en exteriores, brindando un acceso cómodo a las aves. El depósito transparente facilita el control visual de los niveles de semilla, asegurando que siempre haya alimento disponible. Este alimentador está fabricado en plástico resistente al agua, lo que garantiza su durabilidad y funcionalidad en diferentes condiciones climáticas. Además, su capacidad de 360 mL permite almacenar una cantidad adecuada de semillas, mientras que su fácil sistema de llenado y limpieza asegura un mantenimiento sin complicaciones. Con un diámetro de 12 cm y dimensiones compactas, es perfecto para cualquier jardín o patio. Este comedero es una excelente opción para los amantes de la naturaleza que desean observar aves en su entorno.</span></p><p><br></p><p><br></p><p><br></p><p><br></p>', 0, 99, 124, 1, NULL, NULL, NULL, '2026-03-24 08:31:47', NULL, NULL, 'Alimentador-de-semillas-farolito-para-aves-6-estaciones', 0, 0);
