INSERT INTO `ecom_productos` VALUES (1858, NULL, 'producto', 'TERA17404050', 0x544552412D3137, 'TERA-17', 5.00, 'Terrario regen 40 x 40 x 50cm ', '<p>Terrario regen 40 x 40 x 50cm</p><p>Espesor: 6 mm</p><p>Marcos: plástico</p><p>Material: cristal</p><p><br></p><p>Descripción:</p><p>Terrario rectanguar chico para reptiles pequeños como arañas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta corrediza en la parte frontal que se puede abrir para la derecha para fácil limpieza y en la parte superior de malla metálica no corrosiva.</p>', 0, 1690, 124, 1, NULL, NULL, NULL, '2026-03-27 06:15:43', NULL, NULL, 'Terrario-regen-40-x-40-x-50cm-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1859, NULL, 'producto', 'NIDO012PISO', 0x4E49444F2D3031, 'NIDO-01', 5.00, 'NIdo de casa doble piso', '<p>Nido de casa doble piso</p><p><br></p><p>Descripción:</p><p>Casas refugios, meticulosos construidos para las aves con materiales naturales como madera para proteger sus huevos y crías<span style=\"color: rgb(230, 232, 240); background-color: rgb(31, 31, 31);\">.&nbsp;trae gancho para que </span><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Coloque el nido en un lugar tranquilo y seguro dentro de la jaula, asegurándote de fijarlo bien para evitar movimientos o caídas.</span></p><p><br></p><p><br></p>', 0, 290, 124, 1, NULL, NULL, NULL, '2026-03-27 07:48:31', NULL, NULL, 'NIdo-de-casa-doble-piso', 0, 0);
INSERT INTO `ecom_productos` VALUES (1860, NULL, 'producto', 'NIDO02METIXT', 0x4E49444F2D3032, 'NIDO-02', 5.00, 'Nido externo para jaula de pajaros', '<p>Nido externo para jaula de pajaros</p><p><br></p><p>Descripción:</p><p>Casas refugios, meticulosos construidos para las aves con materiales naturales como ixtle para proteger sus huevos y crías<span style=\"background-color: rgb(31, 31, 31); color: rgb(230, 232, 240);\">.&nbsp;trae gancho para que </span><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Coloque el nido en un lugar externo de la jaula donde esten puertas asegurándote de fijarlo bien para evitar movimientos o caídas.</span></p><p><br></p><p>Su estructura de plástico permite una instalación rápida y estable. ademas que el contorno es metálico para que le ave no escape y trae puerta para q pueda interactuar con la ave.</p><p>Proporciona a tus aves un nido natural y práctico: Este nido de ixtle con marco de plástico es perfecto para jaulas, ofreciendo un ambiente seguro y cálido para tus mascotas.</p><p><br></p><p><br></p><p><br></p>', 0, 125, 124, 1, NULL, NULL, NULL, '2026-03-27 07:50:09', NULL, NULL, 'Nido-externo-para-jaula-de-pajaros', 0, 0);
