INSERT INTO `ecom_productos` VALUES (1868, NULL, 'producto', 'JAUPAJ17CAS', 0x4A41524F2D3137, 'JARO-17', 5.00, 'Jaula casa libre para pajaros', '<p>Jaula casa libre para pajaro</p><p>Color: negra</p><p>Medidas: 46 x 46 x 134cm alto es desde las llantas hasta la puntas de arriba de la jaula</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(70, 71, 74);\">Jaula para aves equipada con cuatro tazones de alimento y dos soportes de percha. que proporcionará horas de entretenimiento y ejercicio. Contiene llantas para sea fácil transportar </span></p><p><span style=\"color: rgb(70, 71, 74);\">para un mantenimiento sencillo: La bandeja de limpieza es desmontable hace que el cuidado de tu jaula sea rápido y práctico con rejilla en la parte inferior para que no tenga contacto con sus eses el ave.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Diseño de Parte Superior Abierta- Para mantener estimulado a tu pájaro, el techo de nuestra jaula colgante puede abrirse y cerrarse a voluntad. Incluye una percha que mantiene las puertas superiores abiertas para que las aves puedan posarse y puede cerrarse para brindarles un hogar seguro y cerrado. La percha de madera en el techo de la jaula te permite interactuar mejor con tus queridas aves.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Contiene:</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">4 puertas de alimentación con cerraduras para una alimentación fácil, 2 vasos de plástico para comida, 3 perchas largas de madera en el interior para descansar, y 1 estante elevado para almacenar comida y bocadillos para pájaros, aumentando también el campo de visión del pájaro y con charola de plástico.</span></p><p><br></p><p><br></p><p><br></p><p><span style=\"color: rgb(70, 71, 74);\">Material: bandeja plástico</span></p>', 0, 1990, 124, 1, NULL, NULL, NULL, '2026-04-29 07:27:42', NULL, NULL, 'Jaula-casa-libre-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1869, NULL, 'producto', '7502234338087', 0x5441502D3037, 'SP-3808', 10.00, 'Tapete entrenador puppy desechable 8 pza para mascotas ', '<p>Tapete entrenador puppy desechable y absorbente para mascotas&nbsp;</p><p>Contenido: 8 pza</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Es la solución perfecta para entrenar a tu mascota de manera efectiva y sin complicaciones. Con su diseño descartable, podrás mantener la higiene y limpieza en tu hogar de forma práctica y sencilla. Cuenta con 6 capas de absorción, garantizando que los líquidos se retengan de manera eficiente y evitando cualquier derrame o filtración. Su largo de 58 cm y ancho de 56 cm brindan un amplio espacio para que tu perro pueda moverse cómodamente y realizar sus necesidades. Además, este tapete cuenta con eliminación de olores, asegurando un ambiente fresco y agradable en todo momento.</span></p>', 0, 96, 124, 1, NULL, NULL, NULL, '2026-04-01 07:17:40', NULL, NULL, 'Tapete-entrenador-puppy-desechable-8-pza-para-mascotas-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1870, NULL, 'producto', 'CAELE01546', 0x4341454C2D3031, 'CAEL-01', 5.00, 'Cama elevanda portatil y transpirable extrachica', '<p>Cama elevanda portatil y transpirable extrachica</p><p><br></p><p>Decripción:</p><p>Para perros de razas pequeñas o chicos de edad, gatos y más mascotas e<span style=\"color: rgb(15, 17, 17); background-color: rgb(255, 255, 255);\">n los días calurosos, los perros pueden tumbarse en el suelo para tomar el sol, y la cama para perros elevada con una cubierta Teslin transpirable proporciona un lugar fresco. En épocas de frío, esta caseta mantiene el cuerpo del perro alejado del frío del suelo o de la humedad de la alfombra. con malla lavable y transpirable.</span><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Cama elevada para mascotas interior/exterior: Tu mascota adorará esta cama de descanso.&nbsp;</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Permite que el aire fresco circule debajo de ella mientras la mantiene alejada de superficies frías o duras. Las mascotas mayores, así como aquellas con movilidad reducida o problemas articulares, también se beneficiarán de esta cama, ya que subir y bajar les resultará fácil.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Fácil de limpiar: El pelo de mascota, la tierra, el barro (u otras manchas que tu perro traiga del césped exterior) se pueden limpiar simplemente enjuagando con agua y dejando secar. También puedes limpiarla fácilmente con una toalla húmeda y practica con </span>Su diseño ligero y portátil permite llevar esta cama elevada para perros a cualquier actividad al aire libre, como camping, picnics, etc.</p>', 0, 350, 124, 1, NULL, NULL, NULL, '2026-04-14 08:57:37', NULL, NULL, 'Cama-elevanda-portatil-y-transpirable-extrachica', 0, 0);
