INSERT INTO `ecom_productos` VALUES (1880, NULL, 'producto', '001911202507', 0x414C4950412D3034, 'ALIPA-04', 5.00, 'Alimento para keets para pajaros', '<p>Alimento para keets para pajaros</p><p><br></p><p>Decripción:</p><p>Alimento mezcla de semillas, para aves como ninfas, periquitos y agapornis Mejora el brillo y color fortalece el sistema inmunologico., es un alimento completo y balanceado</p>', 0, 85, 124, 1, NULL, NULL, NULL, '2026-04-08 07:41:27', NULL, NULL, 'Alimento-para-keets-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1881, NULL, 'producto', '001911202506', 0x414C4950412D3035, 'ALIPA-05', 5.00, 'Alimento para parrots para pajaros', '<p>Alimento para parrots para pajaros</p><p><br></p><p>Decripción:</p><p>Alimento mezcla de semillas, para aves como loros y guacamayas nutrición avanzada adisionado con fruta estimula el desarrollo que contiene vitaminas y minerales,mejora loa digestiony salud intestinal con ingredientes naturales es un alimento completo y balanceado</p>', 0, 85, 124, 1, NULL, NULL, NULL, '2026-04-08 07:41:34', NULL, NULL, 'Alimento-para-parrots-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1882, NULL, 'producto', '001911202505', 0x504150492D3034, 'PAPI-04', 5.00, 'Papilla alimento para baby bird´s para pajaros', '<p>Alimento para baby bird´s para pajaros</p><p><br></p><p>Decripción:</p><p>Alimentación manual incrementa la vitalidad y estimula el apetito, para aves pequeñas recien nacidas nutrición avanzada que contiene vitaminas y minerales 100% natural omegas 3 y 6, fácil digestion rica en proteina fortalece el sistema inmunologico.</p>', 0, 140, 124, 1, NULL, NULL, NULL, '2026-04-08 07:36:39', NULL, NULL, 'Papilla-alimento-para-baby-bird´s-para-pajaros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1883, NULL, 'producto', '7501556408850', 0x4C4547412D3031, 'FL3885', 5.00, 'Sustituto de leche para gatito', '<p>Sustituto de leche para gatito</p><p><br></p><p>Descripción:</p><h4>Nutrición completa para cachorros y gatitos</h4><p>Fórmula en polvo diseñada para aportar nutrientes esenciales que ayudan al óptimo desarrollo desde los primeros días de vida.</p><p><strong>Fácil de preparar y digerir,&nbsp;</strong>contiene enzimas digestivas, probióticos y prebióticos que favorecen la digestión y fortalecen la flora intestinal.</p><p><br></p><h4>Piel y pelaje saludables</h4><p>Con lactobacilos, nucleótidos y nutrientes funcionales que contribuyen a reforzar la respuesta inmune y mantener la piel y el pelaje en óptimas condiciones.</p><p><br></p><h4>Con hojuelas de DHA de origen marino</h4><p>Está formulado para cubrir los requerimientos nutricionales de cachorros y gatitos desde recién nacidos hasta los 2 meses de edad.</p><p><br></p>', 0, 430, 124, 1, NULL, NULL, NULL, '2026-04-08 07:54:16', NULL, NULL, 'Sustituto-de-leche-para-gatito', 0, 0);
INSERT INTO `ecom_productos` VALUES (1884, NULL, 'producto', '7501556498714', 0x544152452D3038, 'FL9871', 5.00, 'Tapete refrescante xl sandia', '<p>Tapete refrescante xl sandia</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(33, 37, 41);\">para perros son una excelente opción para mantener a tu mascota fresca y cómoda en los días calurosos. Estos tapetes están diseñados con un material especial que ayuda a disipar el calor corporal de tu perro y a mantenerlo fresco, sin ser necesario el uso de enfriadores extras pero si lo requieres puede ser refrigerado. Además, son fáciles de limpiar y se pueden usar tanto en interiores como exteriores.</span></p><p><br></p><p><span style=\"color: rgb(33, 37, 41);\">Beneficios </span></p><p><span style=\"color: rgb(33, 37, 41);\">Auto enfriamiento</span></p><p><span style=\"color: rgb(33, 37, 41);\">Práctico de transportar y limpiar</span></p><p><span style=\"color: rgb(33, 37, 41);\">No tóxico</span></p><h4><span style=\"color: rgb(33, 37, 41);\">Brinda comodidad y frescura</span></h4>', 0, 730, 124, 1, NULL, NULL, NULL, '2026-04-08 08:21:06', NULL, NULL, 'Tapete-refrescante-xl-sandia', 0, 0);
INSERT INTO `ecom_productos` VALUES (1885, NULL, 'producto', 'SUSMA031KG', 0x5355534D412D3033, 'SUSMA-03', 15.00, 'Sustrato de maiz para roedores de 1 kg', '<p>Sustrato de maíz para roedores</p><p>Cantidad: 1 kg</p><p><br></p><p>Descripción:</p><p>Altamente asorbente</p><p>Mantiene seco por mas tiempo</p><p>100% natural biodegradable</p><p>No toxico si llegara a consumirse, no tiene ningún riesgo.</p><p><br></p><p>Instrucciones:</p><p>Una vez a la semana cambia el sustrato, desinfecta bien la jaula antes de agregar el nuevo sustrato.</p><p>Hecho a base de aserrin de pino y paja de cereales.</p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, huron, etc.</p><p><br></p><p>Este producto es envasado por volumen, debido a la variación en su densidad y humedad la masa puede ser +_ 15%.</p>', 0, 60, 124, 1, NULL, NULL, NULL, '2026-04-13 07:14:17', NULL, NULL, 'Sustrato-de-maiz-para-roedores-de-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1886, NULL, 'producto', 'SUSPAZU06300', 0x535553502D3036, 'SUSP-06', 15.00, 'Sustrato de papel azul con blanco para roedores de 300 gr', '<p>Sustrato de papel azul con blanco para roedores</p><p>Cantidad: 300 g</p><p><br></p><p>Descripción:</p><p>Control de olor 14 dias su cama de papel de larga duración mantiene la jaula de su mascota fresca hasta por dos semanas, el sustrato de papel hace una cama acogedora y suave es un papael triturado virgen apto para uso alimentario; cómodo y encajable para animales pequeños 99.9% libre de polvo y sin aditivos químicos para mantener el hogar de u mascota seguro y limpio.</p><p>absorbe la humaedad hasta 6 veces su peso y se expande hasta tres veces su tamaño para mantener a tu mascota limpia y seca, ecologica.</p><p><br></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p><p><br></p><p><span style=\"color: rgb(146, 146, 159);\">Este producto es envasado por volumen, debido a la variación en su densidad y humedad la masa puede ser +_ 15%.</span></p>', 0, 120, 124, 1, NULL, NULL, NULL, '2026-04-13 07:14:10', NULL, NULL, 'Sustrato-de-papel-azul-con-blanco-para-roedores-de-300-gr', 0, 0);
