INSERT INTO `ecom_productos` VALUES (1889, NULL, 'producto', 'SUSVI011KG', 0x53555356492D3031, 'SUSVI-01', 15.00, 'Sustrato de viruta natural ', '<p>Sustrato de viruta natural&nbsp;</p><p>Cantidad: 1kg a 1 kg y medio</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Sustrato natural para el hábitat de pequeñas mascotas</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Características:</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">• Altamente absorbente</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">• 100% Natural</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">• Biodegradable</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">• No tóxico</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Modo de uso:</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Coloca el sustrato uniformemente en la jaula o hábitat de tu mascota hasta alcanzar de 3 a 5 cm de altura.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Cambia el sustrato una vez a la semana, desinfecta bien la jaula antes de agregar el nuevo sustrato.viruta hecha a base de madera </span>y sin aditivos químicos para mantener el hogar de tu mascota seguro y limpio.</p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Precauciones y advertencias:</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Manténgase en un lugar seco, evite que se humedezca.</span></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p><p><br></p><p><span style=\"color: rgb(146, 146, 159);\">Este producto es envasado por volumen, debido a la variación en su densidad y humedad la masa puede ser +_ 15%.</span></p>', 0, 50, 124, 1, NULL, NULL, NULL, '2026-04-13 07:13:47', NULL, NULL, 'Sustrato-de-viruta-natural-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1890, NULL, 'producto', 'SUSVI021KG', 0x53555356492D3032, 'SUSVI-02', 15.00, 'Sustrato de viruta natural libre de polvo', '<p>Sustrato de viruta natural libre de polvo</p><p>Cantidad: 1kg</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Sustrato natural para el hábitat de pequeñas mascotas</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Características:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• Altamente absorbente</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• 100% Natural</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• Biodegradable</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• No tóxico</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Modo de uso:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Coloca el sustrato uniformemente en la jaula o hábitat de tu mascota hasta alcanzar de 3 a 5 cm de altura.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Cambia el sustrato una vez a la semana, desinfecta bien la jaula antes de agregar el nuevo sustrato.viruta hecha a base de madera </span>y sin aditivos químicos para mantener el hogar de tu mascota seguro y limpio.</p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Precauciones y advertencias:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Manténgase en un lugar seco, evite que se humedezca.</span></p><p><br></p><p>Para: cuyos, hámster, conejos, erizo, avez, chinchilla, cobaya, ratones, jerbos, hurones, etc.</p><p><br></p><p><span style=\"color: rgb(146, 146, 159);\">Este producto es envasado por volumen, debido a la variación en su densidad y humedad la masa puede ser +_ 15%.</span></p>', 0, 80, 124, 1, NULL, NULL, NULL, '2026-04-13 07:13:41', NULL, NULL, 'Sustrato-de-viruta-natural-libre-de-polvo', 0, 0);
INSERT INTO `ecom_productos` VALUES (1891, NULL, 'producto', 'NIDO10HUEV', 0x4E49444F2D3130, 'NIDO-10', 15.00, 'Nido bola de ixtle', '<p>Nido bola de ixtle para jaula de pajaros</p><p><br></p><p>Descripción:</p><p>Casas refugios, meticulosos construidos para las aves con materiales naturales como ixtle para proteger sus huevos y crías<span style=\"background-color: rgb(31, 31, 31); color: rgb(230, 232, 240);\">.&nbsp;trae gancho para que </span><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Coloque el nido en un lugar seguro dentro de la jaula donde este fijarlo bien para evitar movimientos o caídas.</span></p><p><br></p><p>Su estructura de ixtle natural permite una instalación rápida y estable.</p><p>Proporcionando a tus aves un nido natural y práctico es perfecto para jaulas, ofreciendo un ambiente seguro y cálido para tus mascotas.</p>', 0, 80, 124, 1, NULL, NULL, NULL, '2026-04-13 07:33:26', NULL, NULL, 'Nido-bola-de-ixtle', 0, 0);
INSERT INTO `ecom_productos` VALUES (1892, NULL, 'producto', 'NIDO10CASA', 0x4E49444F2D3131, 'NIDO-11', 15.00, 'Nido casa de ixtle', '<p>Nido casa de ixtle para jaula de pajaros</p><p><br></p><p>Descripción:</p><p>Casas refugios, meticulosos construidos para las aves con materiales naturales como ixtle para proteger sus huevos y crías<span style=\"color: rgb(230, 232, 240); background-color: rgb(31, 31, 31);\">.&nbsp;trae gancho para que </span><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Coloque el nido en un lugar seguro dentro de la jaula donde este fijarlo bien para evitar movimientos o caídas.</span></p><p><br></p><p>Su estructura de ixtle natural permite una instalación rápida y estable.</p><p>Proporcionando a tus aves un nido natural y práctico es perfecto para jaulas, ofreciendo un ambiente seguro y cálido para tus mascotas.</p>', 0, 80, 124, 1, NULL, NULL, NULL, '2026-04-13 07:35:41', NULL, NULL, 'Nido-casa-de-ixtle', 0, 0);
INSERT INTO `ecom_productos` VALUES (1893, NULL, 'producto', '7501556491760', 0x4A55472D3436, 'FL9176', 7.00, 'Juguete de elote con aroma a palomitas grande para perros', '<p>Juguete de elote con aroma a palomitas grande para perros</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Estimula la mente y fortalece los dientes de tu perro con los Juguetes dentales de la línea Sniff. Fabricados en materiales seguros, duraderos y diseñados para resistir la masticación. Su superficie con protuberancias y textura ayuda a limpiar los dientes y masajear las encías mientras tu mascota juega. Disponibles en forma de zanahoria con aroma a panque y elote con aroma a palomitas de maíz, cada juguete tiene un aroma irresistible que estimula el olfato de tu perro y lo mantiene entretenido por mas tiempo. Además, incluyen un squeaker para agregar diversión a la hora del juego. Los juguetes están disponibles en dos tamaños para adaptarse a perros de todas las razas y tamaños.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">Promueve la salud dental: La superficie con protuberancia y el material masticable ayuda a remover el sarro y la placa, fortaleciendo las encías y los músculos de la mandíbula mientras tu perro juega. Estimula el olfato y el instinto: El aroma a panqué o palomitas de maíz cautiva la atención de tu perro, canalizando su instinto natural de morder de forma segura y proporcionando una estimulación mental esencial. Reduce el estrés y la ansiedad: Masticar tiene un efecto calmante natural en los perros, ayudando a liberar la energía acumulada, reducir el nerviosismo y prevenir comportamientos destructivos. Entretenimiento interactivo: Incluye un squeaker que despierta la curiosidad de tu perro, lo mantiene interesado por más tiempo y hace que las sesiones de juego se</span></p><p><br></p>', 0, 130, 124, 1, NULL, NULL, NULL, '2026-04-13 07:59:58', NULL, NULL, 'Juguete-de-elote-con-aroma-a-palomitas-grande-para-perros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1894, NULL, 'producto', '7501556491746', 0x4A55472D3437, 'FL9174', 7.00, 'Juguete de zanahoria con aroma a panque de zanahoria grande para perros', '<p>Juguete de zanahoria con aroma a panque de zanahoria grande para perros</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Estimula la mente y fortalece los dientes de tu perro con los Juguetes dentales de la línea Sniff. Fabricados en materiales seguros, duraderos y diseñados para resistir la masticación. Su superficie con protuberancias y textura ayuda a limpiar los dientes y masajear las encías mientras tu mascota juega. Disponibles en forma de zanahoria con aroma a panque y elote con aroma a palomitas de maíz, cada juguete tiene un aroma irresistible que estimula el olfato de tu perro y lo mantiene entretenido por mas tiempo. Además, incluyen un squeaker para agregar diversión a la hora del juego. Los juguetes están disponibles en dos tamaños para adaptarse a perros de todas las razas y tamaños.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">Promueve la salud dental: La superficie con protuberancia y el material masticable ayuda a remover el sarro y la placa, fortaleciendo las encías y los músculos de la mandíbula mientras tu perro juega. Estimula el olfato y el instinto: El aroma a panqué o palomitas de maíz cautiva la atención de tu perro, canalizando su instinto natural de morder de forma segura y proporcionando una estimulación mental esencial. Reduce el estrés y la ansiedad: Masticar tiene un efecto calmante natural en los perros, ayudando a liberar la energía acumulada, reducir el nerviosismo y prevenir comportamientos destructivos. Entretenimiento interactivo: Incluye un squeaker que despierta la curiosidad de tu perro, lo mantiene interesado por más tiempo y hace que las sesiones de juego sean mas divertidas. Durabilidad y seguridad: Fabricados con TPR, son resistentes y seguros para la masticación, diseñados para soportar el juego rudo y durar mucho tiempo.</span></p>', 0, 130, 124, 1, NULL, NULL, NULL, '2026-04-13 08:02:32', NULL, NULL, 'Juguete-de-zanahoria-con-aroma-a-panque-de-zanahoria-grande-para-perros', 0, 0);
