INSERT INTO `ecom_productos` VALUES (1897, NULL, 'producto', '7501556485011', 0x4A55472D3530, 'FL8501', 5.00, 'Juguete jaladera de caucho con argolla', '<p>Juguete jaladera de caucho con argolla</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(0, 0, 0); background-color: rgb(255, 255, 255);\">Juguete con bordes limpiadores para promover la salud dental del perro, sirve para morder, entretener e interactuar y además de ofrecer un suave masaje a las encías, gracias a su diseño. Ideal para cachorros y perros de raza pequeña.</span></p><p><br></p><p><span style=\"color: rgb(50, 51, 56); background-color: rgb(255, 255, 255);\">&nbsp;Ayuda a mantener limpios los dientes.• El perro se distrae, hace ejercicio y ejercita la mandíbula.• Material lavable.</span></p>', 0, 45, 124, 1, NULL, NULL, NULL, '2026-04-13 08:19:38', NULL, NULL, 'Juguete-jaladera-de-caucho-con-argolla', 0, 0);
INSERT INTO `ecom_productos` VALUES (1898, NULL, 'producto', 'CAMELGRA04', 0x4341454C2D3034, 'CAEL-04', 5.00, 'Cama elevanda portatil y transpirable grande', '<p>Cama elevanda portatil y transpirable grande</p><p><br></p><p>Descripción:</p><p>Para perros de razas pequeñas o chicos de edad, gatos y más mascotas e<span style=\"background-color: rgb(255, 255, 255); color: rgb(15, 17, 17);\">n los días calurosos, los perros pueden tumbarse en el suelo para tomar el sol, y la cama para perros elevada con una cubierta Teslin transpirable proporciona un lugar fresco. En épocas de frío, esta caseta mantiene el cuerpo del perro alejado del frío del suelo o de la humedad de la alfombra. con malla lavable y transpirable.</span><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Cama elevada para mascotas interior/exterior: Tu mascota adorará esta cama de descanso.&nbsp;</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Permite que el aire fresco circule debajo de ella mientras la mantiene alejada de superficies frías o duras. Las mascotas mayores, así como aquellas con movilidad reducida o problemas articulares, también se beneficiarán de esta cama, ya que subir y bajar les resultará fácil.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Fácil de limpiar: El pelo de mascota, la tierra, el barro (u otras manchas que tu perro traiga del césped exterior) se pueden limpiar simplemente enjuagando con agua y dejando secar. También puedes limpiarla fácilmente con una toalla húmeda y practica con </span>Su diseño ligero y portátil permite llevar esta cama elevada para perros a cualquier actividad al aire libre, como camping, picnics, etc.</p>', 0, 750, 124, 1, NULL, NULL, NULL, '2026-04-20 06:12:23', NULL, NULL, 'Cama-elevanda-portatil-y-transpirable-grande', 0, 0);
INSERT INTO `ecom_productos` VALUES (1899, NULL, 'producto', 'CAMELEXGRA05', 0x4341454C2D3035, 'CAEL-05', 5.00, 'Cama elevanda portatil y transpirable extra grande ', '<p>Cama elevanda portatil y transpirable extra grande</p><p><br></p><p>Descripción:</p><p>Para perros de razas pequeñas o chicos de edad, gatos y más mascotas e<span style=\"background-color: rgb(255, 255, 255); color: rgb(15, 17, 17);\">n los días calurosos, los perros pueden tumbarse en el suelo para tomar el sol, y la cama para perros elevada con una cubierta Teslin transpirable proporciona un lugar fresco. En épocas de frío, esta caseta mantiene el cuerpo del perro alejado del frío del suelo o de la humedad de la alfombra. con malla lavable y transpirable.</span><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Cama elevada para mascotas interior/exterior: Tu mascota adorará esta cama de descanso.&nbsp;</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Permite que el aire fresco circule debajo de ella mientras la mantiene alejada de superficies frías o duras. Las mascotas mayores, así como aquellas con movilidad reducida o problemas articulares, también se beneficiarán de esta cama, ya que subir y bajar les resultará fácil.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Fácil de limpiar: El pelo de mascota, la tierra, el barro (u otras manchas que tu perro traiga del césped exterior) se pueden limpiar simplemente enjuagando con agua y dejando secar. También puedes limpiarla fácilmente con una toalla húmeda y practica con </span>Su diseño ligero y portátil permite llevar esta cama elevada para perros a cualquier actividad al aire libre, como camping, picnics, etc.</p>', 0, 850, 124, 1, NULL, NULL, NULL, '2026-04-20 06:14:57', NULL, NULL, 'Cama-elevanda-portatil-y-transpirable-extra-grande-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1900, NULL, 'producto', '7501556436211', 0x434F4C412D3031, 'FL3621', 5.00, 'Colageno medical solutions para perros y gatos ', '<p>Colageno medical solution para perros y gatos&nbsp;</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Vitalidad para su pelo, piel y uñas</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">El colágeno es un componente esencial para mantener la salud del cabello, las uñas y las articulaciones, además de la elasticidad de la piel que se va perdiendo con el paso del tiempo. La función principal de este suplemento es aportar resistencia al estiramiento de los tejidos y colaborar con el buen funcionamiento de los cartílagos y huesos.</span></p><p><br></p><p>Se puede mezclar con el alimento o diluir en agua, ideal para incluir en la dieta diaria.</p><p>Presentación de 200 g; una cucharadita (3 g) por cada 10 kg de peso corporal al día.</p><p><br></p>', 0, 290, 124, 1, NULL, NULL, NULL, '2026-04-20 06:18:29', NULL, NULL, 'Colageno-medical-solutions-para-perros-y-gatos-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1901, NULL, 'producto', '7503048378382', 0x414C4950412D3037, 'TP-7838', 5.00, 'Alimento para periquitos australianos monte verde', '<p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">&nbsp;</span>Alimento para periquitos australianos monte verde</p><p><br></p><p>Descipción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Mejora el brillo y calidad del plumaje.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• Fuente de ácidos grasos insaturados.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• Fortalece el sistema inmunológico.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">• Granos y semillas altamente seleccionados.</span></p>', 0, 90, 124, 1, NULL, NULL, NULL, '2026-04-20 08:25:01', NULL, NULL, 'Alimento-para-periquitos-australianos-monte-verde', 0, 0);
INSERT INTO `ecom_productos` VALUES (1902, NULL, 'producto', '7503048378399', 0x414C4950412D3038, 'TP-7839', 5.00, 'Alimento para agapornis y ninfas monte verde', '<p>Alimento para agapornis y ninfas monte verde</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Alimento Premium para Ninfas y Agapornis de Monte Verde es la opción ideal para quienes buscan proporcionar una dieta equilibrada y nutritiva a sus aves.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Este alimento está elaborado con ingredientes 100% naturales, garantizando que tus aves reciban lo mejor en cada bocado. Su formulación está diseñada específicamente para satisfacer las necesidades nutricionales, promoviendo su salud y bienestar.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Cada paquete contiene una mezcla cuidadosamente seleccionada de semillas y nutrientes esenciales que favorecen el plumaje brillante y la energía activa de tus ninfas y agapornis. La calidad de los ingredientes asegura que tus aves disfruten de un sabor delicioso, lo que facilita la aceptación del alimento y fomenta una alimentación adecuada.</span></p>', 0, 90, 124, 1, NULL, NULL, NULL, '2026-04-20 08:28:06', NULL, NULL, 'Alimento-para-agapornis-y-ninfas-monte-verde', 0, 0);
INSERT INTO `ecom_productos` VALUES (1903, NULL, 'producto', '7503048378375', 0x414C4950412D3039, 'TP-7837', 5.00, 'Alimento para canarios y finches monte verde', '<p>Alimento para canarios y finches monte verde</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Alimento para aves pequeñas Canarios y Finches de la marca Monte Verde es la opción ideal para proporcionar una dieta equilibrada y nutritiva a tus aves.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Este producto está formulado específicamente para satisfacer las necesidades alimenticias de canarios y finches, asegurando que reciban todos los nutrientes esenciales para su salud y bienestar.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">La mezcla de semillas seleccionadas y ingredientes de alta calidad promueve una vida activa y saludable, favoreciendo el plumaje brillante y la vitalidad de tus aves. Cada bocado está diseñado para ser sabroso y atractivo, estimulando el apetito y el disfrute de tus mascotas.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Puedes estar seguro de que estás eligiendo un alimento que respeta la naturaleza de tus aves, ayudando a mantener su energía y alegría. Ideal para criadores y amantes de las aves, este alimento es una excelente elección para el cuidado diario de tus canarios y finches.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Ingredientes: Alpiste, Colza, Nabina, Linaza, Avena desvainada, Granulado con vitaminas añadidas.</span></p>', 0, 90, 124, 1, NULL, NULL, NULL, '2026-04-20 08:30:11', NULL, NULL, 'Alimento-para-canarios-y-finches-monte-verde', 0, 0);
INSERT INTO `ecom_productos` VALUES (1904, NULL, 'producto', '7503048378405', 0x414C4950412D3036, 'TP-7840', 5.00, 'Alimento para cacatúa, loro y guacamaya monte verde', '<p>Alimento para cacatúa, loro y guacamaya monte verde</p><p><br></p><p>Descripción:</p><p>Alimento balanceado con granos de alta calidad sin colorantes</p><p>Mijo amarillo, cártamo, girasol fino, mijo rojo, trigo, linaza, sorgo rojo, alforfón, girasol blanco, avena sin cascaras, avena negra, frijol mungo, alpiste, girasol negro, gravilla mineral, granulado con vitaminas añadidas.</p><p><br></p><p>-Satisface las necesidades nutricionales de las ninfas y agapornis</p><p>-Proporciona la cantidad adecuada de minerales y vitaminas</p><p>-Es una fuente de ácidos grasos insaturados</p><p>-Protege a las aves de la obesidad</p><p>-Mejora la digestión favoreciendo la excreción de los desechos</p><p>-Fortacele el sistema inmunológico</p><p>-Estimula la fertilidad</p><p>-Mejora el color, brillo y la calidad del plumaje en épocas de muda</p><p>-Mejora la calidad de piel gracias a sus sales minerales, magnesio, hierro y fosforo.</p>', 0, 90, 124, 1, NULL, NULL, NULL, '2026-04-20 08:09:53', NULL, NULL, 'Alimento-para-cacatua,-loro-y-guacamaya-monte-verde', 0, 0);
INSERT INTO `ecom_productos` VALUES (1905, NULL, 'producto', '5900469523315', 0x414C4950412D3130, 'TP-52331', 5.00, 'Alimento para periquitos budgie tropifit', '<p>Alimento para periquitos budgie tropifit</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">&nbsp;Para Periquito Australiano es la opción ideal para quienes buscan lo mejor para sus aves.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Los cereales para periquitos y las semillas de hierba son el alimento principal de los periquitos en su entorno natural. Gracias a ellos, las aves reciben la mayor parte de los nutrientes, minerales y vitaminas necesarios para la vida. El alimento para periquitos es una mezcla de cereales seleccionados y semillas de hierbas, que deben su riqueza de ingredientes al suelo fértil de regiones ecológicamente limpias y a los rayos del sol. La variedad de sabores deleita a las aves y los anima a alimentarse.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Un excelente alimento para periquitos y otras especies de pájaros pequeños, por ejemplo Agapornis ( Agapornis spp. ), bisbitas ( Psephotus spp. ), lirios de prado ( Neophema spp. ) y lirios ( Neophema bourkii )</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Alimento formulado específicamente para satisfacer las necesidades nutricionales de los periquitos australianos, garantizando una dieta equilibrada y saludable. Contiene cereales seleccionados y semillas de hierba, está enriquecido con gránulos de cereales obtenidos por extrusión, gracias a lo cual los nutrientes de los cereales son mucho mejor absorbidos por las aves. La variedad de sabores de los ingredientes utilizados anima a las aves a alimentarse.</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-23 08:39:12', NULL, NULL, 'Alimento-para-periquitos-budgie-tropifit', 0, 0);
INSERT INTO `ecom_productos` VALUES (1906, NULL, 'producto', '5900469523414', 0x414C4950412D3131, 'TP-52341', 5.00, 'Alimento para canarios canary tropifit 700g', '<p>Alimento para canarios canary tropifit</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Es la elección ideal para garantizar la salud y vitalidad de tu ave. Este alimento ha sido especialmente formulado para canarios, ofreciendo una mezcla de semillas y granos seleccionados que satisfacen sus necesidades nutricionales. Cada bocado está diseñado para promover un plumaje brillante y un canto melodioso, asegurando que tu canario se mantenga en óptimas condiciones.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">La selección de ingredientes de alta calidad en Tropifit proporciona no solo un excelente sabor, sino también los nutrientes esenciales que tu canario necesita para cada etapa de su vida. Con componentes naturales que fomentan la energía y la actividad, este alimento se convierte en la base perfecta para un canario feliz y saludable.</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-23 08:38:31', NULL, NULL, 'Alimento-para-canarios-canary-tropifit-700g', 0, 0);
INSERT INTO `ecom_productos` VALUES (1907, NULL, 'producto', '5900469523513', 0x414C4950412D3132, 'TP-52351', 5.00, 'Alimento para aves exóticas tropifit', '<p>Alimento para aves exóticas tropifit</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">proporciona una mezcla de granos de cereales y semillas para pinzones pequeños, por ejemplo pinzones cebra (Taeniopygia guttata), gaviotas (Lonchura striata domestica), pinzones arroceros grises (Lonchura oryzivora), dientes de león tricolor (Lonchura malacca), gorriones limón (Passer luteus), pico plateado (Euodice spp.), etc.</span></p><p><br></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Con una composición equilibrada y variada satisface las necesidades nutricionales de los granulópodos, Proporciona la cantidad adecuada de minerales y vitaminas. Es una fuente de ácidos grasos insaturados.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Utilizando únicamente granos y semillas controlados y de alta calidad, garantiza la salud de sus aves. Es la opción ideal para quienes buscan proporcionar una dieta equilibrada y nutritiva a sus aves. Está formulado con granos, cereales y semillas selectas que garantizan una alimentación de alta calidad, promoviendo la salud y el bienestar de tus aves.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Cada ingrediente ha sido cuidadosamente seleccionado para ofrecer un perfil nutricional completo, asegurando que tus aves reciban todos los nutrientes esenciales que necesitan para prosperar. La mezcla de semillas y cereales no solo es deliciosa, sino que también fomenta el comportamiento natural de forrajeo, manteniendo a tus aves activas y felices.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Este alimento es perfecto para criadores y amantes de las aves que desean lo mejor para sus mascotas. Con este alimento Súper Premium puedes estar seguro de que estás eligiendo un producto que respeta las necesidades alimenticias de tus finches, pinzones y gorriones, contribuyendo a su longevidad y vitalidad.</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-23 08:42:17', NULL, NULL, 'Alimento-para-aves-exoticas-tropifit', 0, 0);
INSERT INTO `ecom_productos` VALUES (1908, NULL, 'producto', '5900469523216', 0x414C4950412D3133, 'TP-52321', 5.00, 'Alimento para ninfas, agapornis y pericos tropifit 700gr', '<p>Alimento para ninfas, agapornis y pericos tropifit</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Satisface las necesidades nutricionales de tus aves y proporciona la cantidad adecuada de minerales y vitaminas. Es una fuente de ácidos grasos insaturados.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Utilizando únicamente granos y semillas controlados y de alta calidad, garantiza la salud de sus aves. Con una mezcla de granos de cereales y semillas para cacatúas y otras especies de loros de tamaño mediano, por ejemplo: Alejandrinos (Psittacula spp.), Rosellas (Platycercus spp.), Loros Garganta Roja (Pyrrhura spp.) y Loros Africanos del Senegal (Poicephalus senegalus).</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">La opción ideal para quienes buscan proporcionar una dieta equilibrada y nutritiva a sus aves. Este producto está formulado con una mezcla selecta de frutos secos, granos y semillas que favorecen la salud y el bienestar de tus mascotas.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Cada ingrediente ha sido cuidadosamente seleccionado para ofrecer un alto valor nutricional, asegurando que tus ninfas reciban todos los nutrientes esenciales que necesitan para prosperar. La variedad de sabores y texturas estimula su apetito y promueve un comportamiento activo y saludable.</span></p>', 0, 150, 124, 1, NULL, NULL, NULL, '2026-04-23 08:44:12', NULL, NULL, 'Alimento-para-ninfas,-agapornis-y-pericos-tropifit-700gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1909, NULL, 'producto', '7501556440775', 0x414C4950412D3134, 'FL4077', 5.00, 'Alimento mezcla de semillas loritos y ninfas para pajaros 1 kg', '<p>Mezcla de semillas</p><p>Para: Ninfas, pericos australianos, agapornis y pericos de collar.</p><p><br></p><p>Descripción: Este alimento elaborado para aves adultas con una mezcla de semillas exclusivas y balanceadas para este tipo de aves que los nutrirá</p><p>Fortificado con vitaminas y minerales.</p><p>Fórmula 100% natural balanceada</p><p>Coloque diariamente el alimento en un recipiente limpio y seco.</p>', 0, 180, 124, 1, NULL, NULL, NULL, '2026-04-23 08:56:07', NULL, NULL, 'Alimento-mezcla-de-semillas-loritos-y-ninfas-para-pajaros-1-kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1910, NULL, 'producto', '5900469531112', 0x414C4948412D3131, '53111', 5.00, 'Alimento tropifit premium para hámster 500gr', '<p>Alimento tropifit premium para hámster 500gr</p><p><br></p><p>Descripción: </p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(102, 102, 102);\">Alimento completo para hamsters con banana y granos de alfalfa altamente proteica. Los componentes básicos de HAMSTER son granos obtenidos por extrusión, que favorece la digestión y la asimilación de los nutrientes de los granos.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">La alfalfa y los granos presentes en este alimento son ingredientes de alta calidad que proporcionan los nutrientes necesarios para el bienestar de tu hamster. Además, su presentación en gránulos facilita la ingesta y digestión de tu mascota.</span></p><p><br></p><p><br></p>', 0, 155, 124, 1, NULL, NULL, NULL, '2026-04-23 09:56:36', NULL, NULL, 'Alimento-tropifit-premium-para-hamster-500gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1911, NULL, 'producto', 'ARE13LAVA30', 0x4152452D3133, 'ARE-13', 5.00, 'Arena pawffy con aroma lavanada para gato 30kg', '<p>Arena pawffy con aroma lavanada para gato</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">SUPER CONDENSACIÓN, FUERTE AROMA</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Utiliza sodio natural de la bentonita para solidificar rápidamente con heces y orina de gato.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">EL MÍNIMO POLVO Y AMIGABLE CON EL MEDIO AMBIENTE</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Adopta procesos avanzados de esterilización de polvo y esterilización a alta temperatura con bentonita de sodio natural pura.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">MENOR CONSUMO, FRAGANCIA NATURAL</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Las partículas de la arena son más gruesas, lo que permite un mejor rendimiento en la limpieza y ahorros significativos en el consumo. La arena no se sale fácilmente del arenero.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">En caso de que el gato no se acostumbre rápidamente a la arena, mezclar una pequeña porción de la arena anterior puede ayudar.</span></p>', 0, 650, 124, 1, NULL, NULL, NULL, '2026-04-29 07:25:57', NULL, NULL, 'Arena-pawffy-con-aroma-lavanada-para-gato-30kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1912, NULL, 'producto', 'ARE14SINARO30', 0x4152452D3134, 'ARE-14', 5.00, 'Arena pawffy sin aroma para gato 30kg', '<p>Arena pawffy sin aroma para gato</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">SUPER CONDENSACIÓN, FUERTE AROMA</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Utiliza sodio natural de la bentonita para solidificar rápidamente con heces y orina de gato.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">EL MÍNIMO POLVO Y AMIGABLE CON EL MEDIO AMBIENTE</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Adopta procesos avanzados de esterilización de polvo y esterilización a alta temperatura con bentonita de sodio natural pura.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">MENOR CONSUMO, FRAGANCIA NATURAL</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Las partículas de la arena son más gruesas, lo que permite un mejor rendimiento en la limpieza y ahorros significativos en el consumo. La arena no se sale fácilmente del arenero.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">En caso de que el gato no se acostumbre rápidamente a la arena, mezclar una pequeña porción de la arena anterior puede ayudar.</span></p>', 0, 499, 124, 1, NULL, NULL, NULL, '2026-04-29 07:24:28', NULL, NULL, 'Arena-pawffy-sin-aroma-para-gato-30kg', 0, 0);
INSERT INTO `ecom_productos` VALUES (1913, NULL, 'producto', '7501556438482', 0x47414C4C2D3038, 'FL3848', 10.00, 'Premio nutri bark galletascon crema de cacahuate para perros', '<p>Premio nutri bark galletascon crema de cacahuate para perros</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">NUTRI BARK</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Consiente a tu mejor amigo con las Galletas Nutribarck de Fancy Pets, una forma sabrosa y saludable de entretenerlo. Están elaboradas con ingredientes seleccionados como avena, crema de cacahuate, zanahoria y manzana deshidratadas, que no solo conquistan su paladar, sino que también aportan beneficios funcionales. Ayudan a satisfacer el instinto natural de mordisqueo, reducen el estrés y contribuyen a la liberación de energía acumulada, favoreciendo el bienestar físico y emocional de tu mascota.Proteína cruda (mín.).</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">12%Grasa cruda (mín.) 8%Fibra cruda (máx.) 3%Humedad (máx.) 10%</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">sabor:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Avena, manzana, zanahoria.</span></p><p><br></p><p><br></p>', 0, 70, 124, 1, NULL, NULL, NULL, '2026-04-29 07:47:55', NULL, NULL, 'Premio-nutri-bark-galletascon-crema-de-cacahuate-para-perros', 0, 0);
INSERT INTO `ecom_productos` VALUES (1914, NULL, 'producto', '7501556445060', 0x4741542D3031, 'FL4506', 10.00, 'Premios yummy delice para gato 60 gr', '<p>Premios yummy delice para gato para perros</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Los triangulitos Yummy Delice son la mejor opción de snacks saludables para gatos, formulados con ingredientes de la más alta calidad. Hechos con harina de salmón como proteína principal, aportan todos los aminoácidos esenciales, Omega 3 y 6, además de vitaminas y minerales necesarios para el bienestar diario de tu felino.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Los premios para gato Yummy Delice son ideales para consentir a tu felino con un snack saludable, nutritivo y delicioso. Elaborados con harina de salmón de alta calidad, estos premios contienen proteínas de fácil digestión y todos los 11 aminoácidos esenciales que tu gato necesita para una vida activa y feliz.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Gracias a su contenido de aceite de salmón, Yummy Delice proporciona una fuente natural de ácidos grasos Omega 3 y Omega 6 (incluyendo DHA y EPA), que ayudan a mantener un pelaje brillante, piel sana y un sistema inmune fuerte. Además, están fortificados con vitaminas y minerales esenciales, convirtiéndolos en un complemento perfecto para una alimentación equilibrada.</span></p>', 0, 35, 124, 1, NULL, NULL, NULL, '2026-04-29 08:45:48', NULL, NULL, 'Premios-yummy-delice-para-gato-60-gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1915, NULL, 'producto', '7501556445190', 0x4741542D3032, 'FL4519', 10.00, 'Premios yummy crunch para gato 50 gr', '<p>Premios yummy crunch para gato</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">&nbsp;Yummy Crunch contiene Colágeno para articulaciones y Aceite de Salmón (Omega 3) para un pelaje brillante.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Premios crujientes para gatos elaborados con ingredientes de alta calidad que aportan nutrientes esenciales y una textura irresistible.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">El premio crujiente que tu gato amará, ¡y su salud también! Cada bocado combina un sabor irresistible con ingredientes funcionales como el colágeno y el aceite de salmón para cuidar sus articulaciones y darle un pelaje espectacular.</span></p>', 0, 45, 124, 1, NULL, NULL, NULL, '2026-04-29 08:48:26', NULL, NULL, 'Premios-yummy-crunch-para-gato-50-gr', 0, 0);
INSERT INTO `ecom_productos` VALUES (1916, NULL, 'producto', '7501556452020', 0x59554D2D3031, 'FL9202', 10.00, 'Premios yummy cremoso sabor atún', '<p>Premios yummy cremoso sabor atún</p><p>Contiene: 4 tubos de 14gr c/u</p><p><br></p><p>Descripción:</p><p>Delicioso sabor atún, ideal para gatos de todas las edades.</p><p>Aporta taurina, Omega 3 y prebióticos.</p><p>Alta palatabilidad y fácil digestión.</p><p>Sin leche, sin azúcar, sin conservadores.</p><p>Formato en tubo para servir directamente o mezclar.</p><p><br></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-29 08:50:23', NULL, NULL, 'Premios-yummy-cremoso-sabor-atun', 0, 0);
INSERT INTO `ecom_productos` VALUES (1917, NULL, 'producto', '7501556452013', 0x59554D2D3032, 'FL9201', 10.00, 'Premios yummy cremoso sabor salmón', '<p>Premios yummy cremoso sabor salmón</p><p>Contiene: 4 tubos de 14gr c/u</p><p><br></p><p>Descripción:</p><p>Sabor salmón irresistible, ideal para gatos exigentes.</p><p>Premio funcional con Omega 3 y taurina para salud integral.</p><p>Textura lamible para reforzar vínculo y fácil consumo.</p><p>Sin conservadores, azúcar ni lactosa.</p><p>Presentación individual, práctica para uso diario.</p><p><br></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-29 08:52:14', NULL, NULL, 'Premios-yummy-cremoso-sabor-salmon', 0, 0);
INSERT INTO `ecom_productos` VALUES (1918, NULL, 'producto', '7501556452037', 0x59554D2D3033, 'FL9203', 10.00, 'Premios yummy cremoso sabor pescado y camarón', '<p>Premios yummy cremoso sabor pescado y camarón</p><p>Contiene: 4 tubos de 14gr c/u</p><p><br></p><p>Descripción:</p><p>Sabor salmón irresistible, ideal para gatos exigentes.</p><p>Premio funcional con Omega 3 y taurina para salud integral.</p><p>Textura lamible para reforzar vínculo y fácil consumo.</p><p>Sin conservadores, azúcar ni lactosa.</p><p>Presentación individual, práctica para uso diario.</p><p><br></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-29 08:56:54', NULL, NULL, 'Premios-yummy-cremoso-sabor-pescado-y-camaron', 0, 0);
INSERT INTO `ecom_productos` VALUES (1919, NULL, 'producto', '7501556492040', 0x59554D2D3034, 'FL9204', 10.00, 'Premios yummy cremoso sabor atún y salmón', '<p>Premios yummy cremoso sabor atún y salmón</p><p>Contiene: 4 tubos de 14gr c/u</p><p><br></p><p>Descripción:</p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Snack lamible y cremoso ideal para gatos de todas las edades. Fácil de servir, irresistible sabor, perfecto como premio o para reforzar el vínculo con tu gato. Presentación en sobre. ¡Tu gato lo amará!</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Snack Cremoso Para Gato Yummy Creamy | Natural, Con Omega 3, Taurina y Prebióticos | Atún, Salmón o Camarón</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Delicioso snack cremoso para gatos, ideal como premio o complemento diario. Rico en nutrientes, fácil de digerir y con sabores irresistibles que tu gato amará.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.55);\">Yummy Creamy es el snack cremoso diseñado para consentir a los gatos con una mezcla ideal de sabor y nutrición. Con ingredientes de alta calidad, beneficios funcionales y una textura irresistible, es perfecto para reforzar el vínculo con tu mascota mientras la cuidas.</span></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-29 08:59:12', NULL, NULL, 'Premios-yummy-cremoso-sabor-atun-y-salmon', 0, 0);
INSERT INTO `ecom_productos` VALUES (1920, NULL, 'producto', '7501556492057', 0x59554D2D3035, 'FL9205', 10.00, 'Premios yummy cremoso sabor bacalao y salmón', '<p>Premios yummy cremoso sabor bacalao y salmón</p><p>Contiene: 4 tubos de 14gr c/u</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Textura cremosa y suave, fácil de lamer y digerir.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">-Omega 3 para un pelaje brillante, articulaciones sanas y buena función cerebral.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">-Taurina y proteína real, esenciales para músculos fuertes, visión y salud cardíaca.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">-Prebióticos naturales, almidón de tapioca y extracto de levadura que favorecen la digestión.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">-85% de humedad que ayuda a mantener a tu gato hidratado.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">-Sin azúcar, conservadores ni colorantes artificiales.</span></p><p><br></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Uso recomendado:</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Gatos exigentes o con bajo apetito.</span></p><p><span style=\"color: rgba(0, 0, 0, 0.55); background-color: rgb(255, 255, 255);\">Gatos de todas las edades.</span></p>', 0, 65, 124, 1, NULL, NULL, NULL, '2026-04-29 09:01:33', NULL, NULL, 'Premios-yummy-cremoso-sabor-bacalao-y-salmon', 0, 0);
INSERT INTO `ecom_productos` VALUES (1921, NULL, 'producto', 'TERALU12504080', 0x544552414C2D3132, 'TERAL-12', 5.00, 'Terrario ecuatorial 50 x 40 x 80cm puertas deslizables ', '<p>Terrario ecuatorial puertas deslizables</p><p>Marcos: aluminio</p><p>Espesor cristal:6 mm</p><p>Malla: metálica</p><p><br></p><p>Descripción:</p><p><span style=\"color: rgb(94, 98, 120);\">Terrario vertical de cristal con alumnio para reptiles pequeños a medianos como iguanas, gecko, lagartijas, serpientes, tarantulas, lagartos, tortugas, camaleones, ranas, cocodrilo, mantis, etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con dos puertas deslizables malla metálica a los costados y en la parte superior para mayor ventilación.</span></p>', 0, 3900, 124, 1, NULL, NULL, NULL, '2026-05-12 08:47:28', NULL, NULL, 'Terrario-ecuatorial-50-x-40-x-80cm-puertas-deslizables-', 0, 0);
INSERT INTO `ecom_productos` VALUES (1922, NULL, 'producto', 'TERAM06804060', 0x544552414D2D3036, 'TERAM-06', 5.00, 'Terrario delmy 80cm malla de tela', '<p>Terrario delmy</p><p>Marcos: madera</p><p>Malla: tela</p><p><br></p><p>Descripción:</p><p>Terrario horizontal amplio y grande para reptiles como iguanas, gecko, lagartijas, serpientes, tarantulas, tortugas, camaleones, ranas, dragon barbudo etc. los puedes equipar según las necesidades de reptil, anfibio y más. Cuenta con puerta abatible en la parte frontal para fácil limpieza y en la parte superior de madera con tela de lona forrrado con adaptacion de soquet para foco y latereles de malla de metalica para mayor seguridad y contención de tu mascota, piso de madera forrado de tela de lona con decoración de tronco fijo.</p><p><br></p>', 0, 1390, 124, 1, NULL, NULL, NULL, '2026-05-04 08:11:07', NULL, NULL, 'Terrario-delmy-80cm-malla-de-tela', 0, 0);
