INSERT INTO `ecom_productos` VALUES (1924, NULL, 'producto', '7502278911291', 0x4E414E4F2D3131, 'Art.4060', 5.00, 'Acuario paris 15 lts ', '<p>Acuario paris</p><p>Capacidad: 15 litros</p><p>Medidas puro acuario: 30 x 20 x 35 cm (largo x ancho x alto)</p><p>Lampara potencia: w</p><p>Voltaje: 110/120v</p><p>Cabeza de poder flujo maximo: l/h</p><p><br></p><p>Descrpción:</p><p>Acuario panoramico curvo puede montarse como acuarios de agua dulce cuenta con filtro superior en forma de cascada para todo el acuario con lámpara led de bajo consumo y tapa de plástico. Es ideal para peces tropicales, peces japoneces, betas, y mas elegante, sofisticado de tamaño precenciable de instalación rápida y fácil mantenimiento. con cristal impreso de una sola pieza y con cristal ultra claro.</p><p><br></p><p>Incluye:</p><p>Tapa con luz</p><p>filtro interno</p>', 0, 1490, 124, 1, NULL, NULL, NULL, '2026-05-12 08:09:45', NULL, NULL, 'Acuario-paris-15-lts-', 0, 0);
